/* motorcycle-data.js — Motorcycle permit practice (based on the MSF/NHTSA Motorcycle Operator Manual).
   window.MOTO = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] } — all 6 languages. */
window.MOTO = {"cats":[{"id":"controls","name":{"en":"Controls & Operation","es":"Controles y operación","ru":"Органы управления","tr":"Kumandalar ve Kullanım","hi":"नियंत्रण और संचालन","ar":"أدوات التحكم والتشغيل"},"blurb":{"en":"Hand and foot controls, the friction zone, shifting, starting and stopping.","es":"Controles de mano y pie, la zona de fricción, los cambios, arrancar y detenerse.","ru":"Ручные и ножные органы управления, зона сцепления, переключение, старт и остановка.","tr":"El ve ayak kumandaları, friksiyon bölgesi, vites, kalkış ve durma.","hi":"हाथ-पैर के नियंत्रण, फ्रिक्शन ज़ोन, गियर, शुरू करना और रोकना।","ar":"أدوات التحكم اليدوية والقدمية، ومنطقة الاحتكاك، والتبديل، والانطلاق والتوقف."}},{"id":"gear","name":{"en":"Protective Gear","es":"Equipo de protección","ru":"Защитная экипировка","tr":"Koruyucu Ekipman","hi":"सुरक्षात्मक गियर","ar":"معدات الحماية"},"blurb":{"en":"Helmets, eye and face protection, jackets, gloves, boots and being seen.","es":"Cascos, protección de ojos y cara, chaquetas, guantes, botas y ser visible.","ru":"Шлемы, защита глаз и лица, куртки, перчатки, ботинки и заметность.","tr":"Kasklar, göz ve yüz koruması, montlar, eldivenler, botlar ve görünürlük.","hi":"हेलमेट, आँख-चेहरे की सुरक्षा, जैकेट, दस्ताने, बूट और दिखना।","ar":"الخوذات، وحماية العينين والوجه، والسترات، والقفازات، والأحذية، والظهور."}},{"id":"braking","name":{"en":"Braking & Stopping","es":"Frenado y detención","ru":"Торможение и остановка","tr":"Frenleme ve Durma","hi":"ब्रेकिंग और रुकना","ar":"الكبح والتوقف"},"blurb":{"en":"Using both brakes, quick stops, swerving and following distance.","es":"Usar ambos frenos, frenadas rápidas, esquivar y distancia de seguimiento.","ru":"Оба тормоза, экстренная остановка, объезд и дистанция.","tr":"Her iki fren, hızlı duruş, manevra ve takip mesafesi.","hi":"दोनों ब्रेक, तेज़ रुकाव, स्वर्व और फॉलोइंग दूरी।","ar":"استخدام الفرملتين، والتوقف السريع، والمراوغة، ومسافة المتابعة."}},{"id":"cornering","name":{"en":"Turning & Lane Position","es":"Giros y posición en el carril","ru":"Повороты и положение в полосе","tr":"Dönüş ve Şerit Konumu","hi":"मोड़ और लेन स्थिति","ar":"الانعطاف وموضع المسار"},"blurb":{"en":"Slow-Look-Press-Roll, countersteering, leaning and lane positioning.","es":"Reduce-Mira-Presiona-Acelera, contramanillar, inclinarse y posición en el carril.","ru":"Замедлись-Смотри-Нажми-Газуй, контрруление, наклон и положение в полосе.","tr":"Yavaşla-Bak-Bastır-Gazla, ters direksiyon, yatma ve şerit konumu.","hi":"धीमा-देखो-दबाओ-बढ़ाओ, काउंटरस्टीयरिंग, झुकाव और लेन स्थिति।","ar":"أبطئ-انظر-اضغط-سرّع، والتوجيه العكسي، والميل، وموضع المسار."}},{"id":"visibility","name":{"en":"Being Seen & SEE","es":"Ser visible y SEE","ru":"Заметность и SEE","tr":"Görünürlük ve SEE","hi":"दिखना और SEE","ar":"الظهور و SEE"},"blurb":{"en":"The SEE strategy, conspicuity, intersections, signaling and blind spots.","es":"La estrategia SEE, visibilidad, intersecciones, señalización y puntos ciegos.","ru":"Стратегия SEE, заметность, перекрёстки, сигналы и слепые зоны.","tr":"SEE stratejisi, görünürlük, kavşaklar, sinyal ve kör noktalar.","hi":"SEE रणनीति, दृश्यता, चौराहे, सिग्नल और ब्लाइंड स्पॉट।","ar":"استراتيجية SEE، والظهور، والتقاطعات، والإشارة، والنقاط العمياء."}},{"id":"hazards","name":{"en":"Hazards & Surfaces","es":"Peligros y superficies","ru":"Опасности и покрытие","tr":"Tehlikeler ve Yüzeyler","hi":"खतरे और सतहें","ar":"المخاطر والأسطح"},"blurb":{"en":"Slippery roads, railroad tracks, obstacles, night riding, wind and animals.","es":"Caminos resbalosos, vías férreas, obstáculos, conducción nocturna, viento y animales.","ru":"Скользкие дороги, ж/д пути, препятствия, ночь, ветер и животные.","tr":"Kaygan yollar, demir yolu, engeller, gece sürüşü, rüzgâr ve hayvanlar.","hi":"फिसलन सड़कें, रेल पटरी, बाधाएँ, रात की सवारी, हवा और जानवर।","ar":"الطرق الزلقة، وسكك الحديد، والعوائق، والقيادة الليلية، والرياح، والحيوانات."}},{"id":"passenger","name":{"en":"Passengers, Cargo & Groups","es":"Pasajeros, carga y grupos","ru":"Пассажиры, груз и группы","tr":"Yolcu, Yük ve Grup","hi":"सवारी, सामान और समूह","ar":"الركاب والحمولة والمجموعات"},"blurb":{"en":"Carrying a passenger, loading cargo, and group-riding formation.","es":"Llevar pasajero, cargar y la formación de grupo.","ru":"Перевозка пассажира, груз и групповое построение.","tr":"Yolcu taşıma, yük ve grup düzeni.","hi":"सवारी ले जाना, सामान लादना और समूह संरचना।","ar":"حمل راكب، وتحميل البضائع، وتشكيل القيادة الجماعية."}},{"id":"impairment","name":{"en":"Alcohol, Fatigue & Sharing the Road","es":"Alcohol, fatiga y compartir la vía","ru":"Алкоголь, усталость и дорога","tr":"Alkol, Yorgunluk ve Yolu Paylaşma","hi":"शराब, थकान और सड़क साझा करना","ar":"الكحول والتعب ومشاركة الطريق"},"blurb":{"en":"Impairment, the full lane, lane sharing, and riding near traffic.","es":"Deterioro, el carril completo, compartir carril y circular junto al tráfico.","ru":"Опьянение, полная полоса, совместное использование полосы и движение в потоке.","tr":"Bozulma, tam şerit, şerit paylaşımı ve trafik yakınında sürüş.","hi":"क्षीणता, पूरी लेन, लेन साझा करना और ट्रैफ़िक के पास सवारी।","ar":"الإعاقة، والمسار الكامل، ومشاركة المسار، والقيادة قرب المرور."}}],"q":[{"cat":"controls","a":0,"q":{"en":"Which control is operated by your right hand to increase engine speed?","es":"¿Cuál control se opera con la mano derecha para aumentar la velocidad del motor?","ru":"Какой орган управления приводится в действие правой рукой для увеличения оборотов двигателя?","tr":"Motor devrini artırmak için sağ elinizle hangi kumanda kullanılır?","hi":"इंजन की गति बढ़ाने के लिए आपके दाहिने हाथ से कौन सा कंट्रोल चलाया जाता है?","ar":"أي عنصر تحكم يتم تشغيله بيدك اليمنى لزيادة سرعة المحرك؟"},"o":[{"en":"The throttle","es":"El acelerador","ru":"Ручка газа","tr":"Gaz kolu","hi":"थ्रॉटल","ar":"دواسة الوقود (الخانق)"},{"en":"The clutch lever","es":"La palanca del embrague","ru":"Рычаг сцепления","tr":"Debriyaj kolu","hi":"क्लच लीवर","ar":"ذراع القابض"},{"en":"The gear-shift lever","es":"La palanca de cambios","ru":"Рычаг переключения передач","tr":"Vites değiştirme kolu","hi":"गियर-शिफ्ट लीवर","ar":"ذراع تغيير السرعات"},{"en":"The rear brake pedal","es":"El pedal del freno trasero","ru":"Педаль заднего тормоза","tr":"Arka fren pedalı","hi":"रियर ब्रेक पेडल","ar":"دواسة الفرامل الخلفية"}],"e":{"en":"The throttle is the twist grip on the right handgrip and is rolled on to increase engine speed. The Motorcycle Operator Manual lists the throttle among the right-hand controls.","es":"El acelerador es el puño giratorio en la manija derecha y se gira hacia adentro para aumentar la velocidad del motor. El Manual del Operador de Motocicletas incluye el acelerador entre los controles de la mano derecha.","ru":"Ручка газа — это поворотная рукоятка на правой ручке руля, которую проворачивают для увеличения оборотов двигателя. Руководство мотоциклиста (Motorcycle Operator Manual) относит ручку газа к органам управления правой руки.","tr":"Gaz kolu, sağ gidonun üzerindeki döner kabzadır ve motor devrini artırmak için içe doğru çevrilir. Motosiklet Kullanıcı Kılavuzu, gaz kolunu sağ el kumandaları arasında sıralar.","hi":"थ्रॉटल दाहिनी हैंडग्रिप पर मौजूद ट्विस्ट ग्रिप है और इंजन की गति बढ़ाने के लिए इसे रोल किया जाता है। Motorcycle Operator Manual थ्रॉटल को दाहिने हाथ के कंट्रोल में सूचीबद्ध करता है।","ar":"دواسة الوقود (الخانق) هي المقبض الدوار على المقبض الأيمن، ويتم لفها لزيادة سرعة المحرك. يُدرج دليل مشغّل الدراجة النارية الخانق ضمن عناصر التحكم باليد اليمنى."}},{"cat":"controls","a":1,"q":{"en":"Where is the front brake lever located on a motorcycle?","es":"¿Dónde se ubica la palanca del freno delantero en una motocicleta?","ru":"Где расположен рычаг переднего тормоза на мотоцикле?","tr":"Motosiklette ön fren kolu nerede bulunur?","hi":"मोटरसाइकिल पर फ्रंट ब्रेक लीवर कहाँ स्थित होता है?","ar":"أين يقع ذراع الفرامل الأمامية في الدراجة النارية؟"},"o":[{"en":"On the left handlebar, near the clutch","es":"En el manillar izquierdo, cerca del embrague","ru":"На левой рукоятке руля, рядом со сцеплением","tr":"Sol gidonda, debriyajın yanında","hi":"बाएं हैंडलबार पर, क्लच के पास","ar":"على المقود الأيسر، بالقرب من القابض"},{"en":"In front of the right handgrip, operated by the right hand","es":"Frente a la manija derecha, operada por la mano derecha","ru":"Перед правой ручкой руля, приводится в действие правой рукой","tr":"Sağ gidon kabzasının önünde, sağ elle kullanılır","hi":"दाहिनी हैंडग्रिप के सामने, दाहिने हाथ से चलाया जाता है","ar":"أمام المقبض الأيمن، ويُشغَّل باليد اليمنى"},{"en":"On the left footrest, operated by the left foot","es":"En el estribo izquierdo, operada por el pie izquierdo","ru":"На левой подножке, приводится в действие левой ногой","tr":"Sol ayak basamağında, sol ayakla kullanılır","hi":"बाएं फुटरेस्ट पर, बाएं पैर से चलाया जाता है","ar":"على مسند القدم الأيسر، ويُشغَّل بالقدم اليسرى"},{"en":"In front of the right footrest, operated by the right foot","es":"Frente al estribo derecho, operada por el pie derecho","ru":"Перед правой подножкой, приводится в действие правой ногой","tr":"Sağ ayak basamağının önünde, sağ ayakla kullanılır","hi":"दाहिने फुटरेस्ट के सामने, दाहिने पैर से चलाया जाता है","ar":"أمام مسند القدم الأيمن، ويُشغَّل بالقدم اليمنى"}],"e":{"en":"The front brake lever is squeezed by the right hand in front of the right handgrip. The Motorcycle Operator Manual identifies the front brake lever as a right-hand control.","es":"La palanca del freno delantero se aprieta con la mano derecha frente a la manija derecha. El Manual del Operador de Motocicletas identifica la palanca del freno delantero como un control de la mano derecha.","ru":"Рычаг переднего тормоза сжимают правой рукой, он расположен перед правой ручкой руля. Руководство мотоциклиста относит рычаг переднего тормоза к органам управления правой руки.","tr":"Ön fren kolu, sağ gidon kabzasının önünde sağ elle sıkılır. Motosiklet Kullanıcı Kılavuzu, ön fren kolunu sağ el kumandası olarak tanımlar.","hi":"फ्रंट ब्रेक लीवर को दाहिनी हैंडग्रिप के सामने दाहिने हाथ से दबाया जाता है। Motorcycle Operator Manual फ्रंट ब्रेक लीवर को दाहिने हाथ के कंट्रोल के रूप में पहचानता है।","ar":"يتم الضغط على ذراع الفرامل الأمامية باليد اليمنى أمام المقبض الأيمن. يحدد دليل مشغّل الدراجة النارية ذراع الفرامل الأمامية كعنصر تحكم باليد اليمنى."}},{"cat":"controls","a":3,"q":{"en":"Which hand operates the clutch lever?","es":"¿Con qué mano se opera la palanca del embrague?","ru":"Какой рукой приводится в действие рычаг сцепления?","tr":"Debriyaj kolunu hangi el kullanır?","hi":"क्लच लीवर को कौन सा हाथ चलाता है?","ar":"أي يد تشغّل ذراع القابض؟"},"o":[{"en":"The right hand","es":"La mano derecha","ru":"Правой рукой","tr":"Sağ el","hi":"दाहिना हाथ","ar":"اليد اليمنى"},{"en":"Either hand, depending on the model","es":"Cualquiera de las dos manos, según el modelo","ru":"Любой рукой, в зависимости от модели","tr":"Modele bağlı olarak her iki el de","hi":"कोई भी हाथ, मॉडल के अनुसार","ar":"أي يد، حسب الطراز"},{"en":"Neither; the clutch is foot-operated","es":"Ninguna; el embrague se opera con el pie","ru":"Никакой; сцепление приводится в действие ногой","tr":"Hiçbiri; debriyaj ayakla kullanılır","hi":"कोई नहीं; क्लच पैर से चलाया जाता है","ar":"لا يد؛ فالقابض يُشغَّل بالقدم"},{"en":"The left hand","es":"La mano izquierda","ru":"Левой рукой","tr":"Sol el","hi":"बायां हाथ","ar":"اليد اليسرى"}],"e":{"en":"The clutch lever is squeezed by the left hand. The Motorcycle Operator Manual lists the clutch lever as a left-hand control on the handlebar.","es":"La palanca del embrague se aprieta con la mano izquierda. El Manual del Operador de Motocicletas incluye la palanca del embrague como un control de la mano izquierda en el manillar.","ru":"Рычаг сцепления сжимают левой рукой. Руководство мотоциклиста относит рычаг сцепления к органам управления левой руки на руле.","tr":"Debriyaj kolu sol elle sıkılır. Motosiklet Kullanıcı Kılavuzu, debriyaj kolunu gidon üzerindeki sol el kumandası olarak sıralar.","hi":"क्लच लीवर को बाएं हाथ से दबाया जाता है। Motorcycle Operator Manual क्लच लीवर को हैंडलबार पर बाएं हाथ के कंट्रोल के रूप में सूचीबद्ध करता है।","ar":"يتم الضغط على ذراع القابض باليد اليسرى. يُدرج دليل مشغّل الدراجة النارية ذراع القابض كعنصر تحكم باليد اليسرى على المقود."}},{"cat":"controls","a":3,"q":{"en":"Which foot operates the gear-shift lever?","es":"¿Con qué pie se opera la palanca de cambios?","ru":"Какой ногой приводится в действие рычаг переключения передач?","tr":"Vites değiştirme kolunu hangi ayak kullanır?","hi":"गियर-शिफ्ट लीवर को कौन सा पैर चलाता है?","ar":"أي قدم تشغّل ذراع تغيير السرعات؟"},"o":[{"en":"The right foot","es":"El pie derecho","ru":"Правой ногой","tr":"Sağ ayak","hi":"दाहिना पैर","ar":"القدم اليمنى"},{"en":"Both feet together","es":"Ambos pies juntos","ru":"Обеими ногами одновременно","tr":"İki ayak birlikte","hi":"दोनों पैर एक साथ","ar":"كلتا القدمين معًا"},{"en":"Whichever foot is on the ground","es":"El pie que esté en el suelo","ru":"Той ногой, что стоит на земле","tr":"Yerde olan ayak hangisiyse o","hi":"जो भी पैर ज़मीन पर हो","ar":"أي قدم تكون على الأرض"},{"en":"The left foot","es":"El pie izquierdo","ru":"Левой ногой","tr":"Sol ayak","hi":"बायां पैर","ar":"القدم اليسرى"}],"e":{"en":"The gear-shift lever is located in front of the left footrest and is operated by the left foot. The Motorcycle Operator Manual states the gearshift lever is worked with the left foot.","es":"La palanca de cambios se ubica frente al estribo izquierdo y se opera con el pie izquierdo. El Manual del Operador de Motocicletas indica que la palanca de cambios se acciona con el pie izquierdo.","ru":"Рычаг переключения передач расположен перед левой подножкой и приводится в действие левой ногой. Руководство мотоциклиста указывает, что рычаг переключения передач работает левой ногой.","tr":"Vites değiştirme kolu sol ayak basamağının önünde bulunur ve sol ayakla kullanılır. Motosiklet Kullanıcı Kılavuzu, vites kolunun sol ayakla çalıştırıldığını belirtir.","hi":"गियर-शिफ्ट लीवर बाएं फुटरेस्ट के सामने स्थित होता है और इसे बाएं पैर से चलाया जाता है। Motorcycle Operator Manual बताता है कि गियरशिफ्ट लीवर को बाएं पैर से चलाया जाता है।","ar":"يقع ذراع تغيير السرعات أمام مسند القدم الأيسر ويُشغَّل بالقدم اليسرى. ينص دليل مشغّل الدراجة النارية على أن ذراع تغيير السرعات يُشغَّل بالقدم اليسرى."}},{"cat":"controls","a":2,"q":{"en":"Which control is operated by your right foot?","es":"¿Cuál control se opera con el pie derecho?","ru":"Какой орган управления приводится в действие правой ногой?","tr":"Sağ ayağınızla hangi kumanda kullanılır?","hi":"आपके दाहिने पैर से कौन सा कंट्रोल चलाया जाता है?","ar":"أي عنصر تحكم يُشغَّل بقدمك اليمنى؟"},"o":[{"en":"The clutch lever","es":"La palanca del embrague","ru":"Рычаг сцепления","tr":"Debriyaj kolu","hi":"क्लच लीवर","ar":"ذراع القابض"},{"en":"The gear-shift lever","es":"La palanca de cambios","ru":"Рычаг переключения передач","tr":"Vites değiştirme kolu","hi":"गियर-शिफ्ट लीवर","ar":"ذراع تغيير السرعات"},{"en":"The rear brake pedal","es":"El pedal del freno trasero","ru":"Педаль заднего тормоза","tr":"Arka fren pedalı","hi":"रियर ब्रेक पेडल","ar":"دواسة الفرامل الخلفية"},{"en":"The front brake lever","es":"La palanca del freno delantero","ru":"Рычаг переднего тормоза","tr":"Ön fren kolu","hi":"फ्रंट ब्रेक लीवर","ar":"ذراع الفرامل الأمامية"}],"e":{"en":"The rear brake pedal is pressed down with the right foot. The Motorcycle Operator Manual identifies the rear brake pedal as the right-foot control.","es":"El pedal del freno trasero se presiona hacia abajo con el pie derecho. El Manual del Operador de Motocicletas identifica el pedal del freno trasero como el control del pie derecho.","ru":"Педаль заднего тормоза нажимают вниз правой ногой. Руководство мотоциклиста относит педаль заднего тормоза к органам управления правой ноги.","tr":"Arka fren pedalı sağ ayakla aşağıya doğru basılır. Motosiklet Kullanıcı Kılavuzu, arka fren pedalını sağ ayak kumandası olarak tanımlar.","hi":"रियर ब्रेक पेडल को दाहिने पैर से नीचे दबाया जाता है। Motorcycle Operator Manual रियर ब्रेक पेडल को दाहिने पैर के कंट्रोल के रूप में पहचानता है।","ar":"يتم الضغط على دواسة الفرامل الخلفية للأسفل بالقدم اليمنى. يحدد دليل مشغّل الدراجة النارية دواسة الفرامل الخلفية كعنصر تحكم بالقدم اليمنى."}},{"cat":"controls","a":2,"q":{"en":"What is the \"friction zone\" of the clutch?","es":"¿Qué es la \"zona de fricción\" del embrague?","ru":"Что такое «зона пробуксовки сцепления»?","tr":"Debriyajın \"friksiyon bölgesi\" nedir?","hi":"क्लच का \"फ्रिक्शन ज़ोन\" क्या है?","ar":"ما هي \"منطقة الاحتكاك\" في القابض؟"},"o":[{"en":"The point where the front and rear brakes work together","es":"El punto donde el freno delantero y el trasero trabajan juntos","ru":"Точка, в которой передний и задний тормоза работают совместно","tr":"Ön ve arka frenin birlikte çalıştığı nokta","hi":"वह बिंदु जहाँ फ्रंट और रियर ब्रेक एक साथ काम करते हैं","ar":"النقطة التي تعمل فيها الفرامل الأمامية والخلفية معًا"},{"en":"The grip area where your right wrist rests on the throttle","es":"El área de agarre donde la muñeca derecha descansa sobre el acelerador","ru":"Участок хвата, где правое запястье лежит на ручке газа","tr":"Sağ bileğinizin gaz kolu üzerinde durduğu kabza alanı","hi":"वह ग्रिप क्षेत्र जहाँ आपकी दाहिनी कलाई थ्रॉटल पर टिकती है","ar":"منطقة المقبض حيث ترتكز رسغك اليمنى على الخانق"},{"en":"The small range of clutch-lever travel that controls power from the engine to the rear wheel","es":"El pequeño rango de recorrido de la palanca del embrague que controla la potencia del motor a la rueda trasera","ru":"Небольшой диапазон хода рычага сцепления, который регулирует передачу мощности от двигателя к заднему колесу","tr":"Motordan arka tekerleğe aktarılan gücü kontrol eden küçük debriyaj kolu hareket aralığı","hi":"क्लच-लीवर की उस छोटी रेंज की गति जो इंजन से रियर व्हील तक पावर को नियंत्रित करती है","ar":"المدى الصغير من حركة ذراع القابض الذي يتحكم في الطاقة المنتقلة من المحرك إلى العجلة الخلفية"},{"en":"The pivot point of the gear-shift lever on the left footrest","es":"El punto de pivote de la palanca de cambios en el estribo izquierdo","ru":"Точка опоры рычага переключения передач на левой подножке","tr":"Sol ayak basamağındaki vites kolunun dönme noktası","hi":"बाएं फुटरेस्ट पर गियर-शिफ्ट लीवर का पिवट पॉइंट","ar":"نقطة ارتكاز ذراع تغيير السرعات على مسند القدم الأيسر"}],"e":{"en":"The friction zone is the area of clutch-lever travel where the engine begins to transfer power to the rear wheel. The Motorcycle Operator Manual urges riders to be very familiar with the friction zone for manual transmissions.","es":"La zona de fricción es el área de recorrido de la palanca del embrague donde el motor empieza a transferir potencia a la rueda trasera. El Manual del Operador de Motocicletas insta a los conductores a familiarizarse muy bien con la zona de fricción en las transmisiones manuales.","ru":"Зона пробуксовки сцепления — это участок хода рычага сцепления, на котором двигатель начинает передавать мощность на заднее колесо. Руководство мотоциклиста настоятельно рекомендует хорошо изучить зону пробуксовки сцепления при работе с механической коробкой передач.","tr":"Friksiyon bölgesi, motorun arka tekerleğe güç aktarmaya başladığı debriyaj kolu hareket aralığıdır. Motosiklet Kullanıcı Kılavuzu, manuel şanzımanlar için sürücülerin friksiyon bölgesine çok aşina olmalarını ister.","hi":"फ्रिक्शन ज़ोन क्लच-लीवर की गति का वह क्षेत्र है जहाँ इंजन रियर व्हील को पावर ट्रांसफर करना शुरू करता है। Motorcycle Operator Manual राइडर्स को मैनुअल ट्रांसमिशन के लिए फ्रिक्शन ज़ोन से भली-भाँति परिचित होने का आग्रह करता है।","ar":"منطقة الاحتكاك هي المنطقة من حركة ذراع القابض التي يبدأ فيها المحرك بنقل الطاقة إلى العجلة الخلفية. يحث دليل مشغّل الدراجة النارية السائقين على أن يكونوا على دراية تامة بمنطقة الاحتكاك في ناقل الحركة اليدوي."}},{"cat":"controls","a":0,"q":{"en":"On a typical motorcycle with the gear pattern 1-N-2-3-4-5, where is first gear?","es":"En una motocicleta típica con el patrón de cambios 1-N-2-3-4-5, ¿dónde está la primera velocidad?","ru":"На типичном мотоцикле со схемой передач 1-N-2-3-4-5 где находится первая передача?","tr":"Vites düzeni 1-N-2-3-4-5 olan tipik bir motosiklette birinci vites nerededir?","hi":"1-N-2-3-4-5 गियर पैटर्न वाली एक सामान्य मोटरसाइकिल पर, पहला गियर कहाँ होता है?","ar":"في دراجة نارية نموذجية بنمط تروس 1-N-2-3-4-5، أين يقع الترس الأول؟"},"o":[{"en":"All the way down","es":"Totalmente abajo","ru":"В самом нижнем положении","tr":"En aşağıda","hi":"सबसे नीचे तक","ar":"في أسفل المدى تمامًا"},{"en":"All the way up","es":"Totalmente arriba","ru":"В самом верхнем положении","tr":"En yukarıda","hi":"सबसे ऊपर तक","ar":"في أعلى المدى تمامًا"},{"en":"Above neutral","es":"Por encima de neutral","ru":"Над нейтралью","tr":"Boşun üzerinde","hi":"न्यूट्रल के ऊपर","ar":"فوق الوضع المحايد"},{"en":"Two presses up from neutral","es":"Dos presiones hacia arriba desde neutral","ru":"На два нажатия вверх от нейтрали","tr":"Boştan iki basış yukarıda","hi":"न्यूट्रल से दो दबाव ऊपर","ar":"ضغطتان للأعلى من الوضع المحايد"}],"e":{"en":"In the standard 1-N-2-3-4-5 pattern, first gear is at the bottom (all the way down) and neutral is just above it. The Motorcycle Operator Manual describes this typical gear pattern.","es":"En el patrón estándar 1-N-2-3-4-5, la primera velocidad está abajo del todo (totalmente abajo) y neutral está justo por encima de ella. El Manual del Operador de Motocicletas describe este patrón de cambios típico.","ru":"В стандартной схеме 1-N-2-3-4-5 первая передача находится внизу (в самом нижнем положении), а нейтраль — чуть выше неё. Руководство мотоциклиста описывает эту типичную схему передач.","tr":"Standart 1-N-2-3-4-5 düzeninde birinci vites en alttadır (en aşağıda) ve boş hemen onun üzerindedir. Motosiklet Kullanıcı Kılavuzu bu tipik vites düzenini açıklar.","hi":"मानक 1-N-2-3-4-5 पैटर्न में, पहला गियर सबसे नीचे (पूरी तरह नीचे) होता है और न्यूट्रल उसके ठीक ऊपर होता है। Motorcycle Operator Manual इस सामान्य गियर पैटर्न का वर्णन करता है।","ar":"في النمط القياسي 1-N-2-3-4-5، يقع الترس الأول في الأسفل تمامًا، ويقع الوضع المحايد فوقه مباشرة. يصف دليل مشغّل الدراجة النارية نمط التروس النموذجي هذا."}},{"cat":"controls","a":2,"q":{"en":"In the typical 1-N-2-3-4-5 gear pattern, how is neutral selected from first gear?","es":"En el patrón típico de cambios 1-N-2-3-4-5, ¿cómo se selecciona neutral desde la primera velocidad?","ru":"В типичной схеме передач 1-N-2-3-4-5 как выбирается нейтраль из первой передачи?","tr":"Tipik 1-N-2-3-4-5 vites düzeninde, birinci vitesten boş nasıl seçilir?","hi":"सामान्य 1-N-2-3-4-5 गियर पैटर्न में, पहले गियर से न्यूट्रल कैसे चुना जाता है?","ar":"في نمط التروس النموذجي 1-N-2-3-4-5، كيف يُختار الوضع المحايد من الترس الأول؟"},"o":[{"en":"A full lift up two positions","es":"Un levantamiento completo hacia arriba de dos posiciones","ru":"Полным подъёмом вверх на две позиции","tr":"İki konum tam yukarı kaldırarak","hi":"दो स्थान पूरी तरह ऊपर उठाकर","ar":"رفع كامل للأعلى بمقدار وضعين"},{"en":"A full press down from first gear","es":"Una presión completa hacia abajo desde la primera velocidad","ru":"Полным нажатием вниз из первой передачи","tr":"Birinci vitesten tam aşağı basarak","hi":"पहले गियर से पूरी तरह नीचे दबाकर","ar":"ضغط كامل للأسفل من الترس الأول"},{"en":"A \"half lift\" up from first gear","es":"Un \"medio levantamiento\" hacia arriba desde la primera velocidad","ru":"«Половинным подъёмом» вверх из первой передачи","tr":"Birinci vitesten \"yarım kaldırarak\"","hi":"पहले गियर से एक \"आधा लिफ्ट\" ऊपर","ar":"\"نصف رفعة\" للأعلى من الترس الأول"},{"en":"By squeezing the clutch only, with no lever movement","es":"Apretando solo el embrague, sin mover la palanca","ru":"Только сжатием сцепления, без перемещения рычага","tr":"Sadece debriyajı sıkarak, kolu hareket ettirmeden","hi":"केवल क्लच दबाकर, बिना लीवर हिलाए","ar":"بالضغط على القابض فقط، دون تحريك الذراع"}],"e":{"en":"Neutral sits between first and second gear and is found with a \"half lift\" from first or a \"half press\" from second. The Motorcycle Operator Manual describes this method of selecting neutral.","es":"Neutral se ubica entre la primera y la segunda velocidad y se encuentra con un \"medio levantamiento\" desde la primera o una \"media presión\" desde la segunda. El Manual del Operador de Motocicletas describe este método para seleccionar neutral.","ru":"Нейтраль находится между первой и второй передачей, и её можно найти «половинным подъёмом» из первой или «половинным нажатием» из второй. Руководство мотоциклиста описывает этот способ выбора нейтрали.","tr":"Boş, birinci ve ikinci vites arasında yer alır ve birinciden \"yarım kaldırma\" ya da ikinciden \"yarım basma\" ile bulunur. Motosiklet Kullanıcı Kılavuzu, boş seçmenin bu yöntemini açıklar.","hi":"न्यूट्रल पहले और दूसरे गियर के बीच होता है और इसे पहले गियर से \"आधा लिफ्ट\" या दूसरे गियर से \"आधा प्रेस\" से पाया जाता है। Motorcycle Operator Manual न्यूट्रल चुनने की इस विधि का वर्णन करता है।","ar":"يقع الوضع المحايد بين الترس الأول والثاني، ويُوجد بـ\"نصف رفعة\" من الأول أو \"نصف ضغطة\" من الثاني. يصف دليل مشغّل الدراجة النارية هذه الطريقة لاختيار الوضع المحايد."}},{"cat":"controls","a":0,"q":{"en":"To shift up to a higher gear, how do you move the shift lever?","es":"Para subir a una velocidad más alta, ¿cómo se mueve la palanca de cambios?","ru":"Чтобы переключиться на повышенную передачу, как нужно перемещать рычаг переключения?","tr":"Daha yüksek bir vitese geçmek için vites kolunu nasıl hareket ettirirsiniz?","hi":"ऊँचे गियर में शिफ्ट अप करने के लिए, आप शिफ्ट लीवर को कैसे हिलाते हैं?","ar":"لرفع السرعة إلى ترس أعلى، كيف تحرّك ذراع التغيير؟"},"o":[{"en":"Position your foot under the lever and lift it","es":"Coloca el pie debajo de la palanca y levántala","ru":"Подвести ногу под рычаг и поднять его","tr":"Ayağınızı kolun altına yerleştirip kaldırın","hi":"अपने पैर को लीवर के नीचे रखें और उसे ऊपर उठाएं","ar":"ضع قدمك تحت الذراع وارفعه"},{"en":"Press the lever straight down","es":"Presiona la palanca derecho hacia abajo","ru":"Нажать на рычаг прямо вниз","tr":"Kola düz aşağı basın","hi":"लीवर को सीधा नीचे दबाएं","ar":"اضغط الذراع للأسفل مباشرة"},{"en":"Pull the lever toward you with your toe","es":"Jala la palanca hacia ti con la punta del pie","ru":"Потянуть рычаг на себя носком ноги","tr":"Kolu ayak ucunuzla kendinize doğru çekin","hi":"लीवर को अपने पंजे से अपनी ओर खींचें","ar":"اسحب الذراع نحوك بإصبع قدمك"},{"en":"Twist the lever outward","es":"Gira la palanca hacia afuera","ru":"Повернуть рычаг наружу","tr":"Kolu dışa doğru çevirin","hi":"लीवर को बाहर की ओर घुमाएं","ar":"لُفّ الذراع للخارج"}],"e":{"en":"To upshift, place your foot under the shift lever and lift; to downshift, press it down. The Motorcycle Operator Manual explains the lever changes one gear each time it is lifted or pressed.","es":"Para subir de velocidad, coloca el pie debajo de la palanca de cambios y levanta; para bajar de velocidad, presiónala hacia abajo. El Manual del Operador de Motocicletas explica que la palanca cambia una velocidad cada vez que se levanta o se presiona.","ru":"Чтобы повысить передачу, подведите ногу под рычаг переключения и поднимите его; чтобы понизить — нажмите вниз. Руководство мотоциклиста поясняет, что рычаг меняет одну передачу при каждом подъёме или нажатии.","tr":"Vites yükseltmek için ayağınızı vites kolunun altına koyup kaldırın; vites düşürmek için aşağı basın. Motosiklet Kullanıcı Kılavuzu, kolun her kaldırılış ya da basılışında bir vites değiştirdiğini açıklar.","hi":"अपशिफ्ट करने के लिए, अपने पैर को शिफ्ट लीवर के नीचे रखें और ऊपर उठाएं; डाउनशिफ्ट करने के लिए, इसे नीचे दबाएं। Motorcycle Operator Manual समझाता है कि हर बार उठाने या दबाने पर लीवर एक गियर बदलता है।","ar":"لرفع السرعة، ضع قدمك تحت ذراع التغيير وارفعه؛ ولخفض السرعة، اضغطه للأسفل. يوضح دليل مشغّل الدراجة النارية أن الذراع يغيّر ترسًا واحدًا في كل مرة يُرفع أو يُضغط فيها."}},{"cat":"controls","a":2,"q":{"en":"What is the correct 3-step process for upshifting to a higher gear?","es":"¿Cuál es el proceso correcto de 3 pasos para subir a una velocidad más alta?","ru":"Какова правильная последовательность из 3 шагов для переключения на повышенную передачу?","tr":"Daha yüksek bir vitese geçerken doğru 3 adımlı işlem nedir?","hi":"ऊँचे गियर में अपशिफ्ट करने की सही 3-चरण प्रक्रिया क्या है?","ar":"ما هي العملية الصحيحة المكوّنة من 3 خطوات لرفع السرعة إلى ترس أعلى؟"},"o":[{"en":"Roll on the throttle, lift the shift lever, then squeeze the clutch","es":"Acelera, levanta la palanca de cambios y luego aprieta el embrague","ru":"Прибавить газ, поднять рычаг переключения, затем сжать сцепление","tr":"Gazı aç, vites kolunu kaldır, sonra debriyajı sık","hi":"थ्रॉटल रोल ऑन करें, शिफ्ट लीवर उठाएं, फिर क्लच दबाएं","ar":"لُفّ الخانق، ارفع ذراع التغيير، ثم اضغط القابض"},{"en":"Press the rear brake, lift the shift lever, then release the clutch slowly","es":"Presiona el freno trasero, levanta la palanca de cambios y luego suelta el embrague lentamente","ru":"Нажать задний тормоз, поднять рычаг переключения, затем медленно отпустить сцепление","tr":"Arka frene bas, vites kolunu kaldır, sonra debriyajı yavaşça bırak","hi":"रियर ब्रेक दबाएं, शिफ्ट लीवर उठाएं, फिर क्लच धीरे-धीरे छोड़ें","ar":"اضغط الفرامل الخلفية، ارفع ذراع التغيير، ثم حرّر القابض ببطء"},{"en":"Roll off the throttle as you squeeze the clutch, lift the shift lever firmly, then ease out the clutch and adjust the throttle","es":"Suelta el acelerador mientras aprietas el embrague, levanta la palanca de cambios con firmeza y luego suelta el embrague suavemente y ajusta el acelerador","ru":"Сбросить газ, одновременно сжимая сцепление, уверенно поднять рычаг переключения, затем плавно отпустить сцепление и отрегулировать газ","tr":"Debriyajı sıkarken gazı kapat, vites kolunu kararlı şekilde kaldır, sonra debriyajı yavaşça bırakıp gazı ayarla","hi":"क्लच दबाते हुए थ्रॉटल रोल ऑफ करें, शिफ्ट लीवर को मज़बूती से उठाएं, फिर क्लच को धीरे से छोड़ें और थ्रॉटल को समायोजित करें","ar":"ارخِ الخانق أثناء الضغط على القابض، ارفع ذراع التغيير بثبات، ثم أرخِ القابض تدريجيًا واضبط الخانق"},{"en":"Squeeze the front brake, press the shift lever down, then roll on the throttle","es":"Aprieta el freno delantero, presiona la palanca de cambios hacia abajo y luego acelera","ru":"Сжать передний тормоз, нажать рычаг переключения вниз, затем прибавить газ","tr":"Ön freni sık, vites kolunu aşağı bas, sonra gazı aç","hi":"फ्रंट ब्रेक दबाएं, शिफ्ट लीवर को नीचे दबाएं, फिर थ्रॉटल रोल ऑन करें","ar":"اضغط الفرامل الأمامية، اضغط ذراع التغيير للأسفل، ثم لُفّ الخانق"}],"e":{"en":"Upshifting uses a 3-step process: roll off the throttle while squeezing the clutch, lift the shift lever firmly, then ease out the clutch and adjust the throttle. The Motorcycle Operator Manual lists these exact steps.","es":"Para subir de velocidad se usa un proceso de 3 pasos: suelta el acelerador mientras aprietas el embrague, levanta la palanca de cambios con firmeza y luego suelta el embrague suavemente y ajusta el acelerador. El Manual del Operador de Motocicletas indica estos pasos exactos.","ru":"Повышение передачи выполняется в 3 шага: сбросить газ, одновременно сжимая сцепление, уверенно поднять рычаг переключения, затем плавно отпустить сцепление и отрегулировать газ. Руководство мотоциклиста приводит именно эти шаги.","tr":"Vites yükseltme 3 adımlı bir işlem kullanır: debriyajı sıkarken gazı kapatın, vites kolunu kararlı şekilde kaldırın, sonra debriyajı yavaşça bırakıp gazı ayarlayın. Motosiklet Kullanıcı Kılavuzu bu adımları aynen sıralar.","hi":"अपशिफ्टिंग में 3-चरण प्रक्रिया होती है: क्लच दबाते हुए थ्रॉटल रोल ऑफ करें, शिफ्ट लीवर को मज़बूती से उठाएं, फिर क्लच को धीरे से छोड़ें और थ्रॉटल को समायोजित करें। Motorcycle Operator Manual इन्हीं चरणों को सूचीबद्ध करता है।","ar":"يستخدم رفع السرعة عملية من 3 خطوات: ارخِ الخانق أثناء الضغط على القابض، ارفع ذراع التغيير بثبات، ثم أرخِ القابض تدريجيًا واضبط الخانق. يُدرج دليل مشغّل الدراجة النارية هذه الخطوات بالضبط."}},{"cat":"controls","a":1,"q":{"en":"When downshifting, what should you do with the throttle as you ease the clutch lever back out?","es":"Al bajar de velocidad, ¿qué debes hacer con el acelerador mientras sueltas suavemente la palanca del embrague?","ru":"При понижении передачи что нужно делать с газом, когда вы плавно отпускаете рычаг сцепления?","tr":"Vites düşürürken, debriyaj kolunu yavaşça geri bırakırken gazla ne yapmalısınız?","hi":"डाउनशिफ्ट करते समय, जब आप क्लच लीवर को धीरे से वापस छोड़ते हैं तो आपको थ्रॉटल के साथ क्या करना चाहिए?","ar":"عند خفض السرعة، ماذا يجب أن تفعل بالخانق وأنت ترخي ذراع القابض للخارج؟"},"o":[{"en":"Keep the throttle fully closed until the clutch is released","es":"Mantener el acelerador totalmente cerrado hasta que se suelte el embrague","ru":"Держать газ полностью закрытым, пока сцепление не будет отпущено","tr":"Debriyaj bırakılana kadar gazı tamamen kapalı tutun","hi":"क्लच छूटने तक थ्रॉटल को पूरी तरह बंद रखें","ar":"أبقِ الخانق مغلقًا تمامًا حتى يُحرّر القابض"},{"en":"Roll on the throttle slightly to bring the engine up to speed","es":"Acelerar un poco para que el motor suba de revoluciones","ru":"Слегка прибавить газ, чтобы поднять обороты двигателя","tr":"Motoru devrine getirmek için gazı biraz açın","hi":"इंजन को गति तक लाने के लिए थ्रॉटल को थोड़ा रोल ऑन करें","ar":"لُفّ الخانق قليلًا لرفع سرعة المحرك"},{"en":"Snap the throttle fully open at once","es":"Abrir el acelerador por completo de golpe","ru":"Резко открыть газ полностью разом","tr":"Gazı bir anda tamamen sonuna kadar açın","hi":"थ्रॉटल को एक ही बार में पूरी तरह खोल दें","ar":"افتح الخانق بالكامل دفعة واحدة"},{"en":"Press the rear brake instead of using the throttle","es":"Presionar el freno trasero en lugar de usar el acelerador","ru":"Нажать задний тормоз вместо использования газа","tr":"Gaz yerine arka frene basın","hi":"थ्रॉटल के बजाय रियर ब्रेक दबाएं","ar":"اضغط الفرامل الخلفية بدلًا من استخدام الخانق"}],"e":{"en":"When downshifting, roll on the throttle as you ease out the clutch so the engine comes up to speed and the downshift is smoother. The Motorcycle Operator Manual describes this 3-step downshift technique.","es":"Al bajar de velocidad, acelera un poco mientras sueltas suavemente el embrague para que el motor suba de revoluciones y la reducción sea más suave. El Manual del Operador de Motocicletas describe esta técnica de reducción de 3 pasos.","ru":"При понижении передачи прибавляйте газ по мере того, как плавно отпускаете сцепление, чтобы обороты двигателя поднялись и понижение передачи прошло мягче. Руководство мотоциклиста описывает эту технику понижения передачи в 3 шага.","tr":"Vites düşürürken debriyajı bırakırken gazı biraz açın ki motor devrine gelsin ve vites düşürme daha yumuşak olsun. Motosiklet Kullanıcı Kılavuzu bu 3 adımlı vites düşürme tekniğini açıklar.","hi":"डाउनशिफ्ट करते समय, क्लच को धीरे से छोड़ते हुए थ्रॉटल रोल ऑन करें ताकि इंजन गति तक आ जाए और डाउनशिफ्ट सहज हो। Motorcycle Operator Manual इस 3-चरण डाउनशिफ्ट तकनीक का वर्णन करता है।","ar":"عند خفض السرعة، لُفّ الخانق وأنت ترخي القابض للخارج حتى يرتفع المحرك إلى السرعة المناسبة ويكون خفض السرعة أكثر سلاسة. يصف دليل مشغّل الدراجة النارية تقنية خفض السرعة هذه المكوّنة من 3 خطوات."}},{"cat":"controls","a":3,"q":{"en":"When you come to a stop and remain stopped, which gear should you keep the motorcycle in?","es":"Cuando llegas a una parada y permaneces detenido, ¿en qué velocidad debes mantener la motocicleta?","ru":"Когда вы останавливаетесь и стоите на месте, на какой передаче следует держать мотоцикл?","tr":"Durup beklerken motosikleti hangi viteste tutmalısınız?","hi":"जब आप रुकते हैं और रुके रहते हैं, तो आपको मोटरसाइकिल को किस गियर में रखना चाहिए?","ar":"عندما تتوقف وتبقى متوقفًا، في أي ترس يجب أن تُبقي الدراجة النارية؟"},"o":[{"en":"Neutral","es":"Neutral","ru":"Нейтраль","tr":"Boşta","hi":"न्यूट्रल","ar":"الوضع المحايد"},{"en":"Second gear","es":"Segunda velocidad","ru":"Вторая передача","tr":"İkinci viteste","hi":"दूसरा गियर","ar":"الترس الثاني"},{"en":"The highest gear you were using","es":"La velocidad más alta que estabas usando","ru":"Самая высокая из использованных передач","tr":"Kullandığınız en yüksek viteste","hi":"जो सबसे ऊँचा गियर आप उपयोग कर रहे थे","ar":"أعلى ترس كنت تستخدمه"},{"en":"First gear","es":"Primera velocidad","ru":"Первая передача","tr":"Birinci viteste","hi":"पहला गियर","ar":"الترس الأول"}],"e":{"en":"Remain in first gear while stopped so you can move out quickly if you need to. The Motorcycle Operator Manual specifically advises staying in first gear at a stop.","es":"Permanece en primera velocidad mientras estás detenido para poder arrancar rápidamente si lo necesitas. El Manual del Operador de Motocicletas aconseja específicamente quedarse en primera velocidad al detenerse.","ru":"Оставайтесь на первой передаче во время остановки, чтобы можно было быстро тронуться, если потребуется. Руководство мотоциклиста прямо советует оставаться на первой передаче при остановке.","tr":"Dururken birinci viteste kalın ki gerekirse hızlıca hareket edebilesiniz. Motosiklet Kullanıcı Kılavuzu, dururken özellikle birinci viteste kalmayı önerir.","hi":"रुके रहने के दौरान पहले गियर में रहें ताकि ज़रूरत पड़ने पर आप जल्दी निकल सकें। Motorcycle Operator Manual विशेष रूप से रुकने पर पहले गियर में रहने की सलाह देता है।","ar":"ابقَ في الترس الأول أثناء التوقف حتى تتمكن من الانطلاق بسرعة إذا احتجت. ينصح دليل مشغّل الدراجة النارية تحديدًا بالبقاء في الترس الأول عند التوقف."}},{"cat":"controls","a":1,"q":{"en":"Why should you start out with your right wrist held flat?","es":"¿Por qué debes comenzar con la muñeca derecha plana?","ru":"Почему трогаться с места следует, держа правое запястье ровно?","tr":"Sağ bileğinizi düz tutarak başlamanız neden önerilir?","hi":"आपको अपनी दाहिनी कलाई को सपाट रखकर शुरुआत क्यों करनी चाहिए?","ar":"لماذا يجب أن تبدأ ورسغك اليمنى مسطّحة؟"},"o":[{"en":"It keeps the front brake covered at all times","es":"Mantiene el freno delantero cubierto en todo momento","ru":"Это держит передний тормоз всегда наготове","tr":"Ön freni her zaman hazır tutar","hi":"यह हर समय फ्रंट ब्रेक को कवर रखता है","ar":"لأنها تُبقي الفرامل الأمامية مغطاة في كل الأوقات"},{"en":"It helps you keep from accidentally using too much throttle","es":"Ayuda a evitar que uses demasiado acelerador por accidente","ru":"Это помогает избежать случайной подачи слишком большого газа","tr":"Yanlışlıkla çok fazla gaz vermenizi önlemeye yardımcı olur","hi":"यह आपको गलती से बहुत अधिक थ्रॉटल का उपयोग करने से बचने में मदद करता है","ar":"لأنها تساعدك على تجنّب استخدام الخانق بإفراط عن طريق الخطأ"},{"en":"It locks your arm so you can hold yourself up","es":"Bloquea tu brazo para que puedas sostenerte","ru":"Это фиксирует руку, чтобы удерживать себя на мотоцикле","tr":"Kendinizi tutabilmek için kolunuzu kilitler","hi":"यह आपकी बाँह को लॉक कर देता है ताकि आप खुद को सहारा दे सकें","ar":"لأنها تثبّت ذراعك حتى تستطيع أن تسند نفسك"},{"en":"It points your fingers toward the clutch lever","es":"Apunta tus dedos hacia la palanca del embrague","ru":"Это направляет пальцы к рычагу сцепления","tr":"Parmaklarınızı debriyaj koluna doğru yönlendirir","hi":"यह आपकी उंगलियों को क्लच लीवर की ओर इंगित करता है","ar":"لأنها توجّه أصابعك نحو ذراع القابض"}],"e":{"en":"Starting with the right wrist flat helps prevent accidentally rolling on too much throttle. The Motorcycle Operator Manual recommends this hand position when holding the handgrips.","es":"Comenzar con la muñeca derecha plana ayuda a evitar acelerar demasiado por accidente. El Manual del Operador de Motocicletas recomienda esta posición de la mano al sostener las manijas.","ru":"Трогаясь с ровным правым запястьем, вы избегаете случайной подачи слишком большого газа. Руководство мотоциклиста рекомендует такое положение руки при удержании рукояток руля.","tr":"Sağ bilek düz başlamak, yanlışlıkla çok fazla gaz vermeyi önlemeye yardımcı olur. Motosiklet Kullanıcı Kılavuzu, gidon kabzalarını tutarken bu el konumunu önerir.","hi":"दाहिनी कलाई को सपाट रखकर शुरू करने से गलती से बहुत अधिक थ्रॉटल रोल ऑन होने से बचने में मदद मिलती है। Motorcycle Operator Manual हैंडग्रिप पकड़ते समय इस हाथ की स्थिति की सिफारिश करता है।","ar":"البدء والرسغ اليمنى مسطّحة يساعد على منع لفّ الخانق بإفراط عن طريق الخطأ. يوصي دليل مشغّل الدراجة النارية بوضعية اليد هذه عند الإمساك بالمقابض."}},{"cat":"controls","a":3,"q":{"en":"When checked or released, what should a properly working throttle do?","es":"Al revisarlo o soltarlo, ¿qué debe hacer un acelerador que funciona correctamente?","ru":"Что должна делать исправно работающая ручка газа при проверке или отпускании?","tr":"Kontrol edildiğinde ya da bırakıldığında, düzgün çalışan bir gaz kolu ne yapmalıdır?","hi":"जाँच या छोड़े जाने पर, सही ढंग से काम करने वाले थ्रॉटल को क्या करना चाहिए?","ar":"عند فحصه أو تحريره، ماذا يجب أن يفعل الخانق الذي يعمل بشكل سليم؟"},"o":[{"en":"Stay wherever it is set","es":"Quedarse donde quiera que se haya ajustado","ru":"Оставаться в том положении, в котором установлена","tr":"Bırakıldığı yerde kalmalı","hi":"जहाँ भी सेट हो वहीं रहना चाहिए","ar":"يبقى في الوضع الذي ضُبط عليه"},{"en":"Slowly creep open on its own","es":"Abrirse lentamente por sí solo","ru":"Медленно открываться сама по себе","tr":"Kendiliğinden yavaşça açılmalı","hi":"अपने आप धीरे-धीरे खुलते जाना चाहिए","ar":"ينفتح ببطء من تلقاء نفسه"},{"en":"Lock into the last position used","es":"Bloquearse en la última posición usada","ru":"Фиксироваться в последнем использованном положении","tr":"Son kullanılan konumda kilitlenmeli","hi":"अंतिम उपयोग की गई स्थिति में लॉक हो जाना चाहिए","ar":"يثبت في آخر وضع استُخدم"},{"en":"Snap back to the fully closed position","es":"Regresar de golpe a la posición totalmente cerrada","ru":"Возвращаться в полностью закрытое положение","tr":"Tamamen kapalı konuma geri dönmeli","hi":"पूरी तरह बंद स्थिति में वापस स्नैप होना चाहिए","ar":"يرتد بسرعة إلى الوضع المغلق تمامًا"}],"e":{"en":"During the pre-ride check, the throttle should snap back to fully closed when released. The Motorcycle Operator Manual lists this under the Controls portion of the inspection.","es":"Durante la revisión previa al viaje, el acelerador debe regresar de golpe a la posición totalmente cerrada al soltarlo. El Manual del Operador de Motocicletas incluye esto en la sección de Controles de la inspección.","ru":"Во время предрейсовой проверки ручка газа при отпускании должна возвращаться в полностью закрытое положение. Руководство мотоциклиста относит это к разделу «Органы управления» осмотра.","tr":"Sürüş öncesi kontrolde, bırakıldığında gaz kolu tamamen kapalı konuma geri dönmelidir. Motosiklet Kullanıcı Kılavuzu, bunu kontrolün Kumandalar bölümünde sıralar.","hi":"प्री-राइड जाँच के दौरान, छोड़े जाने पर थ्रॉटल को पूरी तरह बंद स्थिति में वापस स्नैप होना चाहिए। Motorcycle Operator Manual इसे निरीक्षण के Controls भाग में सूचीबद्ध करता है।","ar":"أثناء الفحص قبل القيادة، يجب أن يرتد الخانق بسرعة إلى الوضع المغلق تمامًا عند تحريره. يُدرج دليل مشغّل الدراجة النارية ذلك ضمن جزء عناصر التحكم من الفحص."}},{"cat":"controls","a":2,"q":{"en":"For the best stopping ability, how should you use the brakes for normal stops?","es":"Para la mejor capacidad de frenado, ¿cómo debes usar los frenos en las paradas normales?","ru":"Для наилучшей способности к торможению как следует использовать тормоза при обычных остановках?","tr":"En iyi durma kabiliyeti için normal duruşlarda frenleri nasıl kullanmalısınız?","hi":"सबसे अच्छी रुकने की क्षमता के लिए, सामान्य स्टॉप के लिए आपको ब्रेक का उपयोग कैसे करना चाहिए?","ar":"للحصول على أفضل قدرة على التوقف، كيف يجب أن تستخدم الفرامل في حالات التوقف العادية؟"},"o":[{"en":"Use the rear brake only to avoid flipping forward","es":"Usar solo el freno trasero para evitar volcar hacia adelante","ru":"Использовать только задний тормоз, чтобы не перевернуться вперёд","tr":"Öne takla atmamak için sadece arka freni kullanın","hi":"आगे की ओर पलटने से बचने के लिए केवल रियर ब्रेक का उपयोग करें","ar":"استخدم الفرامل الخلفية فقط لتجنّب الانقلاب للأمام"},{"en":"Use the front brake only because it is most powerful","es":"Usar solo el freno delantero porque es el más potente","ru":"Использовать только передний тормоз, так как он самый мощный","tr":"En güçlü olduğu için sadece ön freni kullanın","hi":"केवल फ्रंट ब्रेक का उपयोग करें क्योंकि यह सबसे शक्तिशाली है","ar":"استخدم الفرامل الأمامية فقط لأنها الأقوى"},{"en":"Use both the front and rear brakes every time you slow or stop","es":"Usar tanto el freno delantero como el trasero cada vez que reduzcas o te detengas","ru":"Использовать оба тормоза, передний и задний, каждый раз при замедлении или остановке","tr":"Her yavaşladığınızda ya da durduğunuzda hem ön hem arka freni kullanın","hi":"हर बार धीमा होने या रुकने पर फ्रंट और रियर दोनों ब्रेक का उपयोग करें","ar":"استخدم كلتا الفرامل الأمامية والخلفية في كل مرة تبطئ أو تتوقف فيها"},{"en":"Alternate between the two brakes, one then the other","es":"Alternar entre los dos frenos, uno y luego el otro","ru":"Чередовать тормоза, то один, то другой","tr":"İki fren arasında, biri sonra diğeri olacak şekilde dönüşümlü kullanın","hi":"दोनों ब्रेक के बीच बारी-बारी से, एक फिर दूसरा","ar":"تناوب بين الفرملتين، واحدة ثم الأخرى"}],"e":{"en":"Always use both brakes every time you slow or stop, even for normal stops, so the habit is ready in an emergency. The Motorcycle Operator Manual stresses using both brakes together.","es":"Usa siempre ambos frenos cada vez que reduzcas o te detengas, incluso en paradas normales, para que el hábito esté listo en una emergencia. El Manual del Operador de Motocicletas recalca usar ambos frenos juntos.","ru":"Всегда используйте оба тормоза каждый раз при замедлении или остановке, даже при обычных остановках, чтобы навык был готов в экстренной ситуации. Руководство мотоциклиста подчёркивает совместное использование обоих тормозов.","tr":"Acil durumda alışkanlık hazır olsun diye, normal duruşlarda bile her yavaşladığınızda ya da durduğunuzda her iki freni de kullanın. Motosiklet Kullanıcı Kılavuzu, her iki frenin birlikte kullanılmasını vurgular.","hi":"हर बार धीमा होने या रुकने पर हमेशा दोनों ब्रेक का उपयोग करें, यहाँ तक कि सामान्य स्टॉप के लिए भी, ताकि यह आदत आपातकाल में तैयार रहे। Motorcycle Operator Manual दोनों ब्रेक को एक साथ उपयोग करने पर ज़ोर देता है।","ar":"استخدم دائمًا كلتا الفرملتين في كل مرة تبطئ أو تتوقف فيها، حتى في حالات التوقف العادية، حتى تكون العادة جاهزة في حالة الطوارئ. يشدد دليل مشغّل الدراجة النارية على استخدام كلتا الفرملتين معًا."}},{"cat":"controls","a":2,"q":{"en":"About how much of a motorcycle's total stopping power can the front brake provide?","es":"¿Aproximadamente cuánto de la capacidad total de frenado de una motocicleta puede proporcionar el freno delantero?","ru":"Примерно какую долю общей тормозной силы мотоцикла может обеспечить передний тормоз?","tr":"Bir motosikletin toplam durma gücünün yaklaşık ne kadarını ön fren sağlayabilir?","hi":"मोटरसाइकिल की कुल रुकने की शक्ति का लगभग कितना हिस्सा फ्रंट ब्रेक प्रदान कर सकता है?","ar":"ما هي تقريبًا نسبة قدرة التوقف الكلية للدراجة النارية التي يمكن أن توفرها الفرامل الأمامية؟"},"o":[{"en":"About 25 percent or less","es":"Cerca del 25 por ciento o menos","ru":"Около 25 процентов или меньше","tr":"Yaklaşık yüzde 25 veya daha az","hi":"लगभग 25 प्रतिशत या उससे कम","ar":"نحو 25 بالمئة أو أقل"},{"en":"Exactly 50 percent","es":"Exactamente el 50 por ciento","ru":"Ровно 50 процентов","tr":"Tam olarak yüzde 50","hi":"ठीक 50 प्रतिशत","ar":"50 بالمئة بالضبط"},{"en":"70 percent or more","es":"70 por ciento o más","ru":"70 процентов или больше","tr":"%70 veya daha fazla","hi":"70% या अधिक","ar":"70% أو أكثر"},{"en":"None; the rear brake does all the stopping","es":"Nada; el freno trasero hace todo el frenado","ru":"Никакую; всё торможение выполняет задний тормоз","tr":"Hiç; durmanın tamamını arka fren yapar","hi":"कुछ नहीं; रियर ब्रेक ही सारी रुकावट करता है","ar":"لا شيء؛ فالفرامل الخلفية تقوم بكل التوقف"}],"e":{"en":"The front brake is more powerful and can provide 70% or more of total stopping power, and is safe when used properly. The Motorcycle Operator Manual states this.","es":"El freno delantero es más potente y puede proporcionar el 70% o más de la capacidad total de frenado, y es seguro cuando se usa correctamente. El Manual del Operador de Motocicletas lo indica.","ru":"Передний тормоз мощнее и может обеспечить 70% или больше общей тормозной силы, и он безопасен при правильном использовании. Об этом говорит Руководство мотоциклиста.","tr":"Ön fren daha güçlüdür ve toplam durma gücünün %70 veya daha fazlasını sağlayabilir, doğru kullanıldığında güvenlidir. Motosiklet Kullanıcı Kılavuzu bunu belirtir.","hi":"फ्रंट ब्रेक अधिक शक्तिशाली है और कुल रुकने की शक्ति का 70% या अधिक प्रदान कर सकता है, और सही ढंग से उपयोग करने पर सुरक्षित है। Motorcycle Operator Manual यह बताता है।","ar":"الفرامل الأمامية أقوى ويمكن أن توفر 70% أو أكثر من قدرة التوقف الكلية، وهي آمنة عند استخدامها بشكل صحيح. ينص دليل مشغّل الدراجة النارية على ذلك."}},{"cat":"controls","a":0,"q":{"en":"If your throttle sticks open and twisting it back and forth does not free it, what should you do?","es":"Si tu acelerador se queda abierto y girarlo de un lado a otro no lo libera, ¿qué debes hacer?","ru":"Если ручка газа заклинила в открытом положении и проворачивание её туда-сюда не помогает, что нужно делать?","tr":"Gaz kolunuz açık takılı kalırsa ve ileri geri çevirmek onu kurtarmazsa ne yapmalısınız?","hi":"यदि आपका थ्रॉटल खुला अटक जाए और इसे आगे-पीछे घुमाने से यह मुक्त न हो, तो आपको क्या करना चाहिए?","ar":"إذا علق الخانق مفتوحًا ولم يُحرّره لفّه ذهابًا وإيابًا، فماذا يجب أن تفعل؟"},"o":[{"en":"Immediately operate the engine cut-off switch and squeeze the clutch lever at the same time","es":"Operar de inmediato el interruptor de apagado del motor y apretar la palanca del embrague al mismo tiempo","ru":"Немедленно задействовать выключатель двигателя и одновременно сжать рычаг сцепления","tr":"Hemen motor durdurma anahtarını kullanıp aynı anda debriyaj kolunu sıkın","hi":"तुरंत इंजन कट-ऑफ स्विच चलाएं और साथ ही क्लच लीवर दबाएं","ar":"شغّل فورًا مفتاح إيقاف المحرك واضغط ذراع القابض في الوقت نفسه"},{"en":"Slam on the front brake only and keep the engine running","es":"Frenar de golpe solo con el freno delantero y mantener el motor encendido","ru":"Резко нажать только передний тормоз, оставив двигатель работать","tr":"Sadece ön frene sertçe basın ve motoru çalışır durumda tutun","hi":"केवल फ्रंट ब्रेक ज़ोर से दबाएं और इंजन चालू रखें","ar":"اضغط بقوة على الفرامل الأمامية فقط وأبقِ المحرك يعمل"},{"en":"Shift quickly into neutral and coast indefinitely","es":"Poner rápidamente en neutral y rodar sin parar","ru":"Быстро перейти на нейтраль и катиться сколь угодно долго","tr":"Hızlıca boşa alıp süresiz şekilde rölantide gidin","hi":"जल्दी से न्यूट्रल में शिफ्ट करें और अनिश्चित काल तक कोस्ट करें","ar":"حوّل بسرعة إلى الوضع المحايد وانزلق إلى ما لا نهاية"},{"en":"Turn the ignition key off and let go of the handgrips","es":"Apagar la llave de encendido y soltar las manijas","ru":"Выключить зажигание ключом и отпустить рукоятки руля","tr":"Kontak anahtarını kapatıp gidon kabzalarını bırakın","hi":"इग्निशन की बंद कर दें और हैंडग्रिप छोड़ दें","ar":"أطفئ مفتاح الإشعال واترك المقابض"}],"e":{"en":"If the throttle stays stuck, operate the engine cut-off switch and squeeze the clutch at the same time to remove power from the rear wheel, then move to a safe area and stop. The Motorcycle Operator Manual gives this exact procedure.","es":"Si el acelerador permanece atascado, opera el interruptor de apagado del motor y aprieta el embrague al mismo tiempo para quitar potencia de la rueda trasera, luego dirígete a un área segura y detente. El Manual del Operador de Motocicletas da este procedimiento exacto.","ru":"Если газ остаётся заклиненным, задействуйте выключатель двигателя и одновременно сжимайте сцепление, чтобы убрать мощность с заднего колеса, затем переместитесь в безопасное место и остановитесь. Руководство мотоциклиста даёт именно эту процедуру.","tr":"Gaz takılı kalmaya devam ederse, motor durdurma anahtarını kullanıp aynı anda debriyajı sıkarak arka tekerlekten gücü kesin, sonra güvenli bir alana geçip durun. Motosiklet Kullanıcı Kılavuzu bu işlemi aynen verir.","hi":"यदि थ्रॉटल अटका रहे, तो इंजन कट-ऑफ स्विच चलाएं और साथ ही क्लच दबाएं ताकि रियर व्हील से पावर हट जाए, फिर सुरक्षित क्षेत्र में जाकर रुकें। Motorcycle Operator Manual यही प्रक्रिया देता है।","ar":"إذا بقي الخانق عالقًا، شغّل مفتاح إيقاف المحرك واضغط القابض في الوقت نفسه لإزالة الطاقة عن العجلة الخلفية، ثم انتقل إلى منطقة آمنة وتوقف. يقدّم دليل مشغّل الدراجة النارية هذا الإجراء بالضبط."}},{"cat":"controls","a":3,"q":{"en":"What is a key benefit of stopping the engine with the engine cut-off switch?","es":"¿Cuál es un beneficio clave de apagar el motor con el interruptor de apagado del motor?","ru":"В чём ключевое преимущество остановки двигателя с помощью выключателя двигателя?","tr":"Motoru, motor durdurma anahtarıyla durdurmanın temel bir faydası nedir?","hi":"इंजन कट-ऑफ स्विच से इंजन रोकने का एक प्रमुख लाभ क्या है?","ar":"ما هي الفائدة الرئيسية لإيقاف المحرك باستخدام مفتاح إيقاف المحرك؟"},"o":[{"en":"It charges the battery faster than the key","es":"Carga la batería más rápido que la llave","ru":"Он заряжает аккумулятор быстрее, чем ключ","tr":"Bataryayı anahtardan daha hızlı şarj eder","hi":"यह की की तुलना में बैटरी को तेज़ी से चार्ज करता है","ar":"يشحن البطارية أسرع من المفتاح"},{"en":"It automatically shifts the motorcycle into first gear","es":"Cambia automáticamente la motocicleta a primera velocidad","ru":"Он автоматически переключает мотоцикл на первую передачу","tr":"Motosikleti otomatik olarak birinci vitese alır","hi":"यह मोटरसाइकिल को स्वतः पहले गियर में शिफ्ट कर देता है","ar":"يحوّل الدراجة النارية تلقائيًا إلى الترس الأول"},{"en":"It engages the front brake so the motorcycle cannot roll","es":"Acciona el freno delantero para que la motocicleta no pueda rodar","ru":"Он задействует передний тормоз, чтобы мотоцикл не катился","tr":"Motosiklet kaymasın diye ön freni devreye sokar","hi":"यह फ्रंट ब्रेक लगा देता है ताकि मोटरसाइकिल लुढ़क न सके","ar":"يشغّل الفرامل الأمامية حتى لا تتدحرج الدراجة النارية"},{"en":"It lets you shut off the engine while still holding the handgrip, building a habit useful in an emergency","es":"Te permite apagar el motor mientras sigues sujetando la manija, creando un hábito útil en una emergencia","ru":"Он позволяет заглушить двигатель, не отпуская рукоятку руля, формируя навык, полезный в экстренной ситуации","tr":"Gidon kabzasını tutmaya devam ederken motoru kapatmanıza olanak tanır ve acil durumda işe yarayacak bir alışkanlık oluşturur","hi":"यह आपको हैंडग्रिप पकड़े रहते हुए इंजन बंद करने देता है, जिससे आपातकाल में उपयोगी आदत बनती है","ar":"يتيح لك إيقاف المحرك مع الإمساك بالمقبض، مما يبني عادة مفيدة في حالة الطوارئ"}],"e":{"en":"The engine cut-off switch lets you stop the engine without removing your hand from the handgrip, and using it routinely builds the habit needed for an emergency such as a stuck throttle. The Motorcycle Operator Manual recommends developing this habit.","es":"El interruptor de apagado del motor te permite detener el motor sin quitar la mano de la manija, y usarlo de forma habitual crea el hábito necesario para una emergencia como un acelerador atascado. El Manual del Operador de Motocicletas recomienda desarrollar este hábito.","ru":"Выключатель двигателя позволяет заглушить двигатель, не убирая руку с рукоятки руля, и регулярное его использование формирует навык, необходимый в экстренной ситуации, например при заклинившем газе. Руководство мотоциклиста рекомендует вырабатывать эту привычку.","tr":"Motor durdurma anahtarı, elinizi gidon kabzasından çekmeden motoru durdurmanıza olanak tanır ve bunu rutin olarak kullanmak, takılı gaz kolu gibi bir acil durumda gereken alışkanlığı oluşturur. Motosiklet Kullanıcı Kılavuzu bu alışkanlığı geliştirmeyi önerir.","hi":"इंजन कट-ऑफ स्विच आपको हैंडग्रिप से हाथ हटाए बिना इंजन रोकने देता है, और इसे नियमित रूप से उपयोग करने से अटके थ्रॉटल जैसे आपातकाल के लिए आवश्यक आदत बनती है। Motorcycle Operator Manual इस आदत को विकसित करने की सिफारिश करता है।","ar":"يتيح لك مفتاح إيقاف المحرك إيقاف المحرك دون رفع يدك عن المقبض، واستخدامه بشكل روتيني يبني العادة اللازمة لحالة طوارئ مثل خانق عالق. يوصي دليل مشغّل الدراجة النارية بتطوير هذه العادة."}},{"cat":"controls","a":2,"q":{"en":"What is the proper position for your feet while riding?","es":"¿Cuál es la posición correcta de los pies mientras conduces?","ru":"Каково правильное положение ног во время езды?","tr":"Sürüş sırasında ayaklarınız için doğru konum nedir?","hi":"राइडिंग के दौरान आपके पैरों की सही स्थिति क्या है?","ar":"ما هي الوضعية الصحيحة لقدميك أثناء القيادة؟"},"o":[{"en":"Dragging lightly along the ground for balance","es":"Arrastrándolos ligeramente por el suelo para mantener el equilibrio","ru":"Слегка волочить по земле для равновесия","tr":"Denge için hafifçe yerde sürünerek","hi":"संतुलन के लिए हल्के से ज़मीन पर घिसटते हुए","ar":"تسحبهما بخفة على الأرض للتوازن"},{"en":"Firmly on the footrests with toes pointed downward","es":"Firmes en los estribos con las puntas apuntando hacia abajo","ru":"Прочно на подножках, носки направлены вниз","tr":"Ayak basamaklarında sağlam, ayak uçları aşağı bakacak şekilde","hi":"फुटरेस्ट पर मज़बूती से, पंजे नीचे की ओर इंगित करते हुए","ar":"بثبات على مساند القدمين وأصابع القدمين موجّهة للأسفل"},{"en":"Firmly on the footrests, near the controls, without pointing the toes down","es":"Firmes en los estribos, cerca de los controles, sin apuntar las puntas hacia abajo","ru":"Прочно на подножках, рядом с органами управления, без направления носков вниз","tr":"Ayak basamaklarında sağlam, kumandalara yakın, ayak uçlarını aşağı doğrultmadan","hi":"फुटरेस्ट पर मज़बूती से, कंट्रोल के पास, बिना पंजे नीचे की ओर किए","ar":"بثبات على مساند القدمين، بالقرب من عناصر التحكم، دون توجيه أصابع القدمين للأسفل"},{"en":"Stretched forward off the footrests to relax your legs","es":"Estirados hacia adelante fuera de los estribos para relajar las piernas","ru":"Вытянуты вперёд с подножек, чтобы расслабить ноги","tr":"Bacaklarınızı dinlendirmek için ayak basamaklarından öne uzatılmış","hi":"पैरों को आराम देने के लिए फुटरेस्ट से आगे की ओर फैलाकर","ar":"ممدودتان للأمام بعيدًا عن مساند القدمين لإراحة ساقيك"}],"e":{"en":"Keep your feet firmly on the footrests near the controls and do not let your toes point downward, where they could catch between the road and footrests. The Motorcycle Operator Manual describes this foot position.","es":"Mantén los pies firmes en los estribos cerca de los controles y no dejes que las puntas apunten hacia abajo, donde podrían atascarse entre la carretera y los estribos. El Manual del Operador de Motocicletas describe esta posición de los pies.","ru":"Держите ноги прочно на подножках рядом с органами управления и не направляйте носки вниз, где они могут зацепиться между дорогой и подножками. Руководство мотоциклиста описывает такое положение ног.","tr":"Ayaklarınızı kumandalara yakın şekilde ayak basamaklarında sağlam tutun ve ayak uçlarınızın aşağı bakmasına izin vermeyin; aksi halde yol ile ayak basamakları arasına sıkışabilirler. Motosiklet Kullanıcı Kılavuzu bu ayak konumunu açıklar.","hi":"अपने पैरों को कंट्रोल के पास फुटरेस्ट पर मज़बूती से रखें और अपने पंजों को नीचे की ओर इंगित न होने दें, जहाँ वे सड़क और फुटरेस्ट के बीच फँस सकते हैं। Motorcycle Operator Manual इस पैर की स्थिति का वर्णन करता है।","ar":"أبقِ قدميك بثبات على مساند القدمين بالقرب من عناصر التحكم، ولا تدع أصابع قدميك توجَّه للأسفل، حيث قد تعلق بين الطريق ومساند القدمين. يصف دليل مشغّل الدراجة النارية وضعية القدمين هذه."}},{"cat":"controls","a":2,"q":{"en":"What does the Motorcycle Operator Manual advise about your knees while riding?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre tus rodillas mientras conduces?","ru":"Что Руководство мотоциклиста советует насчёт коленей во время езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş sırasında dizleriniz hakkında ne tavsiye eder?","hi":"Motorcycle Operator Manual राइडिंग के दौरान आपके घुटनों के बारे में क्या सलाह देता है?","ar":"ماذا ينصح دليل مشغّل الدراجة النارية بشأن ركبتيك أثناء القيادة؟"},"o":[{"en":"Spread them wide away from the tank for airflow","es":"Sepáralas bien del tanque para que haya flujo de aire","ru":"Широко разводить их от бака для притока воздуха","tr":"Hava akışı için onları depodan uzakta geniş tutun","hi":"हवा के बहाव के लिए उन्हें टैंक से दूर चौड़ा फैलाएं","ar":"باعد بينهما بعيدًا عن الخزان لتدفق الهواء"},{"en":"Lock them straight to brace against bumps","es":"Mantenlas rígidas para soportar los baches","ru":"Держать их выпрямленными, чтобы упираться при неровностях","tr":"Tümseklere karşı destek için onları düz kilitleyin","hi":"धक्कों के विरुद्ध सहारा देने के लिए उन्हें सीधा लॉक करें","ar":"ثبّتهما مستقيمتين للصمود أمام المطبات"},{"en":"Keep them against the gas tank to help keep your balance as the motorcycle turns","es":"Mantenlas contra el tanque de gasolina para ayudar a mantener el equilibrio cuando la motocicleta gira","ru":"Держать их прижатыми к бензобаку, чтобы помогать удерживать равновесие при поворотах мотоцикла","tr":"Motosiklet dönerken dengenizi korumaya yardımcı olması için onları benzin deposuna yaslayın","hi":"उन्हें गैस टैंक से सटाकर रखें ताकि मोटरसाइकिल मुड़ते समय आपका संतुलन बना रहे","ar":"أبقِهما ملاصقتين لخزان الوقود للمساعدة في حفظ توازنك أثناء انعطاف الدراجة النارية"},{"en":"Lift them onto the seat at low speeds","es":"Súbelas al asiento a baja velocidad","ru":"Поднимать их на сиденье на малой скорости","tr":"Düşük hızlarda onları koltuğa kaldırın","hi":"कम गति पर उन्हें सीट पर उठा लें","ar":"ارفعهما إلى المقعد عند السرعات المنخفضة"}],"e":{"en":"Keep your knees against the gas tank to help maintain balance as the motorcycle turns. The Motorcycle Operator Manual lists this under proper body position.","es":"Mantén las rodillas contra el tanque de gasolina para ayudar a mantener el equilibrio cuando la motocicleta gira. El Manual del Operador de Motocicletas incluye esto en la posición corporal correcta.","ru":"Держите колени прижатыми к бензобаку, чтобы помогать удерживать равновесие при поворотах мотоцикла. Руководство мотоциклиста относит это к правильному положению тела.","tr":"Motosiklet dönerken dengenizi korumaya yardımcı olması için dizlerinizi benzin deposuna yaslayın. Motosiklet Kullanıcı Kılavuzu bunu doğru vücut konumu altında sıralar.","hi":"अपने घुटनों को गैस टैंक से सटाकर रखें ताकि मोटरसाइकिल मुड़ते समय संतुलन बना रहे। Motorcycle Operator Manual इसे सही शारीरिक स्थिति के अंतर्गत सूचीबद्ध करता है।","ar":"أبقِ ركبتيك ملاصقتين لخزان الوقود للمساعدة في الحفاظ على التوازن أثناء انعطاف الدراجة النارية. يُدرج دليل مشغّل الدراجة النارية ذلك ضمن وضعية الجسم الصحيحة."}},{"cat":"controls","a":0,"q":{"en":"Why should you sit far enough forward so your arms are slightly bent at the handgrips?","es":"¿Por qué debes sentarte lo suficientemente adelante para que tus brazos estén ligeramente flexionados en las manijas?","ru":"Почему следует сидеть достаточно близко к рулю, чтобы руки на рукоятках были слегка согнуты?","tr":"Gidon kabzalarındayken kollarınız hafifçe bükülü olacak kadar öne oturmanız neden gereklidir?","hi":"आपको इतना आगे क्यों बैठना चाहिए कि हैंडग्रिप पर आपकी बाँहें थोड़ी मुड़ी हुई हों?","ar":"لماذا يجب أن تجلس متقدمًا بما يكفي لتكون ذراعاك منثنيتين قليلًا عند المقابض؟"},"o":[{"en":"So you can press on the handlebars without having to reach too far","es":"Para poder presionar el manillar sin tener que estirarte demasiado","ru":"Чтобы можно было давить на руль, не дотягиваясь слишком далеко","tr":"Çok uzanmadan gidona baskı yapabilmek için","hi":"ताकि आप बहुत दूर तक पहुँचे बिना हैंडलबार पर दबाव डाल सकें","ar":"حتى تتمكن من الضغط على المقود دون الحاجة إلى المد بعيدًا"},{"en":"So you can rest your full weight on your arms","es":"Para poder apoyar todo tu peso sobre los brazos","ru":"Чтобы можно было переносить весь свой вес на руки","tr":"Tüm ağırlığınızı kollarınıza yükleyebilmek için","hi":"ताकि आप अपना पूरा वज़न अपनी बाँहों पर डाल सकें","ar":"حتى تتمكن من إراحة كامل وزنك على ذراعيك"},{"en":"So your wrists stay angled high on the throttle","es":"Para que tus muñecas queden inclinadas hacia arriba sobre el acelerador","ru":"Чтобы запястья оставались высоко поднятыми на ручке газа","tr":"Bileklerinizin gaz kolunda yüksekte açılı kalması için","hi":"ताकि आपकी कलाइयाँ थ्रॉटल पर ऊँचे कोण पर रहें","ar":"حتى تبقى رسغاك مرفوعتين على الخانق"},{"en":"So your feet leave the footrests during turns","es":"Para que tus pies salgan de los estribos durante las curvas","ru":"Чтобы ноги отрывались от подножек в поворотах","tr":"Dönüşlerde ayaklarınız ayak basamaklarından ayrılsın diye","hi":"ताकि मोड़ों के दौरान आपके पैर फुटरेस्ट से हट जाएं","ar":"حتى تترك قدماك مساند القدمين أثناء الانعطافات"}],"e":{"en":"Sitting forward with slightly bent arms lets you press on the handlebars without overreaching, helping you steer rather than hold yourself up. The Motorcycle Operator Manual describes this seating position.","es":"Sentarte adelante con los brazos ligeramente flexionados te permite presionar el manillar sin estirarte de más, lo que te ayuda a conducir en lugar de sostenerte. El Manual del Operador de Motocicletas describe esta posición al sentarse.","ru":"Если сидеть близко со слегка согнутыми руками, можно давить на руль без чрезмерного вытягивания, что помогает рулить, а не удерживать себя. Руководство мотоциклиста описывает такое положение посадки.","tr":"Kollar hafifçe bükülü şekilde öne oturmak, fazla uzanmadan gidona baskı yapmanızı sağlar ve kendinizi tutmak yerine direksiyona yardımcı olur. Motosiklet Kullanıcı Kılavuzu bu oturuş konumunu açıklar.","hi":"थोड़ी मुड़ी हुई बाँहों के साथ आगे बैठने से आप बहुत दूर पहुँचे बिना हैंडलबार पर दबाव डाल सकते हैं, जिससे आपको खुद को सहारा देने के बजाय स्टीयर करने में मदद मिलती है। Motorcycle Operator Manual इस बैठने की स्थिति का वर्णन करता है।","ar":"الجلوس متقدمًا مع ثني الذراعين قليلًا يتيح لك الضغط على المقود دون المد المفرط، مما يساعدك على التوجيه بدلًا من إسناد نفسك. يصف دليل مشغّل الدراجة النارية وضعية الجلوس هذه."}},{"cat":"controls","a":1,"q":{"en":"In the MSF T-CLOCS pre-ride inspection, what do the letters stand for?","es":"En la inspección previa al viaje T-CLOCS de la MSF, ¿qué representan las letras?","ru":"Что означают буквы в предрейсовом осмотре MSF T-CLOCS?","tr":"MSF T-CLOCS sürüş öncesi kontrolünde harfler neyi ifade eder?","hi":"MSF T-CLOCS प्री-राइड निरीक्षण में, इन अक्षरों का क्या अर्थ है?","ar":"في فحص ما قبل القيادة T-CLOCS من MSF، ماذا ترمز الأحرف؟"},"o":[{"en":"Tank, Clutch, Lights, Oil, Cables, Speed","es":"Tanque, Embrague (Clutch), Luces (Lights), Aceite (Oil), Cables, Velocidad (Speed)","ru":"Бак, Сцепление, Свет, Масло, Тросы, Скорость","tr":"Depo, Debriyaj, Işıklar, Yağ, Kablolar, Hız","hi":"Tank, Clutch, Lights, Oil, Cables, Speed","ar":"الخزان، القابض، الأضواء، الزيت، الكابلات، السرعة"},{"en":"Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, and Stands","es":"Llantas y Ruedas (Tires and Wheels), Controles, Luces y Sistema Eléctrico (Lights and Electrics), Aceite y Otros Fluidos (Oil and Other Fluids), Chasis (Chassis) y Soportes (Stands)","ru":"Шины и колёса (Tires and Wheels), Органы управления (Controls), Свет и электрика (Lights and Electrics), Масло и прочие жидкости (Oil and Other Fluids), Рама (Chassis) и Подножки/стойки (Stands)","tr":"Lastikler ve Jantlar, Kumandalar, Işıklar ve Elektrik, Yağ ve Diğer Sıvılar, Şasi ve Sehpalar","hi":"Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, और Stands","ar":"الإطارات والعجلات، عناصر التحكم، الأضواء والكهربائيات، الزيت والسوائل الأخرى، الهيكل، والحوامل"},{"en":"Throttle, Clutch, Levers, Oil, Choke, and Seat","es":"Acelerador (Throttle), Embrague (Clutch), Palancas (Levers), Aceite (Oil), Estárter (Choke) y Asiento (Seat)","ru":"Газ, Сцепление, Рычаги, Масло, Подсос, Сиденье","tr":"Gaz Kolu, Debriyaj, Kollar, Yağ, Jikle ve Koltuk","hi":"Throttle, Clutch, Levers, Oil, Choke, और Seat","ar":"الخانق، القابض، الأذرع، الزيت، الشفّاط، والمقعد"},{"en":"Tires, Cooling, Lubrication, Odometer, Carburetor, and Steering","es":"Llantas (Tires), Enfriamiento (Cooling), Lubricación (Lubrication), Odómetro (Odometer), Carburador (Carburetor) y Dirección (Steering)","ru":"Шины, Охлаждение, Смазка, Одометр, Карбюратор, Рулевое управление","tr":"Lastikler, Soğutma, Yağlama, Kilometre Sayacı, Karbüratör ve Direksiyon","hi":"Tires, Cooling, Lubrication, Odometer, Carburetor, और Steering","ar":"الإطارات، التبريد، التزييت، عداد المسافة، المكربن، والتوجيه"}],"e":{"en":"T-CLOCS stands for Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, and Stands. The Motorcycle Operator Manual presents T-CLOCS as the pre-ride inspection to perform before every ride.","es":"T-CLOCS representa Llantas y Ruedas (Tires and Wheels), Controles, Luces y Sistema Eléctrico (Lights and Electrics), Aceite y Otros Fluidos (Oil and Other Fluids), Chasis (Chassis) y Soportes (Stands). El Manual del Operador de Motocicletas presenta T-CLOCS como la inspección previa al viaje que debe realizarse antes de cada recorrido.","ru":"T-CLOCS означает Шины и колёса (Tires and Wheels), Органы управления (Controls), Свет и электрика (Lights and Electrics), Масло и прочие жидкости (Oil and Other Fluids), Рама (Chassis) и Подножки/стойки (Stands). Руководство мотоциклиста представляет T-CLOCS как предрейсовый осмотр, который следует выполнять перед каждой поездкой.","tr":"T-CLOCS; Lastikler ve Jantlar (Tires and Wheels), Kumandalar (Controls), Işıklar ve Elektrik (Lights and Electrics), Yağ ve Diğer Sıvılar (Oil and Other Fluids), Şasi (Chassis) ve Sehpalar (Stands) anlamına gelir. Motosiklet Kullanıcı Kılavuzu, T-CLOCS'u her sürüşten önce yapılacak sürüş öncesi kontrol olarak sunar.","hi":"T-CLOCS का अर्थ है Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, और Stands। Motorcycle Operator Manual T-CLOCS को हर राइड से पहले किए जाने वाले प्री-राइड निरीक्षण के रूप में प्रस्तुत करता है।","ar":"يرمز T-CLOCS إلى الإطارات والعجلات، عناصر التحكم، الأضواء والكهربائيات، الزيت والسوائل الأخرى، الهيكل، والحوامل. يقدّم دليل مشغّل الدراجة النارية T-CLOCS كفحص ما قبل القيادة الواجب إجراؤه قبل كل رحلة."}},{"cat":"gear","a":2,"q":{"en":"According to the Motorcycle Operator Manual, what three items give you a far better chance of avoiding serious injury in a crash?","es":"Según el Manual del Operador de Motocicletas, ¿qué tres elementos te dan una probabilidad mucho mayor de evitar lesiones graves en un choque?","ru":"Согласно Руководству мотоциклиста, какие три предмета дают вам гораздо больше шансов избежать серьёзной травмы при аварии?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir kazada ciddi yaralanmayı önleme şansınızı çok daha fazla artıran üç şey nedir?","hi":"Motorcycle Operator Manual के अनुसार, कौन से तीन सामान दुर्घटना में गंभीर चोट से बचने का कहीं बेहतर मौका देते हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، ما هي العناصر الثلاثة التي تمنحك فرصة أفضل بكثير لتجنّب الإصابة الخطيرة في حادث تصادم؟"},"o":[{"en":"Reflective tape, a tank bag, and engine guards","es":"Cinta reflectante, una bolsa de tanque y protectores de motor","ru":"Светоотражающая лента, сумка на бак и дуги безопасности двигателя","tr":"Reflektörlü bant, depo çantası ve motor koruyucuları","hi":"रिफ्लेक्टिव टेप, एक टैंक बैग, और इंजन गार्ड","ar":"شريط عاكس، حقيبة خزان، وواقيات المحرك"},{"en":"A loud horn, anti-lock brakes, and a windshield","es":"Una bocina fuerte, frenos antibloqueo y un parabrisas","ru":"Громкий сигнал, антиблокировочные тормоза и ветровое стекло","tr":"Yüksek sesli korna, ABS frenler ve ön cam","hi":"एक तेज़ हॉर्न, एंटी-लॉक ब्रेक, और एक विंडशील्ड","ar":"بوق عالٍ، فرامل مانعة للانغلاق، وحاجب أمامي"},{"en":"A DOT-compliant helmet, face or eye protection, and protective clothing","es":"Un casco que cumpla con la norma DOT, protección facial o para los ojos y ropa protectora","ru":"Шлем, соответствующий стандарту DOT, защита лица или глаз и защитная одежда","tr":"DOT uyumlu kask, yüz ya da göz koruması ve koruyucu kıyafet","hi":"एक DOT-अनुपालक हेलमेट, चेहरे या आँखों की सुरक्षा, और सुरक्षात्मक कपड़े","ar":"خوذة متوافقة مع معايير DOT، واقٍ للوجه أو العين، وملابس واقية"},{"en":"A passenger backrest, heated grips, and a tachometer","es":"Un respaldo para el pasajero, manijas calefaccionadas y un tacómetro","ru":"Спинка для пассажира, подогрев рукояток и тахометр","tr":"Yolcu sırt dayağı, ısıtmalı kabzalar ve devir saati","hi":"एक यात्री बैकरेस्ट, हीटेड ग्रिप, और एक टैकोमीटर","ar":"مسند ظهر للراكب، مقابض مدفّأة، ومقياس دوران"}],"e":{"en":"The Motorcycle Operator Manual states that in any crash you have a far better chance of avoiding serious injury if you wear a DOT-compliant helmet, face or eye protection, and protective clothing.","es":"El Manual del Operador de Motocicletas indica que en cualquier choque tienes una probabilidad mucho mayor de evitar lesiones graves si usas un casco que cumpla con la norma DOT, protección facial o para los ojos y ropa protectora.","ru":"Руководство мотоциклиста утверждает, что при любой аварии у вас гораздо больше шансов избежать серьёзной травмы, если вы носите шлем, соответствующий стандарту DOT, защиту лица или глаз и защитную одежду.","tr":"Motosiklet Kullanıcı Kılavuzu, herhangi bir kazada DOT uyumlu kask, yüz ya da göz koruması ve koruyucu kıyafet giyerseniz ciddi yaralanmayı önleme şansınızın çok daha fazla olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि किसी भी दुर्घटना में यदि आप DOT-अनुपालक हेलमेट, चेहरे या आँखों की सुरक्षा, और सुरक्षात्मक कपड़े पहनते हैं तो आपके पास गंभीर चोट से बचने का कहीं बेहतर मौका होता है।","ar":"ينص دليل مشغّل الدراجة النارية على أنه في أي حادث تصادم تكون لديك فرصة أفضل بكثير لتجنّب الإصابة الخطيرة إذا ارتديت خوذة متوافقة مع معايير DOT، وواقيًا للوجه أو العين، وملابس واقية."}},{"cat":"gear","a":0,"q":{"en":"About how many motorcycle crashes result in head or neck injuries, according to the Motorcycle Operator Manual?","es":"Según el Manual del Operador de Motocicletas, ¿aproximadamente cuántos choques de motocicleta resultan en lesiones en la cabeza o el cuello?","ru":"Примерно какая доля аварий на мотоцикле приводит к травмам головы или шеи, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, motosiklet kazalarının yaklaşık ne kadarı baş ya da boyun yaralanmasıyla sonuçlanır?","hi":"Motorcycle Operator Manual के अनुसार, लगभग कितनी मोटरसाइकिल दुर्घटनाओं में सिर या गर्दन की चोटें होती हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، كم تقريبًا من حوادث الدراجات النارية تؤدي إلى إصابات في الرأس أو الرقبة؟"},"o":[{"en":"One out of every five","es":"Uno de cada cinco","ru":"Одна из каждых пяти","tr":"Her beşte biri","hi":"हर पाँच में से एक","ar":"واحد من كل خمسة"},{"en":"One out of every fifty","es":"Uno de cada cincuenta","ru":"Одна из каждых пятидесяти","tr":"Her ellide biri","hi":"हर पचास में से एक","ar":"واحد من كل خمسين"},{"en":"One out of every two","es":"Uno de cada dos","ru":"Одна из каждых двух","tr":"Her ikide biri","hi":"हर दो में से एक","ar":"واحد من كل اثنين"},{"en":"One out of every twenty","es":"Uno de cada veinte","ru":"Одна из каждых двадцати","tr":"Her yirmide biri","hi":"हर बीस में से एक","ar":"واحد من كل عشرين"}],"e":{"en":"The Motorcycle Operator Manual reports that one out of every five motorcycle crashes results in head or neck injuries, and these account for a majority of serious and fatal injuries.","es":"El Manual del Operador de Motocicletas reporta que uno de cada cinco choques de motocicleta resulta en lesiones en la cabeza o el cuello, y estas representan la mayoría de las lesiones graves y fatales.","ru":"Руководство мотоциклиста сообщает, что одна из каждых пяти аварий на мотоцикле приводит к травмам головы или шеи, и на них приходится большинство серьёзных и смертельных травм.","tr":"Motosiklet Kullanıcı Kılavuzu, motosiklet kazalarının her beşte birinin baş ya da boyun yaralanmasıyla sonuçlandığını ve bunların ciddi ve ölümcül yaralanmaların çoğunu oluşturduğunu bildirir.","hi":"Motorcycle Operator Manual बताता है कि हर पाँच में से एक मोटरसाइकिल दुर्घटना में सिर या गर्दन की चोटें होती हैं, और ये गंभीर और घातक चोटों का बड़ा हिस्सा बनती हैं।","ar":"يفيد دليل مشغّل الدراجة النارية بأن واحدًا من كل خمسة حوادث دراجات نارية يؤدي إلى إصابات في الرأس أو الرقبة، وهذه تمثّل غالبية الإصابات الخطيرة والقاتلة."}},{"cat":"gear","a":3,"q":{"en":"According to the Motorcycle Operator Manual, what type of clothing is best for making both you and your motorcycle easiest to recognize?","es":"Según el Manual del Operador de Motocicletas, ¿qué tipo de ropa es la mejor para que tanto tú como tu motocicleta sean más fáciles de reconocer?","ru":"Согласно Руководству мотоциклиста, какой тип одежды лучше всего делает вас и ваш мотоцикл наиболее заметными?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, hem sizi hem de motosikletinizi en kolay fark edilir kılmak için en iyi kıyafet türü hangisidir?","hi":"Motorcycle Operator Manual के अनुसार, किस प्रकार के कपड़े आपको और आपकी मोटरसाइकिल दोनों को पहचानने में सबसे आसान बनाते हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، أي نوع من الملابس هو الأفضل لجعلك أنت ودراجتك النارية أسهل في التمييز؟"},"o":[{"en":"Dark leather with no markings","es":"Cuero oscuro sin marcas","ru":"Тёмная кожа без каких-либо элементов","tr":"İşaretsiz koyu renk deri","hi":"बिना किसी निशान के गहरे रंग का चमड़ा","ar":"الجلد الداكن دون أي علامات"},{"en":"A single small reflective ankle band","es":"Una sola banda reflectante pequeña en el tobillo","ru":"Одна небольшая светоотражающая повязка на лодыжке","tr":"Tek bir küçük reflektörlü ayak bilekliği","hi":"एक छोटा रिफ्लेक्टिव टखने का बैंड","ar":"شريط عاكس صغير واحد حول الكاحل"},{"en":"Clothing that matches the color of the road","es":"Ropa que combine con el color de la carretera","ru":"Одежда, совпадающая по цвету с дорогой","tr":"Yolun rengiyle eşleşen kıyafet","hi":"सड़क के रंग से मेल खाते कपड़े","ar":"ملابس تطابق لون الطريق"},{"en":"Reflective, bright-colored clothing such as a helmet and jacket or vest","es":"Ropa reflectante de colores brillantes, como un casco y una chaqueta o chaleco","ru":"Светоотражающая одежда ярких цветов, например шлем и куртка или жилет","tr":"Kask ile ceket ya da yelek gibi reflektörlü, parlak renkli kıyafet","hi":"रिफ्लेक्टिव, चमकीले रंग के कपड़े जैसे हेलमेट और जैकेट या वेस्ट","ar":"ملابس عاكسة زاهية اللون مثل الخوذة والسترة أو الصدرية"}],"e":{"en":"The Motorcycle Operator Manual states reflective, bright-colored clothing (helmet and jacket/vest) is best; reflective material helps drivers spot you from the side, ahead, and behind.","es":"El Manual del Operador de Motocicletas indica que la ropa reflectante de colores brillantes (casco y chaqueta/chaleco) es la mejor; el material reflectante ayuda a los conductores a verte desde el costado, de frente y por detrás.","ru":"Руководство мотоциклиста утверждает, что светоотражающая одежда ярких цветов (шлем и куртка/жилет) лучше всего; светоотражающий материал помогает водителям заметить вас сбоку, спереди и сзади.","tr":"Motosiklet Kullanıcı Kılavuzu, reflektörlü, parlak renkli kıyafetin (kask ve ceket/yelek) en iyisi olduğunu belirtir; reflektörlü malzeme, sürücülerin sizi yandan, önden ve arkadan fark etmesine yardımcı olur.","hi":"Motorcycle Operator Manual बताता है कि रिफ्लेक्टिव, चमकीले रंग के कपड़े (हेलमेट और जैकेट/वेस्ट) सबसे अच्छे होते हैं; रिफ्लेक्टिव सामग्री ड्राइवरों को आपको बगल से, आगे से, और पीछे से देखने में मदद करती है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الملابس العاكسة زاهية اللون (الخوذة والسترة/الصدرية) هي الأفضل؛ فالمادة العاكسة تساعد السائقين على رؤيتك من الجانب ومن الأمام ومن الخلف."}},{"cat":"gear","a":1,"q":{"en":"According to the Motorcycle Operator Manual, the single most important thing you can do to improve your chances of surviving a crash is to:","es":"Según el Manual del Operador de Motocicletas, lo más importante que puedes hacer para mejorar tus probabilidades de sobrevivir a un choque es:","ru":"Согласно Руководству мотоциклиста, самое важное, что вы можете сделать, чтобы повысить свои шансы выжить в аварии, — это:","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir kazada hayatta kalma şansınızı artırmak için yapabileceğiniz en önemli tek şey:","hi":"Motorcycle Operator Manual के अनुसार, दुर्घटना से बचने की अपनी संभावना बेहतर करने के लिए आप जो एकमात्र सबसे महत्वपूर्ण काम कर सकते हैं, वह है:","ar":"وفقًا لدليل مشغّل الدراجة النارية، فإن أهم شيء واحد يمكنك فعله لتحسين فرصك في النجاة من حادث تصادم هو:"},"o":[{"en":"Ride only at speeds below 30 mph","es":"Conducir solo a velocidades menores a 30 mph","ru":"Ездить только со скоростью ниже 30 миль/ч","tr":"Sadece 30 mil/sa altındaki hızlarda sürmek","hi":"केवल 30 mph से कम गति पर राइड करना","ar":"القيادة فقط بسرعات أقل من 30 ميلاً في الساعة"},{"en":"Wear a securely-fastened, quality helmet","es":"Usar un casco de calidad bien abrochado","ru":"Носить надёжно застёгнутый качественный шлем","tr":"Sağlam takılmış, kaliteli bir kask takmak","hi":"एक सुरक्षित रूप से बँधा हुआ, गुणवत्तापूर्ण हेलमेट पहनना","ar":"ارتداء خوذة عالية الجودة ومثبّتة بإحكام"},{"en":"Install crash bars on the motorcycle","es":"Instalar barras de protección en la motocicleta","ru":"Установить дуги безопасности на мотоцикл","tr":"Motosiklete koruma demirleri takmak","hi":"मोटरसाइकिल पर क्रैश बार लगाना","ar":"تركيب قضبان واقية على الدراجة النارية"},{"en":"Always ride with a passenger present","es":"Conducir siempre con un pasajero presente","ru":"Всегда ездить с пассажиром","tr":"Her zaman bir yolcuyla sürmek","hi":"हमेशा एक यात्री के साथ राइड करना","ar":"القيادة دائمًا مع وجود راكب"}],"e":{"en":"The Motorcycle Operator Manual states the single most important thing you can do to improve your chances of surviving a crash is to wear a securely-fastened, quality helmet.","es":"El Manual del Operador de Motocicletas indica que lo más importante que puedes hacer para mejorar tus probabilidades de sobrevivir a un choque es usar un casco de calidad bien abrochado.","ru":"Руководство мотоциклиста утверждает, что самое важное, что вы можете сделать, чтобы повысить свои шансы выжить в аварии, — это носить надёжно застёгнутый качественный шлем.","tr":"Motosiklet Kullanıcı Kılavuzu, bir kazada hayatta kalma şansınızı artırmak için yapabileceğiniz en önemli tek şeyin sağlam takılmış, kaliteli bir kask takmak olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि दुर्घटना से बचने की अपनी संभावना बेहतर करने के लिए आप जो एकमात्र सबसे महत्वपूर्ण काम कर सकते हैं, वह है एक सुरक्षित रूप से बँधा हुआ, गुणवत्तापूर्ण हेलमेट पहनना।","ar":"ينص دليل مشغّل الدراجة النارية على أن أهم شيء واحد يمكنك فعله لتحسين فرصك في النجاة من حادث تصادم هو ارتداء خوذة عالية الجودة ومثبّتة بإحكام."}},{"cat":"gear","a":3,"q":{"en":"At the speeds at which most crashes occur (under 30 mph), what does the Motorcycle Operator Manual say a helmet can do?","es":"A las velocidades a las que ocurren la mayoría de los choques (por debajo de 30 mph), ¿qué dice el Manual del Operador de Motocicletas que puede hacer un casco?","ru":"На скоростях, при которых происходит большинство аварий (менее 30 миль/ч), что, по словам Руководства мотоциклиста, может сделать шлем?","tr":"Çoğu kazanın meydana geldiği hızlarda (30 mil/sa altında), Motosiklet Kullanıcı Kılavuzu kaskın ne yapabileceğini söyler?","hi":"जिन गति पर अधिकांश दुर्घटनाएं होती हैं (30 mph से कम), उन पर Motorcycle Operator Manual के अनुसार हेलमेट क्या कर सकता है?","ar":"عند السرعات التي تقع فيها معظم الحوادث (أقل من 30 ميلاً في الساعة)، ماذا يقول دليل مشغّل الدراجة النارية إن الخوذة تستطيع فعله؟"},"o":[{"en":"Reduce head injuries only on trips over five miles","es":"Reducir las lesiones en la cabeza solo en recorridos de más de cinco millas","ru":"Снизить травмы головы только в поездках свыше пяти миль","tr":"Baş yaralanmalarını yalnızca beş milden uzun yolculuklarda azaltır","hi":"केवल पाँच मील से अधिक की यात्राओं पर सिर की चोटें कम करता है","ar":"تقليل إصابات الرأس فقط في الرحلات التي تزيد عن خمسة أميال"},{"en":"Protect the neck but not the head","es":"Proteger el cuello pero no la cabeza","ru":"Защитить шею, но не голову","tr":"Başı değil ama boynu korur","hi":"गर्दन की रक्षा करता है लेकिन सिर की नहीं","ar":"حماية الرقبة دون الرأس"},{"en":"Eliminate the chance of any head injury entirely","es":"Eliminar por completo la posibilidad de cualquier lesión en la cabeza","ru":"Полностью исключить любую вероятность травмы головы","tr":"Herhangi bir baş yaralanması olasılığını tamamen ortadan kaldırır","hi":"किसी भी सिर की चोट की संभावना को पूरी तरह समाप्त कर देता है","ar":"القضاء التام على احتمال أي إصابة في الرأس"},{"en":"Cut both the number and severity of head injuries by half","es":"Reducir a la mitad tanto el número como la gravedad de las lesiones en la cabeza","ru":"Сократить как количество, так и тяжесть травм головы вдвое","tr":"Baş yaralanmalarının hem sayısını hem şiddetini yarı yarıya azaltır","hi":"सिर की चोटों की संख्या और गंभीरता दोनों को आधा कर देता है","ar":"خفض عدد إصابات الرأس وشدّتها إلى النصف"}],"e":{"en":"The Motorcycle Operator Manual notes most riders are going under 30 mph when a crash occurs, and at these speeds helmets can cut both the number and severity of head injuries by half.","es":"El Manual del Operador de Motocicletas señala que la mayoría de los conductores van a menos de 30 mph cuando ocurre un choque, y a estas velocidades los cascos pueden reducir a la mitad tanto el número como la gravedad de las lesiones en la cabeza.","ru":"Руководство мотоциклиста отмечает, что большинство мотоциклистов движутся со скоростью менее 30 миль/ч в момент аварии, и на этих скоростях шлемы могут сократить как количество, так и тяжесть травм головы вдвое.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu sürücünün bir kaza olduğunda 30 mil/sa altında gittiğini ve bu hızlarda kaskların baş yaralanmalarının hem sayısını hem şiddetini yarı yarıya azaltabileceğini belirtir.","hi":"Motorcycle Operator Manual नोट करता है कि जब दुर्घटना होती है तो अधिकांश राइडर 30 mph से कम पर जा रहे होते हैं, और इन गति पर हेलमेट सिर की चोटों की संख्या और गंभीरता दोनों को आधा कर सकते हैं।","ar":"يشير دليل مشغّل الدراجة النارية إلى أن معظم السائقين يسيرون بأقل من 30 ميلاً في الساعة عند وقوع حادث، وعند هذه السرعات تستطيع الخوذات خفض عدد إصابات الرأس وشدّتها إلى النصف."}},{"cat":"gear","a":2,"q":{"en":"Compared with riders not wearing a helmet, how much more likely are helmeted riders to survive head injuries, per the Motorcycle Operator Manual?","es":"En comparación con los conductores que no usan casco, ¿cuánto más probable es que los conductores con casco sobrevivan a lesiones en la cabeza, según el Manual del Operador de Motocicletas?","ru":"По сравнению с мотоциклистами без шлема, насколько вероятнее мотоциклисты в шлеме выживают при травмах головы, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, kask takmayan sürücülere kıyasla, kask takan sürücülerin baş yaralanmalarından kurtulma olasılığı ne kadar daha fazladır?","hi":"Motorcycle Operator Manual के अनुसार, हेलमेट न पहनने वाले राइडर्स की तुलना में, हेलमेट पहनने वाले राइडर्स के सिर की चोटों से बचने की संभावना कितनी अधिक होती है?","ar":"مقارنةً بالسائقين الذين لا يرتدون خوذة، كم مرة يكون السائقون الذين يرتدون خوذة أكثر احتمالًا للنجاة من إصابات الرأس، بحسب دليل مشغّل الدراجة النارية؟"},"o":[{"en":"About 25 percent more likely","es":"Aproximadamente un 25 por ciento más probable","ru":"Примерно на 25 процентов вероятнее","tr":"Yaklaşık yüzde 25 daha fazla","hi":"लगभग 25 प्रतिशत अधिक","ar":"أكثر احتمالًا بنحو 25 بالمئة"},{"en":"Twice as likely","es":"El doble de probable","ru":"Вдвое вероятнее","tr":"İki kat daha fazla","hi":"दोगुनी","ar":"ضعف الاحتمال"},{"en":"Three times more likely","es":"Tres veces más probable","ru":"В три раза вероятнее","tr":"Üç kat daha fazla","hi":"तीन गुना अधिक","ar":"ثلاث مرات أكثر احتمالًا"},{"en":"Five times more likely","es":"Cinco veces más probable","ru":"В пять раз вероятнее","tr":"Beş kat daha fazla","hi":"पाँच गुना अधिक","ar":"خمس مرات أكثر احتمالًا"}],"e":{"en":"The Motorcycle Operator Manual states that no matter the speed, helmeted riders are three times more likely to survive head injuries than those not wearing helmets at the time of the crash.","es":"El Manual del Operador de Motocicletas indica que, sin importar la velocidad, los conductores con casco tienen tres veces más probabilidades de sobrevivir a lesiones en la cabeza que quienes no usaban casco al momento del choque.","ru":"Руководство мотоциклиста утверждает, что независимо от скорости мотоциклисты в шлеме в три раза вероятнее выживают при травмах головы, чем те, кто был без шлема в момент аварии.","tr":"Motosiklet Kullanıcı Kılavuzu, hız ne olursa olsun, kask takan sürücülerin baş yaralanmalarından kurtulma olasılığının, kaza anında kask takmayanlara göre üç kat daha fazla olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि गति चाहे जो भी हो, हेलमेट पहनने वाले राइडर्स के सिर की चोटों से बचने की संभावना दुर्घटना के समय हेलमेट न पहनने वालों की तुलना में तीन गुना अधिक होती है।","ar":"ينص دليل مشغّل الدراجة النارية على أنه بغض النظر عن السرعة، يكون السائقون الذين يرتدون خوذة أكثر احتمالًا بثلاث مرات للنجاة من إصابات الرأس مقارنةً بمن لا يرتدون خوذة وقت الحادث."}},{"cat":"gear","a":2,"q":{"en":"What are the two primary types of helmets described in the Motorcycle Operator Manual?","es":"¿Cuáles son los dos tipos principales de cascos descritos en el Manual del Operador de Motocicletas?","ru":"Какие два основных типа шлемов описаны в Руководстве мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'nda açıklanan iki temel kask türü nedir?","hi":"Motorcycle Operator Manual में वर्णित दो प्रमुख प्रकार के हेलमेट कौन से हैं?","ar":"ما هما النوعان الرئيسيان من الخوذات الموصوفان في دليل مشغّل الدراجة النارية؟"},"o":[{"en":"Open-face and modular only","es":"Solo abierto y modular","ru":"Только открытый и модульный","tr":"Yalnızca açık yüz ve modüler","hi":"केवल ओपन-फेस और मॉड्यूलर","ar":"مفتوحة الوجه وقابلة للطي فقط"},{"en":"Half-shell and novelty","es":"Media cabeza y de imitación","ru":"Полушлем и сувенирный (неполноценный)","tr":"Yarım kafa ve süs kaskı","hi":"हाफ-शेल और नॉवेल्टी","ar":"نصف القشرة والزائفة"},{"en":"Three-quarter and full face","es":"De tres cuartos y de cara completa","ru":"Три четверти и полнолицевой","tr":"Dörtte üç ve tam yüz","hi":"तीन-चौथाई और फुल फेस","ar":"ثلاثة أرباع والوجه الكامل"},{"en":"Touring and racing","es":"De turismo y de carreras","ru":"Туристический и гоночный","tr":"Turing ve yarış","hi":"टूरिंग और रेसिंग","ar":"السياحية والسباق"}],"e":{"en":"The Motorcycle Operator Manual identifies two primary helmet types offering different levels of coverage: three-quarter and full face.","es":"El Manual del Operador de Motocicletas identifica dos tipos principales de cascos que ofrecen distintos niveles de cobertura: de tres cuartos y de cara completa.","ru":"Руководство мотоциклиста выделяет два основных типа шлемов, обеспечивающих разный уровень защиты: три четверти и полнолицевой.","tr":"Motosiklet Kullanıcı Kılavuzu, farklı düzeyde koruma sağlayan iki temel kask türü tanımlar: dörtte üç ve tam yüz.","hi":"Motorcycle Operator Manual दो प्रमुख प्रकार के हेलमेट की पहचान करता है जो अलग-अलग स्तर की कवरेज प्रदान करते हैं: तीन-चौथाई और फुल फेस।","ar":"يحدد دليل مشغّل الدراجة النارية نوعين رئيسيين من الخوذات يوفران مستويات مختلفة من التغطية: ثلاثة أرباع والوجه الكامل."}},{"cat":"gear","a":3,"q":{"en":"To get the most protection from any helmet, the Motorcycle Operator Manual says the helmet should be designed to meet which standard?","es":"Para obtener la mayor protección de cualquier casco, el Manual del Operador de Motocicletas dice que el casco debe estar diseñado para cumplir con cuál norma?","ru":"Чтобы получить наибольшую защиту от любого шлема, Руководство мотоциклиста говорит, что шлем должен быть рассчитан на соответствие какому стандарту?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, herhangi bir kasktan en fazla korumayı almak için kask hangi standardı karşılayacak şekilde tasarlanmış olmalıdır?","hi":"किसी भी हेलमेट से अधिकतम सुरक्षा पाने के लिए, Motorcycle Operator Manual कहता है कि हेलमेट को किस मानक को पूरा करने के लिए डिज़ाइन किया जाना चाहिए?","ar":"للحصول على أقصى حماية من أي خوذة، يقول دليل مشغّل الدراجة النارية إن الخوذة يجب أن تكون مصممة لتلبية أي معيار؟"},"o":[{"en":"OSHA workplace headgear standards","es":"Las normas de protección para la cabeza en el lugar de trabajo de OSHA","ru":"Стандартам OSHA для рабочих головных уборов","tr":"OSHA işyeri başlık standartları","hi":"OSHA कार्यस्थल हेडगियर मानक","ar":"معايير أغطية الرأس في أماكن العمل من OSHA"},{"en":"EPA emissions standards","es":"Las normas de emisiones de la EPA","ru":"Стандартам EPA по выбросам","tr":"EPA emisyon standartları","hi":"EPA उत्सर्जन मानक","ar":"معايير الانبعاثات من EPA"},{"en":"Federal Aviation Administration standards","es":"Las normas de la Administración Federal de Aviación","ru":"Стандартам Федерального управления гражданской авиации","tr":"Federal Havacılık İdaresi standartları","hi":"Federal Aviation Administration मानक","ar":"معايير الإدارة الفيدرالية للطيران"},{"en":"U.S. Department of Transportation (DOT) and state standards","es":"Las normas del Departamento de Transporte de EE. UU. (DOT) y las normas estatales","ru":"Стандартам Министерства транспорта США (DOT) и стандартам штата","tr":"ABD Ulaştırma Bakanlığı (DOT) ve eyalet standartları","hi":"U.S. Department of Transportation (DOT) और राज्य मानक","ar":"معايير وزارة النقل الأمريكية (DOT) ومعايير الولاية"}],"e":{"en":"The Motorcycle Operator Manual says a helmet should be designed to meet U.S. Department of Transportation (DOT) and state standards; a Snell Memorial Foundation label also assures quality.","es":"El Manual del Operador de Motocicletas dice que un casco debe estar diseñado para cumplir con las normas del Departamento de Transporte de EE. UU. (DOT) y las normas estatales; una etiqueta de la Snell Memorial Foundation también garantiza calidad.","ru":"Руководство мотоциклиста говорит, что шлем должен быть рассчитан на соответствие стандартам Министерства транспорта США (DOT) и стандартам штата; маркировка Snell Memorial Foundation также подтверждает качество.","tr":"Motosiklet Kullanıcı Kılavuzu, bir kaskın ABD Ulaştırma Bakanlığı (DOT) ve eyalet standartlarını karşılayacak şekilde tasarlanmış olması gerektiğini söyler; Snell Memorial Foundation etiketi de kaliteyi güvence altına alır.","hi":"Motorcycle Operator Manual कहता है कि हेलमेट को U.S. Department of Transportation (DOT) और राज्य मानकों को पूरा करने के लिए डिज़ाइन किया जाना चाहिए; Snell Memorial Foundation लेबल भी गुणवत्ता का आश्वासन देता है।","ar":"يقول دليل مشغّل الدراجة النارية إن الخوذة يجب أن تكون مصممة لتلبية معايير وزارة النقل الأمريكية (DOT) ومعايير الولاية؛ كما أن وجود ملصق مؤسسة Snell Memorial يؤكد الجودة."}},{"cat":"gear","a":3,"q":{"en":"Besides meeting DOT standards, which additional label gives assurance of helmet quality according to the Motorcycle Operator Manual?","es":"Además de cumplir con las normas DOT, ¿qué etiqueta adicional ofrece garantía de la calidad del casco según el Manual del Operador de Motocicletas?","ru":"Помимо соответствия стандартам DOT, какая дополнительная маркировка даёт гарантию качества шлема, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, DOT standartlarını karşılamanın yanı sıra hangi ek etiket kask kalitesi güvencesi verir?","hi":"Motorcycle Operator Manual के अनुसार, DOT मानकों को पूरा करने के अलावा, कौन सा अतिरिक्त लेबल हेलमेट की गुणवत्ता का आश्वासन देता है?","ar":"إلى جانب تلبية معايير DOT، أي ملصق إضافي يمنح ضمانًا لجودة الخوذة وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"The American Motorcyclist Association sticker","es":"La calcomanía de la American Motorcyclist Association","ru":"Наклейка Американской ассоциации мотоциклистов","tr":"American Motorcyclist Association çıkartması","hi":"American Motorcyclist Association स्टिकर","ar":"ملصق جمعية راكبي الدراجات النارية الأمريكية"},{"en":"The Underwriters Laboratories label","es":"La etiqueta de Underwriters Laboratories","ru":"Маркировка Underwriters Laboratories","tr":"Underwriters Laboratories etiketi","hi":"Underwriters Laboratories लेबल","ar":"ملصق Underwriters Laboratories"},{"en":"The Better Business Bureau seal","es":"El sello del Better Business Bureau","ru":"Печать Better Business Bureau","tr":"Better Business Bureau mührü","hi":"Better Business Bureau सील","ar":"ختم مكتب تحسين الأعمال"},{"en":"The Snell Memorial Foundation label","es":"La etiqueta de la Snell Memorial Foundation","ru":"Маркировка Snell Memorial Foundation","tr":"Snell Memorial Foundation etiketi","hi":"Snell Memorial Foundation लेबल","ar":"ملصق مؤسسة Snell Memorial"}],"e":{"en":"The Motorcycle Operator Manual states that helmets with a label from the Snell Memorial Foundation also give you an assurance of quality, in addition to meeting DOT standards.","es":"El Manual del Operador de Motocicletas indica que los cascos con una etiqueta de la Snell Memorial Foundation también te dan una garantía de calidad, además de cumplir con las normas DOT.","ru":"Руководство мотоциклиста утверждает, что шлемы с маркировкой Snell Memorial Foundation также дают гарантию качества, в дополнение к соответствию стандартам DOT.","tr":"Motosiklet Kullanıcı Kılavuzu, DOT standartlarını karşılamanın yanı sıra Snell Memorial Foundation etiketli kaskların da size kalite güvencesi verdiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि Snell Memorial Foundation के लेबल वाले हेलमेट DOT मानकों को पूरा करने के अलावा गुणवत्ता का आश्वासन भी देते हैं।","ar":"ينص دليل مشغّل الدراجة النارية على أن الخوذات التي تحمل ملصقًا من مؤسسة Snell Memorial تمنحك أيضًا ضمانًا للجودة، إضافةً إلى تلبية معايير DOT."}},{"cat":"gear","a":2,"q":{"en":"Most motorcycle crashes occur in broad daylight. What does the Motorcycle Operator Manual recommend to increase your chances of being seen?","es":"La mayoría de los choques de motocicleta ocurren a plena luz del día. ¿Qué recomienda el Manual del Operador de Motocicletas para aumentar tus probabilidades de ser visto?","ru":"Большинство аварий на мотоцикле происходит средь бела дня. Что Руководство мотоциклиста рекомендует, чтобы повысить шансы быть замеченным?","tr":"Çoğu motosiklet kazası güpegündüz meydana gelir. Görülme şansınızı artırmak için Motosiklet Kullanıcı Kılavuzu neyi önerir?","hi":"अधिकांश मोटरसाइकिल दुर्घटनाएं दिन के उजाले में होती हैं। देखे जाने की अपनी संभावना बढ़ाने के लिए Motorcycle Operator Manual क्या सलाह देता है?","ar":"تقع معظم حوادث الدراجات النارية في وضح النهار. بماذا يوصي دليل مشغّل الدراجة النارية لزيادة فرص رؤيتك؟"},"o":[{"en":"Rely on your headlight alone for visibility","es":"Confiar únicamente en tu faro para la visibilidad","ru":"Полагаться только на свою фару для видимости","tr":"Görünürlük için yalnızca farınıza güvenin","hi":"दृश्यता के लिए केवल अपनी हेडलाइट पर निर्भर रहें","ar":"الاعتماد على المصباح الأمامي وحده للرؤية"},{"en":"Wear neutral gray so you don't distract drivers","es":"Usar gris neutro para no distraer a los conductores","ru":"Носить нейтральный серый цвет, чтобы не отвлекать водителей","tr":"Sürücülerin dikkatini dağıtmamak için nötr gri giyin","hi":"न्यूट्रल ग्रे पहनें ताकि आप ड्राइवरों का ध्यान न भटकाएं","ar":"ارتداء الرمادي المحايد حتى لا تشتت السائقين"},{"en":"Wear bright-colored clothing such as orange, red, yellow or green","es":"Usar ropa de colores brillantes, como naranja, rojo, amarillo o verde","ru":"Носить одежду ярких цветов, например оранжевого, красного, жёлтого или зелёного","tr":"Turuncu, kırmızı, sarı ya da yeşil gibi parlak renkli kıyafet giyin","hi":"नारंगी, लाल, पीले या हरे जैसे चमकीले रंग के कपड़े पहनें","ar":"ارتداء ملابس زاهية اللون مثل البرتقالي أو الأحمر أو الأصفر أو الأخضر"},{"en":"Wear all-black gear to create a sharp silhouette","es":"Usar equipo todo negro para crear una silueta marcada","ru":"Носить полностью чёрное снаряжение для создания чёткого силуэта","tr":"Keskin bir silüet oluşturmak için tamamen siyah giyin","hi":"एक तीखी आकृति बनाने के लिए पूरी तरह काले गियर पहनें","ar":"ارتداء ملابس سوداء بالكامل لخلق ظل حاد"}],"e":{"en":"The Motorcycle Operator Manual states most crashes occur in broad daylight, so wear bright-colored clothing (orange, red, yellow or green) to increase your chances of being seen.","es":"El Manual del Operador de Motocicletas indica que la mayoría de los choques ocurren a plena luz del día, así que usa ropa de colores brillantes (naranja, rojo, amarillo o verde) para aumentar tus probabilidades de ser visto.","ru":"Руководство мотоциклиста утверждает, что большинство аварий происходит средь бела дня, поэтому носите одежду ярких цветов (оранжевого, красного, жёлтого или зелёного), чтобы повысить шансы быть замеченным.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu kazanın güpegündüz meydana geldiğini, bu yüzden görülme şansınızı artırmak için parlak renkli kıyafet (turuncu, kırmızı, sarı ya da yeşil) giymeniz gerektiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि अधिकांश दुर्घटनाएं दिन के उजाले में होती हैं, इसलिए देखे जाने की अपनी संभावना बढ़ाने के लिए चमकीले रंग के कपड़े (नारंगी, लाल, पीले या हरे) पहनें।","ar":"ينص دليل مشغّل الدراجة النارية على أن معظم الحوادث تقع في وضح النهار، لذا ارتدِ ملابس زاهية اللون (برتقالي، أحمر، أصفر أو أخضر) لزيادة فرص رؤيتك."}},{"cat":"gear","a":3,"q":{"en":"Why does the Motorcycle Operator Manual stress keeping your helmet securely fastened while riding?","es":"¿Por qué el Manual del Operador de Motocicletas insiste en mantener el casco bien abrochado mientras conduces?","ru":"Почему Руководство мотоциклиста подчёркивает необходимость держать шлем надёжно застёгнутым во время езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş sırasında kaskınızı sağlam takılı tutmayı neden vurgular?","hi":"Motorcycle Operator Manual राइडिंग के दौरान अपने हेलमेट को सुरक्षित रूप से बँधा रखने पर ज़ोर क्यों देता है?","ar":"لماذا يشدد دليل مشغّل الدراجة النارية على إبقاء خوذتك مثبّتة بإحكام أثناء القيادة؟"},"o":[{"en":"Fastening straps are only legally required at night","es":"Las correas de sujeción solo son obligatorias por ley de noche","ru":"Застёгивание ремня обязательно по закону только ночью","tr":"Kayışı bağlamak yalnızca gece yasal olarak zorunludur","hi":"फास्टनिंग स्ट्रैप केवल रात में कानूनी रूप से आवश्यक होते हैं","ar":"لأن أحزمة التثبيت مطلوبة قانونيًا ليلًا فقط"},{"en":"A loose strap helps the helmet absorb more impact","es":"Una correa floja ayuda al casco a absorber más impacto","ru":"Ослабленный ремень помогает шлему лучше поглощать удар","tr":"Gevşek bir kayış, kaskın daha fazla darbe emmesine yardımcı olur","hi":"एक ढीला स्ट्रैप हेलमेट को अधिक प्रभाव सोखने में मदद करता है","ar":"لأن الحزام المرتخي يساعد الخوذة على امتصاص صدمة أكبر"},{"en":"An unfastened helmet improves airflow and comfort","es":"Un casco sin abrochar mejora el flujo de aire y la comodidad","ru":"Незастёгнутый шлем улучшает приток воздуха и комфорт","tr":"Bağlanmamış bir kask hava akışını ve konforu artırır","hi":"एक बिना बँधा हेलमेट हवा के बहाव और आराम को बेहतर बनाता है","ar":"لأن الخوذة غير المثبّتة تحسّن تدفق الهواء والراحة"},{"en":"An unfastened helmet is likely to fly off in a crash before it can protect you","es":"Un casco sin abrochar probablemente saldrá volando en un choque antes de poder protegerte","ru":"Незастёгнутый шлем, скорее всего, слетит при аварии прежде, чем сможет защитить вас","tr":"Bağlanmamış bir kaskın, sizi koruyamadan kazada başınızdan fırlama olasılığı yüksektir","hi":"एक बिना बँधा हेलमेट दुर्घटना में आपकी सुरक्षा करने से पहले ही उड़ जाने की संभावना रखता है","ar":"لأن الخوذة غير المثبّتة من المرجح أن تطير في حادث قبل أن تتمكن من حمايتك"}],"e":{"en":"The Motorcycle Operator Manual warns to keep the helmet securely fastened; otherwise in a crash it is likely to fly off your head before it gets a chance to protect you.","es":"El Manual del Operador de Motocicletas advierte que mantengas el casco bien abrochado; de lo contrario, en un choque probablemente saldrá volando de tu cabeza antes de tener la oportunidad de protegerte.","ru":"Руководство мотоциклиста предупреждает: держите шлем надёжно застёгнутым; иначе при аварии он, скорее всего, слетит с головы прежде, чем получит шанс защитить вас.","tr":"Motosiklet Kullanıcı Kılavuzu, kaskı sağlam takılı tutmanız konusunda uyarır; aksi halde bir kazada sizi koruma şansı bulamadan başınızdan fırlama olasılığı yüksektir.","hi":"Motorcycle Operator Manual चेतावनी देता है कि हेलमेट को सुरक्षित रूप से बँधा रखें; अन्यथा दुर्घटना में यह आपकी सुरक्षा करने का मौका पाने से पहले ही आपके सिर से उड़ जाने की संभावना रखता है।","ar":"يحذّر دليل مشغّل الدراجة النارية من ضرورة إبقاء الخوذة مثبّتة بإحكام؛ وإلا فمن المرجح في حادث أن تطير عن رأسك قبل أن تحظى بفرصة لحمايتك."}},{"cat":"gear","a":0,"q":{"en":"What is the key advantage of a face shield over goggles, according to the Motorcycle Operator Manual?","es":"¿Cuál es la ventaja clave de una visera facial sobre las gafas protectoras, según el Manual del Operador de Motocicletas?","ru":"В чём ключевое преимущество защитного щитка для лица перед очками, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, yüz siperinin gözlüğe göre temel avantajı nedir?","hi":"Motorcycle Operator Manual के अनुसार, गॉगल्स की तुलना में फेस शील्ड का प्रमुख लाभ क्या है?","ar":"ما هي الميزة الرئيسية لواقي الوجه على النظارات الواقية، وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"A face shield can help protect your whole face, while goggles protect only the eyes","es":"Una visera facial puede ayudar a proteger toda tu cara, mientras que las gafas protectoras solo protegen los ojos","ru":"Защитный щиток может помочь защитить всё лицо, тогда как очки защищают только глаза","tr":"Yüz siperi tüm yüzünüzü korumaya yardımcı olabilirken, gözlük yalnızca gözleri korur","hi":"एक फेस शील्ड आपके पूरे चेहरे की रक्षा में मदद कर सकती है, जबकि गॉगल्स केवल आँखों की रक्षा करते हैं","ar":"يمكن لواقي الوجه أن يساعد في حماية وجهك بالكامل، بينما تحمي النظارات الواقية العينين فقط"},{"en":"A face shield reduces engine noise more than goggles","es":"Una visera facial reduce el ruido del motor más que las gafas protectoras","ru":"Защитный щиток снижает шум двигателя лучше, чем очки","tr":"Yüz siperi motor gürültüsünü gözlükten daha fazla azaltır","hi":"एक फेस शील्ड गॉगल्स की तुलना में इंजन की आवाज़ अधिक कम करती है","ar":"يقلل واقي الوجه ضوضاء المحرك أكثر من النظارات الواقية"},{"en":"Goggles protect the whole face better than a shield","es":"Las gafas protectoras protegen toda la cara mejor que una visera","ru":"Очки защищают всё лицо лучше, чем щиток","tr":"Gözlük tüm yüzü siperden daha iyi korur","hi":"गॉगल्स शील्ड की तुलना में पूरे चेहरे की बेहतर रक्षा करते हैं","ar":"تحمي النظارات الواقية الوجه بالكامل أفضل من الواقي"},{"en":"A face shield is the only protection that is legal at night","es":"Una visera facial es la única protección que es legal de noche","ru":"Защитный щиток — единственная защита, разрешённая ночью","tr":"Yüz siperi gece yasal olan tek korumadır","hi":"फेस शील्ड ही एकमात्र सुरक्षा है जो रात में कानूनी है","ar":"واقي الوجه هو الحماية الوحيدة القانونية ليلًا"}],"e":{"en":"The Motorcycle Operator Manual states a plastic impact-resistant face shield can help protect your whole face, while goggles protect your eyes but won't protect the rest of your face like a shield does.","es":"El Manual del Operador de Motocicletas indica que una visera facial de plástico resistente a impactos puede ayudar a proteger toda tu cara, mientras que las gafas protectoras protegen los ojos pero no protegen el resto de la cara como lo hace una visera.","ru":"Руководство мотоциклиста утверждает, что ударопрочный пластиковый защитный щиток для лица может помочь защитить всё лицо, тогда как очки защищают глаза, но не защищают остальную часть лица так, как щиток.","tr":"Motosiklet Kullanıcı Kılavuzu, darbeye dayanıklı plastik bir yüz siperinin tüm yüzünüzü korumaya yardımcı olabileceğini, gözlüğün ise gözlerinizi koruduğunu ancak yüzünüzün geri kalanını bir siper gibi korumayacağını belirtir.","hi":"Motorcycle Operator Manual बताता है कि एक प्लास्टिक इम्पैक्ट-रेज़िस्टेंट फेस शील्ड आपके पूरे चेहरे की रक्षा में मदद कर सकती है, जबकि गॉगल्स आपकी आँखों की रक्षा करते हैं पर बाकी चेहरे की शील्ड जैसी रक्षा नहीं करते।","ar":"ينص دليل مشغّل الدراجة النارية على أن واقي الوجه البلاستيكي المقاوم للصدمات يمكن أن يساعد في حماية وجهك بالكامل، بينما تحمي النظارات الواقية عينيك لكنها لا تحمي بقية وجهك كما يفعل الواقي."}},{"cat":"gear","a":2,"q":{"en":"According to the Motorcycle Operator Manual, why is a windshield NOT a substitute for a face shield or goggles?","es":"Según el Manual del Operador de Motocicletas, ¿por qué un parabrisas NO sustituye a una visera facial o gafas protectoras?","ru":"Согласно Руководству мотоциклиста, почему ветровое стекло НЕ является заменой защитному щитку для лица или очкам?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, ön cam neden yüz siperi ya da gözlüğün yerini tutmaz?","hi":"Motorcycle Operator Manual के अनुसार, विंडशील्ड फेस शील्ड या गॉगल्स का विकल्प क्यों नहीं है?","ar":"وفقًا لدليل مشغّل الدراجة النارية، لماذا لا يُعد الحاجب الأمامي بديلًا عن واقي الوجه أو النظارات الواقية؟"},"o":[{"en":"Windshields fog up faster than goggles","es":"Los parabrisas se empañan más rápido que las gafas protectoras","ru":"Ветровые стёкла запотевают быстрее, чем очки","tr":"Ön camlar gözlükten daha hızlı buğulanır","hi":"विंडशील्ड गॉगल्स की तुलना में तेज़ी से धुंधली हो जाती हैं","ar":"تتضبب الحواجب الأمامية أسرع من النظارات الواقية"},{"en":"Windshields are illegal in most states","es":"Los parabrisas son ilegales en la mayoría de los estados","ru":"Ветровые стёкла запрещены в большинстве штатов","tr":"Ön camlar çoğu eyalette yasa dışıdır","hi":"अधिकांश राज्यों में विंडशील्ड अवैध हैं","ar":"الحواجب الأمامية غير قانونية في معظم الولايات"},{"en":"Most windshields will not protect your eyes from the wind","es":"La mayoría de los parabrisas no protegen tus ojos del viento","ru":"Большинство ветровых стёкол не защитят ваши глаза от ветра","tr":"Çoğu ön cam gözlerinizi rüzgardan korumaz","hi":"अधिकांश विंडशील्ड आपकी आँखों को हवा से नहीं बचाएंगी","ar":"معظم الحواجب الأمامية لن تحمي عينيك من الرياح"},{"en":"Windshields block too much of the rider's forward view","es":"Los parabrisas bloquean demasiada visión frontal del conductor","ru":"Ветровые стёкла слишком сильно перекрывают обзор мотоциклиста вперёд","tr":"Ön camlar sürücünün önündeki görüşün çok fazlasını engeller","hi":"विंडशील्ड राइडर के आगे के दृश्य का बहुत अधिक हिस्सा रोक देती हैं","ar":"تحجب الحواجب الأمامية جزءًا كبيرًا جدًا من رؤية السائق الأمامية"}],"e":{"en":"The Motorcycle Operator Manual states a windshield is not a substitute for a face shield or goggles because most windshields will not protect your eyes from the wind.","es":"El Manual del Operador de Motocicletas indica que un parabrisas no sustituye a una visera facial o gafas protectoras porque la mayoría de los parabrisas no protegen tus ojos del viento.","ru":"Руководство мотоциклиста утверждает, что ветровое стекло не является заменой защитному щитку для лица или очкам, потому что большинство ветровых стёкол не защитят ваши глаза от ветра.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu ön camın gözlerinizi rüzgardan korumayacağı için ön camın yüz siperi ya da gözlüğün yerini tutmadığını belirtir.","hi":"Motorcycle Operator Manual बताता है कि विंडशील्ड फेस शील्ड या गॉगल्स का विकल्प नहीं है क्योंकि अधिकांश विंडशील्ड आपकी आँखों को हवा से नहीं बचाएंगी।","ar":"ينص دليل مشغّل الدراجة النارية على أن الحاجب الأمامي ليس بديلًا عن واقي الوجه أو النظارات الواقية لأن معظم الحواجب الأمامية لن تحمي عينيك من الرياح."}},{"cat":"gear","a":0,"q":{"en":"What does the Motorcycle Operator Manual say about using ordinary eyeglasses or sunglasses as eye protection?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre usar anteojos comunes o gafas de sol como protección ocular?","ru":"Что Руководство мотоциклиста говорит об использовании обычных очков для зрения или солнцезащитных очков в качестве защиты глаз?","tr":"Motosiklet Kullanıcı Kılavuzu, sıradan numaralı gözlük ya da güneş gözlüğünü göz koruması olarak kullanmak hakkında ne der?","hi":"Motorcycle Operator Manual आँखों की सुरक्षा के रूप में साधारण चश्मे या धूप के चश्मे के उपयोग के बारे में क्या कहता है?","ar":"ماذا يقول دليل مشغّل الدراجة النارية عن استخدام النظارات الطبية العادية أو النظارات الشمسية كحماية للعين؟"},"o":[{"en":"They won't keep your eyes from watering and might blow off when you turn your head","es":"No evitan que tus ojos lagrimeen y podrían salir volando cuando giras la cabeza","ru":"Они не защитят глаза от слёзотечения и могут слететь, когда вы поворачиваете голову","tr":"Gözlerinizin sulanmasını önlemezler ve başınızı çevirdiğinizde uçabilirler","hi":"वे आपकी आँखों को पानी आने से नहीं बचाएंगे और सिर घुमाने पर उड़ सकते हैं","ar":"لن تمنع عينيك من الدمع وقد تطير عندما تدير رأسك"},{"en":"They fully protect against wind, dust, and insects","es":"Protegen por completo contra el viento, el polvo y los insectos","ru":"Они полностью защищают от ветра, пыли и насекомых","tr":"Rüzgara, toza ve böceklere karşı tam koruma sağlarlar","hi":"वे हवा, धूल और कीड़ों से पूरी तरह रक्षा करते हैं","ar":"تحمي تمامًا من الرياح والغبار والحشرات"},{"en":"They are acceptable only if they are prescription lenses","es":"Son aceptables solo si son lentes recetados","ru":"Они допустимы только если это очки с диоптриями","tr":"Yalnızca numaralı camlarsa kabul edilebilirler","hi":"वे केवल तभी स्वीकार्य हैं जब वे प्रिस्क्रिप्शन लेंस हों","ar":"مقبولة فقط إذا كانت عدسات طبية"},{"en":"They are an approved substitute for goggles at low speeds","es":"Son un sustituto aprobado de las gafas protectoras a baja velocidad","ru":"Они являются одобренной заменой защитным очкам на малой скорости","tr":"Düşük hızlarda gözlük yerine onaylı bir alternatiftirler","hi":"वे कम गति पर गॉगल्स का अनुमोदित विकल्प हैं","ar":"بديل معتمد عن النظارات الواقية عند السرعات المنخفضة"}],"e":{"en":"The Motorcycle Operator Manual states eyeglasses or sunglasses are not adequate: they won't keep your eyes from watering and might blow off when you turn your head while riding.","es":"El Manual del Operador de Motocicletas indica que los anteojos o gafas de sol no son adecuados: no evitan que tus ojos lagrimeen y podrían salir volando cuando giras la cabeza mientras conduces.","ru":"Руководство мотоциклиста утверждает, что очки для зрения или солнцезащитные очки недостаточны: они не защитят глаза от слёзотечения и могут слететь, когда вы поворачиваете голову во время езды.","tr":"Motosiklet Kullanıcı Kılavuzu, numaralı gözlük ya da güneş gözlüğünün yeterli olmadığını belirtir: gözlerinizin sulanmasını önlemezler ve sürerken başınızı çevirdiğinizde uçabilirler.","hi":"Motorcycle Operator Manual बताता है कि चश्मे या धूप के चश्मे पर्याप्त नहीं हैं: वे आपकी आँखों को पानी आने से नहीं बचाएंगे और राइडिंग के दौरान सिर घुमाने पर उड़ सकते हैं।","ar":"ينص دليل مشغّل الدراجة النارية على أن النظارات الطبية أو الشمسية غير كافية: فهي لن تمنع عينيك من الدمع وقد تطير عندما تدير رأسك أثناء القيادة."}},{"cat":"gear","a":0,"q":{"en":"Which of the following is a requirement the Motorcycle Operator Manual lists for effective eye or face-shield protection?","es":"¿Cuál de los siguientes es un requisito que enumera el Manual del Operador de Motocicletas para una protección ocular o de visera facial eficaz?","ru":"Какое из перечисленного является требованием, которое Руководство мотоциклиста предъявляет к эффективной защите глаз или защитному щитку для лица?","tr":"Aşağıdakilerden hangisi, Motosiklet Kullanıcı Kılavuzu'nun etkili göz ya da yüz siperi koruması için sıraladığı bir gerekliliktir?","hi":"निम्नलिखित में से कौन सी एक आवश्यकता है जिसे Motorcycle Operator Manual प्रभावी आँख या फेस-शील्ड सुरक्षा के लिए सूचीबद्ध करता है?","ar":"أي مما يلي يُعد متطلبًا يُدرجه دليل مشغّل الدراجة النارية لحماية فعّالة للعين أو واقي الوجه؟"},"o":[{"en":"It must be free of scratches and resistant to penetration","es":"Debe estar libre de rayones y ser resistente a la penetración","ru":"Она должна быть без царапин и устойчивой к проколу","tr":"Çiziksiz ve delinmeye dayanıklı olmalı","hi":"यह खरोंच से मुक्त और प्रवेश-प्रतिरोधी होनी चाहिए","ar":"يجب أن يكون خاليًا من الخدوش ومقاومًا للاختراق"},{"en":"It must be smaller than the rider's eyeglasses","es":"Debe ser más pequeña que los anteojos del conductor","ru":"Она должна быть меньше очков мотоциклиста","tr":"Sürücünün gözlüğünden daha küçük olmalı","hi":"यह राइडर के चश्मे से छोटी होनी चाहिए","ar":"يجب أن يكون أصغر من نظارات السائق الطبية"},{"en":"It must be heavily tinted in all conditions","es":"Debe estar muy oscurecida en todas las condiciones","ru":"Она должна быть сильно затемнённой во всех условиях","tr":"Her koşulda yoğun renkli (füme) olmalı","hi":"यह सभी परिस्थितियों में गहरे रंग की टिंटेड होनी चाहिए","ar":"يجب أن يكون داكن التظليل في جميع الظروف"},{"en":"It must completely seal off all airflow","es":"Debe sellar por completo todo el flujo de aire","ru":"Она должна полностью перекрывать любой приток воздуха","tr":"Tüm hava akışını tamamen kesmeli","hi":"यह सभी हवा के बहाव को पूरी तरह सील कर देनी चाहिए","ar":"يجب أن يغلق كل تدفق الهواء تمامًا"}],"e":{"en":"The Motorcycle Operator Manual says effective eye or face-shield protection must be free of scratches, resistant to penetration, give a clear view to either side, fasten securely, and permit air to pass through to reduce fogging.","es":"El Manual del Operador de Motocicletas dice que una protección ocular o de visera facial eficaz debe estar libre de rayones, ser resistente a la penetración, dar una vista clara hacia ambos lados, sujetarse de forma segura y permitir el paso del aire para reducir el empañamiento.","ru":"Руководство мотоциклиста говорит, что эффективная защита глаз или защитный щиток для лица должны быть без царапин, устойчивы к проколу, давать чёткий обзор в обе стороны, надёжно крепиться и пропускать воздух, чтобы уменьшить запотевание.","tr":"Motosiklet Kullanıcı Kılavuzu, etkili göz ya da yüz siperi korumasının çiziksiz, delinmeye dayanıklı olması, her iki yana net görüş vermesi, sağlam takılması ve buğulanmayı azaltmak için hava geçirmesi gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि प्रभावी आँख या फेस-शील्ड सुरक्षा खरोंच से मुक्त, प्रवेश-प्रतिरोधी होनी चाहिए, दोनों ओर स्पष्ट दृश्य दे, सुरक्षित रूप से बँधे, और धुंध कम करने के लिए हवा को गुज़रने दे।","ar":"يقول دليل مشغّل الدراجة النارية إن حماية العين أو واقي الوجه الفعّالة يجب أن تكون خالية من الخدوش، مقاومة للاختراق، تمنح رؤية واضحة إلى الجانبين، تُثبَّت بإحكام، وتسمح بمرور الهواء لتقليل التضبب."}},{"cat":"gear","a":3,"q":{"en":"What does the Motorcycle Operator Manual advise about wearing tinted eye protection?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre el uso de protección ocular oscurecida?","ru":"Что Руководство мотоциклиста советует насчёт ношения затемнённой защиты глаз?","tr":"Motosiklet Kullanıcı Kılavuzu, renkli (füme) göz koruması takmak hakkında ne tavsiye eder?","hi":"Motorcycle Operator Manual टिंटेड आँख सुरक्षा पहनने के बारे में क्या सलाह देता है?","ar":"بماذا ينصح دليل مشغّل الدراجة النارية بشأن ارتداء حماية العين المظللة؟"},"o":[{"en":"It is required by DOT for daytime riding","es":"Es obligatoria por la DOT para conducir de día","ru":"Она требуется DOT для езды днём","tr":"Gündüz sürüşü için DOT tarafından zorunludur","hi":"दिन के समय राइडिंग के लिए DOT द्वारा यह आवश्यक है","ar":"إنها مطلوبة من DOT للقيادة النهارية"},{"en":"It must permit no air to pass through","es":"No debe permitir el paso de aire","ru":"Она не должна пропускать воздух","tr":"Hiç hava geçirmemelidir","hi":"इसमें से कोई हवा नहीं गुज़रनी चाहिए","ar":"يجب ألا تسمح بمرور أي هواء"},{"en":"It should be worn at all times for eye safety","es":"Debe usarse en todo momento por seguridad ocular","ru":"Её следует носить постоянно для безопасности глаз","tr":"Göz güvenliği için her zaman takılmalıdır","hi":"आँखों की सुरक्षा के लिए इसे हर समय पहना जाना चाहिए","ar":"يجب ارتداؤها في جميع الأوقات لسلامة العين"},{"en":"It should not be worn when little light is available","es":"No debe usarse cuando hay poca luz disponible","ru":"Её не следует носить при недостатке света","tr":"Az ışık olduğunda takılmamalıdır","hi":"जब बहुत कम रोशनी उपलब्ध हो तब इसे नहीं पहना जाना चाहिए","ar":"يجب عدم ارتدائها عند توفر القليل من الضوء"}],"e":{"en":"The Motorcycle Operator Manual advises that tinted eye protection should not be worn when little light is available, such as at night or in low-light conditions.","es":"El Manual del Operador de Motocicletas aconseja que la protección ocular oscurecida no debe usarse cuando hay poca luz disponible, como de noche o en condiciones de poca luz.","ru":"Руководство мотоциклиста советует, что затемнённую защиту глаз не следует носить при недостатке света, например ночью или в условиях слабой освещённости.","tr":"Motosiklet Kullanıcı Kılavuzu, renkli (füme) göz korumasının gece ya da düşük ışık koşulları gibi az ışık olduğunda takılmaması gerektiğini tavsiye eder.","hi":"Motorcycle Operator Manual सलाह देता है कि जब बहुत कम रोशनी उपलब्ध हो, जैसे रात में या कम रोशनी की स्थिति में, तब टिंटेड आँख सुरक्षा नहीं पहननी चाहिए।","ar":"ينصح دليل مشغّل الدراجة النارية بعدم ارتداء حماية العين المظللة عند توفر القليل من الضوء، مثل الليل أو في ظروف الإضاءة المنخفضة."}},{"cat":"gear","a":2,"q":{"en":"How should a jacket and pants fit for riding, according to the Motorcycle Operator Manual?","es":"¿Cómo debe quedar una chaqueta y un pantalón para conducir, según el Manual del Operador de Motocicletas?","ru":"Как должны сидеть куртка и брюки для езды, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, sürüş için ceket ve pantolon nasıl oturmalıdır?","hi":"Motorcycle Operator Manual के अनुसार, राइडिंग के लिए जैकेट और पैंट कैसे फिट होने चाहिए?","ar":"كيف يجب أن تكون مقاسات السترة والبنطال للقيادة، وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"Tight enough to restrict arm movement for support","es":"Ajustados al punto de restringir el movimiento de los brazos para dar apoyo","ru":"Достаточно плотно, чтобы ограничивать движение рук для опоры","tr":"Destek için kol hareketini kısıtlayacak kadar dar","hi":"सहारे के लिए बाँह की गति को रोकने जितने तंग","ar":"ضيقة بما يكفي لتقييد حركة الذراع للإسناد"},{"en":"Short-sleeved in summer to prevent overheating","es":"De manga corta en verano para evitar el sobrecalentamiento","ru":"С короткими рукавами летом, чтобы не перегреваться","tr":"Aşırı ısınmayı önlemek için yazın kısa kollu","hi":"ज़्यादा गर्मी रोकने के लिए गर्मियों में छोटी आस्तीन वाले","ar":"قصيرة الأكمام في الصيف لمنع فرط الحرارة"},{"en":"Cover arms and legs completely, snug enough not to flap but loose enough to move freely","es":"Cubrir por completo brazos y piernas, lo suficientemente ceñidos para no ondear pero lo suficientemente sueltos para moverse con libertad","ru":"Полностью закрывать руки и ноги, плотно, чтобы не развевались, но достаточно свободно, чтобы двигаться","tr":"Kolları ve bacakları tamamen örtmeli, savrulmayacak kadar sıkı ama serbest hareket edecek kadar bol","hi":"बाँहों और पैरों को पूरी तरह ढकें, इतने फिट कि फड़फड़ाएं नहीं पर इतने ढीले कि स्वतंत्र रूप से हिल सकें","ar":"تغطي الذراعين والساقين بالكامل، محكمة بما يكفي حتى لا ترفرف لكن فضفاضة بما يكفي للتحرك بحرية"},{"en":"As loose and baggy as possible for ventilation","es":"Lo más sueltos y holgados posible para la ventilación","ru":"Как можно более свободными и мешковатыми для вентиляции","tr":"Havalandırma için mümkün olduğunca bol ve geniş","hi":"वेंटिलेशन के लिए जितना संभव हो उतने ढीले और बैगी","ar":"فضفاضة وواسعة قدر الإمكان للتهوية"}],"e":{"en":"The Motorcycle Operator Manual says jacket and pants should cover arms and legs completely, fitting snugly enough to keep from flapping in the wind yet loosely enough to move freely.","es":"El Manual del Operador de Motocicletas dice que la chaqueta y el pantalón deben cubrir por completo brazos y piernas, quedando lo suficientemente ceñidos para no ondear con el viento pero lo suficientemente sueltos para moverse con libertad.","ru":"Руководство мотоциклиста говорит, что куртка и брюки должны полностью закрывать руки и ноги, сидя достаточно плотно, чтобы не развеваться на ветру, но достаточно свободно, чтобы двигаться свободно.","tr":"Motosiklet Kullanıcı Kılavuzu, ceket ve pantolonun kolları ve bacakları tamamen örtmesi, rüzgarda savrulmayacak kadar sıkı ama serbest hareket edecek kadar bol oturması gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि जैकेट और पैंट बाँहों और पैरों को पूरी तरह ढकने चाहिए, इतने फिट कि हवा में फड़फड़ाएं नहीं पर इतने ढीले कि स्वतंत्र रूप से हिल सकें।","ar":"يقول دليل مشغّل الدراجة النارية إن السترة والبنطال يجب أن يغطيا الذراعين والساقين بالكامل، بحيث يكونان محكمين بما يكفي لمنع الرفرفة في الرياح لكن فضفاضين بما يكفي للتحرك بحرية."}},{"cat":"gear","a":2,"q":{"en":"Which clothing material does the Motorcycle Operator Manual say offers the most protection in a collision?","es":"¿Qué material de ropa dice el Manual del Operador de Motocicletas que ofrece la mayor protección en una colisión?","ru":"Какой материал одежды, по словам Руководства мотоциклиста, обеспечивает наибольшую защиту при столкновении?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir çarpışmada en fazla korumayı hangi kıyafet malzemesi sağlar?","hi":"Motorcycle Operator Manual के अनुसार, कौन सी कपड़े की सामग्री टक्कर में सबसे अधिक सुरक्षा प्रदान करती है?","ar":"أي مادة ملابس يقول دليل مشغّل الدراجة النارية إنها توفر أكبر حماية في التصادم؟"},"o":[{"en":"Cotton denim","es":"Mezclilla de algodón","ru":"Хлопковый деним","tr":"Pamuklu kot","hi":"कॉटन डेनिम","ar":"قطن الجينز"},{"en":"Lightweight nylon mesh","es":"Malla de nailon liviana","ru":"Лёгкая нейлоновая сетка","tr":"Hafif naylon file","hi":"हल्के वज़न का नायलॉन मेश","ar":"شبكة النايلون خفيفة الوزن"},{"en":"Leather","es":"Cuero","ru":"Кожа","tr":"Deri","hi":"चमड़ा","ar":"الجلد"},{"en":"Wool","es":"Lana","ru":"Шерсть","tr":"Yün","hi":"ऊन","ar":"الصوف"}],"e":{"en":"The Motorcycle Operator Manual states leather offers the most protection, though sturdy synthetic material provides a lot of protection as well.","es":"El Manual del Operador de Motocicletas indica que el cuero ofrece la mayor protección, aunque el material sintético resistente también brinda mucha protección.","ru":"Руководство мотоциклиста утверждает, что кожа обеспечивает наибольшую защиту, хотя прочный синтетический материал также обеспечивает значительную защиту.","tr":"Motosiklet Kullanıcı Kılavuzu, derinin en fazla korumayı sağladığını, ancak dayanıklı sentetik malzemenin de oldukça fazla koruma sunduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि चमड़ा सबसे अधिक सुरक्षा प्रदान करता है, हालाँकि मज़बूत सिंथेटिक सामग्री भी काफी सुरक्षा देती है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الجلد يوفر أكبر حماية، رغم أن المواد الاصطناعية المتينة توفر قدرًا كبيرًا من الحماية أيضًا."}},{"cat":"gear","a":2,"q":{"en":"Why does the Motorcycle Operator Manual recommend wearing a jacket even in warm weather?","es":"¿Por qué el Manual del Operador de Motocicletas recomienda usar una chaqueta incluso en clima cálido?","ru":"Почему Руководство мотоциклиста рекомендует носить куртку даже в тёплую погоду?","tr":"Motosiklet Kullanıcı Kılavuzu, sıcak havalarda bile neden ceket giymeyi önerir?","hi":"Motorcycle Operator Manual गर्म मौसम में भी जैकेट पहनने की सिफारिश क्यों करता है?","ar":"لماذا يوصي دليل مشغّل الدراجة النارية بارتداء سترة حتى في الطقس الدافئ؟"},"o":[{"en":"Because state law requires a jacket in all temperatures","es":"Porque la ley estatal exige una chaqueta a cualquier temperatura","ru":"Потому что закон штата требует куртку при любой температуре","tr":"Çünkü eyalet yasası her sıcaklıkta ceket zorunlu kılar","hi":"क्योंकि राज्य का कानून सभी तापमानों में जैकेट आवश्यक करता है","ar":"لأن قانون الولاية يفرض سترة في جميع درجات الحرارة"},{"en":"Because warm-weather riding causes the most crashes","es":"Porque conducir en clima cálido causa la mayoría de los choques","ru":"Потому что езда в тёплую погоду вызывает больше всего аварий","tr":"Çünkü en çok kaza sıcak hava sürüşünde olur","hi":"क्योंकि गर्म मौसम में राइडिंग सबसे अधिक दुर्घटनाओं का कारण बनती है","ar":"لأن القيادة في الطقس الدافئ تسبب أكثر الحوادث"},{"en":"To prevent dehydration; many are designed not to overheat you","es":"Para prevenir la deshidratación; muchas están diseñadas para no sobrecalentarte","ru":"Чтобы предотвратить обезвоживание; многие из них рассчитаны на то, чтобы не перегревать вас","tr":"Su kaybını önlemek için; çoğu sizi aşırı ısıtmayacak şekilde tasarlanmıştır","hi":"निर्जलीकरण रोकने के लिए; कई इस तरह डिज़ाइन की जाती हैं कि आपको ज़्यादा गर्मी न लगे","ar":"لمنع الجفاف؛ فالكثير منها مصمم بحيث لا يسبب لك فرط الحرارة"},{"en":"To add weight that improves traction","es":"Para agregar peso que mejore la tracción","ru":"Чтобы добавить вес, улучшающий сцепление с дорогой","tr":"Yol tutuşunu artıran ağırlık eklemek için","hi":"ट्रैक्शन सुधारने के लिए वज़न जोड़ने के लिए","ar":"لإضافة وزن يحسّن الالتصاق بالطريق"}],"e":{"en":"The Motorcycle Operator Manual advises wearing a jacket even in warm weather to prevent dehydration, noting many jackets are designed to protect without getting you overheated.","es":"El Manual del Operador de Motocicletas aconseja usar una chaqueta incluso en clima cálido para prevenir la deshidratación, señalando que muchas chaquetas están diseñadas para proteger sin sobrecalentarte.","ru":"Руководство мотоциклиста советует носить куртку даже в тёплую погоду, чтобы предотвратить обезвоживание, отмечая, что многие куртки рассчитаны на защиту без перегрева.","tr":"Motosiklet Kullanıcı Kılavuzu, su kaybını önlemek için sıcak havalarda bile ceket giymeyi tavsiye eder ve çoğu ceketin sizi aşırı ısıtmadan koruyacak şekilde tasarlandığını belirtir.","hi":"Motorcycle Operator Manual निर्जलीकरण रोकने के लिए गर्म मौसम में भी जैकेट पहनने की सलाह देता है, यह नोट करते हुए कि कई जैकेट आपको ज़्यादा गर्म किए बिना सुरक्षा देने के लिए डिज़ाइन की जाती हैं।","ar":"ينصح دليل مشغّل الدراجة النارية بارتداء سترة حتى في الطقس الدافئ لمنع الجفاف، مشيرًا إلى أن الكثير من السترات مصممة للحماية دون أن تسبب لك فرط الحرارة."}},{"cat":"gear","a":2,"q":{"en":"What does the Motorcycle Operator Manual say about footwear for riding?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre el calzado para conducir?","ru":"Что Руководство мотоциклиста говорит об обуви для езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş için ayakkabı hakkında ne der?","hi":"Motorcycle Operator Manual राइडिंग के लिए जूतों के बारे में क्या कहता है?","ar":"ماذا يقول دليل مشغّل الدراجة النارية عن الأحذية للقيادة؟"},"o":[{"en":"Heels should be tall to grip the foot pegs","es":"Los tacones deben ser altos para agarrar los estribos","ru":"Каблуки должны быть высокими, чтобы цепляться за подножки","tr":"Topuklar, ayağı basamaklara kavratacak kadar yüksek olmalı","hi":"फुट पेग को पकड़ने के लिए हील ऊँची होनी चाहिए","ar":"يجب أن تكون الكعوب عالية للإمساك بمساند القدمين"},{"en":"Laces should hang loose for quick removal","es":"Las agujetas deben colgar sueltas para quitarse el calzado rápido","ru":"Шнурки должны свободно свисать для быстрого снятия","tr":"Bağcıklar hızlı çıkarma için serbest sarkmalı","hi":"जल्दी निकालने के लिए फीते ढीले लटकने चाहिए","ar":"يجب ترك أربطة الحذاء مرتخية للنزع السريع"},{"en":"Boots or shoes should be high and sturdy enough to cover your ankles and give support","es":"Las botas o zapatos deben ser altos y resistentes para cubrir los tobillos y dar apoyo","ru":"Ботинки или обувь должны быть достаточно высокими и прочными, чтобы закрывать лодыжки и обеспечивать поддержку","tr":"Botlar ya da ayakkabılar, bileklerinizi örtecek ve destek verecek kadar yüksek ve sağlam olmalı","hi":"बूट या जूते इतने ऊँचे और मज़बूत होने चाहिए कि आपके टखनों को ढक सकें और सहारा दे सकें","ar":"يجب أن تكون الجزمة أو الحذاء عاليًا ومتينًا بما يكفي لتغطية كاحليك وتوفير الإسناد"},{"en":"Open sandals are acceptable in hot weather","es":"Las sandalias abiertas son aceptables en clima caluroso","ru":"Открытые сандалии допустимы в жаркую погоду","tr":"Sıcak havalarda açık sandaletler kabul edilebilir","hi":"गर्म मौसम में खुली सैंडल स्वीकार्य हैं","ar":"الصنادل المفتوحة مقبولة في الطقس الحار"}],"e":{"en":"The Motorcycle Operator Manual says boots or shoes should be high and sturdy enough to cover your ankles, have hard slip-resistant soles, keep heels short, and have laces tucked in.","es":"El Manual del Operador de Motocicletas dice que las botas o zapatos deben ser altos y resistentes para cubrir los tobillos, tener suelas duras y antideslizantes, mantener los tacones cortos y tener las agujetas metidas.","ru":"Руководство мотоциклиста говорит, что ботинки или обувь должны быть достаточно высокими и прочными, чтобы закрывать лодыжки, иметь жёсткую нескользящую подошву, низкие каблуки и заправленные шнурки.","tr":"Motosiklet Kullanıcı Kılavuzu, botların ya da ayakkabıların bileklerinizi örtecek kadar yüksek ve sağlam olması, sert kaymaz tabanlı olması, topukların kısa tutulması ve bağcıkların içeri sokulması gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि बूट या जूते इतने ऊँचे और मज़बूत होने चाहिए कि आपके टखनों को ढक सकें, उनके तले सख्त और फिसलन-रोधी हों, हील छोटी रखें, और फीते अंदर दबे हों।","ar":"يقول دليل مشغّل الدراجة النارية إن الجزمة أو الحذاء يجب أن يكون عاليًا ومتينًا بما يكفي لتغطية كاحليك، وله نعل صلب مقاوم للانزلاق، وكعوب قصيرة، وأربطة مدسوسة للداخل."}},{"cat":"gear","a":2,"q":{"en":"Why does the Motorcycle Operator Manual recommend full-fingered gloves made of leather or similar durable material?","es":"¿Por qué el Manual del Operador de Motocicletas recomienda guantes de dedos completos hechos de cuero o material duradero similar?","ru":"Почему Руководство мотоциклиста рекомендует перчатки с полными пальцами из кожи или похожего прочного материала?","tr":"Motosiklet Kullanıcı Kılavuzu, deri ya da benzeri dayanıklı malzemeden yapılmış tam parmaklı eldivenleri neden önerir?","hi":"Motorcycle Operator Manual चमड़े या समान टिकाऊ सामग्री के पूर्ण-उंगली वाले दस्तानों की सिफारिश क्यों करता है?","ar":"لماذا يوصي دليل مشغّل الدراجة النارية بقفازات كاملة الأصابع مصنوعة من الجلد أو مادة متينة مماثلة؟"},"o":[{"en":"They are required only for nighttime riding","es":"Solo son obligatorios para conducir de noche","ru":"Они требуются только для езды ночью","tr":"Yalnızca gece sürüşü için zorunludurlar","hi":"वे केवल रात की राइडिंग के लिए आवश्यक हैं","ar":"إنها مطلوبة فقط للقيادة الليلية"},{"en":"They reduce engine noise reaching the hands","es":"Reducen el ruido del motor que llega a las manos","ru":"Они снижают шум двигателя, доходящий до рук","tr":"Ellere ulaşan motor gürültüsünü azaltırlar","hi":"वे हाथों तक पहुँचने वाली इंजन की आवाज़ कम करते हैं","ar":"تقلل ضوضاء المحرك التي تصل إلى اليدين"},{"en":"They allow a better grip and help protect your hands in a crash","es":"Permiten un mejor agarre y ayudan a proteger tus manos en un choque","ru":"Они обеспечивают лучший хват и помогают защитить руки при аварии","tr":"Daha iyi kavrama sağlarlar ve bir kazada ellerinizi korumaya yardımcı olurlar","hi":"वे बेहतर पकड़ देते हैं और दुर्घटना में आपके हाथों की रक्षा में मदद करते हैं","ar":"تتيح قبضة أفضل وتساعد في حماية يديك في حادث"},{"en":"They are needed to operate anti-lock brakes","es":"Son necesarios para operar los frenos antibloqueo","ru":"Они нужны для управления антиблокировочными тормозами","tr":"ABS frenleri çalıştırmak için gereklidirler","hi":"वे एंटी-लॉक ब्रेक चलाने के लिए आवश्यक हैं","ar":"ضرورية لتشغيل الفرامل المانعة للانغلاق"}],"e":{"en":"The Motorcycle Operator Manual states gloves allow a better grip and help protect your hands in a crash, and should be made of leather or similar durable material.","es":"El Manual del Operador de Motocicletas indica que los guantes permiten un mejor agarre y ayudan a proteger tus manos en un choque, y deben estar hechos de cuero o material duradero similar.","ru":"Руководство мотоциклиста утверждает, что перчатки обеспечивают лучший хват и помогают защитить руки при аварии, и должны быть из кожи или похожего прочного материала.","tr":"Motosiklet Kullanıcı Kılavuzu, eldivenlerin daha iyi kavrama sağladığını ve bir kazada ellerinizi korumaya yardımcı olduğunu, deri ya da benzeri dayanıklı malzemeden yapılmaları gerektiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि दस्ताने बेहतर पकड़ देते हैं और दुर्घटना में आपके हाथों की रक्षा में मदद करते हैं, और चमड़े या समान टिकाऊ सामग्री के बने होने चाहिए।","ar":"ينص دليل مشغّل الدراجة النارية على أن القفازات تتيح قبضة أفضل وتساعد في حماية يديك في حادث، ويجب أن تكون مصنوعة من الجلد أو مادة متينة مماثلة."}},{"cat":"gear","a":2,"q":{"en":"For riding in cold or wet weather, what does the Motorcycle Operator Manual emphasize about your clothing?","es":"Para conducir en clima frío o húmedo, ¿qué enfatiza el Manual del Operador de Motocicletas sobre tu ropa?","ru":"Для езды в холодную или сырую погоду что Руководство мотоциклиста подчёркивает насчёт вашей одежды?","tr":"Soğuk ya da yağışlı havalarda sürüş için, Motosiklet Kullanıcı Kılavuzu kıyafetinizle ilgili neyi vurgular?","hi":"ठंडे या गीले मौसम में राइडिंग के लिए, Motorcycle Operator Manual आपके कपड़ों के बारे में किस बात पर ज़ोर देता है?","ar":"للقيادة في الطقس البارد أو الممطر، ماذا يشدد عليه دليل مشغّل الدراجة النارية بشأن ملابسك؟"},"o":[{"en":"It only needs to protect against injury, not the cold","es":"Solo necesita proteger contra lesiones, no contra el frío","ru":"Она должна защищать только от травм, а не от холода","tr":"Yalnızca yaralanmaya karşı korumalı, soğuğa karşı değil","hi":"इसे केवल चोट से बचाने की ज़रूरत है, ठंड से नहीं","ar":"تحتاج فقط إلى الحماية من الإصابة، لا من البرد"},{"en":"It should be loose to allow cold air to keep you alert","es":"Debe quedar suelta para que el aire frío te mantenga alerta","ru":"Она должна быть свободной, чтобы холодный воздух поддерживал вашу бодрость","tr":"Soğuk havanın sizi uyanık tutması için bol olmalı","hi":"आपको सतर्क रखने के लिए ठंडी हवा आने देने हेतु यह ढीला होना चाहिए","ar":"يجب أن تكون فضفاضة للسماح للهواء البارد بإبقائك متيقظًا"},{"en":"It should keep you warm and dry, because you cannot control a motorcycle well if you are numb","es":"Debe mantenerte abrigado y seco, porque no puedes controlar bien una motocicleta si estás entumecido","ru":"Она должна сохранять вас в тепле и сухости, потому что вы не сможете хорошо управлять мотоциклом, если онемеете","tr":"Sizi sıcak ve kuru tutmalı, çünkü uyuşmuşken motosikleti iyi kontrol edemezsiniz","hi":"इसे आपको गर्म और सूखा रखना चाहिए, क्योंकि सुन्न होने पर आप मोटरसाइकिल को अच्छी तरह नियंत्रित नहीं कर सकते","ar":"يجب أن تبقيك دافئًا وجافًا، لأنك لا تستطيع التحكم جيدًا في الدراجة النارية إذا كنت مخدّرًا من البرد"},{"en":"A heavy raincoat that balloons in the wind is ideal","es":"Un impermeable pesado que se infle con el viento es ideal","ru":"Идеален тяжёлый дождевик, раздувающийся на ветру","tr":"Rüzgarda balonlaşan kalın bir yağmurluk idealdir","hi":"हवा में फूलने वाला एक भारी रेनकोट आदर्श है","ar":"المعطف الواقي الثقيل الذي ينتفخ في الرياح مثالي"}],"e":{"en":"The Motorcycle Operator Manual says in cold or wet weather your clothes should keep you warm and dry; you cannot control a motorcycle well if you are numb, and long cold rides cause severe chill and fatigue.","es":"El Manual del Operador de Motocicletas dice que en clima frío o húmedo tu ropa debe mantenerte abrigado y seco; no puedes controlar bien una motocicleta si estás entumecido, y los recorridos largos en frío causan escalofríos intensos y fatiga.","ru":"Руководство мотоциклиста говорит, что в холодную или сырую погоду одежда должна сохранять вас в тепле и сухости; вы не сможете хорошо управлять мотоциклом, если онемеете, а долгие холодные поездки вызывают сильное переохлаждение и усталость.","tr":"Motosiklet Kullanıcı Kılavuzu, soğuk ya da yağışlı havalarda kıyafetlerinizin sizi sıcak ve kuru tutması gerektiğini söyler; uyuşmuşken motosikleti iyi kontrol edemezsiniz ve uzun soğuk yolculuklar şiddetli üşüme ve yorgunluğa neden olur.","hi":"Motorcycle Operator Manual कहता है कि ठंडे या गीले मौसम में आपके कपड़े आपको गर्म और सूखा रखने चाहिए; सुन्न होने पर आप मोटरसाइकिल को अच्छी तरह नियंत्रित नहीं कर सकते, और लंबी ठंडी राइड गंभीर ठिठुरन और थकान का कारण बनती हैं।","ar":"يقول دليل مشغّل الدراجة النارية إنه في الطقس البارد أو الممطر يجب أن تبقيك ملابسك دافئًا وجافًا؛ فأنت لا تستطيع التحكم جيدًا في الدراجة النارية إذا كنت مخدّرًا من البرد، والرحلات الباردة الطويلة تسبب قشعريرة شديدة وإرهاقًا."}},{"cat":"braking","a":1,"q":{"en":"When slowing or stopping your motorcycle under normal conditions, which brakes should you use?","es":"Al reducir la velocidad o detener tu motocicleta en condiciones normales, ¿qué frenos debes usar?","ru":"При замедлении или остановке мотоцикла в обычных условиях какие тормоза следует использовать?","tr":"Normal koşullarda motosikletinizi yavaşlatırken ya da durdururken hangi frenleri kullanmalısınız?","hi":"सामान्य परिस्थितियों में अपनी मोटरसाइकिल को धीमा करते या रोकते समय, आपको कौन से ब्रेक का उपयोग करना चाहिए?","ar":"عند إبطاء أو إيقاف دراجتك النارية في الظروف العادية، أي فرامل يجب أن تستخدم؟"},"o":[{"en":"Only the rear brake to avoid flipping forward","es":"Solo el freno trasero para evitar volcar hacia adelante","ru":"Только задний тормоз, чтобы не перевернуться вперёд","tr":"Öne takla atmamak için yalnızca arka freni","hi":"आगे की ओर पलटने से बचने के लिए केवल रियर ब्रेक","ar":"الفرامل الخلفية فقط لتجنّب الانقلاب للأمام"},{"en":"Both the front and rear brakes together every time","es":"Ambos frenos, el delantero y el trasero, juntos cada vez","ru":"Оба тормоза, передний и задний, совместно каждый раз","tr":"Her seferinde hem ön hem arka freni birlikte","hi":"हर बार फ्रंट और रियर दोनों ब्रेक एक साथ","ar":"كلتا الفرامل الأمامية والخلفية معًا في كل مرة"},{"en":"Only the front brake because the rear is useless","es":"Solo el freno delantero porque el trasero es inútil","ru":"Только передний тормоз, потому что задний бесполезен","tr":"Arka işe yaramadığı için yalnızca ön freni","hi":"केवल फ्रंट ब्रेक क्योंकि रियर बेकार है","ar":"الفرامل الأمامية فقط لأن الخلفية عديمة الفائدة"},{"en":"Alternate between front and rear in quick pulses","es":"Alternar entre el delantero y el trasero en pulsaciones rápidas","ru":"Чередовать передний и задний короткими нажатиями","tr":"Hızlı darbelerle ön ve arka arasında dönüşümlü","hi":"फ्रंट और रियर के बीच तेज़ी से बारी-बारी से दबाव","ar":"التناوب بين الأمامية والخلفية بنبضات سريعة"}],"e":{"en":"The Motorcycle Operator Manual instructs riders to use both brakes every time they slow or stop, which provides the shortest, most controlled stop.","es":"El Manual del Operador de Motocicletas indica a los conductores usar ambos frenos cada vez que reduzcan la velocidad o se detengan, lo que proporciona la parada más corta y controlada.","ru":"Руководство мотоциклиста предписывает мотоциклистам использовать оба тормоза каждый раз при замедлении или остановке, что обеспечивает самую короткую и контролируемую остановку.","tr":"Motosiklet Kullanıcı Kılavuzu, sürücülere her yavaşladıklarında ya da durduklarında her iki freni de kullanmalarını söyler; bu, en kısa ve en kontrollü duruşu sağlar.","hi":"Motorcycle Operator Manual राइडर्स को हर बार धीमा होने या रुकने पर दोनों ब्रेक का उपयोग करने का निर्देश देता है, जो सबसे छोटा, सबसे नियंत्रित स्टॉप प्रदान करता है।","ar":"يوجّه دليل مشغّل الدراجة النارية السائقين إلى استخدام كلتا الفرملتين في كل مرة يبطئون أو يتوقفون فيها، مما يوفر أقصر توقف وأكثره تحكمًا."}},{"cat":"braking","a":1,"q":{"en":"Approximately how much of a motorcycle's total stopping power comes from the front brake?","es":"¿Aproximadamente cuánto de la capacidad total de frenado de una motocicleta proviene del freno delantero?","ru":"Примерно какую долю общей тормозной силы мотоцикла обеспечивает передний тормоз?","tr":"Bir motosikletin toplam durma gücünün yaklaşık ne kadarı ön frenden gelir?","hi":"मोटरसाइकिल की कुल रुकने की शक्ति का लगभग कितना हिस्सा फ्रंट ब्रेक से आता है?","ar":"تقريبًا، ما مقدار قدرة التوقف الكلية للدراجة النارية الذي يأتي من الفرامل الأمامية؟"},"o":[{"en":"About one quarter","es":"Cerca de un cuarto","ru":"Около одной четверти","tr":"Yaklaşık dörtte biri","hi":"लगभग एक चौथाई","ar":"نحو الربع"},{"en":"About three quarters (roughly 70 percent)","es":"Cerca de tres cuartos (aproximadamente el 70 por ciento)","ru":"Около трёх четвертей (примерно 70 процентов)","tr":"Yaklaşık dörtte üçü (kabaca yüzde 70)","hi":"लगभग तीन चौथाई (मोटे तौर पर 70 प्रतिशत)","ar":"نحو ثلاثة أرباع (حوالي 70 بالمئة)"},{"en":"About half","es":"Cerca de la mitad","ru":"Около половины","tr":"Yaklaşık yarısı","hi":"लगभग आधा","ar":"نحو النصف"},{"en":"Almost none, it is mostly cosmetic","es":"Casi nada, es mayormente estético","ru":"Почти никакую, он в основном декоративный","tr":"Neredeyse hiçbiri, çoğunlukla göstermeliktir","hi":"लगभग कुछ नहीं, यह ज़्यादातर दिखावटी है","ar":"تقريبًا لا شيء، فهي شكلية في الغالب"}],"e":{"en":"Per the Motorcycle Operator Manual, the front brake is the more powerful brake and can provide about three quarters (roughly 70 percent) of the total stopping power.","es":"Según el Manual del Operador de Motocicletas, el freno delantero es el freno más potente y puede proporcionar cerca de tres cuartos (aproximadamente el 70 por ciento) de la capacidad total de frenado.","ru":"Согласно Руководству мотоциклиста, передний тормоз — более мощный тормоз и может обеспечить около трёх четвертей (примерно 70 процентов) общей тормозной силы.","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, ön fren daha güçlü olan frendir ve toplam durma gücünün yaklaşık dörtte üçünü (kabaca yüzde 70) sağlayabilir.","hi":"Motorcycle Operator Manual के अनुसार, फ्रंट ब्रेक अधिक शक्तिशाली ब्रेक है और कुल रुकने की शक्ति का लगभग तीन चौथाई (मोटे तौर पर 70 प्रतिशत) प्रदान कर सकता है।","ar":"بحسب دليل مشغّل الدراجة النارية، الفرامل الأمامية هي الأقوى ويمكن أن توفر نحو ثلاثة أرباع (حوالي 70 بالمئة) من قدرة التوقف الكلية."}},{"cat":"braking","a":2,"q":{"en":"Why is the front brake able to provide most of a motorcycle's stopping power?","es":"¿Por qué el freno delantero puede proporcionar la mayor parte de la capacidad de frenado de una motocicleta?","ru":"Почему передний тормоз способен обеспечить большую часть тормозной силы мотоцикла?","tr":"Ön fren neden bir motosikletin durma gücünün çoğunu sağlayabilir?","hi":"फ्रंट ब्रेक मोटरसाइकिल की अधिकांश रुकने की शक्ति क्यों प्रदान कर पाता है?","ar":"لماذا تستطيع الفرامل الأمامية توفير معظم قدرة التوقف للدراجة النارية؟"},"o":[{"en":"It uses a larger reservoir of brake fluid than the rear","es":"Usa un depósito de líquido de frenos más grande que el trasero","ru":"Он использует больший запас тормозной жидкости, чем задний","tr":"Arkadan daha büyük bir fren hidroliği deposu kullanır","hi":"यह रियर की तुलना में ब्रेक फ्लुइड का बड़ा भंडार उपयोग करता है","ar":"لأنها تستخدم خزان سائل فرامل أكبر من الخلفي"},{"en":"The front tire is always wider than the rear tire","es":"La llanta delantera siempre es más ancha que la trasera","ru":"Переднее колесо всегда шире заднего","tr":"Ön lastik her zaman arka lastikten daha geniştir","hi":"फ्रंट टायर हमेशा रियर टायर से चौड़ा होता है","ar":"لأن الإطار الأمامي أعرض دائمًا من الإطار الخلفي"},{"en":"Weight shifts forward during braking, pressing the front tire harder into the pavement","es":"El peso se desplaza hacia adelante durante el frenado, presionando la llanta delantera con más fuerza contra el pavimento","ru":"Вес смещается вперёд при торможении, сильнее прижимая переднюю шину к дороге","tr":"Frenleme sırasında ağırlık öne kayarak ön lastiği yola daha sert bastırır","hi":"ब्रेकिंग के दौरान वज़न आगे की ओर शिफ्ट होता है, जिससे फ्रंट टायर सड़क पर ज़्यादा ज़ोर से दबता है","ar":"لأن الوزن ينتقل للأمام أثناء الفرملة، فيضغط الإطار الأمامي بقوة أكبر على الرصيف"},{"en":"The rear brake is intentionally built weaker by law","es":"El freno trasero está fabricado intencionalmente más débil por ley","ru":"Задний тормоз намеренно сделан слабее по закону","tr":"Arka fren yasa gereği bilerek daha zayıf yapılır","hi":"रियर ब्रेक को कानूनन जानबूझकर कमज़ोर बनाया जाता है","ar":"لأن الفرامل الخلفية مصنوعة عمدًا أضعف بموجب القانون"}],"e":{"en":"The Motorcycle Operator Manual explains that as you brake, weight transfers forward onto the front tire, pressing it harder into the road and making the front brake more effective.","es":"El Manual del Operador de Motocicletas explica que al frenar el peso se transfiere hacia adelante sobre la llanta delantera, presionándola con más fuerza contra la carretera y haciendo que el freno delantero sea más eficaz.","ru":"Руководство мотоциклиста поясняет, что при торможении вес переносится вперёд на переднюю шину, сильнее прижимая её к дороге и делая передний тормоз более эффективным.","tr":"Motosiklet Kullanıcı Kılavuzu, frenlerken ağırlığın öne, ön lastiğe doğru aktarıldığını, lastiği yola daha sert bastırarak ön freni daha etkili kıldığını açıklar.","hi":"Motorcycle Operator Manual समझाता है कि जैसे ही आप ब्रेक लगाते हैं, वज़न फ्रंट टायर पर आगे की ओर स्थानांतरित होता है, जिससे यह सड़क में ज़्यादा ज़ोर से दबता है और फ्रंट ब्रेक अधिक प्रभावी हो जाता है।","ar":"يوضح دليل مشغّل الدراجة النارية أنه أثناء الفرملة ينتقل الوزن للأمام إلى الإطار الأمامي، فيضغطه بقوة أكبر على الطريق ويجعل الفرامل الأمامية أكثر فعالية."}},{"cat":"braking","a":3,"q":{"en":"To make a quick stop on good pavement, how should you apply the front brake lever?","es":"Para hacer una parada rápida sobre buen pavimento, ¿cómo debes aplicar la palanca del freno delantero?","ru":"Чтобы быстро остановиться на хорошем покрытии, как следует нажимать рычаг переднего тормоза?","tr":"İyi zeminde hızlı bir duruş yapmak için ön fren kolunu nasıl uygulamalısınız?","hi":"अच्छी सड़क पर त्वरित स्टॉप करने के लिए, आपको फ्रंट ब्रेक लीवर को कैसे लगाना चाहिए?","ar":"لإجراء توقف سريع على رصيف جيد، كيف يجب أن تطبّق ذراع الفرامل الأمامية؟"},"o":[{"en":"Grab it as hard and fast as possible","es":"Agárrala lo más fuerte y rápido posible","ru":"Схватить его как можно сильнее и быстрее","tr":"Mümkün olduğunca sert ve hızlı kavrayın","hi":"इसे जितना कठोर और तेज़ी से संभव हो पकड़ें","ar":"أمسكها بأقصى قوة وأسرع ما يمكن"},{"en":"Tap it lightly several times only","es":"Tócala suavemente varias veces solamente","ru":"Лишь несколько раз слегка постучать по нему","tr":"Yalnızca birkaç kez hafifçe dokunun","hi":"केवल कई बार हल्के से थपथपाएं","ar":"انقرها بخفة عدة مرات فقط"},{"en":"Avoid it entirely and rely on the rear brake","es":"Evítala por completo y confía en el freno trasero","ru":"Полностью его избегать и полагаться на задний тормоз","tr":"Tamamen ondan kaçınıp arka frene güvenin","hi":"इसे पूरी तरह छोड़ दें और रियर ब्रेक पर निर्भर रहें","ar":"تجنّبها تمامًا واعتمد على الفرامل الخلفية"},{"en":"Squeeze it firmly and progressively, increasing pressure","es":"Apriétala con firmeza y de forma progresiva, aumentando la presión","ru":"Сжимать его уверенно и постепенно, увеличивая усилие","tr":"Sıkıca ve giderek artan şekilde, basıncı yükselterek sıkın","hi":"इसे मज़बूती और क्रमशः दबाएं, दबाव बढ़ाते हुए","ar":"اضغطها بثبات وتدرّج، زائدًا الضغط"}],"e":{"en":"The Motorcycle Operator Manual says to squeeze the front brake lever firmly and progressively rather than grabbing it, applying both brakes at the same time for a quick stop.","es":"El Manual del Operador de Motocicletas dice que aprietes la palanca del freno delantero con firmeza y de forma progresiva en lugar de agarrarla de golpe, aplicando ambos frenos al mismo tiempo para una parada rápida.","ru":"Руководство мотоциклиста говорит сжимать рычаг переднего тормоза уверенно и постепенно, а не хватать его, применяя оба тормоза одновременно для быстрой остановки.","tr":"Motosiklet Kullanıcı Kılavuzu, ön fren kolunu kavramak yerine sıkıca ve giderek artan şekilde sıkmayı, hızlı bir duruş için her iki freni aynı anda uygulamayı söyler.","hi":"Motorcycle Operator Manual कहता है कि फ्रंट ब्रेक लीवर को झपटकर पकड़ने के बजाय मज़बूती और क्रमशः दबाएं, और त्वरित स्टॉप के लिए दोनों ब्रेक एक ही समय में लगाएं।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب الضغط على ذراع الفرامل الأمامية بثبات وتدرّج بدلًا من الإمساك بها بقوة، مع تطبيق كلتا الفرملتين في الوقت نفسه لإجراء توقف سريع."}},{"cat":"braking","a":1,"q":{"en":"During a hard stop, your front wheel locks up. What is the correct response?","es":"Durante una parada brusca, tu rueda delantera se bloquea. ¿Cuál es la respuesta correcta?","ru":"Во время резкой остановки переднее колесо блокируется. Каков правильный ответ?","tr":"Sert bir duruş sırasında ön tekerleğiniz kilitlenir. Doğru tepki nedir?","hi":"कठोर स्टॉप के दौरान, आपका फ्रंट व्हील लॉक हो जाता है। सही प्रतिक्रिया क्या है?","ar":"أثناء توقف قوي، تنغلق عجلتك الأمامية. ما هي الاستجابة الصحيحة؟"},"o":[{"en":"Keep the front brake fully applied until you stop","es":"Mantén el freno delantero totalmente aplicado hasta detenerte","ru":"Держать передний тормоз полностью зажатым до остановки","tr":"Durana kadar ön freni tam basılı tutun","hi":"रुकने तक फ्रंट ब्रेक पूरी तरह लगाए रखें","ar":"أبقِ الفرامل الأمامية مطبّقة بالكامل حتى تتوقف"},{"en":"Release the front brake immediately, then reapply it firmly","es":"Suelta el freno delantero de inmediato y luego vuelve a aplicarlo con firmeza","ru":"Немедленно отпустить передний тормоз, затем снова уверенно его нажать","tr":"Ön freni hemen bırakın, sonra sıkıca yeniden uygulayın","hi":"फ्रंट ब्रेक तुरंत छोड़ें, फिर इसे मज़बूती से दोबारा लगाएं","ar":"حرّر الفرامل الأمامية فورًا، ثم أعد تطبيقها بثبات"},{"en":"Let go of the handlebars and coast","es":"Suelta el manillar y rueda libremente","ru":"Отпустить руль и катиться","tr":"Gidonu bırakıp rölantide gidin","hi":"हैंडलबार छोड़ दें और कोस्ट करें","ar":"اترك المقود وانزلق"},{"en":"Apply much more rear brake to compensate","es":"Aplica mucho más freno trasero para compensar","ru":"Применить намного больше заднего тормоза для компенсации","tr":"Telafi için çok daha fazla arka fren uygulayın","hi":"भरपाई के लिए बहुत अधिक रियर ब्रेक लगाएं","ar":"طبّق فرملة خلفية أكبر بكثير للتعويض"}],"e":{"en":"The Motorcycle Operator Manual states that if the front wheel locks, release the front brake immediately to let the tire roll again, then reapply it firmly.","es":"El Manual del Operador de Motocicletas indica que si la rueda delantera se bloquea, sueltes el freno delantero de inmediato para que la llanta vuelva a rodar y luego lo apliques de nuevo con firmeza.","ru":"Руководство мотоциклиста утверждает, что если переднее колесо блокируется, немедленно отпустите передний тормоз, чтобы шина снова покатилась, затем снова уверенно его нажмите.","tr":"Motosiklet Kullanıcı Kılavuzu, ön tekerlek kilitlenirse, lastiğin tekrar dönmesi için ön freni hemen bırakmanızı, sonra sıkıca yeniden uygulamanızı belirtir.","hi":"Motorcycle Operator Manual बताता है कि यदि फ्रंट व्हील लॉक हो जाए, तो फ्रंट ब्रेक तुरंत छोड़ें ताकि टायर फिर से घूमने लगे, फिर इसे मज़बूती से दोबारा लगाएं।","ar":"ينص دليل مشغّل الدراجة النارية على أنه إذا انغلقت العجلة الأمامية، فحرّر الفرامل الأمامية فورًا للسماح للإطار بالدوران مجددًا، ثم أعد تطبيقها بثبات."}},{"cat":"braking","a":0,"q":{"en":"If your rear wheel locks up while you are stopping upright and in a straight line on good traction, you should:","es":"Si tu rueda trasera se bloquea mientras te detienes en posición vertical y en línea recta sobre buena tracción, debes:","ru":"Если заднее колесо блокируется, когда вы останавливаетесь вертикально и по прямой на хорошем сцеплении, следует:","tr":"İyi tutuşlu zeminde dik ve düz bir çizgide dururken arka tekerleğiniz kilitlenirse şunu yapmalısınız:","hi":"यदि अच्छी ट्रैक्शन पर सीधी रेखा में और सीधे खड़े होकर रुकते समय आपका रियर व्हील लॉक हो जाए, तो आपको:","ar":"إذا انغلقت عجلتك الخلفية أثناء توقفك وأنت منتصب وفي خط مستقيم على التصاق جيد، فعليك أن:"},"o":[{"en":"Keep the rear wheel locked until you have come to a complete stop","es":"Mantener la rueda trasera bloqueada hasta que te hayas detenido por completo","ru":"Держать заднее колесо заблокированным, пока полностью не остановитесь","tr":"Tamamen durana kadar arka tekerleği kilitli tutun","hi":"पूरी तरह रुकने तक रियर व्हील को लॉक रखना चाहिए","ar":"تُبقي العجلة الخلفية منغلقة حتى تتوقف توقفًا تامًا"},{"en":"Release the rear brake immediately and stop using it","es":"Soltar el freno trasero de inmediato y dejar de usarlo","ru":"Немедленно отпустить задний тормоз и прекратить его использовать","tr":"Arka freni hemen bırakın ve kullanmayı bırakın","hi":"रियर ब्रेक तुरंत छोड़ देना चाहिए और इसका उपयोग बंद कर देना चाहिए","ar":"تحرّر الفرامل الخلفية فورًا وتتوقف عن استخدامها"},{"en":"Pump the rear brake rapidly to free the wheel","es":"Bombear el freno trasero rápidamente para liberar la rueda","ru":"Быстро прокачивать задний тормоз, чтобы освободить колесо","tr":"Tekerleği kurtarmak için arka frene hızlıca basıp bırakın","hi":"व्हील को मुक्त करने के लिए रियर ब्रेक को तेज़ी से पंप करना चाहिए","ar":"تضخّ الفرامل الخلفية بسرعة لتحرير العجلة"},{"en":"Quickly steer hard to one side","es":"Girar bruscamente hacia un lado de inmediato","ru":"Резко повернуть в одну сторону","tr":"Hızlıca sert şekilde bir tarafa direksiyon kırın","hi":"जल्दी से एक ओर ज़ोर से स्टीयर करना चाहिए","ar":"توجّه بقوة إلى أحد الجانبين بسرعة"}],"e":{"en":"The Motorcycle Operator Manual notes that with a locked rear wheel you can still control the motorcycle if it is upright and going straight, so keep it locked until you stop completely.","es":"El Manual del Operador de Motocicletas señala que con la rueda trasera bloqueada aún puedes controlar la motocicleta si está vertical y va en línea recta, así que mantenla bloqueada hasta detenerte por completo.","ru":"Руководство мотоциклиста отмечает, что с заблокированным задним колесом вы всё ещё можете управлять мотоциклом, если он вертикален и едет прямо, поэтому держите его заблокированным, пока полностью не остановитесь.","tr":"Motosiklet Kullanıcı Kılavuzu, arka tekerlek kilitliyken motosiklet dik ve düz gidiyorsa onu kontrol edebileceğinizi belirtir, bu yüzden tamamen durana kadar kilitli tutun.","hi":"Motorcycle Operator Manual नोट करता है कि लॉक हुए रियर व्हील के साथ आप अभी भी मोटरसाइकिल को नियंत्रित कर सकते हैं यदि यह सीधी खड़ी है और सीधे जा रही है, इसलिए पूरी तरह रुकने तक इसे लॉक रखें।","ar":"يشير دليل مشغّل الدراجة النارية إلى أنه مع عجلة خلفية منغلقة لا يزال بإمكانك التحكم في الدراجة النارية إذا كانت منتصبة وتسير مستقيمة، لذا أبقِها منغلقة حتى تتوقف توقفًا تامًا."}},{"cat":"braking","a":0,"q":{"en":"What is the main reason for treating a locked front wheel differently from a locked rear wheel?","es":"¿Cuál es la razón principal para tratar una rueda delantera bloqueada de manera diferente a una rueda trasera bloqueada?","ru":"Какова основная причина по-разному относиться к заблокированному переднему колесу и заблокированному заднему колесу?","tr":"Kilitlenmiş bir ön tekerleğin, kilitlenmiş bir arka tekerlekten farklı ele alınmasının temel nedeni nedir?","hi":"लॉक हुए फ्रंट व्हील को लॉक हुए रियर व्हील से अलग तरीके से संभालने का मुख्य कारण क्या है?","ar":"ما هو السبب الرئيسي للتعامل مع عجلة أمامية منغلقة بشكل مختلف عن عجلة خلفية منغلقة؟"},"o":[{"en":"A locked front wheel can cause loss of steering control and a fall","es":"Una rueda delantera bloqueada puede causar pérdida del control de dirección y una caída","ru":"Заблокированное переднее колесо может вызвать потерю управляемости рулём и падение","tr":"Kilitlenmiş bir ön tekerlek, direksiyon kontrolünün kaybına ve düşmeye yol açabilir","hi":"लॉक हुआ फ्रंट व्हील स्टीयरिंग नियंत्रण खोने और गिरने का कारण बन सकता है","ar":"العجلة الأمامية المنغلقة قد تسبب فقدان التحكم في التوجيه والسقوط"},{"en":"A locked front wheel makes no difference to control","es":"Una rueda delantera bloqueada no afecta el control","ru":"Заблокированное переднее колесо никак не влияет на управление","tr":"Kilitlenmiş bir ön tekerlek kontrol açısından fark yaratmaz","hi":"लॉक हुए फ्रंट व्हील से नियंत्रण पर कोई फर्क नहीं पड़ता","ar":"العجلة الأمامية المنغلقة لا تُحدث فرقًا في التحكم"},{"en":"A locked rear wheel always causes the engine to stall","es":"Una rueda trasera bloqueada siempre hace que el motor se apague","ru":"Заблокированное заднее колесо всегда вызывает остановку двигателя","tr":"Kilitlenmiş bir arka tekerlek her zaman motorun stop etmesine neden olur","hi":"लॉक हुआ रियर व्हील हमेशा इंजन को बंद कर देता है","ar":"العجلة الخلفية المنغلقة تسبب دائمًا توقف المحرك"},{"en":"The front brake cannot actually lock the front wheel","es":"El freno delantero en realidad no puede bloquear la rueda delantera","ru":"Передний тормоз на самом деле не может заблокировать переднее колесо","tr":"Ön fren aslında ön tekerleği kilitleyemez","hi":"फ्रंट ब्रेक वास्तव में फ्रंट व्हील को लॉक नहीं कर सकता","ar":"لا يمكن للفرامل الأمامية فعليًا أن تغلق العجلة الأمامية"}],"e":{"en":"The Motorcycle Operator Manual emphasizes that a locked front wheel quickly leads to loss of steering control, so it must be released and reapplied, while a locked rear wheel can be ridden out to a stop if upright and straight.","es":"El Manual del Operador de Motocicletas enfatiza que una rueda delantera bloqueada lleva rápidamente a la pérdida del control de dirección, por lo que debe soltarse y volver a aplicarse, mientras que con una rueda trasera bloqueada puedes seguir hasta detenerte si vas vertical y en línea recta.","ru":"Руководство мотоциклиста подчёркивает, что заблокированное переднее колесо быстро приводит к потере управляемости рулём, поэтому его нужно отпустить и снова нажать, тогда как с заблокированным задним колесом можно доехать до остановки, если мотоцикл вертикален и едет прямо.","tr":"Motosiklet Kullanıcı Kılavuzu, kilitlenmiş bir ön tekerleğin hızla direksiyon kontrolü kaybına yol açtığını, bu yüzden bırakılıp yeniden uygulanması gerektiğini, kilitlenmiş bir arka tekerleğin ise dik ve düz olduğunda durana kadar sürdürülebileceğini vurgular.","hi":"Motorcycle Operator Manual ज़ोर देता है कि लॉक हुआ फ्रंट व्हील जल्दी ही स्टीयरिंग नियंत्रण खोने की ओर ले जाता है, इसलिए इसे छोड़कर दोबारा लगाना चाहिए, जबकि लॉक हुए रियर व्हील को सीधी खड़ी और सीधी स्थिति में रुकने तक चलाया जा सकता है।","ar":"يؤكد دليل مشغّل الدراجة النارية أن العجلة الأمامية المنغلقة تؤدي بسرعة إلى فقدان التحكم في التوجيه، لذا يجب تحريرها وإعادة تطبيقها، بينما يمكن قيادة عجلة خلفية منغلقة حتى التوقف إذا كنت منتصبًا ومستقيمًا."}},{"cat":"braking","a":3,"q":{"en":"You need to stop quickly while leaned over in a curve. What is the best technique?","es":"Necesitas detenerte rápidamente mientras estás inclinado en una curva. ¿Cuál es la mejor técnica?","ru":"Вам нужно быстро остановиться в наклоне в повороте. Какова наилучшая техника?","tr":"Bir virajda yatmışken hızlıca durmanız gerekiyor. En iyi teknik nedir?","hi":"आपको एक मोड़ में झुके हुए जल्दी रुकने की ज़रूरत है। सबसे अच्छी तकनीक क्या है?","ar":"تحتاج إلى التوقف بسرعة وأنت مائل في منحنى. ما هي أفضل تقنية؟"},"o":[{"en":"Apply maximum brakes immediately while fully leaned","es":"Aplicar los frenos al máximo de inmediato mientras estás totalmente inclinado","ru":"Немедленно применить максимальное торможение в полном наклоне","tr":"Tamamen yatmış haldeyken hemen maksimum fren uygulayın","hi":"पूरी तरह झुके रहते हुए तुरंत अधिकतम ब्रेक लगाएं","ar":"طبّق أقصى فرملة فورًا وأنت مائل بالكامل"},{"en":"Use only the rear brake until the curve ends","es":"Usar solo el freno trasero hasta que termine la curva","ru":"Использовать только задний тормоз до конца поворота","tr":"Viraj bitene kadar yalnızca arka freni kullanın","hi":"मोड़ खत्म होने तक केवल रियर ब्रेक का उपयोग करें","ar":"استخدم الفرامل الخلفية فقط حتى ينتهي المنحنى"},{"en":"Lean even harder to tighten your line first","es":"Inclinarte aún más para cerrar tu trazada primero","ru":"Сначала наклониться ещё сильнее, чтобы сузить траекторию","tr":"Önce çizginizi sıkmak için daha da fazla yatın","hi":"पहले अपनी लाइन कसने के लिए और भी ज़्यादा झुकें","ar":"ميل أكثر لتضييق مسارك أولًا"},{"en":"Straighten the motorcycle upright as you brake, then apply firmer braking","es":"Enderezar la motocicleta a posición vertical mientras frenas, y luego aplicar un frenado más firme","ru":"Выпрямить мотоцикл вертикально по мере замедления, затем применить более сильное торможение","tr":"Frenlerken motosikleti dikleştirin, sonra daha sert frenleyin","hi":"ब्रेक लगाते हुए मोटरसाइकिल को सीधा खड़ा करें, फिर मज़बूत ब्रेकिंग लगाएं","ar":"عدّل الدراجة النارية لتصبح منتصبة أثناء الفرملة، ثم طبّق فرملة أقوى"}],"e":{"en":"The Motorcycle Operator Manual advises reducing your lean angle and bringing the bike upright as you slow, then applying more brake pressure, because a leaned tire has less traction available for braking.","es":"El Manual del Operador de Motocicletas aconseja reducir tu ángulo de inclinación y poner la moto vertical mientras reduces la velocidad, y luego aplicar más presión de frenado, porque una llanta inclinada tiene menos tracción disponible para frenar.","ru":"Руководство мотоциклиста советует уменьшать угол наклона и выпрямлять мотоцикл по мере замедления, затем увеличивать усилие на тормозах, потому что у наклонённой шины меньше доступного сцепления для торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, yavaşlarken yatma açınızı azaltıp motosikleti dikleştirmenizi, sonra daha fazla fren basıncı uygulamanızı tavsiye eder, çünkü yatmış bir lastiğin frenleme için daha az tutuşu vardır.","hi":"Motorcycle Operator Manual सलाह देता है कि धीमा होते हुए अपना झुकाव कोण कम करें और बाइक को सीधा खड़ा करें, फिर अधिक ब्रेक दबाव लगाएं, क्योंकि झुके हुए टायर के पास ब्रेकिंग के लिए कम ट्रैक्शन उपलब्ध होता है।","ar":"ينصح دليل مشغّل الدراجة النارية بتقليل زاوية ميلك وجعل الدراجة منتصبة أثناء الإبطاء، ثم تطبيق ضغط فرملة أكبر، لأن الإطار المائل لديه قدر أقل من الالتصاق المتاح للفرملة."}},{"cat":"braking","a":2,"q":{"en":"Why is it harder to brake hard in a curve than on a straight road?","es":"¿Por qué es más difícil frenar fuerte en una curva que en una carretera recta?","ru":"Почему сложнее сильно тормозить в повороте, чем на прямой дороге?","tr":"Bir virajda sert frenlemek neden düz yola göre daha zordur?","hi":"सीधी सड़क की तुलना में मोड़ में ज़ोर से ब्रेक लगाना कठिन क्यों होता है?","ar":"لماذا يصعب الفرملة بقوة في منحنى مقارنةً بطريق مستقيم؟"},"o":[{"en":"Brakes physically work less well when turning","es":"Los frenos físicamente funcionan peor al girar","ru":"Тормоза физически хуже работают при повороте","tr":"Frenler dönerken fiziksel olarak daha az çalışır","hi":"मुड़ते समय ब्रेक भौतिक रूप से कम अच्छी तरह काम करते हैं","ar":"لأن الفرامل تعمل بشكل أقل فعالية عند الانعطاف فيزيائيًا"},{"en":"The front brake disconnects automatically in a turn","es":"El freno delantero se desconecta automáticamente en una curva","ru":"Передний тормоз автоматически отключается в повороте","tr":"Ön fren dönüşte otomatik olarak devre dışı kalır","hi":"मोड़ में फ्रंट ब्रेक स्वतः डिस्कनेक्ट हो जाता है","ar":"لأن الفرامل الأمامية تنفصل تلقائيًا في الانعطاف"},{"en":"Some traction is already being used for cornering, leaving less for braking","es":"Parte de la tracción ya se está usando para tomar la curva, dejando menos para frenar","ru":"Часть сцепления уже используется для прохождения поворота, оставляя меньше для торможения","tr":"Tutuşun bir kısmı zaten viraj almak için kullanılır, frenlemeye daha azı kalır","hi":"कुछ ट्रैक्शन पहले से ही कॉर्नरिंग के लिए उपयोग हो रहा होता है, जिससे ब्रेकिंग के लिए कम बचता है","ar":"لأن جزءًا من الالتصاق يُستخدم بالفعل في المنعطف، مما يترك قدرًا أقل للفرملة"},{"en":"Tires grip better when leaned, so braking is unnecessary","es":"Las llantas agarran mejor cuando están inclinadas, así que frenar es innecesario","ru":"Шины лучше держат в наклоне, поэтому торможение не нужно","tr":"Lastikler yatınca daha iyi tutar, bu yüzden frenleme gereksizdir","hi":"झुकने पर टायर बेहतर पकड़ते हैं, इसलिए ब्रेकिंग अनावश्यक है","ar":"لأن الإطارات تلتصق أفضل عند الميل، فلا حاجة للفرملة"}],"e":{"en":"The Motorcycle Operator Manual explains that a tire has limited traction; in a curve some of it is used to corner, so less remains for braking until you straighten the bike.","es":"El Manual del Operador de Motocicletas explica que una llanta tiene tracción limitada; en una curva parte de ella se usa para tomar la curva, así que queda menos para frenar hasta que enderezas la moto.","ru":"Руководство мотоциклиста поясняет, что у шины ограниченное сцепление; в повороте часть его используется для прохождения поворота, поэтому меньше остаётся для торможения, пока вы не выпрямите мотоцикл.","tr":"Motosiklet Kullanıcı Kılavuzu, bir lastiğin sınırlı tutuşu olduğunu açıklar; virajda bunun bir kısmı viraj almak için kullanılır, bu yüzden motosikleti dikleştirene kadar frenlemeye daha azı kalır.","hi":"Motorcycle Operator Manual समझाता है कि टायर के पास सीमित ट्रैक्शन होता है; मोड़ में इसका कुछ हिस्सा कॉर्नरिंग के लिए उपयोग होता है, इसलिए जब तक आप बाइक सीधी नहीं करते, ब्रेकिंग के लिए कम बचता है।","ar":"يوضح دليل مشغّل الدراجة النارية أن الإطار لديه التصاق محدود؛ ففي المنحنى يُستخدم جزء منه للمنعطف، فيبقى قدر أقل للفرملة حتى تعدّل الدراجة لتصبح مستقيمة."}},{"cat":"braking","a":1,"q":{"en":"If you must brake in a curve before you can fully straighten the bike, you should:","es":"Si debes frenar en una curva antes de poder enderezar por completo la moto, debes:","ru":"Если вам нужно тормозить в повороте, прежде чем вы сможете полностью выпрямить мотоцикл, следует:","tr":"Motosikleti tamamen dikleştiremeden bir virajda frenlemek zorunda kalırsanız şunu yapmalısınız:","hi":"यदि आपको बाइक पूरी तरह सीधी करने से पहले मोड़ में ब्रेक लगाना ही पड़े, तो आपको:","ar":"إذا اضطررت إلى الفرملة في منحنى قبل أن تتمكن من جعل الدراجة مستقيمة تمامًا، فعليك أن:"},"o":[{"en":"Apply maximum front brake right away","es":"Aplicar el freno delantero al máximo de inmediato","ru":"Сразу применить максимальный передний тормоз","tr":"Hemen maksimum ön fren uygulayın","hi":"तुरंत अधिकतम फ्रंट ब्रेक लगाना चाहिए","ar":"تطبّق أقصى فرملة أمامية على الفور"},{"en":"Apply the brakes lightly at first and increase pressure as you reduce lean","es":"Aplicar los frenos suavemente al principio y aumentar la presión a medida que reduces la inclinación","ru":"Сначала применять тормоза слегка и увеличивать усилие по мере уменьшения наклона","tr":"Önce hafif fren basıncı uygulayın ve yatmayı azalttıkça basıncı artırın","hi":"पहले हल्के से ब्रेक लगाना चाहिए और झुकाव कम करते हुए दबाव बढ़ाना चाहिए","ar":"تطبّق الفرامل بخفة في البداية وتزيد الضغط مع تقليل الميل"},{"en":"Use the front brake only and ignore the rear","es":"Usar solo el freno delantero e ignorar el trasero","ru":"Использовать только передний тормоз и не использовать задний","tr":"Yalnızca ön freni kullanın, arkayı yok sayın","hi":"केवल फ्रंट ब्रेक का उपयोग करना चाहिए और रियर को नज़रअंदाज़ करना चाहिए","ar":"تستخدم الفرامل الأمامية فقط وتتجاهل الخلفية"},{"en":"Brake hard with the rear only and never the front","es":"Frenar fuerte solo con el trasero y nunca con el delantero","ru":"Сильно тормозить только задним и никогда передним","tr":"Yalnızca arka frenle sert frenleyin ve asla ön freni kullanmayın","hi":"केवल रियर से ज़ोर से ब्रेक लगाना चाहिए और कभी फ्रंट से नहीं","ar":"تفرمل بقوة بالخلفية فقط ولا تستخدم الأمامية أبدًا"}],"e":{"en":"The Motorcycle Operator Manual says to apply light brake pressure while leaned, then add pressure as you straighten the motorcycle and more traction becomes available for braking.","es":"El Manual del Operador de Motocicletas dice que apliques presión de frenado suave mientras estás inclinado, y luego añadas presión a medida que enderezas la motocicleta y hay más tracción disponible para frenar.","ru":"Руководство мотоциклиста говорит применять лёгкое усилие на тормозах в наклоне, затем добавлять усилие по мере выпрямления мотоцикла, когда становится доступно больше сцепления для торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, yatmışken hafif fren basıncı uygulamayı, sonra motosikleti dikleştirip frenleme için daha fazla tutuş kullanılabilir hale geldikçe basınç eklemeyi söyler.","hi":"Motorcycle Operator Manual कहता है कि झुके हुए हल्के ब्रेक दबाव लगाएं, फिर जैसे-जैसे आप मोटरसाइकिल सीधी करते हैं और ब्रेकिंग के लिए अधिक ट्रैक्शन उपलब्ध होता है, दबाव बढ़ाएं।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب تطبيق ضغط فرملة خفيف وأنت مائل، ثم زيادة الضغط مع جعل الدراجة النارية مستقيمة وتوفر المزيد من الالتصاق للفرملة."}},{"cat":"braking","a":2,"q":{"en":"Which combination of maneuvers should you NEVER perform at the same time?","es":"¿Cuál combinación de maniobras NUNCA debes realizar al mismo tiempo?","ru":"Какое сочетание манёвров НИКОГДА не следует выполнять одновременно?","tr":"Hangi manevra kombinasyonunu ASLA aynı anda yapmamalısınız?","hi":"कौन से युद्धाभ्यासों का संयोजन आपको कभी भी एक साथ नहीं करना चाहिए?","ar":"أي مجموعة من المناورات يجب ألا تؤديها أبدًا في الوقت نفسه؟"},"o":[{"en":"Rolling off the throttle and downshifting","es":"Soltar el acelerador y bajar de velocidad","ru":"Сброс газа и понижение передачи","tr":"Gazı kapatmak ve vites düşürmek","hi":"थ्रॉटल रोल ऑफ करना और डाउनशिफ्ट करना","ar":"إرخاء الخانق وخفض السرعة"},{"en":"Using the front brake and the rear brake","es":"Usar el freno delantero y el freno trasero","ru":"Использование переднего и заднего тормоза","tr":"Ön freni ve arka freni kullanmak","hi":"फ्रंट ब्रेक और रियर ब्रेक का उपयोग करना","ar":"استخدام الفرامل الأمامية والفرامل الخلفية"},{"en":"Braking and swerving","es":"Frenar y esquivar","ru":"Торможение и объезд","tr":"Frenlemek ve manevra yapmak (yalpalamak)","hi":"ब्रेकिंग और स्वर्विंग","ar":"الفرملة والانحراف المفاجئ"},{"en":"Checking mirrors and signaling","es":"Revisar los espejos y señalizar","ru":"Проверка зеркал и подача сигнала","tr":"Aynaları kontrol etmek ve sinyal vermek","hi":"मिरर जाँचना और सिग्नल देना","ar":"فحص المرايا والإشارة"}],"e":{"en":"The Motorcycle Operator Manual warns to never brake while swerving, because braking reduces the traction needed to change direction. Brake before or after, but not during, a swerve.","es":"El Manual del Operador de Motocicletas advierte que nunca frenes mientras esquivas, porque frenar reduce la tracción necesaria para cambiar de dirección. Frena antes o después, pero no durante, una maniobra de esquive.","ru":"Руководство мотоциклиста предупреждает: никогда не тормозите во время объезда, потому что торможение уменьшает сцепление, необходимое для смены направления. Тормозите до или после объезда, но не во время.","tr":"Motosiklet Kullanıcı Kılavuzu, manevra yaparken (yalpalarken) asla frenlememeniz konusunda uyarır, çünkü frenleme yön değiştirmek için gereken tutuşu azaltır. Manevradan önce ya da sonra frenleyin, sırasında değil.","hi":"Motorcycle Operator Manual चेतावनी देता है कि स्वर्विंग करते समय कभी ब्रेक न लगाएं, क्योंकि ब्रेकिंग दिशा बदलने के लिए आवश्यक ट्रैक्शन को कम कर देती है। स्वर्व से पहले या बाद में ब्रेक लगाएं, पर उसके दौरान नहीं।","ar":"يحذّر دليل مشغّل الدراجة النارية من الفرملة أثناء الانحراف المفاجئ أبدًا، لأن الفرملة تقلل الالتصاق اللازم لتغيير الاتجاه. افرمل قبل أو بعد، لكن ليس أثناء الانحراف."}},{"cat":"braking","a":2,"q":{"en":"An obstacle suddenly appears and you have room to go around it but not stop in time. You should:","es":"Un obstáculo aparece de repente y tienes espacio para rodearlo pero no para detenerte a tiempo. Debes:","ru":"Внезапно появляется препятствие, и у вас есть место, чтобы объехать его, но не остановиться вовремя. Следует:","tr":"Aniden bir engel çıkıyor ve etrafından geçecek yeriniz var ama zamanında duramazsınız. Şunu yapmalısınız:","hi":"अचानक एक बाधा सामने आती है और आपके पास उसके चारों ओर जाने की जगह है पर समय पर रुकने की नहीं। आपको:","ar":"تظهر عقبة فجأة ولديك مساحة لتفاديها لكن لا يمكنك التوقف في الوقت المناسب. عليك أن:"},"o":[{"en":"Brake as hard as possible and hope to slow enough","es":"Frenar lo más fuerte posible y esperar reducir lo suficiente","ru":"Тормозить как можно сильнее и надеяться замедлиться достаточно","tr":"Mümkün olduğunca sert frenleyip yeterince yavaşlamayı umun","hi":"जितना ज़ोर से संभव हो ब्रेक लगाना चाहिए और पर्याप्त धीमे होने की उम्मीद करनी चाहिए","ar":"تفرمل بأقصى قوة وتأمل أن تبطئ بما يكفي"},{"en":"Brake and swerve at the same time for maximum effect","es":"Frenar y esquivar al mismo tiempo para máximo efecto","ru":"Тормозить и объезжать одновременно для максимального эффекта","tr":"Maksimum etki için aynı anda frenleyip manevra yapın","hi":"अधिकतम प्रभाव के लिए एक साथ ब्रेक और स्वर्व करना चाहिए","ar":"تفرمل وتنحرف في الوقت نفسه لأقصى تأثير"},{"en":"Swerve around it, separating any braking from the swerve","es":"Esquivarlo, separando cualquier frenado de la maniobra de esquive","ru":"Объехать его, отделив любое торможение от объезда","tr":"Etrafından manevrayla geçin, frenlemeyi manevradan ayrı tutarak","hi":"किसी भी ब्रेकिंग को स्वर्व से अलग रखते हुए, इसके चारों ओर स्वर्व करना चाहिए","ar":"تنحرف حولها، فاصلًا أي فرملة عن الانحراف"},{"en":"Close your eyes and hold a straight line","es":"Cerrar los ojos y mantener una línea recta","ru":"Закрыть глаза и держать прямую траекторию","tr":"Gözlerinizi kapatıp düz bir çizgide kalın","hi":"आँखें बंद करके एक सीधी लाइन पर बने रहना चाहिए","ar":"تغلق عينيك وتحافظ على خط مستقيم"}],"e":{"en":"The Motorcycle Operator Manual recommends swerving to avoid an obstacle when you cannot stop in time, and keeping braking separate from the swerve to preserve traction.","es":"El Manual del Operador de Motocicletas recomienda esquivar para evitar un obstáculo cuando no puedes detenerte a tiempo, y mantener el frenado separado de la maniobra de esquive para conservar la tracción.","ru":"Руководство мотоциклиста рекомендует объезжать препятствие, когда вы не можете остановиться вовремя, и держать торможение отдельно от объезда, чтобы сохранить сцепление.","tr":"Motosiklet Kullanıcı Kılavuzu, zamanında duramadığınızda bir engelden kaçınmak için manevra yapmanızı ve tutuşu korumak için frenlemeyi manevradan ayrı tutmanızı önerir.","hi":"Motorcycle Operator Manual सलाह देता है कि जब आप समय पर न रुक सकें तो बाधा से बचने के लिए स्वर्व करें, और ट्रैक्शन बनाए रखने के लिए ब्रेकिंग को स्वर्व से अलग रखें।","ar":"يوصي دليل مشغّل الدراجة النارية بالانحراف لتفادي عقبة عندما لا تستطيع التوقف في الوقت المناسب، وإبقاء الفرملة منفصلة عن الانحراف للحفاظ على الالتصاق."}},{"cat":"braking","a":2,"q":{"en":"If you decide to both slow down and swerve to avoid a hazard, the correct sequence is:","es":"Si decides tanto reducir la velocidad como esquivar para evitar un peligro, la secuencia correcta es:","ru":"Если вы решаете и замедлиться, и объехать, чтобы избежать опасности, правильная последовательность такова:","tr":"Bir tehlikeden kaçınmak için hem yavaşlamaya hem de manevra yapmaya karar verirseniz, doğru sıra şudur:","hi":"यदि आप एक खतरे से बचने के लिए धीमा होने और स्वर्व करने दोनों का निर्णय लेते हैं, तो सही क्रम है:","ar":"إذا قررت أن تبطئ وتنحرف معًا لتفادي خطر، فإن التسلسل الصحيح هو:"},"o":[{"en":"Brake and swerve simultaneously","es":"Frenar y esquivar simultáneamente","ru":"Тормозить и объезжать одновременно","tr":"Aynı anda frenleyip manevra yapın","hi":"एक साथ ब्रेक और स्वर्व करें","ar":"الفرملة والانحراف في وقت واحد"},{"en":"Always swerve first and never use the brakes","es":"Esquivar siempre primero y nunca usar los frenos","ru":"Всегда сначала объезжать и никогда не использовать тормоза","tr":"Her zaman önce manevra yapın ve asla fren kullanmayın","hi":"हमेशा पहले स्वर्व करें और कभी ब्रेक का उपयोग न करें","ar":"الانحراف أولًا دائمًا وعدم استخدام الفرامل أبدًا"},{"en":"Brake then swerve, or swerve then brake, but never both together","es":"Frenar y luego esquivar, o esquivar y luego frenar, pero nunca ambos a la vez","ru":"Сначала тормозить, потом объезжать, или сначала объезжать, потом тормозить, но никогда не вместе","tr":"Önce frenleyip sonra manevra yapın ya da önce manevra yapıp sonra frenleyin, ama asla ikisini birden yapmayın","hi":"ब्रेक फिर स्वर्व, या स्वर्व फिर ब्रेक, पर कभी दोनों एक साथ नहीं","ar":"الفرملة ثم الانحراف، أو الانحراف ثم الفرملة، لكن ليس معًا أبدًا"},{"en":"Always brake first and never swerve","es":"Frenar siempre primero y nunca esquivar","ru":"Всегда сначала тормозить и никогда не объезжать","tr":"Her zaman önce frenleyin ve asla manevra yapmayın","hi":"हमेशा पहले ब्रेक लगाएं और कभी स्वर्व न करें","ar":"الفرملة أولًا دائمًا وعدم الانحراف أبدًا"}],"e":{"en":"The Motorcycle Operator Manual states that braking and swerving must be done separately: brake then swerve, or swerve then brake, because doing both at once can cause a loss of traction.","es":"El Manual del Operador de Motocicletas indica que frenar y esquivar deben hacerse por separado: frena y luego esquiva, o esquiva y luego frena, porque hacer ambos a la vez puede causar una pérdida de tracción.","ru":"Руководство мотоциклиста утверждает, что торможение и объезд нужно выполнять раздельно: сначала тормозить, потом объезжать, или сначала объезжать, потом тормозить, потому что выполнение обоих одновременно может вызвать потерю сцепления.","tr":"Motosiklet Kullanıcı Kılavuzu, frenleme ve manevranın ayrı ayrı yapılması gerektiğini belirtir: önce frenle sonra manevra ya da önce manevra sonra frenle, çünkü ikisini aynı anda yapmak tutuş kaybına neden olabilir.","hi":"Motorcycle Operator Manual बताता है कि ब्रेकिंग और स्वर्विंग अलग-अलग की जानी चाहिए: ब्रेक फिर स्वर्व, या स्वर्व फिर ब्रेक, क्योंकि दोनों एक साथ करने से ट्रैक्शन खो सकता है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الفرملة والانحراف يجب أن يتما بشكل منفصل: افرمل ثم انحرف، أو انحرف ثم افرمل، لأن القيام بكليهما في آن واحد قد يسبب فقدان الالتصاق."}},{"cat":"braking","a":1,"q":{"en":"A swerve to avoid an obstacle is best described as:","es":"Una maniobra de esquive para evitar un obstáculo se describe mejor como:","ru":"Объезд для избежания препятствия лучше всего описать как:","tr":"Bir engelden kaçınmak için yapılan manevra (yalpalama) en iyi nasıl tanımlanır?","hi":"किसी बाधा से बचने के लिए एक स्वर्व को सबसे अच्छी तरह कैसे वर्णित किया जाता है?","ar":"يُوصف الانحراف لتفادي عقبة على أفضل وجه بأنه:"},"o":[{"en":"A slow, gradual lane change over several seconds","es":"Un cambio de carril lento y gradual durante varios segundos","ru":"Медленную, плавную смену полосы за несколько секунд","tr":"Birkaç saniye süren yavaş, kademeli bir şerit değiştirme","hi":"कई सेकंड में एक धीमा, क्रमिक लेन परिवर्तन","ar":"تغيير حارة بطيء وتدريجي على مدى عدة ثوانٍ"},{"en":"Two quick, consecutive press-steers to change path and recover","es":"Dos giros de presión rápidos y consecutivos para cambiar la trayectoria y recuperarse","ru":"Два быстрых последовательных контрруления для смены траектории и возврата","tr":"Yolu değiştirip toparlamak için iki hızlı, art arda bastır-yönlendir hareketi","hi":"पथ बदलने और रिकवर करने के लिए दो त्वरित, लगातार प्रेस-स्टीयर","ar":"ضغطتا توجيه سريعتان متتاليتان لتغيير المسار والتعافي"},{"en":"Locking the brakes and sliding around the object","es":"Bloquear los frenos y deslizarse alrededor del objeto","ru":"Блокировку тормозов и скольжение вокруг объекта","tr":"Frenleri kilitleyip nesnenin etrafında kaymak","hi":"ब्रेक लॉक करना और वस्तु के चारों ओर फिसलना","ar":"إغلاق الفرامل والانزلاق حول الجسم"},{"en":"Standing on the pegs and leaning your whole body","es":"Pararse sobre los estribos e inclinar todo el cuerpo","ru":"Вставание на подножки и наклон всем телом","tr":"Basamakların üzerinde durup tüm vücudunuzu yatırmak","hi":"पेग पर खड़े होकर अपने पूरे शरीर को झुकाना","ar":"الوقوف على المساند وإمالة كامل جسمك"}],"e":{"en":"The Motorcycle Operator Manual describes a swerve as a quick maneuver: press the handgrip in the direction you want to go, then press the other way to recover, all without braking.","es":"El Manual del Operador de Motocicletas describe una maniobra de esquive como un movimiento rápido: presiona la manija en la dirección hacia la que quieres ir, y luego presiona hacia el otro lado para recuperarte, todo sin frenar.","ru":"Руководство мотоциклиста описывает объезд как быстрый манёвр: нажмите на рукоятку руля в направлении, куда хотите ехать, затем нажмите в обратную сторону для возврата, всё без торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, bir manevrayı hızlı bir hareket olarak tanımlar: gitmek istediğiniz yöndeki gidon kabzasına bastırın, sonra toparlamak için diğer yöne bastırın, hepsi frenlemeden.","hi":"Motorcycle Operator Manual एक स्वर्व को एक त्वरित युद्धाभ्यास के रूप में वर्णित करता है: जिस दिशा में जाना है उस ओर हैंडग्रिप दबाएं, फिर रिकवर करने के लिए दूसरी ओर दबाएं, यह सब बिना ब्रेक लगाए।","ar":"يصف دليل مشغّل الدراجة النارية الانحراف بأنه مناورة سريعة: اضغط المقبض في الاتجاه الذي تريد الذهاب إليه، ثم اضغط في الاتجاه الآخر للتعافي، كل ذلك دون فرملة."}},{"cat":"braking","a":3,"q":{"en":"Under normal conditions, what is the minimum following distance the Motorcycle Operator Manual recommends behind the vehicle ahead?","es":"En condiciones normales, ¿cuál es la distancia mínima de seguimiento que recomienda el Manual del Operador de Motocicletas detrás del vehículo de adelante?","ru":"В обычных условиях какую минимальную дистанцию следования за впереди идущим транспортом рекомендует Руководство мотоциклиста?","tr":"Normal koşullarda, Motosiklet Kullanıcı Kılavuzu önünüzdeki araçtan ne kadar takip mesafesi bırakmanızı önerir?","hi":"सामान्य परिस्थितियों में, Motorcycle Operator Manual आगे वाले वाहन के पीछे न्यूनतम कितनी फॉलोइंग दूरी की सिफारिश करता है?","ar":"في الظروف العادية، ما هي مسافة الاتباع الدنيا التي يوصي بها دليل مشغّل الدراجة النارية خلف المركبة الأمامية؟"},"o":[{"en":"Half a second","es":"Medio segundo","ru":"Полсекунды","tr":"Yarım saniye","hi":"आधा सेकंड","ar":"نصف ثانية"},{"en":"One second","es":"Un segundo","ru":"Одну секунду","tr":"Bir saniye","hi":"1 सेकंड","ar":"ثانية واحدة"},{"en":"Five seconds","es":"Cinco segundos","ru":"Пять секунд","tr":"Beş saniye","hi":"5 सेकंड","ar":"خمس ثوانٍ"},{"en":"Two seconds","es":"Dos segundos","ru":"Две секунды","tr":"İki saniye","hi":"2 सेकंड","ar":"ثانيتان"}],"e":{"en":"The Motorcycle Operator Manual recommends a minimum following distance of two seconds behind the vehicle ahead under normal conditions.","es":"El Manual del Operador de Motocicletas recomienda una distancia mínima de seguimiento de dos segundos detrás del vehículo de adelante en condiciones normales.","ru":"Руководство мотоциклиста рекомендует минимальную дистанцию следования в две секунды за впереди идущим транспортом в обычных условиях.","tr":"Motosiklet Kullanıcı Kılavuzu, normal koşullarda önünüzdeki araçtan en az iki saniye takip mesafesi bırakmanızı önerir.","hi":"Motorcycle Operator Manual सामान्य परिस्थितियों में आगे वाले वाहन के पीछे न्यूनतम 2 सेकंड की फॉलोइंग दूरी की सिफारिश करता है।","ar":"يوصي دليل مشغّل الدراجة النارية بمسافة اتباع دنيا قدرها ثانيتان خلف المركبة الأمامية في الظروف العادية."}},{"cat":"braking","a":0,"q":{"en":"How do you measure a two-second following distance?","es":"¿Cómo se mide una distancia de seguimiento de dos segundos?","ru":"Как измерить дистанцию следования в две секунды?","tr":"İki saniyelik takip mesafesini nasıl ölçersiniz?","hi":"आप 2 सेकंड की फॉलोइंग दूरी कैसे मापते हैं?","ar":"كيف تقيس مسافة اتباع قدرها ثانيتان؟"},"o":[{"en":"When the vehicle ahead passes a fixed point, count the seconds until you reach the same point","es":"Cuando el vehículo de adelante pasa un punto fijo, cuenta los segundos hasta que llegues al mismo punto","ru":"Когда впереди идущий транспорт проезжает неподвижную точку, считайте секунды, пока вы не достигнете той же точки","tr":"Önünüzdeki araç sabit bir noktayı geçtiğinde, aynı noktaya gelene kadar saniyeleri sayın","hi":"जब आगे वाला वाहन एक निश्चित बिंदु पार करे, तो उसी बिंदु तक पहुँचने तक सेकंड गिनें","ar":"عندما تمر المركبة الأمامية بنقطة ثابتة، عُدّ الثواني حتى تصل إلى النقطة نفسها"},{"en":"Estimate the gap in motorcycle lengths and divide by two","es":"Estima la distancia en longitudes de motocicleta y divídela entre dos","ru":"Оцените промежуток в длинах мотоцикла и разделите на два","tr":"Aradaki boşluğu motosiklet boyu olarak tahmin edip ikiye bölün","hi":"अंतर का अनुमान मोटरसाइकिल की लंबाई में लगाएं और दो से भाग दें","ar":"قدّر الفجوة بأطوال الدراجات النارية واقسمها على اثنين"},{"en":"Watch your speedometer and subtract 2 from your speed","es":"Observa tu velocímetro y resta 2 a tu velocidad","ru":"Следите за спидометром и вычтите 2 из своей скорости","tr":"Hız göstergenizi izleyip hızınızdan 2 çıkarın","hi":"अपना स्पीडोमीटर देखें और अपनी गति से 2 घटाएं","ar":"راقب عداد سرعتك واطرح 2 من سرعتك"},{"en":"Count the lane markings between you and the car ahead","es":"Cuenta las marcas del carril entre tú y el auto de adelante","ru":"Считайте разметку полосы между вами и машиной впереди","tr":"Sizinle önünüzdeki araç arasındaki şerit çizgilerini sayın","hi":"आपके और आगे वाली कार के बीच की लेन मार्किंग गिनें","ar":"عُدّ علامات الحارة بينك وبين السيارة الأمامية"}],"e":{"en":"The Motorcycle Operator Manual says to pick a fixed point the vehicle ahead passes, then count the seconds until you reach that same point; two seconds or more is the goal.","es":"El Manual del Operador de Motocicletas dice que elijas un punto fijo que pase el vehículo de adelante y luego cuentes los segundos hasta que llegues a ese mismo punto; dos segundos o más es la meta.","ru":"Руководство мотоциклиста говорит выбрать неподвижную точку, которую проезжает впереди идущий транспорт, затем считать секунды, пока вы не достигнете той же точки; цель — две секунды или больше.","tr":"Motosiklet Kullanıcı Kılavuzu, önünüzdeki aracın geçtiği sabit bir nokta seçmenizi, sonra aynı noktaya gelene kadar saniyeleri saymanızı söyler; iki saniye ya da daha fazlası hedeftir.","hi":"Motorcycle Operator Manual कहता है कि एक निश्चित बिंदु चुनें जिसे आगे वाला वाहन पार करता है, फिर उसी बिंदु तक पहुँचने तक सेकंड गिनें; 2 सेकंड या अधिक लक्ष्य है।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب اختيار نقطة ثابتة تمر بها المركبة الأمامية، ثم عدّ الثواني حتى تصل إلى تلك النقطة نفسها؛ والهدف هو ثانيتان أو أكثر."}},{"cat":"braking","a":1,"q":{"en":"In which situation should you increase your following distance beyond two seconds?","es":"¿En cuál situación debes aumentar tu distancia de seguimiento más allá de dos segundos?","ru":"В какой ситуации следует увеличить дистанцию следования сверх двух секунд?","tr":"Hangi durumda takip mesafenizi iki saniyenin üzerine çıkarmalısınız?","hi":"किस स्थिति में आपको अपनी फॉलोइंग दूरी 2 सेकंड से अधिक बढ़ानी चाहिए?","ar":"في أي موقف يجب أن تزيد مسافة اتباعك عن ثانيتين؟"},"o":[{"en":"On a dry, clear day with light traffic","es":"En un día seco y despejado con poco tráfico","ru":"В сухой ясный день при лёгком трафике","tr":"Hafif trafiğin olduğu kuru, açık bir günde","hi":"हल्के ट्रैफ़िक वाले सूखे, साफ़ दिन में","ar":"في يوم جاف وصافٍ مع حركة مرور خفيفة"},{"en":"When the road is wet or slippery, visibility is poor, or traffic is heavy","es":"Cuando la carretera está mojada o resbaladiza, la visibilidad es mala o el tráfico es intenso","ru":"Когда дорога мокрая или скользкая, видимость плохая или трафик плотный","tr":"Yol ıslak ya da kayganken, görüş kötüyken ya da trafik yoğunken","hi":"जब सड़क गीली या फिसलन भरी हो, दृश्यता खराब हो, या ट्रैफ़िक भारी हो","ar":"عندما يكون الطريق مبللًا أو زلقًا، أو الرؤية ضعيفة، أو حركة المرور كثيفة"},{"en":"Only when riding below 25 mph","es":"Solo al conducir por debajo de 25 mph","ru":"Только при езде ниже 25 миль/ч","tr":"Yalnızca 25 mil/sa altında sürerken","hi":"केवल जब 25 mph से कम पर राइड कर रहे हों","ar":"فقط عند القيادة بأقل من 25 ميلاً في الساعة"},{"en":"Never; two seconds is always enough","es":"Nunca; dos segundos siempre es suficiente","ru":"Никогда; двух секунд всегда достаточно","tr":"Asla; iki saniye her zaman yeterlidir","hi":"कभी नहीं; 2 सेकंड हमेशा पर्याप्त है","ar":"أبدًا؛ فثانيتان كافيتان دائمًا"}],"e":{"en":"The Motorcycle Operator Manual advises opening up to three seconds or more when conditions are poor, such as wet roads, limited visibility, heavy traffic, or when being followed closely.","es":"El Manual del Operador de Motocicletas aconseja ampliar a tres segundos o más cuando las condiciones son malas, como carreteras mojadas, visibilidad limitada, tráfico intenso o cuando alguien te sigue de cerca.","ru":"Руководство мотоциклиста советует увеличивать до трёх секунд или больше, когда условия плохие, например на мокрых дорогах, при ограниченной видимости, плотном трафике или когда за вами едут вплотную.","tr":"Motosiklet Kullanıcı Kılavuzu, ıslak yollar, kısıtlı görüş, yoğun trafik ya da yakından takip edildiğinizde gibi koşullar kötüyken takip mesafesini üç saniye ya da daha fazlasına çıkarmayı tavsiye eder.","hi":"Motorcycle Operator Manual सलाह देता है कि जब परिस्थितियाँ खराब हों, जैसे गीली सड़कें, सीमित दृश्यता, भारी ट्रैफ़िक, या जब कोई आपके करीब-करीब पीछे चल रहा हो, तो 3 सेकंड या अधिक तक खोलें।","ar":"ينصح دليل مشغّل الدراجة النارية بالتوسّع إلى ثلاث ثوانٍ أو أكثر عندما تكون الظروف سيئة، مثل الطرق المبللة، أو الرؤية المحدودة، أو حركة المرور الكثيفة، أو عندما تتبعك مركبة عن قرب."}},{"cat":"braking","a":3,"q":{"en":"Why should motorcyclists keep a larger cushion of space ahead than many drivers expect?","es":"¿Por qué los motociclistas deben mantener un colchón de espacio mayor por delante de lo que muchos conductores esperan?","ru":"Почему мотоциклистам следует держать больший запас пространства впереди, чем ожидают многие водители?","tr":"Motosikletçiler neden birçok sürücünün beklediğinden daha büyük bir ön mesafe boşluğu bırakmalıdır?","hi":"मोटरसाइकिल चालकों को कई ड्राइवरों की अपेक्षा से अधिक आगे की जगह का कुशन क्यों रखना चाहिए?","ar":"لماذا يجب على راكبي الدراجات النارية الحفاظ على هامش مساحة أمامي أكبر مما يتوقعه كثير من السائقين؟"},"o":[{"en":"Motorcycles legally must travel slower than cars","es":"Las motocicletas legalmente deben circular más despacio que los autos","ru":"Мотоциклы по закону должны двигаться медленнее машин","tr":"Motosikletler yasal olarak otomobillerden yavaş gitmek zorundadır","hi":"मोटरसाइकिलों को कानूनन कारों से धीमी चलना चाहिए","ar":"لأن الدراجات النارية يجب قانونيًا أن تسير أبطأ من السيارات"},{"en":"It prevents the engine from overheating","es":"Evita que el motor se sobrecaliente","ru":"Это предотвращает перегрев двигателя","tr":"Motorun aşırı ısınmasını önler","hi":"यह इंजन को ज़्यादा गर्म होने से रोकता है","ar":"لأنه يمنع فرط حرارة المحرك"},{"en":"It is only required during driving tests","es":"Solo se exige durante los exámenes de manejo","ru":"Это требуется только во время экзамена по вождению","tr":"Yalnızca sürüş sınavları sırasında zorunludur","hi":"यह केवल ड्राइविंग टेस्ट के दौरान आवश्यक है","ar":"لأنه مطلوب فقط أثناء اختبارات القيادة"},{"en":"More space gives more time to spot hazards and brake or swerve safely","es":"Más espacio da más tiempo para detectar peligros y frenar o esquivar de forma segura","ru":"Больше пространства даёт больше времени заметить опасности и безопасно затормозить или объехать","tr":"Daha fazla mesafe, tehlikeleri fark etmek ve güvenle frenlemek ya da manevra yapmak için daha fazla zaman tanır","hi":"अधिक जगह खतरों को पहचानने और सुरक्षित रूप से ब्रेक या स्वर्व करने के लिए अधिक समय देती है","ar":"لأن المساحة الأكبر تمنح وقتًا أكثر لرصد المخاطر والفرملة أو الانحراف بأمان"}],"e":{"en":"The Motorcycle Operator Manual stresses that a larger space cushion gives you more time and room to see, react to, and avoid hazards by braking or swerving.","es":"El Manual del Operador de Motocicletas recalca que un mayor colchón de espacio te da más tiempo y espacio para ver, reaccionar y evitar peligros frenando o esquivando.","ru":"Руководство мотоциклиста подчёркивает, что больший запас пространства даёт вам больше времени и места, чтобы увидеть опасности, отреагировать на них и избежать их торможением или объездом.","tr":"Motosiklet Kullanıcı Kılavuzu, daha büyük bir mesafe boşluğunun, tehlikeleri görmeniz, tepki vermeniz ve frenleyerek ya da manevra yaparak kaçınmanız için daha fazla zaman ve alan tanıdığını vurgular.","hi":"Motorcycle Operator Manual ज़ोर देता है कि एक बड़ा स्पेस कुशन आपको ब्रेक या स्वर्व करके खतरों को देखने, उन पर प्रतिक्रिया करने और उनसे बचने के लिए अधिक समय और जगह देता है।","ar":"يشدد دليل مشغّل الدراجة النارية على أن هامش المساحة الأكبر يمنحك وقتًا ومجالًا أكبر لرؤية المخاطر والتفاعل معها وتفاديها بالفرملة أو الانحراف."}},{"cat":"braking","a":0,"q":{"en":"Total stopping distance for a motorcycle is best described as the distance traveled during:","es":"La distancia total de frenado de una motocicleta se describe mejor como la distancia recorrida durante:","ru":"Полный тормозной путь мотоцикла лучше всего описать как расстояние, пройденное за время:","tr":"Bir motosiklet için toplam durma mesafesi en iyi şu süre boyunca kat edilen mesafe olarak tanımlanır:","hi":"मोटरसाइकिल के लिए कुल रुकने की दूरी को सबसे अच्छी तरह किस दौरान तय की गई दूरी के रूप में वर्णित किया जाता है?","ar":"تُوصف مسافة التوقف الكلية للدراجة النارية على أفضل وجه بأنها المسافة المقطوعة خلال:"},"o":[{"en":"Perception time, plus reaction time, plus the actual braking distance","es":"El tiempo de percepción, más el tiempo de reacción, más la distancia real de frenado","ru":"Время восприятия плюс время реакции плюс собственно тормозной путь","tr":"Algılama süresi, artı tepki süresi, artı asıl frenleme mesafesi","hi":"परसेप्शन समय, साथ ही रिएक्शन समय, साथ ही वास्तविक ब्रेकिंग दूरी","ar":"وقت الإدراك، زائد وقت رد الفعل، زائد مسافة الفرملة الفعلية"},{"en":"Only the time the brakes are physically slowing the bike","es":"Solo el tiempo en que los frenos están físicamente reduciendo la velocidad de la moto","ru":"Только время, пока тормоза физически замедляют мотоцикл","tr":"Yalnızca frenlerin motosikleti fiziksel olarak yavaşlattığı süre","hi":"केवल वह समय जब ब्रेक भौतिक रूप से बाइक को धीमा कर रहे होते हैं","ar":"فقط الوقت الذي تُبطئ فيه الفرامل الدراجة فعليًا"},{"en":"Only the rider's reaction time","es":"Solo el tiempo de reacción del conductor","ru":"Только время реакции мотоциклиста","tr":"Yalnızca sürücünün tepki süresi","hi":"केवल राइडर का रिएक्शन समय","ar":"فقط وقت رد فعل السائق"},{"en":"The time from starting the engine to reaching full speed","es":"El tiempo desde que se enciende el motor hasta alcanzar la velocidad máxima","ru":"Время от запуска двигателя до достижения полной скорости","tr":"Motoru çalıştırmaktan tam hıza ulaşmaya kadar geçen süre","hi":"इंजन चालू करने से लेकर पूरी गति तक पहुँचने तक का समय","ar":"الوقت من بدء تشغيل المحرك حتى بلوغ السرعة الكاملة"}],"e":{"en":"The Motorcycle Operator Manual describes total stopping distance as the sum of the distance traveled while perceiving the hazard, reacting to it, and then braking to a stop.","es":"El Manual del Operador de Motocicletas describe la distancia total de frenado como la suma de la distancia recorrida mientras se percibe el peligro, se reacciona a él y luego se frena hasta detenerse.","ru":"Руководство мотоциклиста описывает полный тормозной путь как сумму расстояний, пройденных за время восприятия опасности, реакции на неё и последующего торможения до остановки.","tr":"Motosiklet Kullanıcı Kılavuzu, toplam durma mesafesini, tehlikeyi algılarken, ona tepki verirken ve sonra durana kadar frenlerken kat edilen mesafelerin toplamı olarak tanımlar.","hi":"Motorcycle Operator Manual कुल रुकने की दूरी को खतरे को पहचानने, उस पर प्रतिक्रिया करने और फिर रुकने के लिए ब्रेक लगाने के दौरान तय की गई दूरी के योग के रूप में वर्णित करता है।","ar":"يصف دليل مشغّل الدراجة النارية مسافة التوقف الكلية بأنها مجموع المسافة المقطوعة أثناء إدراك الخطر، والتفاعل معه، ثم الفرملة حتى التوقف."}},{"cat":"braking","a":0,"q":{"en":"Which factor will lengthen your total stopping distance?","es":"¿Cuál factor alargará tu distancia total de frenado?","ru":"Какой фактор удлинит ваш полный тормозной путь?","tr":"Hangi faktör toplam durma mesafenizi uzatır?","hi":"कौन सा कारक आपकी कुल रुकने की दूरी को बढ़ाएगा?","ar":"أي عامل سيطيل مسافة توقفك الكلية؟"},"o":[{"en":"Higher speed and slower reaction time","es":"Mayor velocidad y un tiempo de reacción más lento","ru":"Более высокая скорость и более медленная реакция","tr":"Daha yüksek hız ve daha yavaş tepki süresi","hi":"अधिक गति और धीमा रिएक्शन समय","ar":"سرعة أعلى ووقت رد فعل أبطأ"},{"en":"Fresh tires and dry pavement","es":"Llantas nuevas y pavimento seco","ru":"Новые шины и сухое покрытие","tr":"Yeni lastikler ve kuru zemin","hi":"नए टायर और सूखी सड़क","ar":"إطارات جديدة ورصيف جاف"},{"en":"Staying alert and scanning ahead","es":"Mantenerte alerta y escanear hacia adelante","ru":"Сохранение бдительности и просмотр дороги вперёд","tr":"Tetikte kalmak ve önü taramak","hi":"सतर्क रहना और आगे स्कैन करना","ar":"البقاء متيقظًا والمسح بالنظر للأمام"},{"en":"Using both brakes correctly together","es":"Usar ambos frenos correctamente juntos","ru":"Правильное совместное использование обоих тормозов","tr":"Her iki freni birlikte doğru kullanmak","hi":"दोनों ब्रेक को सही ढंग से एक साथ उपयोग करना","ar":"استخدام كلتا الفرملتين معًا بشكل صحيح"}],"e":{"en":"The Motorcycle Operator Manual notes that higher speed and any delay in perceiving or reacting to a hazard add to the distance traveled before you can stop, increasing total stopping distance.","es":"El Manual del Operador de Motocicletas señala que una mayor velocidad y cualquier retraso en percibir o reaccionar ante un peligro aumentan la distancia recorrida antes de poder detenerte, incrementando la distancia total de frenado.","ru":"Руководство мотоциклиста отмечает, что более высокая скорость и любая задержка в восприятии опасности или реакции на неё добавляют к расстоянию, пройденному до остановки, увеличивая полный тормозной путь.","tr":"Motosiklet Kullanıcı Kılavuzu, daha yüksek hızın ve bir tehlikeyi algılamadaki ya da ona tepki vermedeki herhangi bir gecikmenin, durabilmeden önce kat edilen mesafeye eklendiğini ve toplam durma mesafesini artırdığını belirtir.","hi":"Motorcycle Operator Manual नोट करता है कि अधिक गति और खतरे को पहचानने या उस पर प्रतिक्रिया करने में कोई भी देरी रुकने से पहले तय की गई दूरी को बढ़ाती है, जिससे कुल रुकने की दूरी बढ़ जाती है।","ar":"يشير دليل مشغّل الدراجة النارية إلى أن السرعة الأعلى وأي تأخير في إدراك الخطر أو التفاعل معه يضيفان إلى المسافة المقطوعة قبل أن تتمكن من التوقف، مما يزيد مسافة التوقف الكلية."}},{"cat":"braking","a":3,"q":{"en":"What is a key benefit of practicing quick stops in a safe area before you need one?","es":"¿Cuál es un beneficio clave de practicar paradas rápidas en un área segura antes de necesitarlas?","ru":"В чём ключевая польза отработки быстрых остановок в безопасном месте до того, как они понадобятся?","tr":"İhtiyaç duymadan önce güvenli bir alanda hızlı duruşlar pratiği yapmanın temel bir faydası nedir?","hi":"ज़रूरत पड़ने से पहले एक सुरक्षित क्षेत्र में त्वरित स्टॉप का अभ्यास करने का एक प्रमुख लाभ क्या है?","ar":"ما هي الفائدة الرئيسية لممارسة التوقفات السريعة في منطقة آمنة قبل أن تحتاج إليها؟"},"o":[{"en":"It lets you skip using the front brake in emergencies","es":"Te permite omitir el uso del freno delantero en emergencias","ru":"Это позволяет не использовать передний тормоз в экстренных ситуациях","tr":"Acil durumlarda ön freni kullanmamanıza olanak tanır","hi":"यह आपको आपातकाल में फ्रंट ब्रेक का उपयोग छोड़ने देता है","ar":"تتيح لك تجاوز استخدام الفرامل الأمامية في حالات الطوارئ"},{"en":"It allows you to stop without slowing down","es":"Te permite detenerte sin reducir la velocidad","ru":"Это позволяет останавливаться, не замедляясь","tr":"Yavaşlamadan durmanızı sağlar","hi":"यह आपको धीमा हुए बिना रुकने देता है","ar":"تتيح لك التوقف دون إبطاء"},{"en":"It eliminates the need for any following distance","es":"Elimina la necesidad de cualquier distancia de seguimiento","ru":"Это устраняет необходимость в какой-либо дистанции следования","tr":"Herhangi bir takip mesafesi ihtiyacını ortadan kaldırır","hi":"यह किसी भी फॉलोइंग दूरी की ज़रूरत समाप्त कर देता है","ar":"تلغي الحاجة إلى أي مسافة اتباع"},{"en":"It builds the skill to brake hard with both brakes without locking a wheel","es":"Desarrolla la habilidad de frenar fuerte con ambos frenos sin bloquear una rueda","ru":"Это формирует навык сильно тормозить обоими тормозами без блокировки колеса","tr":"Bir tekerleği kilitlemeden her iki frenle sert frenleme becerisini geliştirir","hi":"यह बिना व्हील लॉक किए दोनों ब्रेक से ज़ोर से ब्रेक लगाने का कौशल बनाता है","ar":"تبني مهارة الفرملة بقوة بكلتا الفرملتين دون إغلاق عجلة"}],"e":{"en":"The Motorcycle Operator Manual recommends practicing quick stops so you can apply both brakes firmly and progressively in an emergency without locking a wheel and losing control.","es":"El Manual del Operador de Motocicletas recomienda practicar paradas rápidas para que puedas aplicar ambos frenos con firmeza y de forma progresiva en una emergencia sin bloquear una rueda y perder el control.","ru":"Руководство мотоциклиста рекомендует отрабатывать быстрые остановки, чтобы в экстренной ситуации вы могли уверенно и постепенно применять оба тормоза без блокировки колеса и потери управления.","tr":"Motosiklet Kullanıcı Kılavuzu, bir acil durumda her iki freni sıkıca ve giderek artan şekilde uygulayabilmeniz için, bir tekerleği kilitleyip kontrolü kaybetmeden hızlı duruş pratiği yapmayı önerir.","hi":"Motorcycle Operator Manual त्वरित स्टॉप का अभ्यास करने की सिफारिश करता है ताकि आप आपातकाल में बिना व्हील लॉक किए और नियंत्रण खोए दोनों ब्रेक को मज़बूती और क्रमशः लगा सकें।","ar":"يوصي دليل مشغّل الدراجة النارية بممارسة التوقفات السريعة حتى تتمكن من تطبيق كلتا الفرملتين بثبات وتدرّج في حالة الطوارئ دون إغلاق عجلة وفقدان التحكم."}},{"cat":"braking","a":0,"q":{"en":"When making a hard stop, applying the rear brake too hard most commonly causes the rear wheel to:","es":"Al hacer una parada brusca, aplicar el freno trasero con demasiada fuerza comúnmente hace que la rueda trasera:","ru":"При резкой остановке слишком сильное нажатие заднего тормоза чаще всего приводит к тому, что заднее колесо:","tr":"Sert bir duruş yaparken arka frene çok sert basmak en çok arka tekerleğin ne yapmasına neden olur?","hi":"एक कठोर स्टॉप करते समय, रियर ब्रेक को बहुत ज़ोर से लगाने पर सबसे आम तौर पर रियर व्हील:","ar":"عند إجراء توقف قوي، فإن تطبيق الفرامل الخلفية بقوة مفرطة يتسبب غالبًا في أن العجلة الخلفية:"},"o":[{"en":"Lock up and skid","es":"Se bloquee y derrape","ru":"Блокируется и идёт юзом","tr":"Kilitlenip kaymasına","hi":"लॉक हो जाता है और स्किड करता है","ar":"تنغلق وتنزلق"},{"en":"Spin faster than the front wheel","es":"Gire más rápido que la rueda delantera","ru":"Вращается быстрее переднего колеса","tr":"Ön tekerlekten daha hızlı dönmesine","hi":"फ्रंट व्हील से तेज़ी से घूमता है","ar":"تدور أسرع من العجلة الأمامية"},{"en":"Lift completely off the ground and stay there","es":"Se levante por completo del suelo y se quede así","ru":"Полностью отрывается от земли и остаётся в воздухе","tr":"Tamamen yerden kalkıp öyle kalmasına","hi":"पूरी तरह ज़मीन से उठ जाता है और उठा रहता है","ar":"ترتفع تمامًا عن الأرض وتبقى مرفوعة"},{"en":"Turn the handlebars automatically","es":"Gire el manillar automáticamente","ru":"Автоматически поворачивает руль","tr":"Gidonu otomatik olarak çevirmesine","hi":"स्वतः हैंडलबार घुमा देता है","ar":"تدير المقود تلقائيًا"}],"e":{"en":"The Motorcycle Operator Manual explains that as weight shifts forward in a hard stop, the lighter rear wheel can lock and skid easily, so rear brake pressure must be controlled.","es":"El Manual del Operador de Motocicletas explica que a medida que el peso se desplaza hacia adelante en una parada brusca, la rueda trasera, más ligera, puede bloquearse y derrapar con facilidad, así que la presión del freno trasero debe controlarse.","ru":"Руководство мотоциклиста поясняет, что при смещении веса вперёд во время резкой остановки облегчённое заднее колесо легко блокируется и идёт юзом, поэтому усилие на заднем тормозе нужно контролировать.","tr":"Motosiklet Kullanıcı Kılavuzu, sert bir duruşta ağırlık öne kayarken, daha hafif kalan arka tekerleğin kolayca kilitlenip kayabileceğini, bu yüzden arka fren basıncının kontrol edilmesi gerektiğini açıklar.","hi":"Motorcycle Operator Manual समझाता है कि कठोर स्टॉप में वज़न आगे की ओर शिफ्ट होने पर हल्का रियर व्हील आसानी से लॉक होकर स्किड कर सकता है, इसलिए रियर ब्रेक दबाव को नियंत्रित किया जाना चाहिए।","ar":"يوضح دليل مشغّل الدراجة النارية أنه مع انتقال الوزن للأمام في توقف قوي، يمكن أن تنغلق العجلة الخلفية الأخف وتنزلق بسهولة، لذا يجب التحكم في ضغط الفرامل الخلفية."}},{"cat":"cornering","a":1,"q":{"en":"According to the Motorcycle Operator Manual, what is the correct order of the four steps for taking a turn?","es":"Según el Manual del Operador de Motocicletas, ¿cuál es el orden correcto de los cuatro pasos para tomar una curva?","ru":"Согласно Руководству мотоциклиста, какова правильная последовательность четырёх шагов прохождения поворота?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir dönüş yapmanın dört adımının doğru sırası nedir?","hi":"Motorcycle Operator Manual के अनुसार, एक मोड़ लेने के चार चरणों का सही क्रम क्या है?","ar":"وفقًا لدليل مشغّل الدراجة النارية، ما هو الترتيب الصحيح للخطوات الأربع لأخذ منعطف؟"},"o":[{"en":"Look, Slow, Roll, Press","es":"Mira, Reduce, Acelera, Presiona","ru":"Смотри, Замедлись, Прибавь газ, Нажми","tr":"Bak, Yavaşla, Gazla, Bastır","hi":"Look, Slow, Roll, Press","ar":"انظر، أبطئ، لُفّ، اضغط"},{"en":"Slow, Look, Press, Roll","es":"Reduce, Mira, Presiona, Acelera","ru":"Замедлись, Смотри, Нажми, Прибавь газ","tr":"Yavaşla, Bak, Bastır, Gazla","hi":"Slow, Look, Press, Roll","ar":"أبطئ، انظر، اضغط، لُفّ"},{"en":"Press, Slow, Look, Roll","es":"Presiona, Reduce, Mira, Acelera","ru":"Нажми, Замедлись, Смотри, Прибавь газ","tr":"Bastır, Yavaşla, Bak, Gazla","hi":"Press, Slow, Look, Roll","ar":"اضغط، أبطئ، انظر، لُفّ"},{"en":"Slow, Press, Roll, Look","es":"Reduce, Presiona, Acelera, Mira","ru":"Замедлись, Нажми, Прибавь газ, Смотри","tr":"Yavaşla, Bastır, Gazla, Bak","hi":"Slow, Press, Roll, Look","ar":"أبطئ، اضغط، لُفّ، انظر"}],"e":{"en":"The manual lists the four steps to turn effectively in order: SLOW (reduce speed before the turn), LOOK (look through the turn), PRESS (press the handgrip to lean), and ROLL (roll on the throttle through the turn). Source: Motorcycle Operator Manual.","es":"El manual enumera los cuatro pasos para tomar una curva de forma eficaz en orden: REDUCE (reduce la velocidad antes de la curva), MIRA (mira a través de la curva), PRESIONA (presiona la manija para inclinarte) y ACELERA (acelera a través de la curva). Fuente: Manual del Operador de Motocicletas.","ru":"Руководство перечисляет четыре шага эффективного прохождения поворота по порядку: ЗАМЕДЛИСЬ (снизь скорость перед поворотом), СМОТРИ (смотри сквозь поворот), НАЖМИ (нажми на рукоятку руля для наклона) и ПРИБАВЬ ГАЗ (прибавляй газ в повороте). Источник: Руководство мотоциклиста.","tr":"Kılavuz, etkili dönüş yapmanın dört adımını sırayla listeler: YAVAŞLA (dönüşten önce hızı azalt), BAK (dönüşün içinden bak), BASTIR (yatmak için gidon kabzasına bastır) ve GAZLA (dönüş boyunca gazı aç). Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल प्रभावी ढंग से मुड़ने के चार चरणों को क्रम में सूचीबद्ध करता है: SLOW (मोड़ से पहले गति कम करें), LOOK (मोड़ के पार देखें), PRESS (झुकने के लिए हैंडग्रिप दबाएं), और ROLL (मोड़ के दौरान थ्रॉटल रोल ऑन करें)। स्रोत: Motorcycle Operator Manual।","ar":"يُدرج الدليل الخطوات الأربع للانعطاف بفعالية مرتبةً: أبطئ (قلل السرعة قبل المنعطف)، انظر (انظر عبر المنعطف)، اضغط (اضغط المقبض للميل)، ولُفّ (لُفّ الخانق عبر المنعطف). المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"What does the 'SLOW' step of the four-step turning procedure require you to do?","es":"¿Qué te exige hacer el paso 'REDUCE' del procedimiento de cuatro pasos para tomar una curva?","ru":"Что требует от вас шаг «ЗАМЕДЛИСЬ» в четырёхшаговой процедуре прохождения поворота?","tr":"Dört adımlı dönüş işleminin 'YAVAŞLA' adımı ne yapmanızı gerektirir?","hi":"चार-चरण मुड़ने की प्रक्रिया का 'SLOW' चरण आपसे क्या करवाता है?","ar":"ماذا تتطلب منك خطوة 'أبطئ' في إجراء الانعطاف المكوّن من أربع خطوات؟"},"o":[{"en":"Slow down gradually only after you have entered the curve","es":"Reducir la velocidad gradualmente solo después de haber entrado a la curva","ru":"Замедляться постепенно только после входа в поворот","tr":"Yalnızca virajı girdikten sonra kademeli olarak yavaşlayın","hi":"मोड़ में प्रवेश करने के बाद ही धीरे-धीरे धीमा हों","ar":"أن تبطئ تدريجيًا فقط بعد أن تدخل المنحنى"},{"en":"Reduce speed before entering the turn by closing the throttle and, if needed, applying both brakes","es":"Reducir la velocidad antes de entrar a la curva cerrando el acelerador y, si es necesario, aplicando ambos frenos","ru":"Снизить скорость перед входом в поворот, закрыв газ и, при необходимости, применив оба тормоза","tr":"Gazı kapatarak ve gerekirse her iki freni uygulayarak dönüşe girmeden önce hızı azaltın","hi":"थ्रॉटल बंद करके और ज़रूरत हो तो दोनों ब्रेक लगाकर मोड़ में प्रवेश करने से पहले गति कम करें","ar":"أن تقلل السرعة قبل دخول المنعطف بإغلاق الخانق، وعند الحاجة، تطبيق كلتا الفرملتين"},{"en":"Coast through the entire turn in neutral to stay smooth","es":"Pasar toda la curva rodando en neutral para mantenerte suave","ru":"Проходить весь поворот накатом на нейтрали, чтобы было плавно","tr":"Yumuşak olmak için tüm dönüş boyunca boşta gidin","hi":"सहज रहने के लिए पूरे मोड़ में न्यूट्रल में कोस्ट करें","ar":"أن تنزلق عبر المنعطف كله في الوضع المحايد لتبقى سلسًا"},{"en":"Apply only the rear brake at the sharpest point of the curve","es":"Aplicar solo el freno trasero en el punto más cerrado de la curva","ru":"Применять только задний тормоз в самой острой точке поворота","tr":"Virajın en keskin noktasında yalnızca arka freni uygulayın","hi":"मोड़ के सबसे तीखे बिंदु पर केवल रियर ब्रेक लगाएं","ar":"أن تطبّق الفرامل الخلفية فقط عند أحدّ نقطة في المنحنى"}],"e":{"en":"In the SLOW step you reduce speed before the turn by rolling off the throttle and, if necessary, applying both brakes. Braking should be completed before you lean into the curve. Source: Motorcycle Operator Manual.","es":"En el paso REDUCE bajas la velocidad antes de la curva soltando el acelerador y, si es necesario, aplicando ambos frenos. El frenado debe completarse antes de inclinarte hacia la curva. Fuente: Manual del Operador de Motocicletas.","ru":"На шаге ЗАМЕДЛИСЬ вы снижаете скорость перед поворотом, сбрасывая газ и, при необходимости, применяя оба тормоза. Торможение следует завершить до того, как вы войдёте в поворот в наклоне. Источник: Руководство мотоциклиста.","tr":"YAVAŞLA adımında, gazı kapatarak ve gerekirse her iki freni uygulayarak dönüşten önce hızı azaltırsınız. Frenleme, viraja yatmadan önce tamamlanmalıdır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"SLOW चरण में आप मोड़ से पहले थ्रॉटल रोल ऑफ करके और यदि आवश्यक हो तो दोनों ब्रेक लगाकर गति कम करते हैं। मोड़ में झुकने से पहले ब्रेकिंग पूरी हो जानी चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"في خطوة أبطئ تقلل السرعة قبل المنعطف بإرخاء الخانق، وعند الضرورة، تطبيق كلتا الفرملتين. يجب إتمام الفرملة قبل أن تميل في المنحنى. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"When should you reduce your speed for a curve?","es":"¿Cuándo debes reducir tu velocidad para una curva?","ru":"Когда следует снижать скорость для поворота?","tr":"Bir viraj için hızınızı ne zaman azaltmalısınız?","hi":"आपको एक मोड़ के लिए अपनी गति कब कम करनी चाहिए?","ar":"متى يجب أن تقلل سرعتك قبل منحنى؟"},"o":[{"en":"While you are leaned over in the middle of the curve","es":"Mientras estás inclinado en medio de la curva","ru":"Пока вы наклонены в середине поворота","tr":"Virajın ortasında yatmış haldeyken","hi":"जब आप मोड़ के बीच में झुके हुए हों","ar":"وأنت مائل في منتصف المنحنى"},{"en":"Only as you exit the curve","es":"Solo al salir de la curva","ru":"Только при выходе из поворота","tr":"Yalnızca virajdan çıkarken","hi":"केवल जब आप मोड़ से बाहर निकल रहे हों","ar":"فقط عند خروجك من المنحنى"},{"en":"Before you enter the curve","es":"Antes de entrar a la curva","ru":"Перед входом в поворот","tr":"Viraja girmeden önce","hi":"मोड़ में प्रवेश करने से पहले","ar":"قبل أن تدخل المنحنى"},{"en":"You should speed up entering the curve and slow at the apex","es":"Debes acelerar al entrar a la curva y reducir en el vértice","ru":"Следует ускоряться на входе в поворот и замедляться в апексе","tr":"Viraja girerken hızlanıp tepe noktasında yavaşlamalısınız","hi":"आपको मोड़ में प्रवेश करते समय गति बढ़ानी चाहिए और शीर्ष पर धीमा होना चाहिए","ar":"يجب أن تسرّع عند دخول المنحنى وتبطئ عند القمة"}],"e":{"en":"The manual stresses slowing before the turn. Adjusting speed while leaned in a curve can cause a skid or loss of control, so reduce speed before you enter it. Source: Motorcycle Operator Manual.","es":"El manual recalca reducir antes de la curva. Ajustar la velocidad mientras estás inclinado en una curva puede causar un derrape o pérdida de control, así que reduce la velocidad antes de entrar a ella. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство подчёркивает замедление до поворота. Регулировка скорости в наклоне в повороте может вызвать занос или потерю управления, поэтому снижайте скорость перед входом. Источник: Руководство мотоциклиста.","tr":"Kılavuz, dönüşten önce yavaşlamayı vurgular. Bir virajda yatmışken hızı ayarlamak kayma ya da kontrol kaybına neden olabilir, bu yüzden hızı viraja girmeden önce azaltın. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल मोड़ से पहले धीमा होने पर ज़ोर देता है। मोड़ में झुके हुए गति समायोजित करने से स्किड या नियंत्रण खो सकता है, इसलिए इसमें प्रवेश करने से पहले गति कम करें। स्रोत: Motorcycle Operator Manual।","ar":"يشدد الدليل على الإبطاء قبل المنعطف. تعديل السرعة وأنت مائل في منحنى قد يسبب انزلاقًا أو فقدان التحكم، لذا قلل السرعة قبل أن تدخله. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"To make a motorcycle turn at normal riding speeds, what must happen?","es":"Para hacer girar una motocicleta a velocidades normales de conducción, ¿qué debe ocurrir?","ru":"Чтобы мотоцикл повернул на обычной скорости езды, что должно произойти?","tr":"Normal sürüş hızlarında bir motosikleti döndürmek için ne olması gerekir?","hi":"सामान्य राइडिंग गति पर मोटरसाइकिल को मोड़ने के लिए, क्या होना चाहिए?","ar":"لجعل الدراجة النارية تنعطف عند سرعات القيادة العادية، ماذا يجب أن يحدث؟"},"o":[{"en":"The handlebars must be turned toward the turn like a car's steering wheel","es":"El manillar debe girarse hacia la curva como el volante de un auto","ru":"Руль нужно повернуть в сторону поворота, как руль автомобиля","tr":"Gidon, bir otomobilin direksiyonu gibi dönüş yönüne çevrilmeli","hi":"हैंडलबार को कार के स्टीयरिंग व्हील की तरह मोड़ की ओर घुमाना चाहिए","ar":"يجب توجيه المقود نحو الانعطاف مثل عجلة قيادة السيارة"},{"en":"The rider must lean opposite the direction of the turn","es":"El conductor debe inclinarse en dirección opuesta a la curva","ru":"Мотоциклист должен наклониться в сторону, противоположную повороту","tr":"Sürücü dönüşün tersi yönde yatmalı","hi":"राइडर को मोड़ की दिशा के विपरीत झुकना चाहिए","ar":"يجب أن يميل السائق عكس اتجاه الانعطاف"},{"en":"Both feet must come off the pegs to balance","es":"Ambos pies deben salir de los estribos para mantener el equilibrio","ru":"Обе ноги должны оторваться от подножек для равновесия","tr":"Dengeyi sağlamak için iki ayak da basamaklardan ayrılmalı","hi":"संतुलन के लिए दोनों पैर पेग से हट जाने चाहिए","ar":"يجب أن ترفع كلتا القدمين عن المساند للتوازن"},{"en":"The motorcycle must lean","es":"La motocicleta debe inclinarse","ru":"Мотоцикл должен наклониться","tr":"Motosiklet yatmalı","hi":"मोटरसाइकिल को झुकना चाहिए","ar":"يجب أن تميل الدراجة النارية"}],"e":{"en":"The manual states that to turn, the motorcycle must lean. You make it lean by pressing on the handgrip in the direction of the turn. Source: Motorcycle Operator Manual.","es":"El manual indica que para girar, la motocicleta debe inclinarse. La haces inclinarse presionando la manija en la dirección de la curva. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство утверждает, что для поворота мотоцикл должен наклониться. Вы заставляете его наклониться, нажимая на рукоятку руля в направлении поворота. Источник: Руководство мотоциклиста.","tr":"Kılavuz, dönmek için motosikletin yatması gerektiğini belirtir. Gidon kabzasına dönüş yönünde bastırarak onu yatırırsınız. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल बताता है कि मुड़ने के लिए, मोटरसाइकिल को झुकना चाहिए। आप इसे मोड़ की दिशा में हैंडग्रिप दबाकर झुकाते हैं। स्रोत: Motorcycle Operator Manual।","ar":"ينص الدليل على أنه للانعطاف يجب أن تميل الدراجة النارية. تجعلها تميل بالضغط على المقبض في اتجاه الانعطاف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"The technique of pressing on the handgrip in the direction you want to go is called:","es":"La técnica de presionar la manija en la dirección hacia la que quieres ir se llama:","ru":"Техника нажатия на рукоятку руля в направлении, куда вы хотите ехать, называется:","tr":"Gitmek istediğiniz yöndeki gidon kabzasına bastırma tekniğine ne ad verilir?","hi":"जिस दिशा में आप जाना चाहते हैं उस दिशा में हैंडग्रिप दबाने की तकनीक को कहा जाता है:","ar":"تقنية الضغط على المقبض في الاتجاه الذي تريد الذهاب إليه تُسمى:"},"o":[{"en":"Trail braking","es":"Frenado en curva (trail braking)","ru":"Торможение в повороте (trail braking)","tr":"İz frenlemesi","hi":"ट्रेल ब्रेकिंग","ar":"الفرملة عند المسار"},{"en":"Countersteering","es":"Contramanillar (countersteering)","ru":"Контрруление","tr":"Ters direksiyon","hi":"काउंटरस्टीयरिंग","ar":"التوجيه العكسي"},{"en":"Throttle blipping","es":"Acelerón breve (throttle blipping)","ru":"Перегазовка (throttle blipping)","tr":"Gaz vurma","hi":"थ्रॉटल ब्लिपिंग","ar":"نبض الخانق"},{"en":"Engine braking","es":"Freno motor (engine braking)","ru":"Торможение двигателем","tr":"Motor freni","hi":"इंजन ब्रेकिंग","ar":"فرملة المحرك"}],"e":{"en":"Pressing forward on the handgrip in the direction of the turn to make the motorcycle lean is countersteering, the 'PRESS' step of the turning procedure. Source: Motorcycle Operator Manual.","es":"Presionar hacia adelante la manija en la dirección de la curva para hacer que la motocicleta se incline es contramanillar (countersteering), el paso 'PRESIONA' del procedimiento para tomar la curva. Fuente: Manual del Operador de Motocicletas.","ru":"Нажатие вперёд на рукоятку руля в направлении поворота, чтобы заставить мотоцикл наклониться, — это контрруление, шаг «НАЖМИ» процедуры прохождения поворота. Источник: Руководство мотоциклиста.","tr":"Motosikleti yatırmak için gidon kabzasına dönüş yönünde ileriye doğru bastırmak ters direksiyondur, dönüş işleminin 'BASTIR' adımıdır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मोटरसाइकिल को झुकाने के लिए मोड़ की दिशा में हैंडग्रिप पर आगे दबाना काउंटरस्टीयरिंग है, जो मुड़ने की प्रक्रिया का 'PRESS' चरण है। स्रोत: Motorcycle Operator Manual।","ar":"الضغط للأمام على المقبض في اتجاه الانعطاف لجعل الدراجة النارية تميل هو التوجيه العكسي، وهو خطوة 'اضغط' في إجراء الانعطاف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"To make the motorcycle lean and go to the left, what should you do with the handgrips?","es":"Para hacer que la motocicleta se incline y vaya hacia la izquierda, ¿qué debes hacer con las manijas?","ru":"Чтобы заставить мотоцикл наклониться и поехать влево, что нужно сделать с рукоятками руля?","tr":"Motosikleti yatırıp sola gitmesini sağlamak için gidon kabzalarıyla ne yapmalısınız?","hi":"मोटरसाइकिल को बाईं ओर झुकाने और मोड़ने के लिए, आपको हैंडग्रिप के साथ क्या करना चाहिए?","ar":"لجعل الدراجة النارية تميل وتتجه إلى اليسار، ماذا يجب أن تفعل بالمقابض؟"},"o":[{"en":"Press the left handgrip","es":"Presionar la manija izquierda","ru":"Нажать на левую рукоятку руля","tr":"Sol gidon kabzasına bastırın","hi":"बायां हैंडग्रिप दबाएं","ar":"اضغط المقبض الأيسر"},{"en":"Press the right handgrip","es":"Presionar la manija derecha","ru":"Нажать на правую рукоятку руля","tr":"Sağ gidon kabzasına bastırın","hi":"दायां हैंडग्रिप दबाएं","ar":"اضغط المقبض الأيمن"},{"en":"Pull the left handgrip toward you","es":"Jalar la manija izquierda hacia ti","ru":"Потянуть левую рукоятку руля на себя","tr":"Sol gidon kabzasını kendinize çekin","hi":"बायां हैंडग्रिप अपनी ओर खींचें","ar":"اسحب المقبض الأيسر نحوك"},{"en":"Push both handgrips forward equally","es":"Empujar ambas manijas hacia adelante por igual","ru":"Толкнуть обе рукоятки руля вперёд одинаково","tr":"Her iki gidon kabzasına eşit şekilde ileri itin","hi":"दोनों हैंडग्रिप समान रूप से आगे धकेलें","ar":"ادفع كلا المقبضين للأمام بالتساوي"}],"e":{"en":"The manual's rule for countersteering is: press left, lean left, go left; press right, lean right, go right. Pressing the left grip makes the motorcycle lean and turn left. Source: Motorcycle Operator Manual.","es":"La regla del manual para el contramanillar es: presiona a la izquierda, inclínate a la izquierda, ve a la izquierda; presiona a la derecha, inclínate a la derecha, ve a la derecha. Presionar la manija izquierda hace que la motocicleta se incline y gire a la izquierda. Fuente: Manual del Operador de Motocicletas.","ru":"Правило контрруления в Руководстве таково: нажми влево, наклонись влево, поезжай влево; нажми вправо, наклонись вправо, поезжай вправо. Нажатие на левую рукоятку заставляет мотоцикл наклониться и повернуть влево. Источник: Руководство мотоциклиста.","tr":"Kılavuzun ters direksiyon kuralı şudur: sola bastır, sola yat, sola git; sağa bastır, sağa yat, sağa git. Sol kabzaya bastırmak motosikleti sola yatırıp döndürür. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल का काउंटरस्टीयरिंग का नियम है: बाएं दबाएं, बाएं झुकें, बाएं जाएं; दाएं दबाएं, दाएं झुकें, दाएं जाएं। बायां ग्रिप दबाने से मोटरसाइकिल बाईं ओर झुकती और मुड़ती है। स्रोत: Motorcycle Operator Manual।","ar":"قاعدة الدليل للتوجيه العكسي هي: اضغط يسارًا، ميل يسارًا، اتجه يسارًا؛ اضغط يمينًا، ميل يمينًا، اتجه يمينًا. الضغط على المقبض الأيسر يجعل الدراجة النارية تميل وتنعطف يسارًا. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"While riding through a normal curve at speed, how should the rider and motorcycle lean?","es":"Mientras conduces a través de una curva normal a velocidad, ¿cómo deben inclinarse el conductor y la motocicleta?","ru":"Во время прохождения обычного поворота на скорости как должны наклоняться мотоциклист и мотоцикл?","tr":"Hızla normal bir virajdan geçerken sürücü ve motosiklet nasıl yatmalıdır?","hi":"गति पर एक सामान्य मोड़ से गुज़रते समय, राइडर और मोटरसाइकिल को कैसे झुकना चाहिए?","ar":"أثناء القيادة عبر منحنى عادي بسرعة، كيف يجب أن يميل السائق والدراجة النارية؟"},"o":[{"en":"The rider and the motorcycle should lean together at the same angle","es":"El conductor y la motocicleta deben inclinarse juntos en el mismo ángulo","ru":"Мотоциклист и мотоцикл должны наклоняться вместе под одним углом","tr":"Sürücü ve motosiklet aynı açıyla birlikte yatmalı","hi":"राइडर और मोटरसाइकिल को एक साथ समान कोण पर झुकना चाहिए","ar":"يجب أن يميل السائق والدراجة النارية معًا بالزاوية نفسها"},{"en":"The rider should stay upright while the motorcycle leans","es":"El conductor debe permanecer vertical mientras la motocicleta se inclina","ru":"Мотоциклист должен оставаться вертикально, пока мотоцикл наклоняется","tr":"Motosiklet yatarken sürücü dik durmalı","hi":"राइडर को सीधा रहना चाहिए जबकि मोटरसाइकिल झुके","ar":"يجب أن يبقى السائق منتصبًا بينما تميل الدراجة النارية"},{"en":"The rider should lean to the outside of the turn","es":"El conductor debe inclinarse hacia el exterior de la curva","ru":"Мотоциклист должен наклоняться наружу поворота","tr":"Sürücü dönüşün dış tarafına doğru yatmalı","hi":"राइडर को मोड़ के बाहरी ओर झुकना चाहिए","ar":"يجب أن يميل السائق إلى الجانب الخارجي من الانعطاف"},{"en":"Neither the rider nor the motorcycle should lean","es":"Ni el conductor ni la motocicleta deben inclinarse","ru":"Ни мотоциклист, ни мотоцикл не должны наклоняться","tr":"Ne sürücü ne de motosiklet yatmalı","hi":"न राइडर को न मोटरसाइकिल को झुकना चाहिए","ar":"يجب ألا يميل السائق ولا الدراجة النارية"}],"e":{"en":"In normal turns the rider and motorcycle should lean together at the same angle. (Only in slow, tight turns do you keep your body upright and lean the motorcycle alone.) Source: Motorcycle Operator Manual.","es":"En curvas normales el conductor y la motocicleta deben inclinarse juntos en el mismo ángulo. (Solo en curvas lentas y cerradas mantienes el cuerpo vertical e inclinas únicamente la motocicleta.) Fuente: Manual del Operador de Motocicletas.","ru":"В обычных поворотах мотоциклист и мотоцикл должны наклоняться вместе под одним углом. (Только в медленных, тесных поворотах вы держите тело вертикально и наклоняете только мотоцикл.) Источник: Руководство мотоциклиста.","tr":"Normal dönüşlerde sürücü ve motosiklet aynı açıyla birlikte yatmalıdır. (Yalnızca yavaş, dar dönüşlerde vücudunuzu dik tutup motosikleti tek başına yatırırsınız.) Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"सामान्य मोड़ों में राइडर और मोटरसाइकिल को एक साथ समान कोण पर झुकना चाहिए। (केवल धीमे, तंग मोड़ों में आप अपना शरीर सीधा रखते हैं और अकेले मोटरसाइकिल को झुकाते हैं।) स्रोत: Motorcycle Operator Manual।","ar":"في المنعطفات العادية يجب أن يميل السائق والدراجة النارية معًا بالزاوية نفسها. (فقط في المنعطفات البطيئة الضيقة تُبقي جسمك منتصبًا وتميل الدراجة النارية وحدها.) المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"During the 'LOOK' step of a turn, where should you direct your eyes?","es":"Durante el paso 'MIRA' de una curva, ¿hacia dónde debes dirigir la vista?","ru":"Во время шага «СМОТРИ» в повороте куда следует направлять взгляд?","tr":"Bir dönüşün 'BAK' adımı sırasında gözlerinizi nereye yöneltmelisiniz?","hi":"एक मोड़ के 'LOOK' चरण के दौरान, आपको अपनी आँखें कहाँ निर्देशित करनी चाहिए?","ar":"أثناء خطوة 'انظر' في المنعطف، إلى أين يجب أن توجّه عينيك؟"},"o":[{"en":"Down at the front fender to watch the pavement","es":"Hacia abajo, al guardabarros delantero, para observar el pavimento","ru":"Вниз на переднее крыло, чтобы следить за покрытием","tr":"Zemini izlemek için ön çamurluğa doğru aşağı","hi":"सड़क देखने के लिए फ्रंट फेंडर पर नीचे","ar":"لأسفل نحو الرفرف الأمامي لمراقبة الرصيف"},{"en":"At the vehicle directly behind you in your mirrors","es":"Al vehículo que está directamente detrás de ti en tus espejos","ru":"На транспорт прямо за вами в зеркалах","tr":"Aynalarınızdan tam arkanızdaki araca","hi":"अपने मिरर में सीधे अपने पीछे वाले वाहन पर","ar":"نحو المركبة التي خلفك مباشرة في مراياك"},{"en":"At the outer edge of the road surface just ahead of your front tire","es":"Al borde exterior de la superficie de la carretera justo delante de tu llanta delantera","ru":"На внешний край дорожного покрытия прямо перед передней шиной","tr":"Ön lastiğinizin hemen önündeki yol yüzeyinin dış kenarına","hi":"अपने फ्रंट टायर के ठीक आगे सड़क की सतह के बाहरी किनारे पर","ar":"نحو الحافة الخارجية لسطح الطريق أمام إطارك الأمامي مباشرة"},{"en":"Through the turn to where you want to go, keeping your eyes level with the horizon","es":"A través de la curva hacia donde quieres ir, manteniendo los ojos al nivel del horizonte","ru":"Сквозь поворот туда, куда вы хотите попасть, держа глаза на уровне горизонта","tr":"Dönüşün içinden gitmek istediğiniz yere, gözlerinizi ufukla aynı seviyede tutarak","hi":"मोड़ के पार जहाँ आप जाना चाहते हैं, अपनी आँखें क्षितिज के स्तर पर रखते हुए","ar":"عبر المنعطف إلى حيث تريد الذهاب، مع إبقاء عينيك بمستوى الأفق"}],"e":{"en":"The LOOK step says to look through the turn to where you want to go, turning your head (not your shoulders) and keeping your eyes level with the horizon. Source: Motorcycle Operator Manual.","es":"El paso MIRA dice que mires a través de la curva hacia donde quieres ir, girando la cabeza (no los hombros) y manteniendo los ojos al nivel del horizonte. Fuente: Manual del Operador de Motocicletas.","ru":"Шаг СМОТРИ предписывает смотреть сквозь поворот туда, куда вы хотите попасть, поворачивая голову (а не плечи) и держа глаза на уровне горизонта. Источник: Руководство мотоциклиста.","tr":"BAK adımı, dönüşün içinden gitmek istediğiniz yere bakmanızı, başınızı (omuzlarınızı değil) çevirmenizi ve gözlerinizi ufukla aynı seviyede tutmanızı söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"LOOK चरण कहता है कि मोड़ के पार जहाँ आप जाना चाहते हैं वहाँ देखें, अपना सिर (कंधे नहीं) घुमाते हुए और आँखें क्षितिज के स्तर पर रखते हुए। स्रोत: Motorcycle Operator Manual।","ar":"تقول خطوة انظر إنه يجب النظر عبر المنعطف إلى حيث تريد الذهاب، مع إدارة رأسك (لا كتفيك) وإبقاء عينيك بمستوى الأفق. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"What is the purpose of the 'ROLL' step when cornering?","es":"¿Cuál es el propósito del paso 'ACELERA' al tomar una curva?","ru":"Какова цель шага «ПРИБАВЬ ГАЗ» при прохождении поворота?","tr":"Viraj alırken 'GAZLA' adımının amacı nedir?","hi":"कॉर्नरिंग करते समय 'ROLL' चरण का उद्देश्य क्या है?","ar":"ما هو الغرض من خطوة 'لُفّ' عند الانعطاف؟"},"o":[{"en":"Roll completely off the throttle to coast through the turn","es":"Soltar por completo el acelerador para pasar la curva rodando libremente","ru":"Полностью сбросить газ, чтобы пройти поворот накатом","tr":"Dönüş boyunca boşta gitmek için gazı tamamen kapatmak","hi":"मोड़ के दौरान कोस्ट करने के लिए थ्रॉटल पूरी तरह रोल ऑफ करें","ar":"إرخاء الخانق تمامًا للانزلاق عبر المنعطف"},{"en":"Roll the bike upright before you have finished the turn","es":"Poner la moto vertical antes de haber terminado la curva","ru":"Выпрямить мотоцикл до завершения поворота","tr":"Dönüşü bitirmeden önce motosikleti dikleştirmek","hi":"मोड़ खत्म करने से पहले बाइक को सीधा खड़ा करें","ar":"جعل الدراجة منتصبة قبل أن تنهي المنعطف"},{"en":"Roll on the throttle through the turn to stabilize the motorcycle","es":"Acelerar a través de la curva para estabilizar la motocicleta","ru":"Прибавлять газ в повороте, чтобы стабилизировать мотоцикл","tr":"Motosikleti dengelemek için dönüş boyunca gazı açmak","hi":"मोटरसाइकिल को स्थिर करने के लिए मोड़ के दौरान थ्रॉटल रोल ऑन करें","ar":"لفّ الخانق عبر المنعطف لتثبيت الدراجة النارية"},{"en":"Roll on the front brake to tighten your line","es":"Aplicar el freno delantero para cerrar tu trazada","ru":"Прибавить передний тормоз, чтобы сузить траекторию","tr":"Çizginizi sıkmak için ön frene basmak","hi":"अपनी लाइन कसने के लिए फ्रंट ब्रेक रोल ऑन करें","ar":"لفّ الفرامل الأمامية لتضييق مسارك"}],"e":{"en":"The ROLL step calls for rolling on the throttle through the turn to maintain or gradually increase speed, which stabilizes the suspension and helps the motorcycle hold its line. Source: Motorcycle Operator Manual.","es":"El paso ACELERA exige acelerar a través de la curva para mantener o aumentar gradualmente la velocidad, lo que estabiliza la suspensión y ayuda a la motocicleta a mantener su trazada. Fuente: Manual del Operador de Motocicletas.","ru":"Шаг ПРИБАВЬ ГАЗ требует прибавлять газ в повороте, чтобы поддерживать или постепенно увеличивать скорость, что стабилизирует подвеску и помогает мотоциклу держать траекторию. Источник: Руководство мотоциклиста.","tr":"GAZLA adımı, hızı korumak ya da kademeli artırmak için dönüş boyunca gazı açmayı gerektirir; bu, süspansiyonu dengeler ve motosikletin çizgisini korumasına yardımcı olur. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"ROLL चरण मोड़ के दौरान गति बनाए रखने या क्रमशः बढ़ाने के लिए थ्रॉटल रोल ऑन करने को कहता है, जो सस्पेंशन को स्थिर करता है और मोटरसाइकिल को अपनी लाइन पर बने रहने में मदद करता है। स्रोत: Motorcycle Operator Manual।","ar":"تدعو خطوة لُفّ إلى لفّ الخانق عبر المنعطف للحفاظ على السرعة أو زيادتها تدريجيًا، مما يثبّت نظام التعليق ويساعد الدراجة النارية على الحفاظ على مسارها. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"How many paths of travel, or lane positions, does the manual say each traffic lane gives a motorcyclist?","es":"¿Cuántas trayectorias de circulación, o posiciones de carril, dice el manual que cada carril de tráfico le da a un motociclista?","ru":"Сколько траекторий движения, или положений в полосе, по словам руководства, даёт мотоциклисту каждая полоса движения?","tr":"Kılavuza göre, her trafik şeridi bir motosikletçiye kaç sürüş yolu ya da şerit konumu sunar?","hi":"मैनुअल के अनुसार हर ट्रैफ़िक लेन एक मोटरसाइकिल चालक को कितने यात्रा पथ, या लेन स्थितियाँ देती है?","ar":"كم عدد مسارات السير، أو مواضع الحارة، التي يقول الدليل إن كل حارة مرورية تمنحها لراكب الدراجة النارية؟"},"o":[{"en":"One","es":"Una","ru":"Одну","tr":"Bir","hi":"एक","ar":"واحد"},{"en":"Three","es":"Tres","ru":"Три","tr":"Üç","hi":"तीन","ar":"ثلاثة"},{"en":"Two","es":"Dos","ru":"Две","tr":"İki","hi":"दो","ar":"اثنان"},{"en":"Five","es":"Cinco","ru":"Пять","tr":"Beş","hi":"पाँच","ar":"خمسة"}],"e":{"en":"The manual explains that each traffic lane gives a motorcycle three paths of travel: the left, center, and right portions of the lane. Source: Motorcycle Operator Manual.","es":"El manual explica que cada carril de tráfico le da a una motocicleta tres trayectorias de circulación: las porciones izquierda, central y derecha del carril. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство поясняет, что каждая полоса движения даёт мотоциклу три траектории движения: левую, центральную и правую части полосы. Источник: Руководство мотоциклиста.","tr":"Kılavuz, her trafik şeridinin bir motosiklete üç sürüş yolu sunduğunu açıklar: şeridin sol, orta ve sağ kısımları. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल समझाता है कि हर ट्रैफ़िक लेन एक मोटरसाइकिल को तीन यात्रा पथ देती है: लेन के बाएं, केंद्र, और दाएं हिस्से। स्रोत: Motorcycle Operator Manual।","ar":"يوضح الدليل أن كل حارة مرورية تمنح الدراجة النارية ثلاثة مسارات سير: الأجزاء اليسرى والوسطى واليمنى من الحارة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"The three lane positions for a motorcycle correspond to which parts of the lane?","es":"Las tres posiciones de carril para una motocicleta corresponden a cuáles partes del carril?","ru":"Три положения в полосе для мотоцикла соответствуют каким частям полосы?","tr":"Bir motosiklet için üç şerit konumu, şeridin hangi kısımlarına karşılık gelir?","hi":"एक मोटरसाइकिल के लिए तीन लेन स्थितियाँ लेन के किन हिस्सों से मेल खाती हैं?","ar":"مواضع الحارة الثلاثة للدراجة النارية تقابل أي أجزاء من الحارة؟"},"o":[{"en":"Only the painted lane lines on each side","es":"Solo las líneas pintadas del carril a cada lado","ru":"Только окрашенной разметке полосы с каждой стороны","tr":"Yalnızca her iki yandaki boyalı şerit çizgileri","hi":"केवल हर तरफ की रंगी हुई लेन लाइनें","ar":"فقط خطوط الحارة المطلية على كل جانب"},{"en":"The shoulder, the center, and the oncoming lane","es":"El acotamiento, el centro y el carril en sentido contrario","ru":"Обочине, центру и встречной полосе","tr":"Banket, orta ve karşı şerit","hi":"कंधा, केंद्र, और सामने से आने वाली लेन","ar":"الكتف، والوسط، والحارة المقابلة"},{"en":"The left, center, and right thirds of the lane","es":"Los tercios izquierdo, central y derecho del carril","ru":"Левой, центральной и правой третям полосы","tr":"Şeridin sol, orta ve sağ üçte birleri","hi":"लेन के बाएं, केंद्र, और दाएं तिहाई","ar":"الأثلاث اليسرى والوسطى واليمنى من الحارة"},{"en":"The front, middle, and rear of the lane","es":"La parte delantera, media y trasera del carril","ru":"Передней, средней и задней частям полосы","tr":"Şeridin önü, ortası ve arkası","hi":"लेन के आगे, बीच, और पीछे","ar":"الجزء الأمامي والأوسط والخلفي من الحارة"}],"e":{"en":"The three paths of travel are the left third, center third, and right third of the lane. A rider chooses among them to see, be seen, and keep a space cushion. Source: Motorcycle Operator Manual.","es":"Las tres trayectorias de circulación son el tercio izquierdo, el tercio central y el tercio derecho del carril. El conductor elige entre ellas para ver, ser visto y mantener un colchón de espacio. Fuente: Manual del Operador de Motocicletas.","ru":"Три траектории движения — это левая треть, центральная треть и правая треть полосы. Мотоциклист выбирает между ними, чтобы видеть, быть видимым и сохранять запас пространства. Источник: Руководство мотоциклиста.","tr":"Üç sürüş yolu, şeridin sol üçte biri, orta üçte biri ve sağ üçte biridir. Sürücü, görmek, görülmek ve bir mesafe boşluğu korumak için bunların arasından seçim yapar. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"तीन यात्रा पथ लेन के बाएं तिहाई, केंद्र तिहाई, और दाएं तिहाई हैं। एक राइडर देखने, दिखने और एक स्पेस कुशन बनाए रखने के लिए इनमें से चुनता है। स्रोत: Motorcycle Operator Manual।","ar":"مسارات السير الثلاثة هي الثلث الأيسر والثلث الأوسط والثلث الأيمن من الحارة. يختار السائق من بينها ليرى، ويُرى، ويحافظ على هامش مساحة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"Why can the center portion of a traffic lane sometimes be slippery?","es":"¿Por qué la porción central de un carril de tráfico a veces puede ser resbaladiza?","ru":"Почему центральная часть полосы движения иногда может быть скользкой?","tr":"Bir trafik şeridinin orta kısmı bazen neden kaygan olabilir?","hi":"ट्रैफ़िक लेन का केंद्रीय हिस्सा कभी-कभी फिसलन भरा क्यों हो सकता है?","ar":"لماذا يمكن للجزء الأوسط من الحارة المرورية أن يكون زلقًا أحيانًا؟"},"o":[{"en":"It is paved with a smoother material than the rest of the lane","es":"Está pavimentada con un material más liso que el resto del carril","ru":"Она вымощена более гладким материалом, чем остальная полоса","tr":"Şeridin geri kalanından daha pürüzsüz bir malzemeyle kaplanmıştır","hi":"यह बाकी लेन की तुलना में अधिक चिकनी सामग्री से बना होता है","ar":"لأنه مرصوف بمادة أنعم من بقية الحارة"},{"en":"Rain always pools in the center of the lane","es":"La lluvia siempre se acumula en el centro del carril","ru":"Дождь всегда скапливается в центре полосы","tr":"Yağmur her zaman şeridin ortasında birikir","hi":"बारिश हमेशा लेन के केंद्र में जमा होती है","ar":"لأن المطر يتجمع دائمًا في وسط الحارة"},{"en":"It collects an oily strip of drippings from cars","es":"Acumula una franja aceitosa de goteos de los autos","ru":"Там собирается масляная полоса от подтёков с машин","tr":"Otomobillerden damlayan yağlı bir şerit toplar","hi":"यह कारों की टपकती बूँदों की एक तैलीय पट्टी जमा करता है","ar":"لأنه يجمع شريطًا زيتيًا من قطرات السيارات"},{"en":"Lane paint is applied down the center of every lane","es":"La pintura del carril se aplica por el centro de cada carril","ru":"Разметка полосы наносится по центру каждой полосы","tr":"Her şeridin ortasına şerit boyası uygulanır","hi":"हर लेन के केंद्र में लेन पेंट लगाया जाता है","ar":"لأن طلاء الحارة يُطبّق في وسط كل حارة"}],"e":{"en":"The center portion can collect an oily strip from drippings left by cars. The manual notes this strip is usually no more than two feet wide and, unless the road is wet, still allows adequate traction. Source: Motorcycle Operator Manual.","es":"La porción central puede acumular una franja aceitosa de goteos dejados por los autos. El manual señala que esta franja por lo general no mide más de dos pies de ancho y, a menos que la carretera esté mojada, aún permite tracción adecuada. Fuente: Manual del Operador de Motocicletas.","ru":"В центральной части может собираться масляная полоса от подтёков, оставленных машинами. Руководство отмечает, что эта полоса обычно не шире двух футов и, если дорога не мокрая, всё равно обеспечивает достаточное сцепление. Источник: Руководство мотоциклиста.","tr":"Orta kısım, otomobillerin bıraktığı damlamalardan oluşan yağlı bir şerit toplayabilir. Kılavuz, bu şeridin genellikle iki fitten geniş olmadığını ve yol ıslak olmadıkça yine de yeterli tutuş sağladığını belirtir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"केंद्रीय हिस्सा कारों द्वारा छोड़ी गई टपकती बूँदों से एक तैलीय पट्टी जमा कर सकता है। मैनुअल नोट करता है कि यह पट्टी आमतौर पर 2 फ़ुट से अधिक चौड़ी नहीं होती और, जब तक सड़क गीली न हो, फिर भी पर्याप्त ट्रैक्शन देती है। स्रोत: Motorcycle Operator Manual।","ar":"يمكن للجزء الأوسط أن يجمع شريطًا زيتيًا من القطرات التي تتركها السيارات. يشير الدليل إلى أن هذا الشريط عادةً لا يزيد عرضه عن قدمين، وما لم يكن الطريق مبللًا، فإنه لا يزال يتيح التصاقًا كافيًا. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"According to the manual, the oily strip in the center of a lane is usually no more than about:","es":"Según el manual, la franja aceitosa en el centro de un carril por lo general no mide más de aproximadamente:","ru":"Согласно руководству, масляная полоса в центре полосы движения обычно не шире примерно:","tr":"Kılavuza göre, bir şeridin ortasındaki yağlı şerit genellikle en fazla yaklaşık ne kadardır?","hi":"मैनुअल के अनुसार, एक लेन के केंद्र में तैलीय पट्टी आमतौर पर लगभग कितनी से अधिक नहीं होती:","ar":"وفقًا للدليل، فإن الشريط الزيتي في وسط الحارة عادةً لا يزيد عن نحو:"},"o":[{"en":"Six inches wide","es":"Seis pulgadas de ancho","ru":"Шести дюймов","tr":"Altı inç genişliğinde","hi":"6 इंच चौड़ी","ar":"ست بوصات عرضًا"},{"en":"Six feet wide","es":"Seis pies de ancho","ru":"Шести футов","tr":"Altı fit genişliğinde","hi":"6 फ़ुट चौड़ी","ar":"ستة أقدام عرضًا"},{"en":"Two feet wide","es":"Dos pies de ancho","ru":"Двух футов","tr":"İki fit genişliğinde","hi":"2 फ़ुट चौड़ी","ar":"قدمين عرضًا"},{"en":"The full width of the lane","es":"El ancho completo del carril","ru":"Всей ширины полосы","tr":"Şeridin tam genişliğinde","hi":"लेन की पूरी चौड़ाई","ar":"عرض الحارة الكامل"}],"e":{"en":"The manual states the oily strip that collects car drippings is usually no more than two feet wide, leaving room on either side to ride safely within the center portion. Source: Motorcycle Operator Manual.","es":"El manual indica que la franja aceitosa que acumula los goteos de los autos por lo general no mide más de dos pies de ancho, dejando espacio a cada lado para conducir de forma segura dentro de la porción central. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство утверждает, что масляная полоса, собирающая подтёки с машин, обычно не шире двух футов, оставляя место по обе стороны, чтобы безопасно ехать в пределах центральной части. Источник: Руководство мотоциклиста.","tr":"Kılavuz, otomobil damlamalarını toplayan yağlı şeridin genellikle iki fitten geniş olmadığını, orta kısımda güvenle sürmek için her iki yanda yer bıraktığını belirtir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल बताता है कि कारों की टपकती बूँदें जमा करने वाली तैलीय पट्टी आमतौर पर 2 फ़ुट से अधिक चौड़ी नहीं होती, जिससे केंद्रीय हिस्से के भीतर सुरक्षित रूप से राइड करने के लिए दोनों ओर जगह बचती है। स्रोत: Motorcycle Operator Manual।","ar":"ينص الدليل على أن الشريط الزيتي الذي يجمع قطرات السيارات عادةً لا يزيد عرضه عن قدمين، مما يترك مجالًا على أي من الجانبين للقيادة بأمان ضمن الجزء الأوسط. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"Is it safe to ride in the center portion of a lane despite the oily strip?","es":"¿Es seguro conducir en la porción central de un carril a pesar de la franja aceitosa?","ru":"Безопасно ли ехать в центральной части полосы, несмотря на масляную полосу?","tr":"Yağlı şeride rağmen bir şeridin orta kısmında sürmek güvenli midir?","hi":"तैलीय पट्टी के बावजूद लेन के केंद्रीय हिस्से में राइड करना सुरक्षित है?","ar":"هل من الآمن القيادة في الجزء الأوسط من الحارة رغم الشريط الزيتي؟"},"o":[{"en":"No, you must never ride in the center portion of any lane","es":"No, nunca debes conducir en la porción central de ningún carril","ru":"Нет, никогда нельзя ехать в центральной части любой полосы","tr":"Hayır, hiçbir şeridin orta kısmında asla sürmemelisiniz","hi":"नहीं, आपको कभी भी किसी लेन के केंद्रीय हिस्से में राइड नहीं करना चाहिए","ar":"لا، يجب ألا تقود أبدًا في الجزء الأوسط من أي حارة"},{"en":"Yes, unless the road is wet the center strip usually permits adequate traction","es":"Sí, a menos que la carretera esté mojada, la franja central por lo general permite tracción adecuada","ru":"Да, если дорога не мокрая, центральная полоса обычно обеспечивает достаточное сцепление","tr":"Evet, yol ıslak olmadıkça orta şerit genellikle yeterli tutuş sağlar","hi":"हाँ, जब तक सड़क गीली न हो, केंद्रीय पट्टी आमतौर पर पर्याप्त ट्रैक्शन देती है","ar":"نعم، ما لم يكن الطريق مبللًا، فالشريط الأوسط عادةً يتيح التصاقًا كافيًا"},{"en":"Only at night when the oil has cooled and hardened","es":"Solo de noche, cuando el aceite se ha enfriado y endurecido","ru":"Только ночью, когда масло остыло и затвердело","tr":"Yalnızca gece yağ soğuyup sertleştiğinde","hi":"केवल रात में जब तेल ठंडा होकर सख्त हो गया हो","ar":"فقط ليلًا عندما يكون الزيت قد برد وتصلّب"},{"en":"Only if you ride exactly down the middle of the oily strip","es":"Solo si conduces exactamente por el medio de la franja aceitosa","ru":"Только если ехать точно по середине масляной полосы","tr":"Yalnızca tam olarak yağlı şeridin ortasından sürerseniz","hi":"केवल यदि आप ठीक तैलीय पट्टी के बीचों-बीच राइड करें","ar":"فقط إذا قُدت تمامًا في منتصف الشريط الزيتي"}],"e":{"en":"The manual says that unless the road is wet, the average center strip permits adequate traction to ride on safely, and you can ride to the left or right of the grease strip and still be in the center portion. Source: Motorcycle Operator Manual.","es":"El manual dice que, a menos que la carretera esté mojada, la franja central promedio permite tracción adecuada para conducir con seguridad, y puedes conducir a la izquierda o a la derecha de la franja de grasa y seguir estando en la porción central. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство говорит, что если дорога не мокрая, средняя центральная полоса обеспечивает достаточное сцепление для безопасной езды, и вы можете ехать левее или правее масляной полосы и всё равно находиться в центральной части. Источник: Руководство мотоциклиста.","tr":"Kılavuz, yol ıslak olmadıkça ortalama orta şeridin güvenle sürmek için yeterli tutuş sağladığını ve yağ şeridinin soluna ya da sağına sürüp yine de orta kısımda kalabileceğinizi söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल कहता है कि जब तक सड़क गीली न हो, औसत केंद्रीय पट्टी सुरक्षित रूप से राइड करने के लिए पर्याप्त ट्रैक्शन देती है, और आप ग्रीस पट्टी के बाएं या दाएं राइड कर सकते हैं और फिर भी केंद्रीय हिस्से में रह सकते हैं। स्रोत: Motorcycle Operator Manual।","ar":"يقول الدليل إنه ما لم يكن الطريق مبللًا، فإن الشريط الأوسط المتوسط يتيح التصاقًا كافيًا للقيادة بأمان، ويمكنك القيادة على يسار أو يمين شريط الشحم وتبقى ضمن الجزء الأوسط. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"How should you choose which lane position to ride in?","es":"¿Cómo debes elegir en qué posición de carril conducir?","ru":"Как следует выбирать, в каком положении полосы ехать?","tr":"Hangi şerit konumunda süreceğinizi nasıl seçmelisiniz?","hi":"आपको कौन सी लेन स्थिति में राइड करना है, यह कैसे चुनना चाहिए?","ar":"كيف يجب أن تختار موضع الحارة الذي تقود فيه؟"},"o":[{"en":"Always ride in the right portion of the lane no matter the situation","es":"Conduce siempre en la porción derecha del carril sin importar la situación","ru":"Всегда ехать в правой части полосы, независимо от ситуации","tr":"Durum ne olursa olsun her zaman şeridin sağ kısmında sürün","hi":"स्थिति चाहे जो हो, हमेशा लेन के दाएं हिस्से में राइड करें","ar":"قُد دائمًا في الجزء الأيمن من الحارة مهما كان الوضع"},{"en":"Always ride exactly in the center of every lane","es":"Conduce siempre exactamente en el centro de cada carril","ru":"Всегда ехать точно по центру каждой полосы","tr":"Her zaman tam olarak her şeridin ortasında sürün","hi":"हमेशा हर लेन के ठीक केंद्र में राइड करें","ar":"قُد دائمًا في وسط كل حارة بالضبط"},{"en":"Choose the position that lets you travel fastest","es":"Elige la posición que te permita avanzar más rápido","ru":"Выбирать положение, позволяющее ехать быстрее всего","tr":"En hızlı gitmenizi sağlayan konumu seçin","hi":"वह स्थिति चुनें जो आपको सबसे तेज़ चलने दे","ar":"اختر الموضع الذي يتيح لك السير أسرع"},{"en":"Pick whatever portion of the lane best helps you see, be seen, and keep a space cushion","es":"Elige la porción del carril que mejor te ayude a ver, ser visto y mantener un colchón de espacio","ru":"Выбирать ту часть полосы, которая лучше всего помогает видеть, быть видимым и сохранять запас пространства","tr":"Görmenize, görülmenize ve bir mesafe boşluğu korumanıza en iyi yardımcı olan şerit kısmını seçin","hi":"लेन का वह हिस्सा चुनें जो आपको सबसे अच्छी तरह देखने, दिखने और एक स्पेस कुशन बनाए रखने में मदद करे","ar":"اختر الجزء من الحارة الأنسب لمساعدتك على أن ترى، وتُرى، وتحافظ على هامش مساحة"}],"e":{"en":"There is no single best lane position. The manual says to change to whatever portion of the lane is best able to help you see, be seen, and maintain an adequate space cushion as conditions change. Source: Motorcycle Operator Manual.","es":"No hay una única mejor posición de carril. El manual dice que cambies a la porción del carril que mejor te ayude a ver, ser visto y mantener un colchón de espacio adecuado a medida que cambian las condiciones. Fuente: Manual del Operador de Motocicletas.","ru":"Единого лучшего положения в полосе нет. Руководство говорит переходить в ту часть полосы, которая лучше всего помогает видеть, быть видимым и сохранять достаточный запас пространства по мере изменения условий. Источник: Руководство мотоциклиста.","tr":"Tek bir en iyi şerit konumu yoktur. Kılavuz, koşullar değiştikçe görmenize, görülmenize ve yeterli bir mesafe boşluğu korumanıza en iyi yardımcı olan şerit kısmına geçmenizi söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"कोई एक सर्वश्रेष्ठ लेन स्थिति नहीं है। मैनुअल कहता है कि जैसे-जैसे परिस्थितियाँ बदलती हैं, लेन के उस हिस्से में बदलें जो आपको सबसे अच्छी तरह देखने, दिखने और एक पर्याप्त स्पेस कुशन बनाए रखने में मदद करे। स्रोत: Motorcycle Operator Manual।","ar":"لا يوجد موضع حارة أفضل واحد. يقول الدليل إنه يجب التغيير إلى أي جزء من الحارة هو الأقدر على مساعدتك على أن ترى، وتُرى، وتحافظ على هامش مساحة كافٍ مع تغيّر الظروف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"If there are parked cars on your right with the danger of doors opening, which lane position is generally best?","es":"Si hay autos estacionados a tu derecha con el peligro de que se abran las puertas, ¿cuál posición de carril es generalmente la mejor?","ru":"Если справа от вас стоят припаркованные машины с опасностью открывания дверей, какое положение в полосе обычно лучше?","tr":"Sağınızda kapıların açılma tehlikesi olan park etmiş arabalar varsa, genellikle hangi şerit konumu en iyisidir?","hi":"यदि आपके दाहिनी ओर खड़ी कारें हैं और दरवाज़े खुलने का खतरा है, तो आमतौर पर कौन सी लेन स्थिति सबसे अच्छी है?","ar":"إذا كانت هناك سيارات متوقفة على يمينك مع خطر فتح الأبواب، فأي موضع حارة هو الأفضل عمومًا؟"},"o":[{"en":"The center or left portion of the lane, away from the parked cars","es":"La porción central o izquierda del carril, lejos de los autos estacionados","ru":"Центральная или левая часть полосы, в стороне от припаркованных машин","tr":"Park etmiş arabalardan uzakta, şeridin orta ya da sol kısmı","hi":"लेन का केंद्रीय या बायां हिस्सा, खड़ी कारों से दूर","ar":"الجزء الأوسط أو الأيسر من الحارة، بعيدًا عن السيارات المتوقفة"},{"en":"The right portion of the lane, close to the parked cars","es":"La porción derecha del carril, cerca de los autos estacionados","ru":"Правая часть полосы, близко к припаркованным машинам","tr":"Park etmiş arabalara yakın, şeridin sağ kısmı","hi":"लेन का दायां हिस्सा, खड़ी कारों के करीब","ar":"الجزء الأيمن من الحارة، قريبًا من السيارات المتوقفة"},{"en":"Half on the shoulder beside the parked cars","es":"A medias sobre el acotamiento junto a los autos estacionados","ru":"Наполовину на обочине рядом с припаркованными машинами","tr":"Park etmiş arabaların yanında, yarı banket","hi":"खड़ी कारों के बगल में आधा कंधे पर","ar":"نصفًا على الكتف بجانب السيارات المتوقفة"},{"en":"Wherever the oily strip is widest","es":"Donde la franja aceitosa sea más ancha","ru":"Там, где масляная полоса шире всего","tr":"Yağlı şeridin en geniş olduğu yer","hi":"जहाँ तैलीय पट्टी सबसे चौड़ी हो","ar":"حيثما يكون الشريط الزيتي أعرض"}],"e":{"en":"When a hazard such as opening car doors is on your right, the manual advises riding in the center or left portion to keep a space cushion away from the hazard on that side. Source: Motorcycle Operator Manual.","es":"Cuando hay un peligro como puertas de autos que se abren a tu derecha, el manual aconseja conducir en la porción central o izquierda para mantener un colchón de espacio lejos del peligro de ese lado. Fuente: Manual del Operador de Motocicletas.","ru":"Когда опасность, например открывающиеся двери машин, находится справа, руководство советует ехать в центральной или левой части, чтобы сохранять запас пространства в стороне от опасности с этой стороны. Источник: Руководство мотоциклиста.","tr":"Açılan araba kapıları gibi bir tehlike sağınızdayken kılavuz, o yandaki tehlikeden uzakta bir mesafe boşluğu korumak için orta ya da sol kısımda sürmeyi tavsiye eder. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"जब आपके दाहिनी ओर खुलते कार दरवाज़ों जैसा कोई खतरा हो, तो मैनुअल केंद्रीय या बाएं हिस्से में राइड करने की सलाह देता है ताकि उस ओर के खतरे से दूर एक स्पेस कुशन बना रहे। स्रोत: Motorcycle Operator Manual।","ar":"عندما يكون خطر مثل فتح أبواب السيارات على يمينك، ينصح الدليل بالقيادة في الجزء الأوسط أو الأيسر للحفاظ على هامش مساحة بعيدًا عن الخطر على ذلك الجانب. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"When vehicles are traveling on both sides of you, which lane position is usually best?","es":"Cuando hay vehículos circulando a ambos lados de ti, ¿cuál posición de carril suele ser la mejor?","ru":"Когда транспорт движется по обе стороны от вас, какое положение в полосе обычно лучше?","tr":"Her iki yanınızda araçlar giderken genellikle hangi şerit konumu en iyisidir?","hi":"जब वाहन आपके दोनों ओर चल रहे हों, तो आमतौर पर कौन सी लेन स्थिति सबसे अच्छी है?","ar":"عندما تسير المركبات على جانبيك، أي موضع حارة هو الأفضل عادةً؟"},"o":[{"en":"The far left portion of the lane","es":"La porción más a la izquierda del carril","ru":"Крайняя левая часть полосы","tr":"Şeridin en sol kısmı","hi":"लेन का सबसे बायां हिस्सा","ar":"الجزء الأقصى يسارًا من الحارة"},{"en":"The center portion of the lane","es":"La porción central del carril","ru":"Центральная часть полосы","tr":"Şeridin orta kısmı","hi":"लेन का केंद्रीय हिस्सा","ar":"الجزء الأوسط من الحارة"},{"en":"The far right portion of the lane","es":"La porción más a la derecha del carril","ru":"Крайняя правая часть полосы","tr":"Şeridin en sağ kısmı","hi":"लेन का सबसे दायां हिस्सा","ar":"الجزء الأقصى يمينًا من الحارة"},{"en":"Straddling the lane line nearest the slower vehicle","es":"A horcajadas sobre la línea del carril más cercana al vehículo más lento","ru":"По разметке полосы ближе к более медленному транспорту","tr":"Daha yavaş araca en yakın şerit çizgisine biniş","hi":"धीमे वाहन के सबसे नज़दीक की लेन लाइन पर सवार होकर","ar":"التمركز على خط الحارة الأقرب إلى المركبة الأبطأ"}],"e":{"en":"When vehicles are on both sides of you, the center portion of the lane is usually your best option because it keeps a cushion of space on each side. Source: Motorcycle Operator Manual.","es":"Cuando hay vehículos a ambos lados de ti, la porción central del carril suele ser tu mejor opción porque mantiene un colchón de espacio a cada lado. Fuente: Manual del Operador de Motocicletas.","ru":"Когда транспорт находится по обе стороны от вас, центральная часть полосы обычно ваш лучший вариант, потому что она сохраняет запас пространства с каждой стороны. Источник: Руководство мотоциклиста.","tr":"Her iki yanınızda araçlar varken, şeridin orta kısmı genellikle en iyi seçeneğinizdir çünkü her iki yanda bir mesafe boşluğu korur. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"जब वाहन आपके दोनों ओर हों, तो लेन का केंद्रीय हिस्सा आमतौर पर आपका सबसे अच्छा विकल्प होता है क्योंकि यह हर तरफ जगह का कुशन बनाए रखता है। स्रोत: Motorcycle Operator Manual।","ar":"عندما تكون المركبات على جانبيك، يكون الجزء الأوسط من الحارة عادةً خيارك الأفضل لأنه يحافظ على هامش مساحة على كل جانب. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"How does lane position relate to being seen by the driver ahead of you?","es":"¿Cómo se relaciona la posición de carril con ser visto por el conductor que va delante de ti?","ru":"Как положение в полосе связано с тем, видит ли вас водитель впереди?","tr":"Şerit konumu, önünüzdeki sürücü tarafından görülmenizle nasıl ilişkilidir?","hi":"लेन स्थिति का आपके आगे वाले ड्राइवर द्वारा देखे जाने से क्या संबंध है?","ar":"كيف يرتبط موضع الحارة برؤية السائق الذي أمامك لك؟"},"o":[{"en":"Lane position has no effect on whether drivers can see you","es":"La posición de carril no influye en si los conductores pueden verte","ru":"Положение в полосе никак не влияет на то, могут ли водители вас видеть","tr":"Şerit konumunun, sürücülerin sizi görüp görmemesinde hiçbir etkisi yoktur","hi":"लेन स्थिति का इस पर कोई प्रभाव नहीं कि ड्राइवर आपको देख सकते हैं या नहीं","ar":"موضع الحارة لا يؤثر على ما إذا كان السائقون يرونك"},{"en":"Riding on the far edge of the lane makes you most visible in mirrors","es":"Conducir en el borde más alejado del carril te hace más visible en los espejos","ru":"Езда по крайнему краю полосы делает вас наиболее заметным в зеркалах","tr":"Şeridin en dış kenarında sürmek sizi aynalarda en görünür kılar","hi":"लेन के सबसे बाहरी किनारे पर राइड करना आपको मिरर में सबसे अधिक दृश्यमान बनाता है","ar":"القيادة على الحافة القصوى للحارة تجعلك أكثر وضوحًا في المرايا"},{"en":"Being seen depends only on your headlight, not your position","es":"Ser visto depende solo de tu faro, no de tu posición","ru":"Видимость зависит только от вашей фары, а не от положения","tr":"Görülmek yalnızca farınıza bağlıdır, konumunuza değil","hi":"देखे जाना केवल आपकी हेडलाइट पर निर्भर करता है, आपकी स्थिति पर नहीं","ar":"الرؤية تعتمد فقط على مصباحك الأمامي، لا على موضعك"},{"en":"Riding in the center portion can place your image in the middle of the driver's rearview mirror where you are most likely to be seen","es":"Conducir en la porción central puede colocar tu imagen en el medio del espejo retrovisor del conductor, donde es más probable que te vea","ru":"Езда в центральной части может поместить ваше изображение в середину зеркала заднего вида водителя, где вас вероятнее всего заметят","tr":"Orta kısımda sürmek, görüntünüzü sürücünün dikiz aynasının ortasına, sizi en çok fark edebileceği yere yerleştirebilir","hi":"केंद्रीय हिस्से में राइड करना आपकी छवि को ड्राइवर के रियरव्यू मिरर के बीच में रख सकता है जहाँ आप सबसे अधिक देखे जाने की संभावना रखते हैं","ar":"القيادة في الجزء الأوسط قد تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق حيث يُرجَّح أكثر أن يراك"}],"e":{"en":"The manual notes that riding in the center portion places your image in the middle of a driver's rearview mirror, the spot where a driver is most likely to notice you. Lane position is a tool to be seen. Source: Motorcycle Operator Manual.","es":"El manual señala que conducir en la porción central coloca tu imagen en el medio del espejo retrovisor de un conductor, el lugar donde es más probable que un conductor te note. La posición de carril es una herramienta para ser visto. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство отмечает, что езда в центральной части помещает ваше изображение в середину зеркала заднего вида водителя — место, где водитель вероятнее всего вас заметит. Положение в полосе — это инструмент, чтобы быть видимым. Источник: Руководство мотоциклиста.","tr":"Kılavuz, orta kısımda sürmenin görüntünüzü sürücünün dikiz aynasının ortasına, bir sürücünün sizi fark etme olasılığının en yüksek olduğu noktaya yerleştirdiğini belirtir. Şerit konumu, görülmek için bir araçtır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल नोट करता है कि केंद्रीय हिस्से में राइड करना आपकी छवि को ड्राइवर के रियरव्यू मिरर के बीच में रखता है, वह स्थान जहाँ ड्राइवर आपको नोटिस करने की सबसे अधिक संभावना रखता है। लेन स्थिति दिखने का एक साधन है। स्रोत: Motorcycle Operator Manual।","ar":"يشير الدليل إلى أن القيادة في الجزء الأوسط تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق، وهو الموضع الذي يُرجَّح فيه أكثر أن يلاحظك السائق. موضع الحارة أداة لكي تُرى. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"What is the minimum following distance the manual recommends behind the vehicle ahead under normal conditions?","es":"¿Cuál es la distancia mínima de seguimiento que recomienda el manual detrás del vehículo de adelante en condiciones normales?","ru":"Какую минимальную дистанцию следования за впереди идущим транспортом рекомендует руководство в обычных условиях?","tr":"Kılavuz, normal koşullarda önünüzdeki araçtan en az ne kadar takip mesafesi önerir?","hi":"सामान्य परिस्थितियों में मैनुअल आगे वाले वाहन के पीछे न्यूनतम कितनी फॉलोइंग दूरी की सिफारिश करता है?","ar":"ما هي مسافة الاتباع الدنيا التي يوصي بها الدليل خلف المركبة الأمامية في الظروف العادية؟"},"o":[{"en":"Two seconds","es":"Dos segundos","ru":"Две секунды","tr":"İki saniye","hi":"2 सेकंड","ar":"ثانيتان"},{"en":"Half a second","es":"Medio segundo","ru":"Полсекунды","tr":"Yarım saniye","hi":"आधा सेकंड","ar":"نصف ثانية"},{"en":"One car length per 10 mph","es":"Una longitud de auto por cada 10 mph","ru":"Одна длина машины на каждые 10 миль/ч","tr":"Her 10 mil/sa için bir araç boyu","hi":"प्रति 10 mph एक कार की लंबाई","ar":"طول سيارة واحد لكل 10 ميلاً في الساعة"},{"en":"Ten seconds","es":"Diez segundos","ru":"Десять секунд","tr":"On saniye","hi":"10 सेकंड","ar":"عشر ثوانٍ"}],"e":{"en":"The manual recommends keeping a minimum of two seconds of following distance behind the vehicle ahead to give yourself room to react and stop. Source: Motorcycle Operator Manual.","es":"El manual recomienda mantener un mínimo de dos segundos de distancia de seguimiento detrás del vehículo de adelante para darte espacio para reaccionar y detenerte. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство рекомендует держать минимум две секунды дистанции следования за впереди идущим транспортом, чтобы дать себе место отреагировать и остановиться. Источник: Руководство мотоциклиста.","tr":"Kılavuz, tepki vermek ve durmak için kendinize alan tanımak amacıyla önünüzdeki araçtan en az iki saniye takip mesafesi bırakmanızı önerir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल आगे वाले वाहन के पीछे न्यूनतम 2 सेकंड की फॉलोइंग दूरी रखने की सिफारिश करता है ताकि आपको प्रतिक्रिया करने और रुकने के लिए जगह मिल सके। स्रोत: Motorcycle Operator Manual।","ar":"يوصي الدليل بالحفاظ على ثانيتين كحد أدنى من مسافة الاتباع خلف المركبة الأمامية لتمنح نفسك مجالًا للتفاعل والتوقف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"When should you increase your following distance to more than two seconds?","es":"¿Cuándo debes aumentar tu distancia de seguimiento a más de dos segundos?","ru":"Когда следует увеличить дистанцию следования более чем до двух секунд?","tr":"Takip mesafenizi ne zaman iki saniyenin üzerine çıkarmalısınız?","hi":"आपको अपनी फॉलोइंग दूरी 2 सेकंड से अधिक कब बढ़ानी चाहिए?","ar":"متى يجب أن تزيد مسافة اتباعك إلى أكثر من ثانيتين؟"},"o":[{"en":"Only on dry, clear, open highways","es":"Solo en autopistas secas, despejadas y abiertas","ru":"Только на сухих, ясных, открытых трассах","tr":"Yalnızca kuru, açık, geniş otoyollarda","hi":"केवल सूखे, साफ़, खुले राजमार्गों पर","ar":"فقط على الطرق السريعة الجافة الصافية المفتوحة"},{"en":"Never; two seconds is always enough in every condition","es":"Nunca; dos segundos siempre es suficiente en toda condición","ru":"Никогда; двух секунд всегда достаточно в любых условиях","tr":"Asla; iki saniye her koşulda her zaman yeterlidir","hi":"कभी नहीं; 2 सेकंड हर परिस्थिति में हमेशा पर्याप्त है","ar":"أبدًا؛ فثانيتان كافيتان دائمًا في كل الظروف"},{"en":"Only when you are leading a group of riders","es":"Solo cuando lideras un grupo de conductores","ru":"Только когда вы ведёте группу мотоциклистов","tr":"Yalnızca bir sürücü grubuna liderlik ederken","hi":"केवल जब आप राइडर्स के एक समूह का नेतृत्व कर रहे हों","ar":"فقط عندما تقود مجموعة من السائقين"},{"en":"On slippery roads, in poor visibility, or in heavy traffic","es":"En carreteras resbaladizas, con poca visibilidad o con tráfico intenso","ru":"На скользких дорогах, при плохой видимости или в плотном трафике","tr":"Kaygan yollarda, kötü görüşte ya da yoğun trafikte","hi":"फिसलन भरी सड़कों पर, खराब दृश्यता में, या भारी ट्रैफ़िक में","ar":"على الطرق الزلقة، أو في الرؤية الضعيفة، أو في حركة المرور الكثيفة"}],"e":{"en":"Two seconds is the minimum under ideal conditions. The manual advises a larger cushion (three seconds or more) when the road is slippery, visibility is reduced, or traffic is heavy. Source: Motorcycle Operator Manual.","es":"Dos segundos es el mínimo en condiciones ideales. El manual aconseja un colchón mayor (tres segundos o más) cuando la carretera está resbaladiza, la visibilidad es reducida o el tráfico es intenso. Fuente: Manual del Operador de Motocicletas.","ru":"Две секунды — это минимум в идеальных условиях. Руководство советует больший запас (три секунды или больше), когда дорога скользкая, видимость снижена или трафик плотный. Источник: Руководство мотоциклиста.","tr":"İki saniye, ideal koşullarda asgari süredir. Kılavuz, yol kaygan olduğunda, görüş azaldığında ya da trafik yoğun olduğunda daha büyük bir boşluk (üç saniye ya da daha fazla) bırakmayı tavsiye eder. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"आदर्श परिस्थितियों में 2 सेकंड न्यूनतम है। मैनुअल सलाह देता है कि जब सड़क फिसलन भरी हो, दृश्यता कम हो, या ट्रैफ़िक भारी हो तो एक बड़ा कुशन (3 सेकंड या अधिक) रखें। स्रोत: Motorcycle Operator Manual।","ar":"ثانيتان هما الحد الأدنى في الظروف المثالية. ينصح الدليل بهامش أكبر (ثلاث ثوانٍ أو أكثر) عندما يكون الطريق زلقًا، أو الرؤية منخفضة، أو حركة المرور كثيفة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"Why is keeping a space cushion around your motorcycle important?","es":"¿Por qué es importante mantener un colchón de espacio alrededor de tu motocicleta?","ru":"Почему важно сохранять запас пространства вокруг мотоцикла?","tr":"Motosikletinizin çevresinde bir mesafe boşluğu korumak neden önemlidir?","hi":"अपनी मोटरसाइकिल के चारों ओर एक स्पेस कुशन रखना क्यों महत्वपूर्ण है?","ar":"لماذا يُعد الحفاظ على هامش مساحة حول دراجتك النارية مهمًا؟"},"o":[{"en":"It gives you time and room to see hazards and react or maneuver safely","es":"Te da tiempo y espacio para ver peligros y reaccionar o maniobrar de forma segura","ru":"Это даёт вам время и место, чтобы видеть опасности и безопасно реагировать или маневрировать","tr":"Tehlikeleri görmeniz ve güvenle tepki verip manevra yapmanız için size zaman ve alan tanır","hi":"यह आपको खतरों को देखने और सुरक्षित रूप से प्रतिक्रिया करने या युद्धाभ्यास करने के लिए समय और जगह देता है","ar":"لأنه يمنحك وقتًا ومجالًا لرؤية المخاطر والتفاعل أو المناورة بأمان"},{"en":"It guarantees other drivers will always yield to you","es":"Garantiza que otros conductores siempre te cederán el paso","ru":"Это гарантирует, что другие водители всегда вас пропустят","tr":"Diğer sürücülerin size her zaman yol vereceğini garanti eder","hi":"यह गारंटी देता है कि अन्य ड्राइवर हमेशा आपको रास्ता देंगे","ar":"لأنه يضمن أن السائقين الآخرين سيفسحون لك دائمًا"},{"en":"It allows you to ride faster than surrounding traffic","es":"Te permite conducir más rápido que el tráfico que te rodea","ru":"Это позволяет ехать быстрее окружающего трафика","tr":"Çevredeki trafikten daha hızlı sürmenizi sağlar","hi":"यह आपको आसपास के ट्रैफ़िक से तेज़ राइड करने देता है","ar":"لأنه يتيح لك القيادة أسرع من حركة المرور المحيطة"},{"en":"It is only required when riding in a group","es":"Solo se exige al conducir en grupo","ru":"Это требуется только при езде в группе","tr":"Yalnızca grup halinde sürerken zorunludur","hi":"यह केवल समूह में राइड करते समय आवश्यक है","ar":"لأنه مطلوب فقط عند القيادة في مجموعة"}],"e":{"en":"Maintaining a space cushion on all sides gives you the time and space to spot hazards, brake, or change position to avoid trouble. The manual stresses adjusting position to keep that cushion as traffic changes. Source: Motorcycle Operator Manual.","es":"Mantener un colchón de espacio en todos los lados te da el tiempo y el espacio para detectar peligros, frenar o cambiar de posición para evitar problemas. El manual recalca ajustar la posición para mantener ese colchón a medida que cambia el tráfico. Fuente: Manual del Operador de Motocicletas.","ru":"Сохранение запаса пространства со всех сторон даёт вам время и место, чтобы заметить опасности, затормозить или сменить положение во избежание неприятностей. Руководство подчёркивает корректировку положения для сохранения этого запаса по мере изменения трафика. Источник: Руководство мотоциклиста.","tr":"Her yönde bir mesafe boşluğu korumak, tehlikeleri fark etmeniz, frenlemeniz ya da sorundan kaçınmak için konum değiştirmeniz için size zaman ve alan tanır. Kılavuz, trafik değiştikçe bu boşluğu korumak için konumu ayarlamayı vurgular. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"हर तरफ एक स्पेस कुशन बनाए रखना आपको खतरों को पहचानने, ब्रेक लगाने, या मुसीबत से बचने के लिए स्थिति बदलने का समय और जगह देता है। मैनुअल जैसे-जैसे ट्रैफ़िक बदलता है, उस कुशन को बनाए रखने के लिए स्थिति समायोजित करने पर ज़ोर देता है। स्रोत: Motorcycle Operator Manual।","ar":"الحفاظ على هامش مساحة على جميع الجوانب يمنحك الوقت والمجال لرصد المخاطر، أو الفرملة، أو تغيير الموضع لتفادي المشاكل. يشدد الدليل على ضبط الموضع للحفاظ على ذلك الهامش مع تغيّر حركة المرور. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"visibility","a":3,"q":{"en":"In the SEE strategy taught in the Motorcycle Operator Manual, what do the three letters stand for?","es":"En la estrategia SEE que se enseña en el Manual del Operador de Motocicletas, ¿qué representan las tres letras?","ru":"В стратегии SEE, которой учит Руководство мотоциклиста, что означают эти три буквы?","tr":"Motosiklet Kullanıcı Kılavuzu'nda öğretilen SEE stratejisinde üç harf neyi ifade eder?","hi":"Motorcycle Operator Manual में सिखाई गई SEE रणनीति में, इन तीन अक्षरों का क्या अर्थ है?","ar":"في استراتيجية SEE التي يعلّمها دليل مشغّل الدراجة النارية، ماذا ترمز الأحرف الثلاثة؟"},"o":[{"en":"Stop, Examine, Enter","es":"Detente (Stop), Examina (Examine), Entra (Enter)","ru":"Stop, Examine, Enter (Остановись, Изучи, Войди)","tr":"Dur, İncele, Gir (Stop, Examine, Enter)","hi":"Stop, Examine, Enter","ar":"توقّف، افحص، ادخل"},{"en":"Scan, Estimate, Exit","es":"Escanea (Scan), Estima (Estimate), Sal (Exit)","ru":"Scan, Estimate, Exit (Просканируй, Оцени, Выйди)","tr":"Tara, Tahmin Et, Çık (Scan, Estimate, Exit)","hi":"Scan, Estimate, Exit","ar":"امسح، قدّر، اخرج"},{"en":"Slow, Engage, Escape","es":"Reduce (Slow), Involúcrate (Engage), Escapa (Escape)","ru":"Slow, Engage, Escape (Замедлись, Включись, Уйди)","tr":"Yavaşla, Devreye Gir, Kaç (Slow, Engage, Escape)","hi":"Slow, Engage, Escape","ar":"أبطئ، اشتبك، اهرب"},{"en":"Search, Evaluate, Execute","es":"Busca (Search), Evalúa (Evaluate), Ejecuta (Execute)","ru":"Search, Evaluate, Execute (Ищи, Оценивай, Действуй)","tr":"Ara, Değerlendir, Uygula (Search, Evaluate, Execute)","hi":"Search, Evaluate, Execute","ar":"ابحث، قيّم، نفّذ"}],"e":{"en":"SEE is a three-step process for making safe decisions in traffic: Search, Evaluate, and Execute, as described in the Motorcycle Operator Manual.","es":"SEE es un proceso de tres pasos para tomar decisiones seguras en el tráfico: Busca (Search), Evalúa (Evaluate) y Ejecuta (Execute), como se describe en el Manual del Operador de Motocicletas.","ru":"SEE — это трёхэтапный процесс принятия безопасных решений в трафике: Search (Ищи), Evaluate (Оценивай) и Execute (Действуй), как описано в Руководстве мотоциклиста.","tr":"SEE, trafikte güvenli kararlar vermek için üç adımlı bir süreçtir: Ara (Search), Değerlendir (Evaluate) ve Uygula (Execute); Motosiklet Kullanıcı Kılavuzu'nda açıklandığı gibi.","hi":"SEE ट्रैफ़िक में सुरक्षित निर्णय लेने के लिए एक तीन-चरण प्रक्रिया है: Search, Evaluate, और Execute, जैसा कि Motorcycle Operator Manual में वर्णित है।","ar":"SEE هي عملية من ثلاث خطوات لاتخاذ قرارات آمنة في حركة المرور: ابحث، وقيّم، ونفّذ، كما هو موصوف في دليل مشغّل الدراجة النارية."}},{"cat":"visibility","a":0,"q":{"en":"What does the 'Search' step of the SEE strategy mainly involve?","es":"¿Qué implica principalmente el paso de 'Buscar' (Search) de la estrategia SEE?","ru":"Что в основном включает в себя шаг «Поиск» (Search) стратегии SEE?","tr":"SEE stratejisinin 'Araştır' (Search) adımı esas olarak neyi içerir?","hi":"SEE रणनीति के 'Search' (खोज) चरण में मुख्य रूप से क्या शामिल होता है?","ar":"ما الذي تتضمنه خطوة 'البحث' (Search) في استراتيجية SEE بشكل رئيسي؟"},"o":[{"en":"Scanning aggressively ahead, to the sides, and behind for possible hazards","es":"Explorar activamente hacia adelante, a los lados y hacia atrás en busca de posibles peligros","ru":"Активное сканирование дороги впереди, по сторонам и сзади для выявления возможных опасностей","tr":"Olası tehlikeler için ileriyi, yanları ve arkayı dikkatlice taramayı","hi":"संभावित खतरों के लिए आगे, बगल में और पीछे की ओर सक्रियता से नज़र दौड़ाना","ar":"المسح البصري الحثيث للأمام وإلى الجانبين وإلى الخلف بحثاً عن المخاطر المحتملة"},{"en":"Choosing a faster route to your destination","es":"Elegir una ruta más rápida hacia tu destino","ru":"Выбор более быстрого маршрута к месту назначения","tr":"Hedefinize daha hızlı bir güzergah seçmeyi","hi":"अपने गंतव्य तक तेज़ रास्ता चुनना","ar":"اختيار طريق أسرع إلى وجهتك"},{"en":"Checking your fuel and tire pressure before riding","es":"Revisar el combustible y la presión de las llantas antes de conducir","ru":"Проверку топлива и давления в шинах перед поездкой","tr":"Sürüşten önce yakıt ve lastik basıncınızı kontrol etmeyi","hi":"सवारी से पहले अपना ईंधन और टायर का दबाव जाँचना","ar":"فحص الوقود وضغط الإطارات قبل القيادة"},{"en":"Looking only directly in front of your motorcycle","es":"Mirar únicamente justo frente a tu motocicleta","ru":"Наблюдение только за тем, что находится прямо перед мотоциклом","tr":"Yalnızca motosikletinizin tam önüne bakmayı","hi":"केवल अपनी मोटरसाइकिल के ठीक सामने देखना","ar":"النظر فقط إلى الأمام مباشرةً أمام دراجتك النارية"}],"e":{"en":"In the Search step, the rider scans aggressively ahead, to the sides, and behind to spot potential hazards early, per the Motorcycle Operator Manual.","es":"En el paso de Buscar, el conductor explora activamente hacia adelante, a los lados y hacia atrás para detectar peligros potenciales con anticipación, según el Manual del Operador de Motocicletas.","ru":"На шаге «Поиск» водитель активно сканирует дорогу впереди, по сторонам и сзади, чтобы заранее заметить потенциальные опасности, согласно Руководству для водителей мотоциклов.","tr":"Araştır adımında sürücü, olası tehlikeleri erkenden fark etmek için Motosiklet Sürücü Kılavuzu'na göre ileriyi, yanları ve arkayı dikkatlice tarar.","hi":"Search चरण में सवार आगे, बगल में और पीछे की ओर सक्रियता से नज़र दौड़ाता है ताकि संभावित खतरों को जल्दी पहचान सके, जैसा कि Motorcycle Operator Manual में बताया गया है।","ar":"في خطوة البحث، يقوم السائق بالمسح البصري الحثيث للأمام وإلى الجانبين وإلى الخلف لرصد المخاطر المحتملة مبكراً، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":0,"q":{"en":"Which action best fits the 'Execute' step of the SEE strategy?","es":"¿Qué acción corresponde mejor al paso de 'Ejecutar' (Execute) de la estrategia SEE?","ru":"Какое действие лучше всего соответствует шагу «Выполнение» (Execute) стратегии SEE?","tr":"Hangi eylem SEE stratejisinin 'Uygula' (Execute) adımına en iyi uyar?","hi":"कौन सी क्रिया SEE रणनीति के 'Execute' (निष्पादन) चरण से सबसे अच्छी तरह मेल खाती है?","ar":"أي إجراء يتوافق بشكل أفضل مع خطوة 'التنفيذ' (Execute) في استراتيجية SEE؟"},"o":[{"en":"Carrying out your decision by adjusting speed, position, or communicating your presence","es":"Llevar a cabo tu decisión ajustando la velocidad, la posición o comunicando tu presencia","ru":"Выполнение принятого решения путём изменения скорости, положения или обозначения своего присутствия","tr":"Hızınızı, konumunuzu ayarlayarak veya varlığınızı belirterek kararınızı hayata geçirmek","hi":"गति, स्थिति को समायोजित करके या अपनी उपस्थिति बताकर अपने निर्णय को अमल में लाना","ar":"تنفيذ قرارك عبر تعديل السرعة أو الموضع أو الإبلاغ عن وجودك"},{"en":"Thinking about how hazards might interact with one another","es":"Pensar en cómo los peligros podrían interactuar entre sí","ru":"Размышление о том, как опасности могут взаимодействовать друг с другом","tr":"Tehlikelerin birbirleriyle nasıl etkileşebileceğini düşünmek","hi":"सोचना कि खतरे एक-दूसरे के साथ कैसे टकरा सकते हैं","ar":"التفكير في كيفية تفاعل المخاطر مع بعضها البعض"},{"en":"Deciding which gear to keep your motorcycle parked in","es":"Decidir en qué cambio dejar tu motocicleta estacionada","ru":"Выбор передачи, на которой держать мотоцикл припаркованным","tr":"Motosikletinizi hangi viteste park edeceğinize karar vermek","hi":"यह तय करना कि अपनी मोटरसाइकिल को किस गियर में पार्क रखें","ar":"تحديد الترس الذي تُبقي عليه دراجتك النارية متوقفة"},{"en":"Searching the road far ahead for stopped traffic","es":"Buscar muy adelante en la vía si hay tráfico detenido","ru":"Поиск остановившегося транспорта далеко впереди на дороге","tr":"Durmuş trafik için yolun çok ilerisini taramak","hi":"रुकी हुई ट्रैफ़िक के लिए सड़क पर बहुत दूर तक खोजना","ar":"البحث في الطريق إلى الأمام البعيد عن حركة مرور متوقفة"}],"e":{"en":"Execute means carrying out your decision-adjusting speed or position and communicating with lights or horn, as described in the Motorcycle Operator Manual.","es":"Ejecutar significa llevar a cabo tu decisión —ajustar la velocidad o la posición y comunicarte con las luces o la bocina—, como se describe en el Manual del Operador de Motocicletas.","ru":"«Выполнение» означает реализацию принятого решения — изменение скорости или положения и обозначение своего присутствия светом или сигналом, как описано в Руководстве для водителей мотоциклов.","tr":"Uygula, kararınızı hayata geçirmek demektir; Motosiklet Sürücü Kılavuzu'nda açıklandığı gibi hızınızı veya konumunuzu ayarlamak ve farlar ya da kornayla iletişim kurmaktır.","hi":"Execute का मतलब है अपने निर्णय को अमल में लाना—गति या स्थिति को समायोजित करना और लाइट या हॉर्न से संवाद करना, जैसा कि Motorcycle Operator Manual में वर्णित है।","ar":"يعني التنفيذ تنفيذ قرارك عبر تعديل السرعة أو الموضع والإبلاغ عن وجودك بالأضواء أو البوق، كما هو موضح في دليل مشغل الدراجة النارية."}},{"cat":"visibility","a":2,"q":{"en":"According to the Motorcycle Operator Manual, where does the greatest potential for conflict with other traffic occur?","es":"Según el Manual del Operador de Motocicletas, ¿dónde ocurre el mayor potencial de conflicto con otro tráfico?","ru":"Согласно Руководству для водителей мотоциклов, где возникает наибольшая вероятность конфликта с другим транспортом?","tr":"Motosiklet Sürücü Kılavuzu'na göre, diğer trafikle çatışma potansiyeli en çok nerede ortaya çıkar?","hi":"Motorcycle Operator Manual के अनुसार, अन्य ट्रैफ़िक के साथ टकराव की सबसे अधिक संभावना कहाँ होती है?","ar":"وفقاً لدليل مشغل الدراجة النارية، أين تحدث أكبر احتمالية للتعارض مع حركة المرور الأخرى؟"},"o":[{"en":"On long, straight rural highways","es":"En carreteras rurales largas y rectas","ru":"На длинных прямых сельских шоссе","tr":"Uzun, düz kırsal otoyollarda","hi":"लंबे, सीधे ग्रामीण राजमार्गों पर","ar":"على الطرق السريعة الريفية الطويلة والمستقيمة"},{"en":"In parking lots while walking the bike","es":"En estacionamientos, mientras caminas con la moto","ru":"На парковках при проводке мотоцикла","tr":"Otoparklarda motosikleti iterken","hi":"पार्किंग लॉट में बाइक को पैदल ले जाते समय","ar":"في مواقف السيارات أثناء دفع الدراجة سيراً"},{"en":"At intersections","es":"En las intersecciones","ru":"На перекрёстках","tr":"Kavşaklarda","hi":"चौराहों पर","ar":"عند التقاطعات"},{"en":"On freeway on-ramps merging right","es":"En las rampas de acceso a la autopista al incorporarse por la derecha","ru":"На съездах на автомагистраль при перестроении вправо","tr":"Sağa katılan otoyol giriş rampalarında","hi":"दाईं ओर मिलने वाली फ़्रीवे ऑन-रैंप पर","ar":"على منحدرات الدخول إلى الطرق السريعة عند الاندماج يميناً"}],"e":{"en":"The manual states the greatest potential for conflict between a rider and other traffic is at intersections, where drivers often violate the rider's right-of-way.","es":"El manual indica que el mayor potencial de conflicto entre un conductor y otro tráfico se da en las intersecciones, donde los conductores a menudo violan el derecho de paso del motociclista.","ru":"В Руководстве указано, что наибольшая вероятность конфликта между водителем мотоцикла и другим транспортом возникает на перекрёстках, где водители часто нарушают преимущественное право проезда мотоциклиста.","tr":"Kılavuz, bir sürücü ile diğer trafik arasındaki çatışma potansiyelinin en çok, sürücülerin çoğu zaman sürücünün geçiş üstünlüğünü ihlal ettiği kavşaklarda olduğunu belirtir.","hi":"मैनुअल बताता है कि सवार और अन्य ट्रैफ़िक के बीच टकराव की सबसे अधिक संभावना चौराहों पर होती है, जहाँ चालक अक्सर सवार के रास्ते के अधिकार का उल्लंघन करते हैं।","ar":"ينص الدليل على أن أكبر احتمالية للتعارض بين السائق وحركة المرور الأخرى تكون عند التقاطعات، حيث كثيراً ما ينتهك السائقون حق أولوية المرور الخاص بسائق الدراجة."}},{"cat":"visibility","a":1,"q":{"en":"Which vehicle movement is identified by the manual as one of the biggest dangers to a motorcyclist at an intersection?","es":"¿Qué movimiento de vehículo identifica el manual como uno de los mayores peligros para un motociclista en una intersección?","ru":"Какой манёвр транспортного средства Руководство определяет как одну из самых больших опасностей для мотоциклиста на перекрёстке?","tr":"Kılavuz tarafından kavşakta bir motosikletliye yönelik en büyük tehlikelerden biri olarak hangi araç hareketi tanımlanmıştır?","hi":"मैनुअल के अनुसार, चौराहे पर मोटरसाइकिल चालक के लिए सबसे बड़े खतरों में से एक के रूप में कौन सी वाहन गतिविधि पहचानी गई है?","ar":"أي حركة مركبة يحددها الدليل بوصفها من أكبر المخاطر على سائق الدراجة النارية عند التقاطع؟"},"o":[{"en":"A car parallel parking on the right","es":"Un auto estacionándose en paralelo a la derecha","ru":"Автомобиль, паркующийся параллельно справа","tr":"Sağda paralel park eden bir araba","hi":"दाईं ओर समानांतर पार्क करती हुई कार","ar":"سيارة تركن بشكل موازٍ على اليمين"},{"en":"A car turning left in front of you","es":"Un auto que gira a la izquierda frente a ti","ru":"Автомобиль, поворачивающий налево перед вами","tr":"Önünüzde sola dönen bir araba","hi":"आपके सामने बाएँ मुड़ती हुई कार","ar":"سيارة تنعطف يساراً أمامك"},{"en":"A car slowing down well ahead of you","es":"Un auto que reduce la velocidad bastante adelante de ti","ru":"Автомобиль, замедляющийся далеко впереди вас","tr":"Çok ilerinizde yavaşlayan bir araba","hi":"आपसे काफी आगे धीमी होती हुई कार","ar":"سيارة تبطئ على بُعد جيد أمامك"},{"en":"A car backing slowly out of a driveway behind you","es":"Un auto que retrocede lentamente saliendo de una entrada detrás de ti","ru":"Автомобиль, медленно выезжающий задним ходом из проезда позади вас","tr":"Arkanızda bir garaj yolundan yavaşça geri geri çıkan bir araba","hi":"आपके पीछे ड्राइववे से धीरे-धीरे बैक होती हुई कार","ar":"سيارة ترجع للخلف ببطء خارجة من ممر خاص خلفك"}],"e":{"en":"The Motorcycle Operator Manual warns that cars turning left in front of you are among the biggest dangers, because drivers often fail to see the rider.","es":"El Manual del Operador de Motocicletas advierte que los autos que giran a la izquierda frente a ti están entre los mayores peligros, porque los conductores a menudo no ven al motociclista.","ru":"Руководство для водителей мотоциклов предупреждает, что автомобили, поворачивающие налево перед вами, относятся к числу самых больших опасностей, поскольку водители часто не замечают мотоциклиста.","tr":"Motosiklet Sürücü Kılavuzu, önünüzde sola dönen arabaların en büyük tehlikeler arasında olduğu konusunda uyarır; çünkü sürücüler çoğu zaman motosikletliyi görmezler.","hi":"Motorcycle Operator Manual चेतावनी देता है कि आपके सामने बाएँ मुड़ती हुई कारें सबसे बड़े खतरों में से एक हैं, क्योंकि चालक अक्सर सवार को देख नहीं पाते।","ar":"يحذر دليل مشغل الدراجة النارية من أن السيارات التي تنعطف يساراً أمامك من أكبر المخاطر، لأن السائقين كثيراً ما يفشلون في رؤية سائق الدراجة."}},{"cat":"visibility","a":2,"q":{"en":"The Motorcycle Operator Manual says that more than half of car-motorcycle crashes are caused by what?","es":"El Manual del Operador de Motocicletas dice que más de la mitad de los choques entre autos y motocicletas son causados por ¿qué?","ru":"Руководство для водителей мотоциклов утверждает, что более половины столкновений автомобилей с мотоциклами вызваны чем?","tr":"Motosiklet Sürücü Kılavuzu, araba-motosiklet kazalarının yarısından fazlasının neyin yüzünden olduğunu söyler?","hi":"Motorcycle Operator Manual कहता है कि कार-मोटरसाइकिल दुर्घटनाओं में से आधे से अधिक किस कारण से होती हैं?","ar":"يقول دليل مشغل الدراجة النارية إن أكثر من نصف حوادث التصادم بين السيارات والدراجات النارية يسببها ماذا؟"},"o":[{"en":"Riders speeding through yellow lights","es":"Motociclistas que pasan a toda velocidad las luces amarillas","ru":"Мотоциклистами, проезжающими на жёлтый сигнал на высокой скорости","tr":"Sürücülerin sarı ışıkta hızla geçmesi","hi":"सवार पीली बत्तियों से तेज़ गुज़रना","ar":"تجاوز السائقين الإشارات الصفراء بسرعة"},{"en":"Riders following too closely behind cars","es":"Motociclistas que siguen demasiado cerca detrás de los autos","ru":"Мотоциклистами, слишком близко следующими за автомобилями","tr":"Sürücülerin arabaları çok yakından takip etmesi","hi":"सवार कारों के बहुत पास-पास चलना","ar":"سير السائقين قريباً جداً خلف السيارات"},{"en":"Drivers entering a rider's right-of-way","es":"Conductores que invaden el derecho de paso de un motociclista","ru":"Водителями, въезжающими в зону преимущественного права мотоциклиста","tr":"Sürücülerin bir sürücünün geçiş üstünlüğüne girmesi","hi":"चालक सवार के रास्ते के अधिकार में प्रवेश करना","ar":"دخول السائقين إلى حق أولوية المرور الخاص بسائق الدراجة"},{"en":"Mechanical failures on the motorcycle","es":"Fallas mecánicas en la motocicleta","ru":"Механическими поломками мотоцикла","tr":"Motosiklette meydana gelen mekanik arızalar","hi":"मोटरसाइकिल में यांत्रिक खराबी","ar":"الأعطال الميكانيكية في الدراجة النارية"}],"e":{"en":"The manual reports that over half of motorcycle/car crashes are caused by drivers entering the rider's right-of-way, often by turning left in front of the rider.","es":"El manual informa que más de la mitad de los choques entre motocicletas y autos son causados por conductores que invaden el derecho de paso del motociclista, a menudo al girar a la izquierda frente a él.","ru":"Руководство сообщает, что более половины столкновений мотоциклов с автомобилями вызваны водителями, въезжающими в зону преимущественного права мотоциклиста, часто при повороте налево перед ним.","tr":"Kılavuz, motosiklet/araba kazalarının yarısından fazlasının, sürücülerin çoğu zaman sürücünün önünde sola dönerek onun geçiş üstünlüğüne girmesinden kaynaklandığını bildirir.","hi":"मैनुअल बताता है कि आधे से अधिक मोटरसाइकिल/कार दुर्घटनाएँ चालकों द्वारा सवार के रास्ते के अधिकार में प्रवेश करने से होती हैं, अक्सर सवार के सामने बाएँ मुड़कर।","ar":"يفيد الدليل بأن أكثر من نصف حوادث التصادم بين الدراجات النارية والسيارات يسببها دخول السائقين إلى حق أولوية المرور الخاص بسائق الدراجة، غالباً بالانعطاف يساراً أمام السائق."}},{"cat":"visibility","a":2,"q":{"en":"What does the Motorcycle Operator Manual advise about relying on eye contact with a driver?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre confiar en el contacto visual con un conductor?","ru":"Что Руководство для водителей мотоциклов советует по поводу того, чтобы полагаться на зрительный контакт с водителем?","tr":"Motosiklet Sürücü Kılavuzu, bir sürücüyle göz teması kurmaya güvenmek konusunda ne tavsiye eder?","hi":"Motorcycle Operator Manual चालक के साथ नज़र मिलाने पर भरोसा करने के बारे में क्या सलाह देता है?","ar":"بماذا ينصح دليل مشغل الدراجة النارية بشأن الاعتماد على التواصل البصري مع السائق؟"},"o":[{"en":"Eye contact guarantees the driver has seen you","es":"El contacto visual garantiza que el conductor te ha visto","ru":"Зрительный контакт гарантирует, что водитель вас увидел","tr":"Göz teması, sürücünün sizi gördüğünü garanti eder","hi":"नज़र मिलाना इस बात की गारंटी देता है कि चालक ने आपको देख लिया है","ar":"التواصل البصري يضمن أن السائق قد رآك"},{"en":"Eye contact replaces the need to use your headlight","es":"El contacto visual reemplaza la necesidad de usar tu faro","ru":"Зрительный контакт заменяет необходимость использовать фару","tr":"Göz teması, farınızı kullanma ihtiyacının yerini tutar","hi":"नज़र मिलाना आपके हेडलाइट का उपयोग करने की आवश्यकता को बदल देता है","ar":"التواصل البصري يغني عن الحاجة لاستخدام مصباحك الأمامي"},{"en":"Never count on eye contact as a sign the driver will yield","es":"Nunca confíes en el contacto visual como señal de que el conductor cederá el paso","ru":"Никогда не рассчитывайте на зрительный контакт как на признак того, что водитель уступит дорогу","tr":"Sürücünün yol vereceğinin işareti olarak asla göz temasına güvenmeyin","hi":"नज़र मिलाने को कभी भी इस संकेत के रूप में न लें कि चालक रास्ता देगा","ar":"لا تعتمد أبداً على التواصل البصري كعلامة على أن السائق سيفسح لك الطريق"},{"en":"Only make eye contact with drivers turning right","es":"Haz contacto visual solo con los conductores que giran a la derecha","ru":"Устанавливайте зрительный контакт только с водителями, поворачивающими направо","tr":"Yalnızca sağa dönen sürücülerle göz teması kurun","hi":"केवल दाएँ मुड़ रहे चालकों से नज़र मिलाएँ","ar":"تواصل بصرياً فقط مع السائقين الذين ينعطفون يميناً"}],"e":{"en":"The manual cautions never to count on eye contact; a driver may look right at a motorcyclist and still fail to truly 'see' the rider.","es":"El manual advierte que nunca se debe confiar en el contacto visual; un conductor puede mirar directamente a un motociclista y aun así no 'ver' realmente al conductor.","ru":"Руководство предупреждает: никогда не рассчитывайте на зрительный контакт; водитель может смотреть прямо на мотоциклиста и всё равно по-настоящему его не «увидеть».","tr":"Kılavuz, asla göz temasına güvenmemek konusunda uyarır; bir sürücü doğrudan motosikletliye bakıyor olsa bile yine de sürücüyü gerçekten 'görememiş' olabilir.","hi":"मैनुअल चेतावनी देता है कि नज़र मिलाने पर कभी भरोसा न करें; एक चालक मोटरसाइकिल चालक की ओर सीधे देख सकता है और फिर भी सवार को वास्तव में 'देख' नहीं पाता।","ar":"يحذر الدليل من الاعتماد أبداً على التواصل البصري؛ فقد ينظر السائق إلى سائق الدراجة مباشرةً ومع ذلك يفشل في 'رؤيته' حقاً."}},{"cat":"visibility","a":3,"q":{"en":"According to the manual, what is the single best way to help others see your motorcycle?","es":"Según el manual, ¿cuál es la mejor manera de ayudar a que otros vean tu motocicleta?","ru":"Согласно Руководству, какой единственный лучший способ помочь другим увидеть ваш мотоцикл?","tr":"Kılavuza göre, başkalarının motosikletinizi görmesine yardımcı olmanın tek en iyi yolu nedir?","hi":"मैनुअल के अनुसार, दूसरों को आपकी मोटरसाइकिल दिखाने में मदद करने का सबसे अच्छा एकमात्र तरीका क्या है?","ar":"وفقاً للدليل، ما هي الطريقة الوحيدة الأفضل لمساعدة الآخرين على رؤية دراجتك النارية؟"},"o":[{"en":"Rev your engine loudly at intersections","es":"Acelerar el motor ruidosamente en las intersecciones","ru":"Громко газовать двигателем на перекрёстках","tr":"Kavşaklarda motorunuzu gürültülü bir şekilde gazlamak","hi":"चौराहों पर अपने इंजन को ज़ोर से रेव करना","ar":"إصدار صوت محرك عالٍ عند التقاطعات"},{"en":"Ride with your turn signal blinking continuously","es":"Conducir con la direccional parpadeando continuamente","ru":"Ехать с постоянно мигающим указателем поворота","tr":"Sinyalinizi sürekli yanıp sönecek şekilde sürmek","hi":"अपने टर्न सिग्नल को लगातार ब्लिंक करते हुए चलाना","ar":"القيادة مع إبقاء إشارة الانعطاف وامضة باستمرار"},{"en":"Stay in the far right edge of every lane","es":"Mantenerte en el extremo derecho de cada carril","ru":"Держаться у крайнего правого края каждой полосы","tr":"Her şeritin en sağ kenarında kalmak","hi":"हर लेन के बिल्कुल दाएँ किनारे पर रहना","ar":"البقاء في الحافة اليمنى القصوى من كل مسار"},{"en":"Keep your headlight on at all times","es":"Mantener tu faro encendido en todo momento","ru":"Держать фару включённой всё время","tr":"Farınızı her zaman açık tutmak","hi":"हर समय अपनी हेडलाइट चालू रखना","ar":"إبقاء مصباحك الأمامي مضاءً في جميع الأوقات"}],"e":{"en":"The Motorcycle Operator Manual states the best way to help others see you is to keep the headlight on at all times, day and night.","es":"El Manual del Operador de Motocicletas indica que la mejor manera de ayudar a que otros te vean es mantener el faro encendido en todo momento, de día y de noche.","ru":"Руководство для водителей мотоциклов гласит, что лучший способ помочь другим увидеть вас — держать фару включённой всё время, днём и ночью.","tr":"Motosiklet Sürücü Kılavuzu, başkalarının sizi görmesine yardımcı olmanın en iyi yolunun, farı gece gündüz her zaman açık tutmak olduğunu belirtir.","hi":"Motorcycle Operator Manual कहता है कि दूसरों को आपको देखने में मदद करने का सबसे अच्छा तरीका है दिन और रात हर समय हेडलाइट चालू रखना।","ar":"ينص دليل مشغل الدراجة النارية على أن أفضل طريقة لمساعدة الآخرين على رؤيتك هي إبقاء المصباح الأمامي مضاءً في جميع الأوقات، ليلاً ونهاراً."}},{"cat":"visibility","a":1,"q":{"en":"Studies cited in the manual show that a motorcycle running its headlight during the day is how much more likely to be noticed?","es":"Según los estudios citados en el manual, una motocicleta con el faro encendido durante el día ¿cuánto más probable es que sea notada?","ru":"Согласно исследованиям, упомянутым в Руководстве, насколько более заметным становится мотоцикл с включённой фарой днём?","tr":"Kılavuzda atıfta bulunulan çalışmalar, gündüz farını açık tutan bir motosikletin ne kadar daha fazla fark edilme olasılığı olduğunu gösterir?","hi":"मैनुअल में उद्धृत अध्ययन दिखाते हैं कि दिन में अपनी हेडलाइट चलाने वाली मोटरसाइकिल पर ध्यान दिए जाने की संभावना कितनी अधिक होती है?","ar":"تُظهر الدراسات المذكورة في الدليل أن الدراجة النارية التي تُشغّل مصباحها الأمامي خلال النهار يزداد احتمال ملاحظتها بأي قدر؟"},"o":[{"en":"About the same as with no light","es":"Casi lo mismo que sin luz","ru":"Примерно так же, как и без света","tr":"Hiç ışık olmamasıyla yaklaşık aynı","hi":"कोई लाइट न होने जितनी ही लगभग","ar":"تقريباً نفس القدر كما لو لم يكن هناك ضوء"},{"en":"About twice as likely to be noticed","es":"Cerca del doble de probable de ser notada","ru":"Примерно вдвое более заметным","tr":"Yaklaşık iki kat daha fazla fark edilme olasılığı","hi":"लगभग दोगुनी संभावना से ध्यान दिया जाना","ar":"تقريباً ضعف احتمال ملاحظتها"},{"en":"Slightly less likely to be noticed","es":"Ligeramente menos probable de ser notada","ru":"Чуть менее заметным","tr":"Biraz daha az fark edilme olasılığı","hi":"थोड़ी कम ध्यान दिए जाने की संभावना","ar":"احتمال أقل قليلاً لملاحظتها"},{"en":"Roughly ten times more likely to be noticed","es":"Aproximadamente diez veces más probable de ser notada","ru":"Примерно в десять раз более заметным","tr":"Kabaca on kat daha fazla","hi":"लगभग दस गुना अधिक संभावना","ar":"نحو عشرة أضعاف احتمال ملاحظتها"}],"e":{"en":"The manual notes that studies show a motorcycle with its headlight on during the day is about twice as likely to be noticed by other drivers.","es":"El manual señala que los estudios muestran que una motocicleta con el faro encendido durante el día tiene cerca del doble de probabilidad de ser notada por otros conductores.","ru":"Руководство отмечает, что, согласно исследованиям, мотоцикл с включённой фарой днём примерно вдвое более заметен для других водителей.","tr":"Kılavuz, çalışmaların gündüz farı açık olan bir motosikletin diğer sürücüler tarafından yaklaşık iki kat daha fazla fark edilme olasılığı olduğunu gösterdiğini belirtir.","hi":"मैनुअल बताता है कि अध्ययन दिखाते हैं कि दिन में अपनी हेडलाइट चालू रखने वाली मोटरसाइकिल पर अन्य चालकों द्वारा ध्यान दिए जाने की संभावना लगभग दोगुनी होती है।","ar":"يشير الدليل إلى أن الدراسات تُظهر أن الدراجة النارية التي يكون مصباحها الأمامي مضاءً خلال النهار يزداد احتمال ملاحظتها من قبل السائقين الآخرين بنحو الضعف."}},{"cat":"visibility","a":2,"q":{"en":"What clothing does the Motorcycle Operator Manual recommend to help you be seen?","es":"¿Qué vestimenta recomienda el Manual del Operador de Motocicletas para ayudar a que te vean?","ru":"Какую одежду рекомендует Руководство для водителей мотоциклов, чтобы вас было видно?","tr":"Motosiklet Sürücü Kılavuzu, görülmenize yardımcı olması için hangi kıyafeti önerir?","hi":"Motorcycle Operator Manual आपको दिखने में मदद करने के लिए कौन से कपड़ों की सिफ़ारिश करता है?","ar":"ما الملابس التي يوصي بها دليل مشغل الدراجة النارية لمساعدتك على أن تكون مرئياً؟"},"o":[{"en":"Dark, non-reflective clothing that resists dirt","es":"Ropa oscura y no reflectante que resista la suciedad","ru":"Тёмную, нессветоотражающую одежду, устойчивую к загрязнению","tr":"Koyu renkli, yansıtıcı olmayan ve kire dayanıklı kıyafet","hi":"गहरे रंग के, बिना परावर्तक कपड़े जो गंदगी से बचते हों","ar":"ملابس داكنة غير عاكسة تقاوم الأوساخ"},{"en":"Loose camouflage gear that blends with surroundings","es":"Ropa de camuflaje holgada que se mezcle con el entorno","ru":"Свободную камуфляжную экипировку, сливающуюся с окружением","tr":"Çevreyle kaynaşan bol kamuflaj giysi","hi":"ढीले छलावरण वाले कपड़े जो आसपास के माहौल में घुल-मिल जाएँ","ar":"ملابس تمويه فضفاضة تندمج مع المحيط"},{"en":"Bright-colored, reflective clothing such as a helmet and jacket or vest","es":"Ropa de colores brillantes y reflectante, como un casco y una chaqueta o chaleco","ru":"Яркую светоотражающую одежду, например шлем и куртку или жилет","tr":"Kask ve ceket ya da yelek gibi parlak renkli, yansıtıcı kıyafet","hi":"चमकीले रंग के, परावर्तक कपड़े जैसे हेलमेट और जैकेट या वेस्ट","ar":"ملابس زاهية الألوان وعاكسة مثل خوذة وسترة أو صدرية"},{"en":"Only black leather for maximum protection","es":"Solo cuero negro para máxima protección","ru":"Только чёрную кожу для максимальной защиты","tr":"Maksimum koruma için yalnızca siyah deri","hi":"अधिकतम सुरक्षा के लिए केवल काला चमड़ा","ar":"الجلد الأسود فقط لأقصى حماية"}],"e":{"en":"The manual recommends bright-colored, reflective clothing-helmet and a jacket or vest-as the best way to make yourself conspicuous to other drivers.","es":"El manual recomienda ropa de colores brillantes y reflectante —casco y una chaqueta o chaleco— como la mejor manera de hacerte visible ante otros conductores.","ru":"Руководство рекомендует яркую светоотражающую одежду — шлем и куртку или жилет — как лучший способ сделать себя заметным для других водителей.","tr":"Kılavuz, kendinizi diğer sürücülere belli etmenin en iyi yolu olarak parlak renkli, yansıtıcı kıyafeti (kask ve ceket ya da yelek) önerir.","hi":"मैनुअल चमकीले रंग के, परावर्तक कपड़ों—हेलमेट और जैकेट या वेस्ट—की सिफ़ारिश करता है, जो अन्य चालकों के लिए खुद को स्पष्ट दिखाने का सबसे अच्छा तरीका है।","ar":"يوصي الدليل بملابس زاهية الألوان وعاكسة — خوذة وسترة أو صدرية — بوصفها أفضل طريقة لجعل نفسك واضحاً للسائقين الآخرين."}},{"cat":"visibility","a":3,"q":{"en":"Why does the manual advise wearing reflective material on the sides of your gear or helmet?","es":"¿Por qué aconseja el manual usar material reflectante en los lados de tu equipo o casco?","ru":"Почему Руководство советует носить светоотражающий материал по бокам экипировки или шлема?","tr":"Kılavuz neden ekipmanınızın veya kaskınızın yanlarına yansıtıcı malzeme takmanızı tavsiye eder?","hi":"मैनुअल आपके गियर या हेलमेट के किनारों पर परावर्तक सामग्री पहनने की सलाह क्यों देता है?","ar":"لماذا ينصح الدليل بارتداء مواد عاكسة على جانبي معداتك أو خوذتك؟"},"o":[{"en":"It keeps the rider cooler in hot weather","es":"Mantiene al conductor más fresco en clima caluroso","ru":"Это сохраняет водителю прохладу в жаркую погоду","tr":"Sürücüyü sıcak havada daha serin tutar","hi":"यह गर्म मौसम में सवार को ठंडा रखता है","ar":"تُبقي السائق أكثر برودة في الطقس الحار"},{"en":"It reduces wind noise at highway speeds","es":"Reduce el ruido del viento a velocidades de autopista","ru":"Это снижает шум ветра на высокой скорости","tr":"Otoyol hızlarında rüzgar gürültüsünü azaltır","hi":"यह राजमार्ग की गति पर हवा का शोर कम करता है","ar":"تقلل ضوضاء الرياح عند سرعات الطرق السريعة"},{"en":"It improves the motorcycle's fuel economy","es":"Mejora el rendimiento de combustible de la motocicleta","ru":"Это улучшает экономичность расхода топлива мотоцикла","tr":"Motosikletin yakıt ekonomisini iyileştirir","hi":"यह मोटरसाइकिल की ईंधन क्षमता में सुधार करता है","ar":"تحسّن اقتصاد الوقود للدراجة النارية"},{"en":"It helps drivers approaching from the side spot you","es":"Ayuda a que los conductores que se acercan por el costado te vean","ru":"Это помогает водителям, приближающимся сбоку, заметить вас","tr":"Yandan yaklaşan sürücülerin sizi fark etmesine yardımcı olur","hi":"यह बगल से आ रहे चालकों को आपको देखने में मदद करता है","ar":"تساعد السائقين القادمين من الجانب على رصدك"}],"e":{"en":"Reflective material on the sides helps drivers approaching from the side notice you, improving your conspicuity, per the Motorcycle Operator Manual.","es":"El material reflectante en los lados ayuda a que los conductores que se acercan por el costado te noten, mejorando tu visibilidad, según el Manual del Operador de Motocicletas.","ru":"Светоотражающий материал по бокам помогает водителям, приближающимся сбоку, заметить вас, повышая вашу заметность, согласно Руководству для водителей мотоциклов.","tr":"Yanlardaki yansıtıcı malzeme, Motosiklet Sürücü Kılavuzu'na göre yandan yaklaşan sürücülerin sizi fark etmesine yardımcı olur ve görünürlüğünüzü artırır.","hi":"किनारों पर परावर्तक सामग्री बगल से आ रहे चालकों को आपको देखने में मदद करती है, जिससे आपकी दृश्यता बेहतर होती है, Motorcycle Operator Manual के अनुसार।","ar":"تساعد المواد العاكسة على الجانبين السائقين القادمين من الجانب على ملاحظتك، مما يحسّن وضوحك، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":2,"q":{"en":"How should you use lane position to improve your visibility, according to the manual?","es":"¿Cómo debes usar la posición en el carril para mejorar tu visibilidad, según el manual?","ru":"Как, согласно Руководству, следует использовать положение на полосе для повышения своей видимости?","tr":"Kılavuza göre, görünürlüğünüzü artırmak için şerit konumunu nasıl kullanmalısınız?","hi":"मैनुअल के अनुसार, अपनी दृश्यता बेहतर करने के लिए आपको लेन की स्थिति का उपयोग कैसे करना चाहिए?","ar":"كيف ينبغي أن تستخدم موضعك في المسار لتحسين وضوحك، وفقاً للدليل؟"},"o":[{"en":"Always hug the right edge line of the lane","es":"Siempre pégate a la línea del borde derecho del carril","ru":"Всегда прижиматься к правой краевой линии полосы","tr":"Her zaman şeritin sağ kenar çizgisine yapışın","hi":"हमेशा लेन की दाईं किनारा रेखा से सटे रहें","ar":"التصق دائماً بخط الحافة اليمنى للمسار"},{"en":"Weave between lane portions every few seconds","es":"Zigzaguea entre las porciones del carril cada pocos segundos","ru":"Перемещаться между частями полосы каждые несколько секунд","tr":"Birkaç saniyede bir şerit bölümleri arasında zikzak çizin","hi":"हर कुछ सेकंड में लेन के हिस्सों के बीच घूमते रहें","ar":"تنقّل بين أجزاء المسار كل بضع ثوانٍ"},{"en":"Ride in the portion of the lane where you are most likely to be seen","es":"Conduce en la porción del carril donde es más probable que te vean","ru":"Ехать в той части полосы, где вас вероятнее всего увидят","tr":"Şeritin en çok görülme olasılığınızın olduğu bölümünde sürün","hi":"लेन के उस हिस्से में चलें जहाँ आपके दिखने की सबसे अधिक संभावना हो","ar":"اركب في جزء المسار الذي يُرجّح أن تُرى فيه"},{"en":"Stay exactly on the center line of the road","es":"Mantente exactamente sobre la línea central de la vía","ru":"Держаться точно по центральной линии дороги","tr":"Tam olarak yolun orta çizgisinde kalın","hi":"सड़क की केंद्र रेखा पर बिल्कुल बने रहें","ar":"ابقَ تماماً على الخط الأوسط للطريق"}],"e":{"en":"The manual advises choosing the lane portion where you are most likely to be seen while keeping a space cushion, adjusting position as conditions change.","es":"El manual aconseja elegir la porción del carril donde es más probable que te vean, manteniendo un colchón de espacio y ajustando la posición a medida que cambian las condiciones.","ru":"Руководство советует выбирать ту часть полосы, где вас вероятнее всего увидят, сохраняя при этом запас пространства и меняя положение по мере изменения условий.","tr":"Kılavuz, bir tampon boşluğu korurken en çok görülme olasılığınızın olduğu şerit bölümünü seçmenizi ve koşullar değiştikçe konumunuzu ayarlamanızı tavsiye eder.","hi":"मैनुअल सलाह देता है कि स्पेस कुशन बनाए रखते हुए लेन का वह हिस्सा चुनें जहाँ आपके दिखने की सबसे अधिक संभावना हो, और परिस्थितियाँ बदलने पर स्थिति समायोजित करें।","ar":"ينصح الدليل باختيار جزء المسار الذي يُرجّح أن تُرى فيه مع الحفاظ على مسافة أمان، وتعديل موضعك مع تغير الظروف."}},{"cat":"visibility","a":1,"q":{"en":"When you are following a car, which lane position helps put your image in the driver's rearview mirror?","es":"Cuando vas siguiendo a un auto, ¿qué posición en el carril ayuda a poner tu imagen en el espejo retrovisor del conductor?","ru":"Когда вы следуете за автомобилем, какое положение на полосе помогает поместить ваше изображение в зеркало заднего вида водителя?","tr":"Bir arabayı takip ederken, hangi şerit konumu görüntünüzü sürücünün dikiz aynasına yerleştirmeye yardımcı olur?","hi":"जब आप किसी कार के पीछे चल रहे हों, तो कौन सी लेन स्थिति आपकी छवि को चालक के रियरव्यू मिरर में लाने में मदद करती है?","ar":"عندما تسير خلف سيارة، أي موضع في المسار يساعد على وضع صورتك في مرآة الرؤية الخلفية للسائق؟"},"o":[{"en":"The far right of the lane","es":"El extremo derecho del carril","ru":"Крайнее правое в полосе","tr":"Şeritin en sağı","hi":"लेन का बिल्कुल दायाँ हिस्सा","ar":"أقصى يمين المسار"},{"en":"The center portion of the lane","es":"La porción central del carril","ru":"Центральная часть полосы","tr":"Şeritin orta bölümü","hi":"लेन का केंद्रीय हिस्सा","ar":"الجزء الأوسط من المسار"},{"en":"The far left of the lane next to oncoming traffic","es":"El extremo izquierdo del carril, junto al tráfico que viene en sentido contrario","ru":"Крайнее левое в полосе, рядом со встречным потоком","tr":"Karşı trafiğin yanındaki şeritin en solu","hi":"सामने से आ रही ट्रैफ़िक के बगल में लेन का बिल्कुल बायाँ हिस्सा","ar":"أقصى يسار المسار بجوار حركة المرور القادمة"},{"en":"Riding directly on the car's bumper","es":"Conducir directamente sobre el parachoques del auto","ru":"Движение прямо за бампером автомобиля","tr":"Doğrudan arabanın tamponunda sürmek","hi":"कार के बंपर पर सीधे सटकर चलना","ar":"القيادة مباشرةً على مصد السيارة"}],"e":{"en":"The manual notes that riding in the center portion of the lane puts your image in the middle of the driver's rearview mirror, where they are most likely to see you.","es":"El manual señala que conducir en la porción central del carril coloca tu imagen en el centro del espejo retrovisor del conductor, donde es más probable que te vea.","ru":"Руководство отмечает, что движение в центральной части полосы помещает ваше изображение в середину зеркала заднего вида водителя, где он вероятнее всего вас увидит.","tr":"Kılavuz, şeritin orta bölümünde sürmenin, görüntünüzü sürücünün en çok sizi görme olasılığının olduğu dikiz aynasının ortasına yerleştirdiğini belirtir.","hi":"मैनुअल बताता है कि लेन के केंद्रीय हिस्से में चलना आपकी छवि को चालक के रियरव्यू मिरर के बीच में लाता है, जहाँ उनके आपको देखने की सबसे अधिक संभावना होती है।","ar":"يشير الدليل إلى أن القيادة في الجزء الأوسط من المسار تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق، حيث يُرجّح أن يراك."}},{"cat":"visibility","a":0,"q":{"en":"Before changing lanes, what does the Motorcycle Operator Manual tell riders to do about blind spots?","es":"Antes de cambiar de carril, ¿qué les indica el Manual del Operador de Motocicletas a los conductores que hagan respecto a los puntos ciegos?","ru":"Перед перестроением что Руководство для водителей мотоциклов рекомендует делать в отношении слепых зон?","tr":"Şerit değiştirmeden önce Motosiklet Sürücü Kılavuzu, sürücülere kör noktalar konusunda ne yapmalarını söyler?","hi":"लेन बदलने से पहले, Motorcycle Operator Manual सवारों को ब्लाइंड स्पॉट के बारे में क्या करने को कहता है?","ar":"قبل تغيير المسارات، بماذا يخبر دليل مشغل الدراجة النارية السائقين أن يفعلوا بشأن النقاط العمياء؟"},"o":[{"en":"Turn your head and look to the side because motorcycles and cars have blind spots","es":"Girar la cabeza y mirar hacia el costado, porque las motocicletas y los autos tienen puntos ciegos","ru":"Повернуть голову и посмотреть в сторону, потому что у мотоциклов и автомобилей есть слепые зоны","tr":"Başınızı çevirip yana bakın, çünkü motosikletlerin ve arabaların kör noktaları vardır","hi":"अपना सिर घुमाएँ और बगल में देखें क्योंकि मोटरसाइकिल और कारों के ब्लाइंड स्पॉट होते हैं","ar":"أدر رأسك وانظر إلى الجانب لأن للدراجات النارية والسيارات نقاطاً عمياء"},{"en":"Rely only on the rearview mirrors","es":"Confiar solo en los espejos retrovisores","ru":"Полагаться только на зеркала заднего вида","tr":"Yalnızca dikiz aynalarına güvenin","hi":"केवल रियरव्यू मिरर पर भरोसा करें","ar":"اعتمد فقط على مرايا الرؤية الخلفية"},{"en":"Honk the horn and change lanes immediately","es":"Tocar la bocina y cambiar de carril de inmediato","ru":"Просигналить и немедленно перестроиться","tr":"Korna çalıp hemen şerit değiştirin","hi":"हॉर्न बजाएँ और तुरंत लेन बदल लें","ar":"انفخ البوق وغيّر المسار فوراً"},{"en":"Assume the lane is clear if no headlights are visible","es":"Suponer que el carril está libre si no se ven faros","ru":"Считать полосу свободной, если не видно фар","tr":"Far görünmüyorsa şeritin boş olduğunu varsayın","hi":"अगर कोई हेडलाइट न दिखे तो मान लें कि लेन खाली है","ar":"افترض أن المسار خالٍ إذا لم تكن هناك مصابيح أمامية مرئية"}],"e":{"en":"The manual says motorcycles, like cars, have blind spots, so you must turn your head and look to the side before changing lanes-not rely on mirrors alone.","es":"El manual dice que las motocicletas, al igual que los autos, tienen puntos ciegos, por lo que debes girar la cabeza y mirar hacia el costado antes de cambiar de carril, sin confiar solo en los espejos.","ru":"Руководство гласит, что у мотоциклов, как и у автомобилей, есть слепые зоны, поэтому перед перестроением нужно повернуть голову и посмотреть в сторону, а не полагаться только на зеркала.","tr":"Kılavuz, motosikletlerin de arabalar gibi kör noktaları olduğunu, bu yüzden şerit değiştirmeden önce yalnızca aynalara güvenmeyip başınızı çevirip yana bakmanız gerektiğini söyler.","hi":"मैनुअल कहता है कि कारों की तरह मोटरसाइकिलों के भी ब्लाइंड स्पॉट होते हैं, इसलिए लेन बदलने से पहले आपको अपना सिर घुमाकर बगल में देखना चाहिए—केवल मिरर पर भरोसा न करें।","ar":"يقول الدليل إن للدراجات النارية، مثل السيارات، نقاطاً عمياء، لذا يجب أن تدير رأسك وتنظر إلى الجانب قبل تغيير المسارات — لا أن تعتمد على المرايا وحدها."}},{"cat":"visibility","a":2,"q":{"en":"What does the manual recommend regarding riding in the blind spots of other vehicles?","es":"¿Qué recomienda el manual respecto a conducir en los puntos ciegos de otros vehículos?","ru":"Что Руководство рекомендует в отношении движения в слепых зонах других транспортных средств?","tr":"Kılavuz, diğer araçların kör noktalarında sürme konusunda ne önerir?","hi":"अन्य वाहनों के ब्लाइंड स्पॉट में चलने के बारे में मैनुअल क्या सिफ़ारिश करता है?","ar":"بماذا يوصي الدليل فيما يتعلق بالقيادة في النقاط العمياء للمركبات الأخرى؟"},"o":[{"en":"Stay in a truck's blind spot to save fuel by drafting","es":"Quedarte en el punto ciego de un camión para ahorrar combustible aprovechando su estela","ru":"Держаться в слепой зоне грузовика, чтобы экономить топливо за счёт движения в потоке за ним","tr":"Slipstream ile yakıt tasarrufu için bir kamyonun kör noktasında kalın","hi":"ईंधन बचाने के लिए ट्रक के ब्लाइंड स्पॉट में रहकर ड्राफ्टिंग करें","ar":"ابقَ في النقطة العمياء لشاحنة لتوفير الوقود عبر الانسياب خلفها"},{"en":"Ride in blind spots only on the highway","es":"Conducir en los puntos ciegos solo en la autopista","ru":"Ехать в слепых зонах только на шоссе","tr":"Kör noktalarda yalnızca otoyolda sürün","hi":"ब्लाइंड स्पॉट में केवल राजमार्ग पर चलें","ar":"اركب في النقاط العمياء فقط على الطريق السريع"},{"en":"Avoid riding in the blind spots of cars and trucks","es":"Evitar conducir en los puntos ciegos de autos y camiones","ru":"Избегать движения в слепых зонах автомобилей и грузовиков","tr":"Arabaların ve kamyonların kör noktalarında sürmekten kaçının","hi":"कारों और ट्रकों के ब्लाइंड स्पॉट में चलने से बचें","ar":"تجنّب القيادة في النقاط العمياء للسيارات والشاحنات"},{"en":"Blind spots are safe as long as your light is on","es":"Los puntos ciegos son seguros mientras tu luz esté encendida","ru":"Слепые зоны безопасны, пока ваша фара включена","tr":"Işığınız açıksa kör noktalar güvenlidir","hi":"जब तक आपकी लाइट चालू है, ब्लाइंड स्पॉट सुरक्षित हैं","ar":"النقاط العمياء آمنة طالما أن ضوءك مضاء"}],"e":{"en":"The Motorcycle Operator Manual advises avoiding the blind spots of cars and trucks so other drivers can see you and are aware of your presence.","es":"El Manual del Operador de Motocicletas aconseja evitar los puntos ciegos de autos y camiones para que los otros conductores puedan verte y estén conscientes de tu presencia.","ru":"Руководство для водителей мотоциклов советует избегать слепых зон автомобилей и грузовиков, чтобы другие водители могли вас видеть и осознавать ваше присутствие.","tr":"Motosiklet Sürücü Kılavuzu, diğer sürücülerin sizi görebilmesi ve varlığınızın farkında olabilmesi için arabaların ve kamyonların kör noktalarından kaçınmayı tavsiye eder.","hi":"Motorcycle Operator Manual कारों और ट्रकों के ब्लाइंड स्पॉट से बचने की सलाह देता है ताकि अन्य चालक आपको देख सकें और आपकी उपस्थिति से अवगत रहें।","ar":"ينصح دليل مشغل الدراجة النارية بتجنّب النقاط العمياء للسيارات والشاحنات حتى يتمكن السائقون الآخرون من رؤيتك ويكونوا على دراية بوجودك."}},{"cat":"visibility","a":0,"q":{"en":"What does the manual say about using your turn signals?","es":"¿Qué dice el manual sobre el uso de las direccionales?","ru":"Что Руководство говорит об использовании указателей поворота?","tr":"Kılavuz, sinyallerinizi kullanmak konusunda ne der?","hi":"अपने टर्न सिग्नल का उपयोग करने के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن استخدام إشارات الانعطاف الخاصة بك؟"},"o":[{"en":"Use them any time you plan to turn or change lanes, even if no one seems around","es":"Úsalas cada vez que planees girar o cambiar de carril, aunque parezca que no hay nadie cerca","ru":"Используйте их каждый раз, когда планируете повернуть или перестроиться, даже если рядом, кажется, никого нет","tr":"Etrafta kimse yokmuş gibi görünse bile, dönmeyi veya şerit değiştirmeyi planladığınız her an kullanın","hi":"जब भी आप मुड़ने या लेन बदलने की योजना बनाएँ तब उन्हें उपयोग करें, भले ही कोई आसपास न दिखे","ar":"استخدمها في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى لو بدا أنه لا أحد حولك"},{"en":"Use them only when other vehicles are clearly nearby","es":"Úsalas solo cuando haya otros vehículos claramente cerca","ru":"Используйте их только когда поблизости явно есть другие транспортные средства","tr":"Yalnızca başka araçlar açıkça yakındayken kullanın","hi":"उन्हें केवल तब उपयोग करें जब अन्य वाहन स्पष्ट रूप से पास हों","ar":"استخدمها فقط عندما تكون المركبات الأخرى قريبة بوضوح"},{"en":"Avoid them because they distract other drivers","es":"Evítalas porque distraen a los demás conductores","ru":"Избегайте их, потому что они отвлекают других водителей","tr":"Diğer sürücülerin dikkatini dağıttığı için kullanmaktan kaçının","hi":"उनसे बचें क्योंकि वे अन्य चालकों का ध्यान भटकाते हैं","ar":"تجنّبها لأنها تشتت انتباه السائقين الآخرين"},{"en":"Use them only at night for added visibility","es":"Úsalas solo de noche para mayor visibilidad","ru":"Используйте их только ночью для дополнительной видимости","tr":"Ek görünürlük için yalnızca gece kullanın","hi":"अतिरिक्त दृश्यता के लिए उन्हें केवल रात में उपयोग करें","ar":"استخدمها فقط ليلاً لزيادة الوضوح"}],"e":{"en":"The manual instructs riders to signal their intentions early-any time they plan to turn or change lanes-even when they think no one else is around.","es":"El manual indica a los conductores que señalicen sus intenciones con anticipación —cada vez que planeen girar o cambiar de carril— incluso cuando crean que no hay nadie más alrededor.","ru":"Руководство предписывает водителям заранее сигнализировать о своих намерениях — каждый раз, когда они планируют повернуть или перестроиться, — даже когда кажется, что рядом никого нет.","tr":"Kılavuz, sürücülere niyetlerini erkenden, dönmeyi veya şerit değiştirmeyi planladıkları her an, etrafta başka kimse olmadığını düşündüklerinde bile sinyal vermelerini söyler.","hi":"मैनुअल सवारों को निर्देश देता है कि वे अपने इरादे जल्दी संकेत दें—जब भी वे मुड़ने या लेन बदलने की योजना बनाएँ—भले ही उन्हें लगे कि आसपास कोई और नहीं है।","ar":"يوجّه الدليل السائقين إلى الإشارة إلى نواياهم مبكراً — في أي وقت يخططون فيه للانعطاف أو تغيير المسار — حتى عندما يظنون أنه لا أحد آخر حولهم."}},{"cat":"visibility","a":3,"q":{"en":"After completing a turn, what does the manual remind riders to do with the turn signal?","es":"Después de completar un giro, ¿qué les recuerda el manual a los conductores que hagan con la direccional?","ru":"После завершения поворота о чём Руководство напоминает водителям в отношении указателя поворота?","tr":"Bir dönüşü tamamladıktan sonra kılavuz, sürücülere sinyalle ilgili ne yapmalarını hatırlatır?","hi":"मोड़ पूरा करने के बाद, मैनुअल सवारों को टर्न सिग्नल के साथ क्या करने की याद दिलाता है?","ar":"بعد إتمام الانعطاف، بماذا يذكّر الدليل السائقين أن يفعلوا بإشارة الانعطاف؟"},"o":[{"en":"Leave it blinking to stay visible longer","es":"Dejarla parpadeando para seguir siendo visible más tiempo","ru":"Оставить его мигающим, чтобы дольше оставаться заметным","tr":"Daha uzun süre görünür kalmak için yanıp sönmeye bırakın","hi":"अधिक समय तक दिखने के लिए इसे ब्लिंक करते रहने दें","ar":"اتركها وامضة لتبقى مرئياً لفترة أطول"},{"en":"Switch it to the opposite direction","es":"Cambiarla a la dirección opuesta","ru":"Переключить его на противоположное направление","tr":"Ters yöne çevirin","hi":"इसे विपरीत दिशा में बदल दें","ar":"حوّلها إلى الاتجاه المعاكس"},{"en":"Tap it three times to confirm the turn","es":"Tocarla tres veces para confirmar el giro","ru":"Нажать на него три раза для подтверждения поворота","tr":"Dönüşü onaylamak için üç kez basın","hi":"मोड़ की पुष्टि के लिए इसे तीन बार टैप करें","ar":"انقر عليها ثلاث مرات لتأكيد الانعطاف"},{"en":"Make sure it is turned off so a driver does not think you plan to turn again","es":"Asegurarte de que esté apagada para que un conductor no piense que planeas girar de nuevo","ru":"Убедиться, что он выключен, чтобы водитель не подумал, что вы снова собираетесь поворачивать","tr":"Bir sürücünün tekrar dönmeyi planladığınızı düşünmemesi için kapalı olduğundan emin olun","hi":"सुनिश्चित करें कि यह बंद हो जाए ताकि चालक यह न सोचे कि आप फिर से मुड़ने की योजना बना रहे हैं","ar":"تأكد من إيقافها حتى لا يظن السائق أنك تخطط للانعطاف مرة أخرى"}],"e":{"en":"The manual warns to cancel your signal after turning, because a driver seeing it still on may pull into your path thinking you intend to turn again.","es":"El manual advierte que canceles tu direccional después de girar, porque un conductor que la vea aún encendida podría meterse en tu trayectoria pensando que tienes la intención de girar otra vez.","ru":"Руководство предупреждает: отменяйте сигнал после поворота, потому что водитель, видя его всё ещё включённым, может выехать на ваш путь, думая, что вы снова намерены повернуть.","tr":"Kılavuz, dönüşten sonra sinyalinizi iptal etmeniz konusunda uyarır; çünkü hala açık gören bir sürücü, tekrar dönmek istediğinizi düşünerek yolunuza çıkabilir.","hi":"मैनुअल चेतावनी देता है कि मुड़ने के बाद अपना सिग्नल रद्द कर दें, क्योंकि इसे अभी भी चालू देखकर कोई चालक यह सोचकर आपके रास्ते में आ सकता है कि आप फिर से मुड़ने का इरादा रखते हैं।","ar":"يحذر الدليل من ضرورة إلغاء إشارتك بعد الانعطاف، لأن السائق الذي يراها لا تزال مضاءة قد يندفع إلى مسارك ظناً منه أنك تنوي الانعطاف مرة أخرى."}},{"cat":"visibility","a":1,"q":{"en":"What does the Motorcycle Operator Manual say about a motorcycle's horn?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre la bocina de una motocicleta?","ru":"Что Руководство для водителей мотоциклов говорит о звуковом сигнале мотоцикла?","tr":"Motosiklet Sürücü Kılavuzu, bir motosikletin kornası hakkında ne der?","hi":"मोटरसाइकिल के हॉर्न के बारे में Motorcycle Operator Manual क्या कहता है?","ar":"ماذا يقول دليل مشغل الدراجة النارية عن بوق الدراجة النارية؟"},"o":[{"en":"It is louder than a car horn and stops all hazards","es":"Es más fuerte que la bocina de un auto y detiene todos los peligros","ru":"Он громче автомобильного сигнала и устраняет все опасности","tr":"Bir araba kornasından daha yüksek seslidir ve tüm tehlikeleri durdurur","hi":"यह कार के हॉर्न से तेज़ होता है और सभी खतरों को रोक देता है","ar":"إنه أعلى صوتاً من بوق السيارة ويوقف كل المخاطر"},{"en":"It is not as loud as a car horn, so use it but do not rely on it","es":"No es tan fuerte como la bocina de un auto, así que úsala pero no dependas de ella","ru":"Он не такой громкий, как автомобильный сигнал, поэтому используйте его, но не полагайтесь на него","tr":"Bir araba kornası kadar yüksek sesli değildir, bu yüzden kullanın ama ona güvenmeyin","hi":"यह कार के हॉर्न जितना तेज़ नहीं है, इसलिए इसका उपयोग करें लेकिन इस पर भरोसा न करें","ar":"إنه ليس بقوة صوت بوق السيارة، لذا استخدمه لكن لا تعتمد عليه"},{"en":"It should never be used in traffic","es":"Nunca debe usarse en el tráfico","ru":"Его никогда не следует использовать в потоке","tr":"Trafikte asla kullanılmamalıdır","hi":"इसे ट्रैफ़िक में कभी उपयोग नहीं करना चाहिए","ar":"يجب ألا يُستخدم أبداً في حركة المرور"},{"en":"It works only when the headlight is off","es":"Funciona solo cuando el faro está apagado","ru":"Он работает только когда фара выключена","tr":"Yalnızca far kapalıyken çalışır","hi":"यह केवल तब काम करता है जब हेडलाइट बंद हो","ar":"يعمل فقط عندما يكون المصباح الأمامي مطفأً"}],"e":{"en":"The manual states a motorcycle horn is not as loud as a car horn, so riders should use it to get attention but not rely on it to prevent a crash.","es":"El manual indica que la bocina de una motocicleta no es tan fuerte como la de un auto, por lo que los conductores deben usarla para llamar la atención pero no depender de ella para evitar un choque.","ru":"Руководство утверждает, что звуковой сигнал мотоцикла не такой громкий, как автомобильный, поэтому водителям следует использовать его, чтобы привлечь внимание, но не полагаться на него для предотвращения столкновения.","tr":"Kılavuz, bir motosiklet kornasının bir araba kornası kadar yüksek sesli olmadığını, bu yüzden sürücülerin dikkat çekmek için kullanması ama bir kazayı önlemek için ona güvenmemesi gerektiğini belirtir.","hi":"मैनुअल बताता है कि मोटरसाइकिल का हॉर्न कार के हॉर्न जितना तेज़ नहीं है, इसलिए सवारों को ध्यान आकर्षित करने के लिए इसका उपयोग करना चाहिए लेकिन दुर्घटना रोकने के लिए इस पर भरोसा नहीं करना चाहिए।","ar":"ينص الدليل على أن بوق الدراجة النارية ليس بقوة صوت بوق السيارة، لذا ينبغي للسائقين استخدامه للفت الانتباه لكن لا الاعتماد عليه لمنع التصادم."}},{"cat":"visibility","a":1,"q":{"en":"In what situation does the manual suggest being ready to use your horn?","es":"¿En qué situación sugiere el manual estar listo para usar tu bocina?","ru":"В какой ситуации Руководство советует быть готовым использовать звуковой сигнал?","tr":"Kılavuz, hangi durumda kornanızı kullanmaya hazır olmanızı önerir?","hi":"मैनुअल किस स्थिति में अपने हॉर्न का उपयोग करने के लिए तैयार रहने का सुझाव देता है?","ar":"في أي موقف يقترح الدليل أن تكون مستعداً لاستخدام بوقك؟"},"o":[{"en":"Only to greet other motorcyclists you recognize","es":"Solo para saludar a otros motociclistas que reconozcas","ru":"Только чтобы поприветствовать знакомых мотоциклистов","tr":"Yalnızca tanıdığınız diğer motosikletlileri selamlamak için","hi":"केवल उन मोटरसाइकिल चालकों का अभिवादन करने के लिए जिन्हें आप पहचानते हैं","ar":"فقط لتحية سائقي الدراجات النارية الآخرين الذين تعرفهم"},{"en":"When another vehicle may move into your lane or fail to see you","es":"Cuando otro vehículo pueda meterse en tu carril o no verte","ru":"Когда другое транспортное средство может въехать на вашу полосу или не заметить вас","tr":"Başka bir araç şeritinize girebileceğinde veya sizi göremeyebileceğinde","hi":"जब कोई अन्य वाहन आपकी लेन में आ सकता है या आपको देखने में विफल हो सकता है","ar":"عندما قد تتحرك مركبة أخرى إلى مسارك أو تفشل في رؤيتك"},{"en":"Continuously while riding through a city","es":"Continuamente mientras conduces por la ciudad","ru":"Постоянно во время движения по городу","tr":"Bir şehirde sürerken sürekli olarak","hi":"शहर में चलते समय लगातार","ar":"باستمرار أثناء القيادة عبر المدينة"},{"en":"Only when your headlight has burned out","es":"Solo cuando tu faro se haya fundido","ru":"Только когда перегорела фара","tr":"Yalnızca farınız yanıp söndüğünde","hi":"केवल तब जब आपकी हेडलाइट जल गई हो","ar":"فقط عندما يحترق مصباحك الأمامي"}],"e":{"en":"The manual advises being ready to sound your horn to quickly get the attention of a driver who may move into your lane or otherwise fail to see you.","es":"El manual aconseja estar listo para tocar la bocina para llamar rápidamente la atención de un conductor que pueda meterse en tu carril o que de otro modo no te vea.","ru":"Руководство советует быть готовым подать звуковой сигнал, чтобы быстро привлечь внимание водителя, который может въехать на вашу полосу или иным образом не заметить вас.","tr":"Kılavuz, şeritinize girebilecek veya başka şekilde sizi göremeyebilecek bir sürücünün dikkatini hızla çekmek için kornanızı çalmaya hazır olmanızı tavsiye eder.","hi":"मैनुअल सलाह देता है कि उस चालक का ध्यान तुरंत आकर्षित करने के लिए हॉर्न बजाने के लिए तैयार रहें जो आपकी लेन में आ सकता है या अन्यथा आपको देखने में विफल हो सकता है।","ar":"ينصح الدليل بأن تكون مستعداً لإطلاق بوقك للفت انتباه سائق بسرعة قد يتحرك إلى مسارك أو يفشل بطريقة أخرى في رؤيتك."}},{"cat":"visibility","a":0,"q":{"en":"Why does the Motorcycle Operator Manual emphasize keeping a 'cushion of space' around your motorcycle?","es":"¿Por qué enfatiza el Manual del Operador de Motocicletas mantener un 'colchón de espacio' alrededor de tu motocicleta?","ru":"Почему Руководство для водителей мотоциклов подчёркивает важность сохранения «запаса пространства» вокруг мотоцикла?","tr":"Motosiklet Sürücü Kılavuzu, motosikletinizin etrafında bir 'tampon boşluğu' tutmayı neden vurgular?","hi":"Motorcycle Operator Manual आपकी मोटरसाइकिल के चारों ओर 'स्पेस कुशन' बनाए रखने पर ज़ोर क्यों देता है?","ar":"لماذا يؤكد دليل مشغل الدراجة النارية على الحفاظ على 'مسافة أمان' حول دراجتك النارية؟"},"o":[{"en":"It gives you time to react and space to maneuver if someone makes a mistake","es":"Te da tiempo para reaccionar y espacio para maniobrar si alguien comete un error","ru":"Это даёт вам время на реакцию и пространство для манёвра, если кто-то совершит ошибку","tr":"Birisi hata yaparsa tepki vermeniz için zaman ve manevra yapmanız için alan tanır","hi":"अगर कोई गलती करे तो यह आपको प्रतिक्रिया करने का समय और चलने-फिरने की जगह देता है","ar":"تمنحك الوقت لرد الفعل والمساحة للمناورة إذا ارتكب أحدهم خطأً"},{"en":"It makes the motorcycle accelerate faster","es":"Hace que la motocicleta acelere más rápido","ru":"Это заставляет мотоцикл разгоняться быстрее","tr":"Motosikletin daha hızlı hızlanmasını sağlar","hi":"यह मोटरसाइकिल को तेज़ी से एक्सीलरेट कराता है","ar":"تجعل الدراجة النارية تتسارع أسرع"},{"en":"It is only needed when riding at night","es":"Solo se necesita al conducir de noche","ru":"Это нужно только при езде ночью","tr":"Yalnızca gece sürerken gereklidir","hi":"यह केवल रात में चलते समय आवश्यक है","ar":"ضرورية فقط عند القيادة ليلاً"},{"en":"It reduces the legal following distance required","es":"Reduce la distancia de seguimiento legal requerida","ru":"Это уменьшает требуемую законом дистанцию следования","tr":"Gerekli yasal takip mesafesini azaltır","hi":"यह आवश्यक कानूनी फॉलोइंग दूरी को कम करता है","ar":"تقلل مسافة الاتباع القانونية المطلوبة"}],"e":{"en":"The manual explains that a cushion of space all around the motorcycle gives you time to react and room to maneuver if another driver makes a mistake.","es":"El manual explica que un colchón de espacio alrededor de toda la motocicleta te da tiempo para reaccionar y espacio para maniobrar si otro conductor comete un error.","ru":"Руководство объясняет, что запас пространства со всех сторон мотоцикла даёт вам время на реакцию и место для манёвра, если другой водитель совершит ошибку.","tr":"Kılavuz, motosikletin tüm çevresindeki bir tampon boşluğunun, başka bir sürücü hata yaparsa tepki vermeniz için zaman ve manevra yapmanız için yer tanıdığını açıklar.","hi":"मैनुअल समझाता है कि मोटरसाइकिल के चारों ओर का स्पेस कुशन आपको प्रतिक्रिया करने का समय और चलने-फिरने की जगह देता है अगर कोई अन्य चालक गलती करे।","ar":"يوضح الدليل أن مسافة الأمان حول الدراجة النارية بالكامل تمنحك الوقت لرد الفعل والمساحة للمناورة إذا ارتكب سائق آخر خطأً."}},{"cat":"visibility","a":0,"q":{"en":"During the 'Evaluate' step of SEE, what is the rider primarily doing?","es":"Durante el paso de 'Evaluar' (Evaluate) de SEE, ¿qué hace principalmente el conductor?","ru":"Чем главным образом занимается водитель на шаге «Оценка» (Evaluate) стратегии SEE?","tr":"SEE'nin 'Değerlendir' (Evaluate) adımında, sürücü öncelikle ne yapar?","hi":"SEE के 'Evaluate' (मूल्यांकन) चरण के दौरान, सवार मुख्य रूप से क्या कर रहा होता है?","ar":"خلال خطوة 'التقييم' (Evaluate) في استراتيجية SEE، ما الذي يفعله السائق بشكل أساسي؟"},"o":[{"en":"Thinking about how hazards can interact and anticipating problems","es":"Pensar en cómo pueden interactuar los peligros y anticipar problemas","ru":"Размышляет о том, как опасности могут взаимодействовать, и предвидит проблемы","tr":"Tehlikelerin nasıl etkileşebileceğini düşünmek ve sorunları öngörmek","hi":"सोचना कि खतरे कैसे टकरा सकते हैं और समस्याओं का पूर्वानुमान लगाना","ar":"التفكير في كيفية تفاعل المخاطر وتوقّع المشكلات"},{"en":"Physically swerving away from danger","es":"Esquivar físicamente el peligro","ru":"Физически уклоняется от опасности","tr":"Tehlikeden fiziksel olarak savrularak kaçmak","hi":"शारीरिक रूप से खतरे से दूर मुड़ना","ar":"الانعطاف الجسدي بعيداً عن الخطر"},{"en":"Turning the headlight to high beam","es":"Poner el faro en luz alta","ru":"Переключает фару на дальний свет","tr":"Farı uzun huzmeye çevirmek","hi":"हेडलाइट को हाई बीम पर करना","ar":"تحويل المصباح الأمامي إلى الضوء العالي"},{"en":"Coming to a complete stop at every intersection","es":"Detenerse por completo en cada intersección","ru":"Полностью останавливается на каждом перекрёстке","tr":"Her kavşakta tamamen durmak","hi":"हर चौराहे पर पूरी तरह रुक जाना","ar":"التوقف الكامل عند كل تقاطع"}],"e":{"en":"Evaluate means thinking about how identified hazards can interact to create risk and anticipating problems so you can plan a response, per the Motorcycle Operator Manual.","es":"Evaluar significa pensar en cómo los peligros identificados pueden interactuar para crear riesgo y anticipar problemas para que puedas planear una respuesta, según el Manual del Operador de Motocicletas.","ru":"«Оценка» означает размышление о том, как выявленные опасности могут взаимодействовать, создавая риск, и предвидение проблем, чтобы спланировать реакцию, согласно Руководству для водителей мотоциклов.","tr":"Değerlendir, Motosiklet Sürücü Kılavuzu'na göre, tanımlanan tehlikelerin risk oluşturmak için nasıl etkileşebileceğini düşünmek ve bir yanıt planlayabilmeniz için sorunları öngörmek demektir.","hi":"Evaluate का मतलब है यह सोचना कि पहचाने गए खतरे कैसे टकराकर जोखिम पैदा कर सकते हैं और समस्याओं का पूर्वानुमान लगाना ताकि आप प्रतिक्रिया की योजना बना सकें, Motorcycle Operator Manual के अनुसार।","ar":"يعني التقييم التفكير في كيفية تفاعل المخاطر المحددة لخلق خطر وتوقّع المشكلات حتى تتمكن من التخطيط للاستجابة، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":3,"q":{"en":"According to the manual, why are motorcycles often not 'seen' by other drivers even in plain view?","es":"Según el manual, ¿por qué a menudo los demás conductores no 'ven' las motocicletas, incluso estando a plena vista?","ru":"Согласно Руководству, почему мотоциклы часто остаются «незамеченными» другими водителями даже на виду?","tr":"Kılavuza göre, motosikletler tam görüş alanında olsa bile diğer sürücüler tarafından neden çoğu zaman 'görülmez'?","hi":"मैनुअल के अनुसार, मोटरसाइकिलें अक्सर सामने होने पर भी अन्य चालकों को क्यों नहीं 'दिखाई' देतीं?","ar":"وفقاً للدليل، لماذا كثيراً ما لا 'يرى' السائقون الآخرون الدراجات النارية حتى عندما تكون في مرأى واضح؟"},"o":[{"en":"They are usually painted in bright colors that confuse drivers","es":"Suelen estar pintadas de colores brillantes que confunden a los conductores","ru":"Они обычно окрашены в яркие цвета, которые сбивают водителей с толку","tr":"Genellikle sürücüleri şaşırtan parlak renklere boyanmışlardır","hi":"वे आमतौर पर चमकीले रंगों में रंगी होती हैं जो चालकों को भ्रमित करते हैं","ar":"عادةً ما تكون مطلية بألوان زاهية تربك السائقين"},{"en":"They travel slower than the surrounding traffic","es":"Viajan más despacio que el tráfico que las rodea","ru":"Они движутся медленнее окружающего транспорта","tr":"Çevredeki trafikten daha yavaş giderler","hi":"वे आसपास की ट्रैफ़िक की तुलना में धीमी चलती हैं","ar":"تسير أبطأ من حركة المرور المحيطة"},{"en":"Their headlights blend in with car headlights","es":"Sus faros se confunden con los faros de los autos","ru":"Их фары сливаются с фарами автомобилей","tr":"Farları araba farlarıyla kaynaşır","hi":"उनकी हेडलाइट कार की हेडलाइट के साथ घुल-मिल जाती हैं","ar":"تندمج مصابيحها الأمامية مع مصابيح السيارات"},{"en":"Their smaller size makes them easy for drivers to overlook or misjudge","es":"Su menor tamaño hace que los conductores las pasen por alto o las juzguen mal con facilidad","ru":"Их меньший размер делает их лёгкими для пропуска или неверной оценки водителями","tr":"Daha küçük boyutları, sürücülerin onları gözden kaçırmasını veya yanlış değerlendirmesini kolaylaştırır","hi":"उनका छोटा आकार चालकों के लिए उन्हें अनदेखा करना या गलत आँकना आसान बनाता है","ar":"حجمها الأصغر يجعل من السهل على السائقين إغفالها أو إساءة تقدير موقعها"}],"e":{"en":"The manual explains a motorcycle's small size makes it easy for drivers to overlook, so riders must take active steps-light, clothing, and position-to be seen.","es":"El manual explica que el pequeño tamaño de una motocicleta hace que los conductores la pasen por alto con facilidad, por lo que los motociclistas deben tomar medidas activas —luz, ropa y posición— para ser vistos.","ru":"Руководство объясняет, что небольшой размер мотоцикла делает его лёгким для пропуска водителями, поэтому мотоциклисты должны предпринимать активные шаги — свет, одежда и положение, — чтобы быть замеченными.","tr":"Kılavuz, bir motosikletin küçük boyutunun sürücülerin onu gözden kaçırmasını kolaylaştırdığını, bu yüzden sürücülerin görülmek için aktif adımlar (ışık, kıyafet ve konum) atması gerektiğini açıklar.","hi":"मैनुअल समझाता है कि मोटरसाइकिल का छोटा आकार चालकों के लिए उसे अनदेखा करना आसान बनाता है, इसलिए सवारों को दिखने के लिए सक्रिय कदम—लाइट, कपड़े और स्थिति—उठाने चाहिए।","ar":"يوضح الدليل أن صغر حجم الدراجة النارية يجعل من السهل على السائقين إغفالها، لذا يجب على السائقين اتخاذ خطوات فعّالة — الضوء والملابس والموضع — لكي يُرَوا."}},{"cat":"hazards","a":0,"q":{"en":"When is wet pavement generally most slippery for a motorcycle rider?","es":"¿Cuándo suele estar más resbaloso el pavimento mojado para un motociclista?","ru":"Когда мокрое покрытие обычно наиболее скользкое для водителя мотоцикла?","tr":"Islak zemin, bir motosiklet sürücüsü için genellikle ne zaman en kaygandır?","hi":"मोटरसाइकिल सवार के लिए गीली सड़क आमतौर पर सबसे अधिक फिसलन भरी कब होती है?","ar":"متى يكون الرصيف المبلل عموماً أكثر زلقاً لسائق الدراجة النارية؟"},"o":[{"en":"Just after it starts to rain, before surface oil washes away","es":"Justo después de que empieza a llover, antes de que el aceite de la superficie se lave","ru":"Сразу после начала дождя, до того как поверхностное масло смоется","tr":"Yağmur yeni başladıktan hemen sonra, yüzeydeki yağ yıkanıp gitmeden önce","hi":"बारिश शुरू होने के ठीक बाद, इससे पहले कि सतह का तेल बह जाए","ar":"بعد بدء المطر مباشرةً، قبل أن يُغسل الزيت السطحي"},{"en":"After it has been raining steadily for several hours","es":"Después de que ha llovido de forma constante durante varias horas","ru":"После того как дождь идёт устойчиво в течение нескольких часов","tr":"Birkaç saat sürekli yağmur yağdıktan sonra","hi":"कई घंटों तक लगातार बारिश होने के बाद","ar":"بعد أن يستمر هطول المطر بثبات لعدة ساعات"},{"en":"Only when the rain finally stops and the road begins to dry","es":"Solo cuando finalmente deja de llover y la vía empieza a secarse","ru":"Только когда дождь наконец прекращается и дорога начинает высыхать","tr":"Yalnızca yağmur sonunda durup yol kurumaya başladığında","hi":"केवल तब जब बारिश आखिरकार रुक जाए और सड़क सूखने लगे","ar":"فقط عندما يتوقف المطر أخيراً ويبدأ الطريق بالجفاف"},{"en":"Wet pavement offers the same traction no matter how long it rains","es":"El pavimento mojado ofrece la misma tracción sin importar cuánto tiempo llueva","ru":"Мокрое покрытие обеспечивает одинаковое сцепление независимо от продолжительности дождя","tr":"Islak zemin, ne kadar süre yağmur yağarsa yağsın aynı tutuşu sunar","hi":"गीली सड़क समान कर्षण देती है चाहे कितनी भी देर बारिश हो","ar":"يوفر الرصيف المبلل نفس قوة الاحتكاك مهما طال هطول المطر"}],"e":{"en":"Pavement is most slippery just after it starts to rain, before the surface oil washes off to the side of the road. The Motorcycle Operator Manual warns riders to use extra caution during the first part of a rain.","es":"El pavimento está más resbaloso justo después de que empieza a llover, antes de que el aceite de la superficie se lave hacia los lados de la vía. El Manual del Operador de Motocicletas advierte a los conductores que extremen la precaución durante la primera parte de la lluvia.","ru":"Покрытие наиболее скользкое сразу после начала дождя, до того как поверхностное масло смоется к краю дороги. Руководство для водителей мотоциклов предупреждает водителей соблюдать особую осторожность в первой части дождя.","tr":"Zemin, yüzeydeki yağ yolun kenarına yıkanıp gitmeden önce, yağmur yeni başladıktan hemen sonra en kaygandır. Motosiklet Sürücü Kılavuzu, sürücüleri yağmurun ilk bölümünde ekstra dikkatli olmaları konusunda uyarır.","hi":"सड़क बारिश शुरू होने के ठीक बाद सबसे अधिक फिसलन भरी होती है, इससे पहले कि सतह का तेल सड़क के किनारे बह जाए। Motorcycle Operator Manual सवारों को बारिश के पहले हिस्से के दौरान अतिरिक्त सावधानी बरतने की चेतावनी देता है।","ar":"يكون الرصيف أكثر زلقاً بعد بدء المطر مباشرةً، قبل أن يُغسل الزيت السطحي إلى جانب الطريق. يحذر دليل مشغل الدراجة النارية السائقين من توخّي مزيد من الحذر خلال الجزء الأول من المطر."}},{"cat":"hazards","a":1,"q":{"en":"Where in the lane does oil and grease dripped from cars usually collect, making it slippery when wet?","es":"¿En qué parte del carril suelen acumularse el aceite y la grasa que gotean de los autos, haciéndolo resbaloso cuando está mojado?","ru":"Где в полосе обычно скапливаются масло и смазка, капающие с автомобилей, делая её скользкой при намокании?","tr":"Arabalardan damlayan yağ ve gres, şeritte genellikle nerede toplanarak ıslakken kaygan hale gelir?","hi":"कारों से टपका तेल और ग्रीस आमतौर पर लेन में कहाँ जमा होता है, जिससे गीला होने पर यह फिसलन भरा हो जाता है?","ar":"أين في المسار يتجمع عادةً الزيت والشحم المتساقط من السيارات، مما يجعله زلقاً عند البلل؟"},"o":[{"en":"Along the far right edge of the lane","es":"A lo largo del extremo derecho del carril","ru":"Вдоль крайнего правого края полосы","tr":"Şeritin en sağ kenarı boyunca","hi":"लेन के बिल्कुल दाएँ किनारे के साथ","ar":"على طول الحافة اليمنى القصوى من المسار"},{"en":"In the center portion of the lane","es":"En la porción central del carril","ru":"В центральной части полосы","tr":"Şeritin orta bölümünde","hi":"लेन के केंद्रीय हिस्से में","ar":"في الجزء الأوسط من المسار"},{"en":"Only in the left tire track","es":"Solo en la huella de la llanta izquierda","ru":"Только в левой колее","tr":"Yalnızca sol lastik izinde","hi":"केवल बाएँ टायर ट्रैक में","ar":"فقط في مسار الإطار الأيسر"},{"en":"Spread evenly across the whole lane","es":"Repartidos de manera uniforme por todo el carril","ru":"Равномерно распределяются по всей полосе","tr":"Tüm şerite eşit olarak yayılmış","hi":"पूरी लेन में समान रूप से फैला हुआ","ar":"موزعاً بالتساوي عبر المسار بأكمله"}],"e":{"en":"The oily strip that collects drippings from cars runs down the center of the lane and is usually no more than two feet wide. The Motorcycle Operator Manual notes it can be slippery, especially when wet.","es":"La franja aceitosa que acumula los goteos de los autos corre por el centro del carril y por lo general no mide más de dos pies de ancho. El Manual del Operador de Motocicletas señala que puede ser resbalosa, especialmente cuando está mojada.","ru":"Масляная полоса, в которой собираются капли с автомобилей, проходит по центру полосы и обычно имеет ширину не более двух футов. Руководство для водителей мотоциклов отмечает, что она может быть скользкой, особенно при намокании.","tr":"Arabalardan damlayanları toplayan yağlı şerit, şeritin ortasından gider ve genellikle iki fitten geniş değildir. Motosiklet Sürücü Kılavuzu, özellikle ıslakken kaygan olabileceğini belirtir.","hi":"कारों से टपकने वाली बूँदों को इकट्ठा करने वाली तैलीय पट्टी लेन के बीच में चलती है और आमतौर पर दो फ़ुट से अधिक चौड़ी नहीं होती। Motorcycle Operator Manual बताता है कि यह फिसलन भरी हो सकती है, खासकर गीला होने पर।","ar":"يمتد الشريط الزيتي الذي يتجمع فيه ما يتساقط من السيارات في وسط المسار وعادةً لا يزيد عرضه عن قدمين. يشير دليل مشغل الدراجة النارية إلى أنه يمكن أن يكون زلقاً، خاصة عند البلل."}},{"cat":"hazards","a":2,"q":{"en":"When it begins to rain, what is often the best lane position to find better traction?","es":"Cuando empieza a llover, ¿cuál suele ser la mejor posición en el carril para encontrar mejor tracción?","ru":"Когда начинается дождь, какое положение на полосе часто является лучшим для нахождения лучшего сцепления?","tr":"Yağmur başladığında, daha iyi tutuş bulmak için genellikle en iyi şerit konumu hangisidir?","hi":"जब बारिश शुरू होती है, तो बेहतर कर्षण पाने के लिए अक्सर सबसे अच्छी लेन स्थिति कौन सी होती है?","ar":"عندما يبدأ المطر، ما هو غالباً أفضل موضع في المسار للعثور على قوة احتكاك أفضل؟"},"o":[{"en":"Squarely in the center of the lane","es":"Justo en el centro del carril","ru":"Точно по центру полосы","tr":"Tam şeritin ortasında","hi":"लेन के बिल्कुल केंद्र में","ar":"في وسط المسار تماماً"},{"en":"On the painted lane markings","es":"Sobre las marcas pintadas del carril","ru":"По нанесённой разметке полосы","tr":"Boyalı şerit işaretlerinin üzerinde","hi":"पेंट की गई लेन चिह्नों पर","ar":"على علامات المسار المطلية"},{"en":"In the tire tracks left by other vehicles","es":"En las huellas de las llantas dejadas por otros vehículos","ru":"В колеях, оставленных другими транспортными средствами","tr":"Diğer araçların bıraktığı lastik izlerinde","hi":"अन्य वाहनों द्वारा छोड़े गए टायर ट्रैक में","ar":"في مسارات الإطارات التي تركتها المركبات الأخرى"},{"en":"As close to the shoulder gravel as possible","es":"Lo más cerca posible de la grava del acotamiento","ru":"Как можно ближе к гравию на обочине","tr":"Banket çakılına olabildiğince yakın","hi":"कंधे की बजरी के जितना संभव हो उतना पास","ar":"أقرب ما يمكن إلى حصى الكتف"}],"e":{"en":"When it starts to rain, ride in the tire tracks left by cars, where the surface is least slippery; the left track is often best. The Motorcycle Operator Manual advises riding on the least slippery portion of the lane.","es":"Cuando empieza a llover, conduce en las huellas de las llantas dejadas por los autos, donde la superficie es menos resbalosa; la huella izquierda suele ser la mejor. El Manual del Operador de Motocicletas aconseja conducir en la porción menos resbalosa del carril.","ru":"Когда начинается дождь, ездите в колеях, оставленных автомобилями, где поверхность наименее скользкая; левая колея часто лучше всего. Руководство для водителей мотоциклов советует ездить по наименее скользкой части полосы.","tr":"Yağmur başladığında, yüzeyin en az kaygan olduğu, arabaların bıraktığı lastik izlerinde sürün; sol iz çoğu zaman en iyisidir. Motosiklet Sürücü Kılavuzu, şeritin en az kaygan bölümünde sürmeyi tavsiye eder.","hi":"जब बारिश शुरू होती है, तो कारों द्वारा छोड़े गए टायर ट्रैक में चलें, जहाँ सतह सबसे कम फिसलन भरी होती है; बायाँ ट्रैक अक्सर सबसे अच्छा होता है। Motorcycle Operator Manual लेन के सबसे कम फिसलन भरे हिस्से पर चलने की सलाह देता है।","ar":"عندما يبدأ المطر، اركب في مسارات الإطارات التي تركتها السيارات، حيث يكون السطح أقل زلقاً؛ غالباً ما يكون المسار الأيسر هو الأفضل. ينصح دليل مشغل الدراجة النارية بالقيادة على الجزء الأقل زلقاً من المسار."}},{"cat":"hazards","a":3,"q":{"en":"Which of the following surfaces is most likely to be slippery and reduce traction, especially when wet?","es":"¿Cuál de las siguientes superficies es más probable que sea resbalosa y reduzca la tracción, especialmente cuando está mojada?","ru":"Какая из следующих поверхностей наиболее вероятно будет скользкой и снизит сцепление, особенно при намокании?","tr":"Aşağıdaki yüzeylerden hangisi, özellikle ıslakken kaygan olma ve tutuşu azaltma olasılığı en yüksek olanıdır?","hi":"निम्नलिखित में से कौन सी सतह सबसे अधिक फिसलन भरी होने और कर्षण कम करने की संभावना रखती है, खासकर गीला होने पर?","ar":"أي من الأسطح التالية يُرجّح أن يكون زلقاً ويقلل قوة الاحتكاك، خاصة عند البلل؟"},"o":[{"en":"Clean, dry, freshly laid asphalt","es":"Asfalto limpio, seco y recién colocado","ru":"Чистый, сухой, только что уложенный асфальт","tr":"Temiz, kuru, yeni serilmiş asfalt","hi":"साफ़, सूखा, ताज़ा बिछाया गया डामर","ar":"إسفلت نظيف وجاف وحديث الفرش"},{"en":"A coarse concrete roadway in the sun","es":"Una vía de concreto rugoso bajo el sol","ru":"Шероховатое бетонное покрытие на солнце","tr":"Güneşte pürüzlü bir beton yol","hi":"धूप में खुरदरी कंक्रीट की सड़क","ar":"طريق خرساني خشن تحت الشمس"},{"en":"Newly swept pavement free of debris","es":"Pavimento recién barrido y libre de escombros","ru":"Только что подметённое покрытие без мусора","tr":"Döküntüden arınmış, yeni süpürülmüş zemin","hi":"नई बुहारी गई सतह जिस पर कोई मलबा न हो","ar":"رصيف مكنوس حديثاً وخالٍ من الحطام"},{"en":"Painted lane markings, steel plates, and manhole covers","es":"Marcas pintadas del carril, placas de acero y tapas de alcantarilla","ru":"Нанесённая разметка полос, стальные плиты и канализационные люки","tr":"Boyalı şerit işaretleri, çelik plakalar ve rögar kapakları","hi":"पेंट की गई लेन चिह्न, स्टील प्लेट और मैनहोल कवर","ar":"علامات المسار المطلية والألواح الفولاذية وأغطية فتحات الصيانة"}],"e":{"en":"Lane markings, steel plates, manhole covers, and similar smooth surfaces offer little traction and are especially slippery when wet. The Motorcycle Operator Manual lists them among hazardous slippery surfaces.","es":"Las marcas del carril, las placas de acero, las tapas de alcantarilla y superficies lisas similares ofrecen poca tracción y son especialmente resbalosas cuando están mojadas. El Manual del Operador de Motocicletas las incluye entre las superficies resbalosas peligrosas.","ru":"Разметка полос, стальные плиты, канализационные люки и подобные гладкие поверхности обеспечивают слабое сцепление и особенно скользки при намокании. Руководство для водителей мотоциклов относит их к опасным скользким поверхностям.","tr":"Şerit işaretleri, çelik plakalar, rögar kapakları ve benzeri pürüzsüz yüzeyler çok az tutuş sunar ve özellikle ıslakken kaygandır. Motosiklet Sürücü Kılavuzu, bunları tehlikeli kaygan yüzeyler arasında sıralar.","hi":"लेन चिह्न, स्टील प्लेट, मैनहोल कवर और इसी तरह की चिकनी सतहें बहुत कम कर्षण देती हैं और गीली होने पर विशेष रूप से फिसलन भरी होती हैं। Motorcycle Operator Manual इन्हें खतरनाक फिसलन भरी सतहों में सूचीबद्ध करता है।","ar":"توفر علامات المسار والألواح الفولاذية وأغطية فتحات الصيانة والأسطح الناعمة المماثلة قوة احتكاك ضئيلة وتكون زلقة بشكل خاص عند البلل. يدرج دليل مشغل الدراجة النارية هذه ضمن الأسطح الزلقة الخطرة."}},{"cat":"hazards","a":1,"q":{"en":"How should you ride when you must travel across a stretch of gravel, sand, mud, or wet leaves?","es":"¿Cómo debes conducir cuando tienes que atravesar un tramo de grava, arena, lodo u hojas mojadas?","ru":"Как следует ехать, когда нужно пересечь участок гравия, песка, грязи или мокрых листьев?","tr":"Çakıl, kum, çamur veya ıslak yapraklardan oluşan bir kesimi geçmek zorunda kaldığınızda nasıl sürmelisiniz?","hi":"जब आपको बजरी, रेत, कीचड़ या गीली पत्तियों के किसी हिस्से से होकर गुज़रना पड़े तो आपको कैसे चलना चाहिए?","ar":"كيف ينبغي أن تقود عندما يتعين عليك السير عبر مساحة من الحصى أو الرمل أو الطين أو الأوراق المبللة؟"},"o":[{"en":"Speed up to power through quickly before losing traction","es":"Acelerar para pasarlo rápidamente antes de perder tracción","ru":"Ускориться, чтобы быстро проскочить, прежде чем потерять сцепление","tr":"Tutuşu kaybetmeden hızla geçmek için hızlanın","hi":"कर्षण खोने से पहले जल्दी से ताकत से पार करने के लिए गति बढ़ाएँ","ar":"تسارع لتعبرها بقوة وبسرعة قبل فقدان قوة الاحتكاك"},{"en":"Reduce speed, avoid sudden moves, and use both brakes gently","es":"Reducir la velocidad, evitar movimientos bruscos y usar ambos frenos suavemente","ru":"Снизить скорость, избегать резких движений и плавно использовать оба тормоза","tr":"Hızı azaltın, ani hareketlerden kaçının ve her iki freni de nazikçe kullanın","hi":"गति कम करें, अचानक हरकतों से बचें और दोनों ब्रेकों का हल्के से उपयोग करें","ar":"قلّل السرعة وتجنّب الحركات المفاجئة واستخدم كلا المكبحين برفق"},{"en":"Grab the front brake hard to keep the wheel from slipping","es":"Apretar el freno delantero con fuerza para evitar que la rueda resbale","ru":"Резко нажать на передний тормоз, чтобы колесо не проскальзывало","tr":"Tekerleğin kaymasını önlemek için ön frene sert basın","hi":"पहिए को फिसलने से रोकने के लिए फ्रंट ब्रेक को ज़ोर से दबाएँ","ar":"اقبض على المكبح الأمامي بقوة لمنع العجلة من الانزلاق"},{"en":"Lean the motorcycle far over to plant the tires firmly","es":"Inclinar la motocicleta bastante para asentar firmemente las llantas","ru":"Сильно наклонить мотоцикл, чтобы крепко прижать шины","tr":"Lastikleri sağlamca yerleştirmek için motosikleti iyice yatırın","hi":"टायरों को मज़बूती से टिकाने के लिए मोटरसाइकिल को बहुत झुकाएँ","ar":"أمِل الدراجة النارية بعيداً لتثبيت الإطارات بثبات"}],"e":{"en":"On any slippery surface, reduce speed, make no sudden moves, and use both brakes gradually. The Motorcycle Operator Manual stresses smooth, gentle control inputs to keep traction on slick surfaces.","es":"En cualquier superficie resbalosa, reduce la velocidad, no hagas movimientos bruscos y usa ambos frenos de forma gradual. El Manual del Operador de Motocicletas resalta usar controles suaves y delicados para mantener la tracción en superficies resbalosas.","ru":"На любой скользкой поверхности снижайте скорость, не делайте резких движений и плавно используйте оба тормоза. Руководство для водителей мотоциклов подчёркивает важность плавных, мягких управляющих воздействий для сохранения сцепления на скользких поверхностях.","tr":"Herhangi bir kaygan yüzeyde, hızı azaltın, ani hareket yapmayın ve her iki freni de kademeli olarak kullanın. Motosiklet Sürücü Kılavuzu, kaygan yüzeylerde tutuşu korumak için yumuşak, nazik kontrol girdilerini vurgular.","hi":"किसी भी फिसलन भरी सतह पर गति कम करें, कोई अचानक हरकत न करें और दोनों ब्रेकों का धीरे-धीरे उपयोग करें। Motorcycle Operator Manual फिसलन भरी सतहों पर कर्षण बनाए रखने के लिए सहज, हल्के नियंत्रण पर ज़ोर देता है।","ar":"على أي سطح زلق، قلّل السرعة، ولا تقم بحركات مفاجئة، واستخدم كلا المكبحين تدريجياً. يشدد دليل مشغل الدراجة النارية على نعومة ولطف مدخلات التحكم للحفاظ على قوة الاحتكاك على الأسطح الزلقة."}},{"cat":"hazards","a":2,"q":{"en":"Why are metal bridge gratings and rain grooves a special concern for motorcyclists?","es":"¿Por qué las rejillas metálicas de los puentes y las ranuras antilluvia son una preocupación especial para los motociclistas?","ru":"Почему металлические решётки мостов и дождевые канавки представляют особую проблему для мотоциклистов?","tr":"Metal köprü ızgaraları ve yağmur olukları motosikletliler için neden özel bir endişe kaynağıdır?","hi":"धातु के पुल की जालियाँ और रेन ग्रूव मोटरसाइकिल चालकों के लिए विशेष चिंता का विषय क्यों हैं?","ar":"لماذا تُعد شبكات الجسور المعدنية وأخاديد المطر مصدر قلق خاص لسائقي الدراجات النارية؟"},"o":[{"en":"They cause the tires to overheat and lose air pressure","es":"Hacen que las llantas se sobrecalienten y pierdan presión de aire","ru":"Они вызывают перегрев шин и потерю давления воздуха","tr":"Lastiklerin aşırı ısınmasına ve hava basıncı kaybetmesine neden olurlar","hi":"वे टायरों को ज़्यादा गर्म कर देते हैं और हवा का दबाव कम कर देते हैं","ar":"تتسبب في ارتفاع حرارة الإطارات وفقدان ضغط الهواء"},{"en":"They make the throttle stick in the open position","es":"Hacen que el acelerador se atasque en posición abierta","ru":"Они заставляют дроссель заклинивать в открытом положении","tr":"Gazın açık konumda takılı kalmasına neden olurlar","hi":"वे थ्रॉटल को खुली स्थिति में अटका देते हैं","ar":"تجعل دواسة الوقود عالقة في وضع الفتح"},{"en":"They can make the motorcycle weave and feel unsteady","es":"Pueden hacer que la motocicleta serpentee y se sienta inestable","ru":"Они могут заставить мотоцикл вилять и ощущаться неустойчиво","tr":"Motosikletin sallanmasına ve dengesiz hissettirmesine neden olabilirler","hi":"वे मोटरसाइकिल को लहराने और अस्थिर महसूस करा सकते हैं","ar":"يمكن أن تجعل الدراجة النارية تتمايل وتبدو غير مستقرة"},{"en":"They are completely safe and require no special attention","es":"Son completamente seguras y no requieren atención especial","ru":"Они полностью безопасны и не требуют особого внимания","tr":"Tamamen güvenlidirler ve özel dikkat gerektirmezler","hi":"वे पूरी तरह सुरक्षित हैं और किसी विशेष ध्यान की आवश्यकता नहीं है","ar":"إنها آمنة تماماً ولا تتطلب أي اهتمام خاص"}],"e":{"en":"Riding over rain grooves or bridge gratings may make a motorcycle weave. The Motorcycle Operator Manual explains this wandering feeling is generally not hazardous if you stay relaxed and ride straight across.","es":"Conducir sobre ranuras antilluvia o rejillas de puentes puede hacer que una motocicleta serpentee. El Manual del Operador de Motocicletas explica que esta sensación de vagabundeo por lo general no es peligrosa si te mantienes relajado y conduces recto a través de ellas.","ru":"Езда по дождевым канавкам или решёткам мостов может заставить мотоцикл вилять. Руководство для водителей мотоциклов объясняет, что это ощущение блуждания обычно не опасно, если вы остаётесь расслабленным и едете прямо поперёк.","tr":"Yağmur olukları veya köprü ızgaraları üzerinde sürmek motosikletin sallanmasına neden olabilir. Motosiklet Sürücü Kılavuzu, rahat kalır ve düz geçerseniz bu gezinme hissinin genellikle tehlikeli olmadığını açıklar.","hi":"रेन ग्रूव या पुल की जालियों पर चलने से मोटरसाइकिल लहरा सकती है। Motorcycle Operator Manual समझाता है कि अगर आप शांत रहें और सीधे पार करें तो यह भटकने का एहसास आमतौर पर खतरनाक नहीं होता।","ar":"قد يجعل القيادة فوق أخاديد المطر أو شبكات الجسور الدراجة النارية تتمايل. يوضح دليل مشغل الدراجة النارية أن هذا الشعور بالتجوال ليس خطراً عموماً إذا بقيت مسترخياً وقدت في خط مستقيم عبرها."}},{"cat":"hazards","a":3,"q":{"en":"What is the correct way to cross a metal bridge grating or section of rain grooves on a motorcycle?","es":"¿Cuál es la manera correcta de cruzar una rejilla metálica de puente o un tramo de ranuras antilluvia en motocicleta?","ru":"Каков правильный способ пересечения металлической решётки моста или участка дождевых канавок на мотоцикле?","tr":"Bir motosiklette metal köprü ızgarasını veya yağmur olukları bölümünü geçmenin doğru yolu nedir?","hi":"मोटरसाइकिल पर धातु की पुल जाली या रेन ग्रूव के हिस्से को पार करने का सही तरीका क्या है?","ar":"ما هي الطريقة الصحيحة لعبور شبكة جسر معدنية أو قسم من أخاديد المطر على دراجة نارية؟"},"o":[{"en":"Zigzag back and forth to follow the grooves","es":"Zigzaguear de un lado a otro para seguir las ranuras","ru":"Двигаться зигзагом из стороны в сторону, следуя за канавками","tr":"Olukları takip etmek için ileri geri zikzak çizin","hi":"ग्रूव का अनुसरण करने के लिए आगे-पीछे ज़िगज़ैग करें","ar":"تعرّج ذهاباً وإياباً لتتبع الأخاديد"},{"en":"Stop on the grating, then ease across slowly","es":"Detenerte sobre la rejilla y luego cruzar despacio","ru":"Остановиться на решётке, затем медленно переехать","tr":"Izgarada durun, ardından yavaşça geçin","hi":"जाली पर रुकें, फिर धीरे-धीरे पार करें","ar":"توقف على الشبكة، ثم اعبرها ببطء"},{"en":"Cross at a sharp angle to the grooves","es":"Cruzar en un ángulo cerrado respecto a las ranuras","ru":"Пересекать под острым углом к канавкам","tr":"Oluklara keskin bir açıyla geçin","hi":"ग्रूव के तीखे कोण पर पार करें","ar":"اعبر بزاوية حادة على الأخاديد"},{"en":"Relax, keep a steady speed, and ride straight across","es":"Relajarte, mantener una velocidad constante y conducir recto a través de ellas","ru":"Расслабиться, держать постоянную скорость и ехать прямо поперёк","tr":"Rahatlayın, sabit bir hız koruyun ve düz geçin","hi":"आराम से रहें, स्थिर गति बनाए रखें और सीधे पार करें","ar":"استرخِ، حافظ على سرعة ثابتة، وقُد في خط مستقيم عبرها"}],"e":{"en":"Relax, maintain a steady speed, and ride straight across gratings and grooves. The Motorcycle Operator Manual notes the wandering feeling is not dangerous, and zigzagging to fight it is far more hazardous.","es":"Relájate, mantén una velocidad constante y conduce recto a través de las rejillas y ranuras. El Manual del Operador de Motocicletas señala que la sensación de vagabundeo no es peligrosa, y que zigzaguear para combatirla es mucho más arriesgado.","ru":"Расслабьтесь, поддерживайте постоянную скорость и едьте прямо поперёк решёток и канавок. Руководство для водителей мотоциклов отмечает, что ощущение блуждания не опасно, а движение зигзагом для борьбы с ним гораздо опаснее.","tr":"Rahatlayın, sabit bir hız koruyun ve ızgaraları ve olukları düz geçin. Motosiklet Sürücü Kılavuzu, gezinme hissinin tehlikeli olmadığını ve buna karşı zikzak çizmenin çok daha tehlikeli olduğunu belirtir.","hi":"आराम से रहें, स्थिर गति बनाए रखें और जालियों व ग्रूव के सीधे पार करें। Motorcycle Operator Manual बताता है कि भटकने का एहसास खतरनाक नहीं है, और इससे लड़ने के लिए ज़िगज़ैग करना कहीं अधिक खतरनाक है।","ar":"استرخِ، حافظ على سرعة ثابتة، وقُد في خط مستقيم عبر الشبكات والأخاديد. يشير دليل مشغل الدراجة النارية إلى أن الشعور بالتجوال ليس خطراً، وأن التعرّج لمقاومته أكثر خطورة بكثير."}},{"cat":"hazards","a":0,"q":{"en":"What is usually the safest way to cross railroad or trolley tracks that run across your lane?","es":"¿Cuál suele ser la manera más segura de cruzar vías de tren o de tranvía que atraviesan tu carril?","ru":"Какой обычно самый безопасный способ пересечения железнодорожных или трамвайных путей, проходящих поперёк вашей полосы?","tr":"Şeritinizi enine kesen demiryolu veya tramvay raylarını geçmenin genellikle en güvenli yolu nedir?","hi":"आपकी लेन के आर-पार चलने वाली रेलरोड या ट्रॉली पटरियों को पार करने का आमतौर पर सबसे सुरक्षित तरीका क्या है?","ar":"ما هي عادةً الطريقة الأكثر أماناً لعبور سكك القطارات أو الترام التي تمتد عبر مسارك؟"},"o":[{"en":"Ride straight within your lane, crossing as near a right angle as practical","es":"Conducir recto dentro de tu carril, cruzando lo más cerca posible de un ángulo recto","ru":"Ехать прямо в пределах своей полосы, пересекая как можно ближе к прямому углу","tr":"Şeritinizin içinde düz sürün, raylara mümkün olduğunca dik açıya yakın geçin","hi":"अपनी लेन में सीधे चलें, जितना व्यावहारिक हो उतना समकोण के पास पार करें","ar":"قُد في خط مستقيم داخل مسارك، عابراً إياها بأقرب ما يمكن من زاوية قائمة عملياً"},{"en":"Stop completely and walk the motorcycle across the rails","es":"Detenerte por completo y caminar con la motocicleta a través de los rieles","ru":"Полностью остановиться и провести мотоцикл через рельсы пешком","tr":"Tamamen durun ve motosikleti raylardan iterek geçirin","hi":"पूरी तरह रुकें और मोटरसाइकिल को पटरियों के पार पैदल ले जाएँ","ar":"توقف تماماً وادفع الدراجة النارية سيراً عبر القضبان"},{"en":"Swerve into the next lane to take the tracks head-on at 90 degrees","es":"Desviarte al siguiente carril para tomar las vías de frente a 90 grados","ru":"Перестроиться в соседнюю полосу, чтобы пересечь пути в лоб под углом 90 градусов","tr":"Rayları 90 derecede karşıdan almak için bir sonraki şerite savrulun","hi":"अगली लेन में मुड़ें ताकि पटरियों को 90 डिग्री पर सीधे लें","ar":"انعطف إلى المسار التالي لتأخذ السكك بشكل مباشر بزاوية 90 درجة"},{"en":"Edge across the rails slowly at a shallow angle","es":"Cruzar los rieles despacio en un ángulo poco pronunciado","ru":"Медленно переезжать рельсы под небольшим углом","tr":"Raylardan sığ bir açıyla yavaşça geçin","hi":"पटरियों के उथले कोण पर धीरे-धीरे पार करें","ar":"اعبر القضبان ببطء بزاوية ضحلة"}],"e":{"en":"It is usually safest to ride straight within your lane to cross tracks, taking them as close to a right angle as practical. The Motorcycle Operator Manual warns that turning to take tracks head-on can send you into another lane.","es":"Por lo general es más seguro conducir recto dentro de tu carril para cruzar las vías, tomándolas lo más cerca posible de un ángulo recto. El Manual del Operador de Motocicletas advierte que girar para tomar las vías de frente puede mandarte a otro carril.","ru":"Обычно безопаснее всего ехать прямо в пределах своей полосы, чтобы пересечь пути, проходя их как можно ближе к прямому углу. Руководство для водителей мотоциклов предупреждает, что поворот для пересечения путей в лоб может выбросить вас на другую полосу.","tr":"Rayları geçmek için genellikle en güvenlisi şeritinizin içinde düz sürmek, onları mümkün olduğunca dik açıya yakın almaktır. Motosiklet Sürücü Kılavuzu, rayları karşıdan almak için dönmenin sizi başka bir şerite sokabileceği konusunda uyarır.","hi":"पटरियों को पार करने के लिए आमतौर पर अपनी लेन में सीधे चलना सबसे सुरक्षित होता है, जितना व्यावहारिक हो उतना समकोण के पास उन्हें लेते हुए। Motorcycle Operator Manual चेतावनी देता है कि पटरियों को सीधे लेने के लिए मुड़ना आपको दूसरी लेन में भेज सकता है।","ar":"عادةً ما يكون من الأكثر أماناً القيادة في خط مستقيم داخل مسارك لعبور السكك، آخذاً إياها بأقرب ما يمكن من زاوية قائمة عملياً. يحذر دليل مشغل الدراجة النارية من أن الانعطاف لأخذ السكك بشكل مباشر قد يدفعك إلى مسار آخر."}},{"cat":"hazards","a":2,"q":{"en":"When tracks, ruts, or pavement seams run parallel to your path of travel, how should you cross them?","es":"Cuando hay vías, surcos o juntas del pavimento que corren paralelos a tu trayectoria, ¿cómo debes cruzarlos?","ru":"Когда пути, колеи или швы покрытия проходят параллельно вашему направлению движения, как следует их пересекать?","tr":"Raylar, oyuklar veya zemin ekleri gidiş yolunuza paralel uzandığında, bunları nasıl geçmelisiniz?","hi":"जब पटरियाँ, खाँचे या सड़क की दरारें आपके चलने के रास्ते के समानांतर चलती हों, तो आपको उन्हें कैसे पार करना चाहिए?","ar":"عندما تمتد السكك أو الأخاديد أو وصلات الرصيف بشكل موازٍ لمسار سيرك، كيف ينبغي أن تعبرها؟"},"o":[{"en":"Cross with your tire riding right along the seam","es":"Cruzar con tu llanta justo sobre la junta","ru":"Пересекать, едучи шиной прямо вдоль шва","tr":"Lastiğiniz tam eke yaslanarak geçin","hi":"अपने टायर को दरार के ठीक साथ रखते हुए पार करें","ar":"اعبر وإطارك يسير تماماً على طول الوصلة"},{"en":"Cross at a shallow 10-degree angle to stay smooth","es":"Cruzar en un ángulo poco pronunciado de 10 grados para mantenerte suave","ru":"Пересекать под небольшим углом в 10 градусов для плавности","tr":"Pürüzsüz kalmak için sığ bir 10 derece açıyla geçin","hi":"सहज रहने के लिए उथले 10 डिग्री कोण पर पार करें","ar":"اعبر بزاوية ضحلة 10 درجات للبقاء بسلاسة"},{"en":"Move away first, then cross at an angle of at least 45 degrees","es":"Alejarte primero y luego cruzar en un ángulo de al menos 45 grados","ru":"Сначала отъехать в сторону, затем пересечь под углом не менее 45 градусов","tr":"Önce uzaklaşın, ardından en az 45 derecelik bir açıyla geçin","hi":"पहले दूर हटें, फिर कम से कम 45 डिग्री के कोण पर पार करें","ar":"ابتعد أولاً، ثم اعبر بزاوية لا تقل عن 45 درجة"},{"en":"Avoid crossing and ride with your tire in the groove","es":"Evitar cruzarlos y conducir con tu llanta dentro de la ranura","ru":"Избегать пересечения и ехать шиной в канавке","tr":"Geçmekten kaçının ve lastiğiniz oyukta olacak şekilde sürün","hi":"पार करने से बचें और अपने टायर को खाँचे में रखकर चलें","ar":"تجنّب العبور وقُد وإطارك في الأخدود"}],"e":{"en":"Move far enough away from parallel tracks or seams to cross them at an angle of at least 45 degrees, then make a quick, sharp turn. The Motorcycle Operator Manual warns that edging across could catch a tire and unbalance you.","es":"Aléjate lo suficiente de las vías o juntas paralelas para cruzarlas en un ángulo de al menos 45 grados, y luego haz un giro rápido y cerrado. El Manual del Operador de Motocicletas advierte que cruzarlas de canto podría atrapar una llanta y desequilibrarte.","ru":"Отъедьте достаточно далеко от параллельных путей или швов, чтобы пересечь их под углом не менее 45 градусов, затем сделайте быстрый резкий поворот. Руководство для водителей мотоциклов предупреждает, что движение вдоль края может зацепить шину и нарушить равновесие.","tr":"Paralel raylardan veya eklerden, en az 45 derecelik bir açıyla geçebilecek kadar uzaklaşın, ardından hızlı, keskin bir dönüş yapın. Motosiklet Sürücü Kılavuzu, kenarından geçmenin bir lastiği yakalayıp dengenizi bozabileceği konusunda uyarır.","hi":"समानांतर पटरियों या दरारों से इतना दूर हट जाएँ कि उन्हें कम से कम 45 डिग्री के कोण पर पार कर सकें, फिर एक तेज़, तीखा मोड़ लें। Motorcycle Operator Manual चेतावनी देता है कि किनारे से पार करना टायर को फँसा सकता है और आपको असंतुलित कर सकता है।","ar":"ابتعد بما يكفي عن السكك أو الوصلات الموازية لعبورها بزاوية لا تقل عن 45 درجة، ثم قم بانعطاف سريع وحاد. يحذر دليل مشغل الدراجة النارية من أن العبور على الحافة قد يحتجز الإطار ويفقدك توازنك."}},{"cat":"hazards","a":3,"q":{"en":"If you cannot avoid riding over an obstacle such as a piece of debris or a pothole edge, what should you do with the handlebars?","es":"Si no puedes evitar pasar sobre un obstáculo, como un trozo de escombro o el borde de un bache, ¿qué debes hacer con el manubrio?","ru":"Если вы не можете избежать наезда на препятствие, например на обломки или край ямы, что следует делать с рулём?","tr":"Bir döküntü parçası veya çukur kenarı gibi bir engelin üzerinden geçmekten kaçınamazsanız, gidonla ne yapmalısınız?","hi":"अगर आप किसी बाधा जैसे मलबे के टुकड़े या गड्ढे के किनारे पर चलने से बच नहीं सकते, तो आपको हैंडलबार के साथ क्या करना चाहिए?","ar":"إذا لم تستطع تجنّب القيادة فوق عائق مثل قطعة حطام أو حافة حفرة، فماذا ينبغي أن تفعل بالمقود؟"},"o":[{"en":"Turn them sharply at the last moment to skip around it","es":"Girarlo bruscamente en el último momento para esquivarlo","ru":"Резко повернуть его в последний момент, чтобы объехать препятствие","tr":"Etrafından atlamak için son anda keskin bir şekilde çevirin","hi":"इसके आसपास से बचने के लिए आखिरी क्षण में उन्हें तीखा मोड़ें","ar":"أدِره بحدة في اللحظة الأخيرة لتتجاوزه"},{"en":"Let them go loose so the wheel floats over the object","es":"Soltarlo para que la rueda flote sobre el objeto","ru":"Отпустить его, чтобы колесо свободно перекатилось через предмет","tr":"Tekerleğin nesnenin üzerinden süzülmesi için gevşek bırakın","hi":"उन्हें ढीला छोड़ दें ताकि पहिया वस्तु के ऊपर तैर जाए","ar":"اتركه مرتخياً حتى تطفو العجلة فوق الجسم"},{"en":"Pull them toward you to lift the front wheel high","es":"Jalarlo hacia ti para levantar bien la rueda delantera","ru":"Потянуть его на себя, чтобы высоко поднять переднее колесо","tr":"Ön tekerleği yükseltmek için kendinize doğru çekin","hi":"सामने के पहिए को ऊँचा उठाने के लिए उन्हें अपनी ओर खींचें","ar":"اسحبه نحوك لرفع العجلة الأمامية عالياً"},{"en":"Keep them straight so the motorcycle stays upright and balanced","es":"Mantenerlo recto para que la motocicleta se mantenga vertical y equilibrada","ru":"Держать его прямо, чтобы мотоцикл оставался вертикальным и сбалансированным","tr":"Motosikletin dik ve dengeli kalması için düz tutun","hi":"उन्हें सीधा रखें ताकि मोटरसाइकिल सीधी और संतुलित रहे","ar":"أبقِه مستقيماً حتى تبقى الدراجة النارية منتصبة ومتوازنة"}],"e":{"en":"Make sure the motorcycle is straight and keep the handlebars straight when riding over an obstacle. The Motorcycle Operator Manual states that an angled approach increases the chance the obstacle will deflect the front wheel.","es":"Asegúrate de que la motocicleta esté recta y mantén el manubrio recto al pasar sobre un obstáculo. El Manual del Operador de Motocicletas indica que un acercamiento en ángulo aumenta la probabilidad de que el obstáculo desvíe la rueda delantera.","ru":"Убедитесь, что мотоцикл едет прямо, и держите руль прямо при наезде на препятствие. Руководство для водителей мотоциклов утверждает, что подход под углом увеличивает вероятность того, что препятствие отклонит переднее колесо.","tr":"Bir engelin üzerinden geçerken motosikletin düz olduğundan emin olun ve gidonu düz tutun. Motosiklet Sürücü Kılavuzu, açılı bir yaklaşımın engelin ön tekerleği saptırma olasılığını artırdığını belirtir.","hi":"सुनिश्चित करें कि मोटरसाइकिल सीधी हो और बाधा पर चलते समय हैंडलबार को सीधा रखें। Motorcycle Operator Manual बताता है कि कोण से पहुँचने से बाधा द्वारा सामने के पहिए को मोड़ देने की संभावना बढ़ जाती है।","ar":"تأكد من أن الدراجة النارية مستقيمة وأبقِ المقود مستقيماً عند القيادة فوق عائق. ينص دليل مشغل الدراجة النارية على أن الاقتراب بزاوية يزيد من فرصة أن يحرف العائق العجلة الأمامية."}},{"cat":"hazards","a":1,"q":{"en":"When you must ride over an obstacle in the road, what should you do with your body just before contact?","es":"Cuando debes pasar sobre un obstáculo en la vía, ¿qué debes hacer con tu cuerpo justo antes del contacto?","ru":"Когда вам приходится наезжать на препятствие на дороге, что следует делать с телом непосредственно перед контактом?","tr":"Yoldaki bir engelin üzerinden geçmek zorunda kaldığınızda, temastan hemen önce vücudunuzla ne yapmalısınız?","hi":"जब आपको सड़क पर किसी बाधा पर चलना पड़े, तो संपर्क से ठीक पहले आपको अपने शरीर के साथ क्या करना चाहिए?","ar":"عندما يتعين عليك القيادة فوق عائق في الطريق، ماذا ينبغي أن تفعل بجسمك قبل الاصطدام مباشرةً؟"},"o":[{"en":"Press your full weight down into the seat to stay planted","es":"Presionar todo tu peso contra el asiento para mantenerte firme","ru":"Прижаться всем весом к сиденью, чтобы оставаться на месте","tr":"Sabit kalmak için tüm ağırlığınızı sele üzerine bastırın","hi":"टिके रहने के लिए अपना पूरा वज़न सीट में नीचे दबाएँ","ar":"اضغط بكامل وزنك على المقعد لتبقى ثابتاً"},{"en":"Rise slightly off the seat with your weight on the foot pegs","es":"Levantarte ligeramente del asiento con el peso sobre los estribos","ru":"Слегка приподняться над сиденьем, перенеся вес на подножки","tr":"Ağırlığınız basamaklarda olacak şekilde seleden hafifçe yükselin","hi":"अपना वज़न फुट पेग पर रखते हुए सीट से थोड़ा ऊपर उठें","ar":"ارتفع قليلاً عن المقعد مع وضع وزنك على مساند القدمين"},{"en":"Lean far back and lock both arms straight against the bars","es":"Inclinarte bien hacia atrás y trabar ambos brazos rectos contra el manubrio","ru":"Сильно откинуться назад и зафиксировать обе руки прямо на руле","tr":"Geriye doğru iyice yaslanın ve her iki kolu gidona karşı düz kilitleyin","hi":"बहुत पीछे झुकें और दोनों बाँहों को बार पर सीधा लॉक करें","ar":"انحنِ بعيداً للخلف واقفل كلتا ذراعيك مستقيمتين على المقود"},{"en":"Stand fully upright with your feet off the pegs","es":"Pararte completamente erguido con los pies fuera de los estribos","ru":"Полностью встать в полный рост, сняв ноги с подножек","tr":"Ayaklarınız basamaklardan kalkmış halde tamamen ayağa kalkın","hi":"अपने पैरों को पेग से हटाकर पूरी तरह सीधे खड़े हो जाएँ","ar":"قف منتصباً تماماً مع رفع قدميك عن المساند"}],"e":{"en":"Rise slightly off the seat with your weight on the foot pegs to let your knees and elbows absorb the shock. The Motorcycle Operator Manual says this keeps you from being thrown off when crossing an obstacle.","es":"Levántate ligeramente del asiento con el peso sobre los estribos para dejar que tus rodillas y codos absorban el impacto. El Manual del Operador de Motocicletas dice que esto evita que salgas despedido al cruzar un obstáculo.","ru":"Слегка приподнимитесь над сиденьем, перенеся вес на подножки, чтобы колени и локти поглотили удар. Руководство для водителей мотоциклов гласит, что это не даёт вам быть сброшенным при наезде на препятствие.","tr":"Dizlerinizin ve dirseklerinizin şoku emmesine izin vermek için ağırlığınız basamaklarda olacak şekilde seleden hafifçe yükselin. Motosiklet Sürücü Kılavuzu, bunun bir engeli geçerken atılmanızı önlediğini söyler.","hi":"अपना वज़न फुट पेग पर रखते हुए सीट से थोड़ा ऊपर उठें ताकि आपके घुटने और कोहनियाँ झटका सोख सकें। Motorcycle Operator Manual कहता है कि यह आपको बाधा पार करते समय फेंके जाने से बचाता है।","ar":"ارتفع قليلاً عن المقعد مع وضع وزنك على مساند القدمين للسماح لركبتيك ومرفقيك بامتصاص الصدمة. يقول دليل مشغل الدراجة النارية إن هذا يمنعك من أن تُقذف عند عبور عائق."}},{"cat":"hazards","a":0,"q":{"en":"What is the recommended approach to speed before riding over an unavoidable obstacle?","es":"¿Cuál es el enfoque recomendado respecto a la velocidad antes de pasar sobre un obstáculo inevitable?","ru":"Каков рекомендуемый подход к скорости перед наездом на неизбежное препятствие?","tr":"Kaçınılmaz bir engelin üzerinden geçmeden önce hız konusunda önerilen yaklaşım nedir?","hi":"किसी अपरिहार्य बाधा पर चलने से पहले गति के लिए अनुशंसित दृष्टिकोण क्या है?","ar":"ما هو الأسلوب الموصى به بشأن السرعة قبل القيادة فوق عائق لا يمكن تجنّبه؟"},"o":[{"en":"Slow down as much as possible before contact","es":"Reducir la velocidad tanto como sea posible antes del contacto","ru":"Снизить скорость как можно больше перед контактом","tr":"Temastan önce mümkün olduğunca yavaşlayın","hi":"संपर्क से पहले जितना संभव हो उतनी गति कम करें","ar":"أبطئ قدر الإمكان قبل الاصطدام"},{"en":"Accelerate hard to launch the front wheel over it","es":"Acelerar fuerte para impulsar la rueda delantera por encima","ru":"Сильно ускориться, чтобы запустить переднее колесо через него","tr":"Ön tekerleği üzerinden fırlatmak için sert hızlanın","hi":"सामने के पहिए को इसके ऊपर लॉन्च करने के लिए ज़ोर से एक्सीलरेट करें","ar":"تسارع بقوة لإطلاق العجلة الأمامية فوقه"},{"en":"Keep your normal cruising speed for stability","es":"Mantener tu velocidad de crucero normal para tener estabilidad","ru":"Сохранять обычную крейсерскую скорость для устойчивости","tr":"Stabilite için normal seyir hızınızı koruyun","hi":"स्थिरता के लिए अपनी सामान्य क्रूज़िंग गति बनाए रखें","ar":"حافظ على سرعتك العادية للحفاظ على الثبات"},{"en":"Coast in neutral with the clutch pulled in","es":"Avanzar en neutro con el embrague apretado","ru":"Катиться на нейтрали с выжатым сцеплением","tr":"Debriyaj basılı halde boşta süzülün","hi":"क्लच दबाकर न्यूट्रल में कोस्ट करें","ar":"انزلق في وضع الحياد مع سحب القابض"}],"e":{"en":"Slow down as much as possible before contact with an obstacle. The Motorcycle Operator Manual then advises making sure the bike is straight and rising off the seat to absorb the shock with your knees and elbows.","es":"Reduce la velocidad tanto como sea posible antes del contacto con un obstáculo. Luego, el Manual del Operador de Motocicletas aconseja asegurarte de que la moto esté recta y levantarte del asiento para absorber el impacto con las rodillas y los codos.","ru":"Снизьте скорость как можно больше перед контактом с препятствием. Затем Руководство для водителей мотоциклов советует убедиться, что мотоцикл едет прямо, и приподняться над сиденьем, чтобы поглотить удар коленями и локтями.","tr":"Bir engelle temastan önce mümkün olduğunca yavaşlayın. Motosiklet Sürücü Kılavuzu ardından motosikletin düz olduğundan emin olmayı ve şoku dizlerinizle ve dirseklerinizle emmek için seleden yükselmeyi tavsiye eder.","hi":"बाधा से संपर्क से पहले जितना संभव हो उतनी गति कम करें। Motorcycle Operator Manual फिर सलाह देता है कि सुनिश्चित करें कि बाइक सीधी हो और झटके को अपने घुटनों व कोहनियों से सोखने के लिए सीट से ऊपर उठें।","ar":"أبطئ قدر الإمكان قبل الاصطدام بعائق. ثم ينصح دليل مشغل الدراجة النارية بالتأكد من أن الدراجة مستقيمة والارتفاع عن المقعد لامتصاص الصدمة بركبتيك ومرفقيك."}},{"cat":"hazards","a":3,"q":{"en":"Compared with daytime riding, how should you adjust your speed when riding at night?","es":"En comparación con la conducción diurna, ¿cómo debes ajustar tu velocidad al conducir de noche?","ru":"По сравнению с дневной ездой, как следует регулировать скорость при езде ночью?","tr":"Gündüz sürüşüyle karşılaştırıldığında, gece sürerken hızınızı nasıl ayarlamalısınız?","hi":"दिन की सवारी की तुलना में, रात में सवारी करते समय आपको अपनी गति कैसे समायोजित करनी चाहिए?","ar":"مقارنةً بالقيادة نهاراً، كيف ينبغي أن تعدّل سرعتك عند القيادة ليلاً؟"},"o":[{"en":"Ride faster to spend less time in the dark","es":"Conducir más rápido para pasar menos tiempo en la oscuridad","ru":"Ехать быстрее, чтобы провести меньше времени в темноте","tr":"Karanlıkta daha az zaman geçirmek için daha hızlı sürün","hi":"अंधेरे में कम समय बिताने के लिए तेज़ चलें","ar":"قُد أسرع لتقضي وقتاً أقل في الظلام"},{"en":"Keep exactly the same speed as in daylight","es":"Mantener exactamente la misma velocidad que de día","ru":"Сохранять точно такую же скорость, как при дневном свете","tr":"Tam olarak gündüzdeki aynı hızı koruyun","hi":"दिन के उजाले की तरह बिल्कुल वही गति बनाए रखें","ar":"حافظ تماماً على نفس السرعة كما في وضح النهار"},{"en":"Match the speed of the fastest nearby traffic","es":"Igualar la velocidad del tráfico cercano más rápido","ru":"Подстраиваться под скорость самого быстрого транспорта поблизости","tr":"Yakındaki en hızlı trafiğin hızına uyun","hi":"आसपास की सबसे तेज़ ट्रैफ़िक की गति से मिलाएँ","ar":"اضبط سرعتك على سرعة أسرع حركة مرور قريبة"},{"en":"Ride even slower than you would during the day","es":"Conducir aún más despacio de lo que lo harías de día","ru":"Ехать ещё медленнее, чем вы ехали бы днём","tr":"Gündüz süreceğinizden bile daha yavaş sürün","hi":"दिन की तुलना में और भी धीमे चलें","ar":"قُد أبطأ حتى مما تفعل خلال النهار"}],"e":{"en":"Ride more slowly at night than you would during the day, especially on unfamiliar roads. The Motorcycle Operator Manual explains that reduced visibility means you need more room and time to react to hazards.","es":"Conduce más despacio de noche de lo que lo harías de día, especialmente en vías desconocidas. El Manual del Operador de Motocicletas explica que la visibilidad reducida significa que necesitas más espacio y tiempo para reaccionar ante los peligros.","ru":"Ездите медленнее ночью, чем днём, особенно на незнакомых дорогах. Руководство для водителей мотоциклов объясняет, что сниженная видимость означает, что вам нужно больше места и времени для реакции на опасности.","tr":"Gece, özellikle tanımadığınız yollarda gündüz süreceğinizden daha yavaş sürün. Motosiklet Sürücü Kılavuzu, azalan görüşün tehlikelere tepki vermek için daha fazla yer ve zamana ihtiyaç duymanız anlamına geldiğini açıklar.","hi":"रात में दिन की तुलना में अधिक धीमे चलें, खासकर अपरिचित सड़कों पर। Motorcycle Operator Manual समझाता है कि कम दृश्यता का मतलब है कि आपको खतरों पर प्रतिक्रिया करने के लिए अधिक जगह और समय चाहिए।","ar":"قُد أبطأ ليلاً مما تفعل خلال النهار، خاصة على الطرق غير المألوفة. يوضح دليل مشغل الدراجة النارية أن انخفاض الرؤية يعني أنك بحاجة إلى مزيد من المساحة والوقت لرد الفعل تجاه المخاطر."}},{"cat":"hazards","a":1,"q":{"en":"How can the vehicle ahead of you help you ride more safely at night?","es":"¿Cómo puede ayudarte el vehículo que va adelante a conducir con más seguridad de noche?","ru":"Как транспортное средство впереди вас может помочь вам ездить безопаснее ночью?","tr":"Önünüzdeki araç, gece daha güvenli sürmenize nasıl yardımcı olabilir?","hi":"आपके आगे चल रहा वाहन रात में अधिक सुरक्षित सवारी करने में आपकी मदद कैसे कर सकता है?","ar":"كيف يمكن للمركبة أمامك أن تساعدك على القيادة بأمان أكبر ليلاً؟"},"o":[{"en":"It blocks oncoming headlight glare so you can switch your lights off","es":"Bloquea el resplandor de los faros que vienen de frente para que puedas apagar tus luces","ru":"Оно блокирует слепящий свет встречных фар, чтобы вы могли выключить свои огни","tr":"Karşıdan gelen far parıltısını engeller, böylece ışıklarınızı kapatabilirsiniz","hi":"यह सामने से आ रही हेडलाइट की चकाचौंध रोकता है ताकि आप अपनी लाइट बंद कर सकें","ar":"تحجب وهج المصابيح الأمامية القادمة حتى تتمكن من إطفاء أضوائك"},{"en":"Its taillights and headlights can reveal dips, bumps, and the road ahead","es":"Sus luces traseras y faros pueden revelar hondonadas, baches y la vía adelante","ru":"Его задние и передние фары могут выявить впадины, неровности и дорогу впереди","tr":"Stop lambaları ve farları çukurları, tümsekleri ve ileriki yolu ortaya çıkarabilir","hi":"इसकी टेललाइट और हेडलाइट गड्ढों, उभारों और आगे की सड़क को उजागर कर सकती हैं","ar":"يمكن لأضوائها الخلفية والأمامية أن تكشف المنخفضات والمطبات والطريق أمامك"},{"en":"It lets you draft close behind to save fuel and stay alert","es":"Te permite ir muy pegado detrás para ahorrar combustible y mantenerte alerta","ru":"Оно позволяет вам двигаться вплотную за ним, чтобы экономить топливо и сохранять бдительность","tr":"Yakıt tasarrufu yapıp uyanık kalmak için arkasından yakın sürmenize olanak tanır","hi":"यह आपको ईंधन बचाने और सतर्क रहने के लिए पास से ड्राफ्ट करने देता है","ar":"تتيح لك الانسياب قريباً خلفها لتوفير الوقود والبقاء يقظاً"},{"en":"It guarantees the lane is clear so you no longer need to scan","es":"Garantiza que el carril está libre, así que ya no necesitas explorar","ru":"Оно гарантирует, что полоса свободна, так что вам больше не нужно сканировать","tr":"Şeritin boş olduğunu garanti eder, böylece artık taramaya gerek kalmaz","hi":"यह गारंटी देता है कि लेन खाली है ताकि आपको अब स्कैन करने की ज़रूरत न पड़े","ar":"تضمن أن المسار خالٍ فلا تعود بحاجة إلى المسح البصري"}],"e":{"en":"The headlights of a car ahead can give you a better view of the road than even your own high beam. The Motorcycle Operator Manual suggests using the lights of vehicles ahead to spot the road's contour and hazards.","es":"Los faros de un auto que va adelante pueden darte una mejor visión de la vía que incluso tu propia luz alta. El Manual del Operador de Motocicletas sugiere usar las luces de los vehículos que van adelante para detectar el contorno de la vía y los peligros.","ru":"Фары автомобиля впереди могут дать вам лучший обзор дороги, чем даже ваш собственный дальний свет. Руководство для водителей мотоциклов предлагает использовать огни транспортных средств впереди, чтобы заметить рельеф дороги и опасности.","tr":"Önünüzdeki bir arabanın farları, size kendi uzun huzmenizden bile daha iyi bir yol görüşü verebilir. Motosiklet Sürücü Kılavuzu, yolun konturunu ve tehlikeleri fark etmek için önünüzdeki araçların ışıklarını kullanmanızı önerir.","hi":"आगे चल रही कार की हेडलाइट आपको आपकी अपनी हाई बीम से भी बेहतर सड़क का दृश्य दे सकती है। Motorcycle Operator Manual सड़क की बनावट और खतरों को पहचानने के लिए आगे के वाहनों की लाइट का उपयोग करने का सुझाव देता है।","ar":"يمكن للمصابيح الأمامية لسيارة أمامك أن تمنحك رؤية أفضل للطريق من ضوئك العالي نفسه. يقترح دليل مشغل الدراجة النارية استخدام أضواء المركبات الأمامية لرصد تضاريس الطريق والمخاطر."}},{"cat":"hazards","a":2,"q":{"en":"When should you use your high beam at night while riding a motorcycle?","es":"¿Cuándo debes usar tu luz alta de noche al conducir una motocicleta?","ru":"Когда следует использовать дальний свет ночью при езде на мотоцикле?","tr":"Bir motosiklet sürerken gece uzun huzmeyi ne zaman kullanmalısınız?","hi":"मोटरसाइकिल चलाते समय रात में आपको अपनी हाई बीम का उपयोग कब करना चाहिए?","ar":"متى ينبغي أن تستخدم ضوءك العالي ليلاً أثناء قيادة دراجة نارية؟"},"o":[{"en":"Only when riding through well-lit city streets","es":"Solo al conducir por calles bien iluminadas de la ciudad","ru":"Только при езде по хорошо освещённым городским улицам","tr":"Yalnızca iyi aydınlatılmış şehir sokaklarında sürerken","hi":"केवल तब जब अच्छी रोशनी वाली शहरी सड़कों से गुज़र रहे हों","ar":"فقط عند القيادة عبر شوارع المدينة جيدة الإضاءة"},{"en":"Never, because a high beam blinds you to the road","es":"Nunca, porque la luz alta te deslumbra y te impide ver la vía","ru":"Никогда, потому что дальний свет ослепляет вас на дороге","tr":"Asla, çünkü uzun huzme sizi yola karşı kör eder","hi":"कभी नहीं, क्योंकि हाई बीम आपको सड़क के लिए अंधा कर देती है","ar":"أبداً، لأن الضوء العالي يُعمي رؤيتك للطريق"},{"en":"Whenever you are not following or meeting another vehicle","es":"Siempre que no estés siguiendo o cruzándote con otro vehículo","ru":"Всякий раз, когда вы не следуете за другим транспортным средством и не встречаете его","tr":"Başka bir aracı takip etmediğiniz veya karşılaşmadığınız her zaman","hi":"जब भी आप किसी अन्य वाहन के पीछे न चल रहे हों या सामने से न आ रहे हों","ar":"كلما لم تكن تسير خلف مركبة أخرى أو تلتقي بها"},{"en":"Only when another vehicle is close in front of you","es":"Solo cuando otro vehículo está cerca frente a ti","ru":"Только когда другое транспортное средство находится близко впереди вас","tr":"Yalnızca başka bir araç önünüzde yakınken","hi":"केवल तब जब कोई अन्य वाहन आपके बिल्कुल सामने हो","ar":"فقط عندما تكون مركبة أخرى قريبة أمامك"}],"e":{"en":"Use your high beam whenever you are not following or meeting a car, to see as far ahead as possible. The Motorcycle Operator Manual recommends the high beam in the dark except when it would dazzle other drivers.","es":"Usa tu luz alta siempre que no estés siguiendo a un auto ni cruzándote con uno, para ver lo más lejos posible. El Manual del Operador de Motocicletas recomienda la luz alta en la oscuridad, salvo cuando deslumbre a otros conductores.","ru":"Используйте дальний свет всякий раз, когда вы не следуете за автомобилем и не встречаете его, чтобы видеть как можно дальше вперёд. Руководство для водителей мотоциклов рекомендует дальний свет в темноте, кроме случаев, когда он ослепляет других водителей.","tr":"Mümkün olduğunca ileriyi görebilmek için bir arabayı takip etmediğiniz veya bir arabayla karşılaşmadığınız her zaman uzun huzmenizi kullanın. Motosiklet Sürücü Kılavuzu, diğer sürücülerin gözünü kamaştıracağı durumlar dışında karanlıkta uzun huzmeyi önerir.","hi":"जब भी आप किसी कार के पीछे न चल रहे हों या सामने से न मिल रहे हों, तो जितना दूर तक संभव हो देखने के लिए अपनी हाई बीम का उपयोग करें। Motorcycle Operator Manual अंधेरे में हाई बीम की सिफ़ारिश करता है, सिवाय जब यह अन्य चालकों को चकाचौंध कर दे।","ar":"استخدم ضوءك العالي كلما لم تكن تسير خلف سيارة أو تلتقي بها، لترى أبعد ما يمكن أمامك. يوصي دليل مشغل الدراجة النارية بالضوء العالي في الظلام إلا عندما يبهر السائقين الآخرين."}},{"cat":"hazards","a":0,"q":{"en":"How should you adjust your following distance when riding at night?","es":"¿Cómo debes ajustar tu distancia de seguimiento al conducir de noche?","ru":"Как следует регулировать дистанцию следования при езде ночью?","tr":"Gece sürerken takip mesafenizi nasıl ayarlamalısınız?","hi":"रात में सवारी करते समय आपको अपनी फॉलोइंग दूरी कैसे समायोजित करनी चाहिए?","ar":"كيف ينبغي أن تعدّل مسافة الاتباع عند القيادة ليلاً؟"},"o":[{"en":"Increase it, opening up a larger cushion than you keep by day","es":"Aumentarla, abriendo un colchón más grande del que mantienes de día","ru":"Увеличить её, оставляя больший запас, чем днём","tr":"Artırın, gündüz tuttuğunuzdan daha büyük bir tampon açın","hi":"इसे बढ़ाएँ, दिन में रखे जाने वाले कुशन से बड़ा कुशन खोलें","ar":"زِدها، بفتح مسافة أمان أكبر مما تحافظ عليه نهاراً"},{"en":"Decrease it so you can use the leader's lights up close","es":"Disminuirla para poder usar de cerca las luces del que va adelante","ru":"Уменьшить её, чтобы вблизи использовать огни едущего впереди","tr":"Önderin ışıklarını yakından kullanabilmek için azaltın","hi":"इसे कम करें ताकि आप आगे वाले की लाइट को पास से उपयोग कर सकें","ar":"قلّلها حتى تتمكن من استخدام أضواء المركبة الأمامية عن قرب"},{"en":"Keep the same one-second gap you use in daylight","es":"Mantener el mismo intervalo de un segundo que usas de día","ru":"Сохранять тот же односекундный интервал, что и днём","tr":"Gündüz kullandığınız aynı bir saniyelik boşluğu koruyun","hi":"वही एक-सेकंड का अंतर बनाए रखें जो आप दिन के उजाले में रखते हैं","ar":"حافظ على نفس فجوة الثانية الواحدة التي تستخدمها في وضح النهار"},{"en":"Following distance does not matter once headlights are on","es":"La distancia de seguimiento no importa una vez que los faros están encendidos","ru":"Дистанция следования не имеет значения, когда фары включены","tr":"Farlar açık olunca takip mesafesi önemli değildir","hi":"हेडलाइट चालू होने के बाद फॉलोइंग दूरी मायने नहीं रखती","ar":"لا تهم مسافة الاتباع بمجرد إضاءة المصابيح الأمامية"}],"e":{"en":"Increase your following distance at night because it is harder to judge distances and spot hazards in the dark. The Motorcycle Operator Manual advises opening up a larger space cushion when visibility is reduced.","es":"Aumenta tu distancia de seguimiento de noche porque es más difícil calcular distancias y detectar peligros en la oscuridad. El Manual del Operador de Motocicletas aconseja abrir un colchón de espacio más grande cuando la visibilidad es reducida.","ru":"Увеличивайте дистанцию следования ночью, потому что в темноте труднее оценивать расстояния и замечать опасности. Руководство для водителей мотоциклов советует оставлять больший запас пространства при сниженной видимости.","tr":"Gece mesafeleri değerlendirmek ve tehlikeleri fark etmek daha zor olduğu için takip mesafenizi artırın. Motosiklet Sürücü Kılavuzu, görüş azaldığında daha büyük bir tampon boşluğu açmayı tavsiye eder.","hi":"रात में अपनी फॉलोइंग दूरी बढ़ाएँ क्योंकि अंधेरे में दूरी आँकना और खतरों को पहचानना कठिन होता है। Motorcycle Operator Manual सलाह देता है कि दृश्यता कम होने पर बड़ा स्पेस कुशन खोलें।","ar":"زِد مسافة الاتباع ليلاً لأن من الأصعب تقدير المسافات ورصد المخاطر في الظلام. ينصح دليل مشغل الدراجة النارية بفتح مسافة أمان أكبر عند انخفاض الرؤية."}},{"cat":"hazards","a":3,"q":{"en":"How should you handle a sudden strong gust of wind that pushes you sideways while riding?","es":"¿Cómo debes manejar una ráfaga de viento fuerte y repentina que te empuja de lado mientras conduces?","ru":"Как следует справляться с внезапным сильным порывом ветра, толкающим вас вбок во время езды?","tr":"Sürerken sizi yana iten ani, güçlü bir rüzgar hamlesini nasıl ele almalısınız?","hi":"सवारी करते समय अचानक तेज़ हवा का झोंका जो आपको बगल में धकेलता है, उसे आपको कैसे संभालना चाहिए?","ar":"كيف ينبغي أن تتعامل مع هبّة رياح قوية مفاجئة تدفعك جانبياً أثناء القيادة؟"},"o":[{"en":"Lock your arms stiff and grip the bars as hard as you can","es":"Trabar los brazos rígidos y agarrar el manubrio lo más fuerte que puedas","ru":"Зафиксировать руки жёстко и схватить руль как можно крепче","tr":"Kollarınızı sertçe kilitleyin ve gidonu olabildiğince sıkı kavrayın","hi":"अपनी बाँहें अकड़कर लॉक करें और बार को जितना ज़ोर से पकड़ सकें पकड़ें","ar":"اقفل ذراعيك بصلابة واقبض على المقود بأقصى قوة"},{"en":"Brake hard and come to a quick stop in your lane","es":"Frenar fuerte y detenerte rápidamente en tu carril","ru":"Резко затормозить и быстро остановиться на своей полосе","tr":"Sert fren yapın ve şeritinizde hızla durun","hi":"ज़ोर से ब्रेक लगाएँ और अपनी लेन में जल्दी रुक जाएँ","ar":"اكبح بقوة وتوقف بسرعة في مسارك"},{"en":"Lift both feet and let the wind straighten the bike for you","es":"Levantar ambos pies y dejar que el viento enderece la moto por ti","ru":"Поднять обе ноги и дать ветру самому выровнять мотоцикл","tr":"Her iki ayağınızı kaldırın ve rüzgarın motoru sizin için düzeltmesine izin verin","hi":"दोनों पैर उठाएँ और हवा को बाइक सीधी करने दें","ar":"ارفع كلتا قدميك ودع الرياح تقوّم لك الدراجة"},{"en":"Stay relaxed on the bars and steer gently to bring the bike back into your lane","es":"Mantenerte relajado en el manubrio y dirigir con suavidad para volver a tu carril","ru":"Оставаться расслабленным на руле и мягко рулить, чтобы вернуть мотоцикл на свою полосу","tr":"Gidonda rahat kalın ve motosikleti şeritinize geri getirmek için nazikçe yönlendirin","hi":"बार पर आराम से रहें और बाइक को वापस अपनी लेन में लाने के लिए हल्के से स्टीयर करें","ar":"ابقَ مسترخياً على المقود ووجّه برفق لإعادة الدراجة إلى مسارك"}],"e":{"en":"Keep a firm but relaxed grip and make gentle steering corrections to recover from a wind gust. The Motorcycle Operator Manual warns that a stiff, locked grip makes a motorcycle harder to control in wind.","es":"Mantén un agarre firme pero relajado y haz correcciones suaves de dirección para recuperarte de una ráfaga de viento. El Manual del Operador de Motocicletas advierte que un agarre rígido y trabado hace que la motocicleta sea más difícil de controlar con viento.","ru":"Держите руль крепко, но расслабленно, и делайте мягкие корректировки рулём, чтобы восстановиться после порыва ветра. Руководство для водителей мотоциклов предупреждает, что жёсткий, зафиксированный хват затрудняет управление мотоциклом на ветру.","tr":"Bir rüzgar hamlesinden toparlanmak için sıkı ama rahat bir tutuş koruyun ve nazik yönlendirme düzeltmeleri yapın. Motosiklet Sürücü Kılavuzu, sert, kilitli bir tutuşun rüzgarda bir motosikleti kontrol etmeyi zorlaştırdığı konusunda uyarır.","hi":"हवा के झोंके से उबरने के लिए मज़बूत लेकिन आराम से पकड़ बनाए रखें और हल्के स्टीयरिंग सुधार करें। Motorcycle Operator Manual चेतावनी देता है कि अकड़ी, लॉक की गई पकड़ हवा में मोटरसाइकिल को नियंत्रित करना कठिन बना देती है।","ar":"حافظ على قبضة ثابتة لكن مسترخية وقم بتصحيحات توجيه لطيفة للتعافي من هبّة رياح. يحذر دليل مشغل الدراجة النارية من أن القبضة الصلبة المقفلة تجعل الدراجة النارية أصعب في التحكم في الرياح."}},{"cat":"hazards","a":1,"q":{"en":"What should you anticipate when a large truck or bus passes you or comes toward you on the highway?","es":"¿Qué debes anticipar cuando un camión o autobús grande te rebasa o viene hacia ti en la carretera?","ru":"Что следует ожидать, когда большой грузовик или автобус обгоняет вас или едет вам навстречу на шоссе?","tr":"Büyük bir kamyon veya otobüs sizi geçtiğinde ya da otoyolda size doğru geldiğinde neyi öngörmelisiniz?","hi":"जब कोई बड़ा ट्रक या बस राजमार्ग पर आपको पास करे या आपकी ओर आए तो आपको क्या अनुमान लगाना चाहिए?","ar":"ماذا ينبغي أن تتوقع عندما تتجاوزك شاحنة أو حافلة كبيرة أو تأتي نحوك على الطريق السريع؟"},"o":[{"en":"A loss of engine power as your bike is shielded from the air","es":"Una pérdida de potencia del motor al quedar tu moto resguardada del aire","ru":"Потери мощности двигателя, так как ваш мотоцикл оказывается заслонён от воздуха","tr":"Motorunuz havadan korunduğu için bir motor gücü kaybı","hi":"इंजन की शक्ति का नुकसान क्योंकि आपकी बाइक हवा से बच जाती है","ar":"فقدان قدرة المحرك مع حماية دراجتك من الهواء"},{"en":"A blast of wind that can push your motorcycle, so be ready to react","es":"Una ráfaga de viento que puede empujar tu motocicleta, así que prepárate para reaccionar","ru":"Порыва ветра, который может толкнуть ваш мотоцикл, поэтому будьте готовы среагировать","tr":"Motosikletinizi itebilecek bir rüzgar patlaması, bu yüzden tepki vermeye hazır olun","hi":"हवा का झोंका जो आपकी मोटरसाइकिल को धकेल सकता है, इसलिए प्रतिक्रिया के लिए तैयार रहें","ar":"هبّة رياح يمكن أن تدفع دراجتك النارية، فكن مستعداً للتفاعل"},{"en":"That your tires will suddenly grip the road much better","es":"Que tus llantas de pronto se agarrarán mucho mejor a la vía","ru":"Что ваши шины внезапно станут гораздо лучше держаться за дорогу","tr":"Lastiklerinizin aniden yola çok daha iyi tutunacağını","hi":"कि आपके टायर अचानक सड़क को बहुत बेहतर पकड़ लेंगे","ar":"أن إطاراتك ستلتصق فجأة بالطريق بشكل أفضل بكثير"},{"en":"Nothing, because large vehicles create no airflow effect","es":"Nada, porque los vehículos grandes no generan efecto de flujo de aire","ru":"Ничего, потому что большие транспортные средства не создают воздушного эффекта","tr":"Hiçbir şey, çünkü büyük araçlar hava akımı etkisi oluşturmaz","hi":"कुछ नहीं, क्योंकि बड़े वाहन कोई वायुप्रवाह प्रभाव पैदा नहीं करते","ar":"لا شيء، لأن المركبات الكبيرة لا تُحدث أي تأثير على تدفق الهواء"}],"e":{"en":"Large vehicles can create wind blasts that push a motorcycle around as they pass. The Motorcycle Operator Manual advises anticipating the gust, keeping a firm grip, and being ready to make steering corrections.","es":"Los vehículos grandes pueden crear ráfagas de viento que empujan a una motocicleta al pasar. El Manual del Operador de Motocicletas aconseja anticipar la ráfaga, mantener un agarre firme y estar listo para hacer correcciones de dirección.","ru":"Большие транспортные средства могут создавать порывы ветра, толкающие мотоцикл при проезде. Руководство для водителей мотоциклов советует предвидеть порыв, держать руль крепко и быть готовым делать корректировки рулём.","tr":"Büyük araçlar geçerken bir motosikleti oradan oraya itebilen rüzgar patlamaları oluşturabilir. Motosiklet Sürücü Kılavuzu, hamleyi öngörmeyi, sıkı bir tutuş korumayı ve yönlendirme düzeltmeleri yapmaya hazır olmayı tavsiye eder.","hi":"बड़े वाहन गुज़रते समय हवा के झोंके पैदा कर सकते हैं जो मोटरसाइकिल को इधर-उधर धकेलते हैं। Motorcycle Operator Manual झोंके का अनुमान लगाने, मज़बूत पकड़ बनाए रखने और स्टीयरिंग सुधार के लिए तैयार रहने की सलाह देता है।","ar":"يمكن للمركبات الكبيرة أن تُحدث هبّات رياح تدفع الدراجة النارية أثناء مرورها. ينصح دليل مشغل الدراجة النارية بتوقّع الهبّة، والحفاظ على قبضة ثابتة، والاستعداد لإجراء تصحيحات توجيه."}},{"cat":"hazards","a":2,"q":{"en":"You are riding in traffic when a small animal darts into your path. What is the safest response?","es":"Vas conduciendo en el tráfico cuando un animal pequeño se cruza de pronto en tu trayectoria. ¿Cuál es la respuesta más segura?","ru":"Вы едете в потоке, когда небольшое животное выскакивает на ваш путь. Какова самая безопасная реакция?","tr":"Trafikte sürerken küçük bir hayvan yolunuza atlıyor. En güvenli tepki nedir?","hi":"आप ट्रैफ़िक में चल रहे हैं जब एक छोटा जानवर आपके रास्ते में आ जाता है। सबसे सुरक्षित प्रतिक्रिया क्या है?","ar":"أنت تقود في حركة المرور عندما يندفع حيوان صغير إلى مسارك. ما هي الاستجابة الأكثر أماناً؟"},"o":[{"en":"Swerve sharply into the next lane to avoid hitting it","es":"Desviarte bruscamente al siguiente carril para evitar atropellarlo","ru":"Резко вильнуть в соседнюю полосу, чтобы не сбить его","tr":"Çarpmamak için keskin bir şekilde bir sonraki şerite savrulun","hi":"इसे टकराने से बचने के लिए तीखे ढंग से अगली लेन में मुड़ें","ar":"انعطف بحدة إلى المسار التالي لتجنّب الاصطدام به"},{"en":"Slam on the front brake only and skid to a stop","es":"Apretar solo el freno delantero y derrapar hasta detenerte","ru":"Нажать только на передний тормоз и остановиться юзом","tr":"Yalnızca ön frene basın ve kayarak durun","hi":"केवल फ्रंट ब्रेक ज़ोर से लगाएँ और स्किड करके रुकें","ar":"اضغط على المكبح الأمامي فقط وانزلق إلى التوقف"},{"en":"Stay in your lane, since swerving into traffic is more dangerous than the collision","es":"Permanecer en tu carril, ya que desviarte hacia el tráfico es más peligroso que la colisión","ru":"Оставаться на своей полосе, поскольку вилять в поток опаснее, чем столкновение","tr":"Şeritinizde kalın, çünkü trafiğe savrulmak çarpışmadan daha tehlikelidir","hi":"अपनी लेन में रहें, क्योंकि ट्रैफ़िक में मुड़ना टक्कर से अधिक खतरनाक है","ar":"ابقَ في مسارك، لأن الانعطاف إلى حركة المرور أخطر من الاصطدام"},{"en":"Speed up and steer toward the shoulder gravel","es":"Acelerar y dirigirte hacia la grava del acotamiento","ru":"Ускориться и направиться к гравию на обочине","tr":"Hızlanın ve banket çakılına doğru yönelin","hi":"गति बढ़ाएँ और कंधे की बजरी की ओर स्टीयर करें","ar":"تسارع ووجّه نحو حصى الكتف"}],"e":{"en":"In traffic, remain in your lane; hitting a small animal is less dangerous than swerving into another vehicle or off the road. The Motorcycle Operator Manual says do not risk a worse crash to spare a small animal.","es":"En el tráfico, permanece en tu carril; atropellar a un animal pequeño es menos peligroso que desviarte hacia otro vehículo o fuera de la vía. El Manual del Operador de Motocicletas dice que no arriesgues un choque peor por salvar a un animal pequeño.","ru":"В потоке оставайтесь на своей полосе; наезд на небольшое животное менее опасен, чем виляние в другое транспортное средство или съезд с дороги. Руководство для водителей мотоциклов гласит: не рискуйте более серьёзной аварией ради спасения небольшого животного.","tr":"Trafikte şeritinizde kalın; küçük bir hayvana çarpmak, başka bir araca veya yoldan dışarı savrulmaktan daha az tehlikelidir. Motosiklet Sürücü Kılavuzu, küçük bir hayvanı kurtarmak için daha kötü bir kaza riskine girmemeyi söyler.","hi":"ट्रैफ़िक में अपनी लेन में रहें; एक छोटे जानवर को टकराना किसी अन्य वाहन में मुड़ने या सड़क से बाहर जाने से कम खतरनाक है। Motorcycle Operator Manual कहता है कि एक छोटे जानवर को बचाने के लिए बदतर दुर्घटना का जोखिम न उठाएँ।","ar":"في حركة المرور، ابقَ في مسارك؛ الاصطدام بحيوان صغير أقل خطورة من الانعطاف إلى مركبة أخرى أو خارج الطريق. يقول دليل مشغل الدراجة النارية لا تخاطر بتصادم أسوأ لإنقاذ حيوان صغير."}},{"cat":"hazards","a":0,"q":{"en":"What does the manual advise if a dog chases your motorcycle?","es":"¿Qué aconseja el manual si un perro persigue tu motocicleta?","ru":"Что советует Руководство, если собака преследует ваш мотоцикл?","tr":"Bir köpek motosikletinizi kovalarsa kılavuz ne tavsiye eder?","hi":"अगर कोई कुत्ता आपकी मोटरसाइकिल का पीछा करे तो मैनुअल क्या सलाह देता है?","ar":"بماذا ينصح الدليل إذا طارد كلب دراجتك النارية؟"},"o":[{"en":"Downshift and approach slowly, then accelerate away once you near it","es":"Reducir la marcha y acercarte despacio, luego acelerar para alejarte una vez que estés cerca de él","ru":"Понизить передачу и приблизиться медленно, затем ускориться прочь, когда приблизитесь к ней","tr":"Vites küçültün ve yavaşça yaklaşın, ardından ona yaklaşınca hızlanarak uzaklaşın","hi":"डाउनशिफ्ट करें और धीरे-धीरे पास जाएँ, फिर उसके पास पहुँचते ही एक्सीलरेट करके निकल जाएँ","ar":"خفّض الترس واقترب ببطء، ثم تسارع مبتعداً بمجرد اقترابك منه"},{"en":"Kick at the dog to keep it away from your wheels","es":"Patear al perro para mantenerlo lejos de tus ruedas","ru":"Отбиваться от собаки ногой, чтобы держать её подальше от колёс","tr":"Köpeği tekerleklerinizden uzak tutmak için tekme atın","hi":"कुत्ते को अपने पहियों से दूर रखने के लिए उसे लात मारें","ar":"اركل الكلب لإبعاده عن عجلاتك"},{"en":"Stop and wait for the dog to lose interest","es":"Detenerte y esperar a que el perro pierda el interés","ru":"Остановиться и подождать, пока собака потеряет интерес","tr":"Durun ve köpeğin ilgisini kaybetmesini bekleyin","hi":"रुकें और कुत्ते की रुचि खत्म होने का इंतज़ार करें","ar":"توقف وانتظر حتى يفقد الكلب اهتمامه"},{"en":"Swerve repeatedly to confuse the animal","es":"Desviarte repetidamente para confundir al animal","ru":"Многократно вилять, чтобы запутать животное","tr":"Hayvanı şaşırtmak için defalarca savrulun","hi":"जानवर को भ्रमित करने के लिए बार-बार मुड़ें","ar":"انعطف مراراً لإرباك الحيوان"}],"e":{"en":"If a dog chases you, slow and downshift as you approach, then accelerate away to leave it behind. The Motorcycle Operator Manual warns never to kick at an animal, since that can cause you to lose control.","es":"Si un perro te persigue, reduce la velocidad y baja la marcha al acercarte, luego acelera para alejarte y dejarlo atrás. El Manual del Operador de Motocicletas advierte que nunca patees a un animal, ya que eso puede hacerte perder el control.","ru":"Если собака преследует вас, замедлитесь и понизьте передачу при приближении, затем ускорьтесь прочь, чтобы оставить её позади. Руководство для водителей мотоциклов предупреждает: никогда не отбивайтесь от животного ногой, поскольку это может привести к потере управления.","tr":"Bir köpek sizi kovalarsa, yaklaşırken yavaşlayın ve vites küçültün, ardından hızlanarak onu geride bırakın. Motosiklet Sürücü Kılavuzu, bunun kontrolü kaybetmenize neden olabileceği için asla bir hayvana tekme atmamak konusunda uyarır.","hi":"अगर कोई कुत्ता आपका पीछा करे, तो पास पहुँचते समय धीमा करें और डाउनशिफ्ट करें, फिर एक्सीलरेट करके उसे पीछे छोड़ दें। Motorcycle Operator Manual चेतावनी देता है कि किसी जानवर को कभी लात न मारें, क्योंकि इससे आपका नियंत्रण छूट सकता है।","ar":"إذا طاردك كلب، أبطئ وخفّض الترس عند اقترابك، ثم تسارع مبتعداً لتتركه خلفك. يحذر دليل مشغل الدراجة النارية من ركل حيوان أبداً، لأن ذلك قد يفقدك السيطرة."}},{"cat":"hazards","a":2,"q":{"en":"How should you treat a large animal such as a deer standing in or near the roadway?","es":"¿Cómo debes tratar a un animal grande, como un venado, que está en la vía o cerca de ella?","ru":"Как следует обращаться с крупным животным, например с оленем, стоящим на проезжей части или рядом с ней?","tr":"Yolda veya yol kenarında duran geyik gibi büyük bir hayvana nasıl davranmalısınız?","hi":"सड़क पर या उसके पास खड़े हिरण जैसे बड़े जानवर को आपको कैसे संभालना चाहिए?","ar":"كيف ينبغي أن تتعامل مع حيوان كبير مثل غزال يقف في الطريق أو بالقرب منه؟"},"o":[{"en":"Maintain speed and rely on the animal to move away","es":"Mantener la velocidad y confiar en que el animal se aparte","ru":"Сохранять скорость и полагаться на то, что животное уйдёт","tr":"Hızı koruyun ve hayvanın uzaklaşmasına güvenin","hi":"गति बनाए रखें और जानवर के हट जाने पर भरोसा करें","ar":"حافظ على السرعة واعتمد على ابتعاد الحيوان"},{"en":"Sound your horn once and accelerate past it","es":"Tocar la bocina una vez y acelerar para pasarlo","ru":"Один раз подать сигнал и проехать мимо на ускорении","tr":"Bir kez korna çalın ve hızlanarak geçin","hi":"एक बार हॉर्न बजाएँ और उसके पास से एक्सीलरेट करके निकल जाएँ","ar":"انفخ بوقك مرة واحدة وتسارع لتتجاوزه"},{"en":"Slow down, prepare to stop, and expect it to move unpredictably","es":"Reducir la velocidad, prepararte para detenerte y esperar que se mueva de forma impredecible","ru":"Снизить скорость, приготовиться к остановке и ожидать, что оно будет двигаться непредсказуемо","tr":"Yavaşlayın, durmaya hazırlanın ve öngörülemez şekilde hareket etmesini bekleyin","hi":"धीमा करें, रुकने के लिए तैयार रहें और उम्मीद करें कि यह अप्रत्याशित रूप से हिलेगा","ar":"أبطئ، واستعد للتوقف، وتوقّع أن يتحرك بشكل غير متوقع"},{"en":"Steer straight at it to scare it off the road","es":"Dirigirte recto hacia él para asustarlo y sacarlo de la vía","ru":"Направить мотоцикл прямо на него, чтобы согнать его с дороги","tr":"Onu yoldan korkutup kaçırmak için doğrudan üzerine yönelin","hi":"इसे सड़क से डराकर भगाने के लिए सीधे इसकी ओर स्टीयर करें","ar":"وجّه مباشرةً نحوه لإخافته خارج الطريق"}],"e":{"en":"Large animals like deer are unpredictable, so brake and prepare to stop. The Motorcycle Operator Manual advises slowing and being ready to stop rather than gambling on which way the animal will move.","es":"Los animales grandes como los venados son impredecibles, así que frena y prepárate para detenerte. El Manual del Operador de Motocicletas aconseja reducir la velocidad y estar listo para detenerte, en lugar de apostar a hacia qué lado se moverá el animal.","ru":"Крупные животные, такие как олени, непредсказуемы, поэтому тормозите и готовьтесь к остановке. Руководство для водителей мотоциклов советует снижать скорость и быть готовым остановиться, а не угадывать, в какую сторону двинется животное.","tr":"Geyik gibi büyük hayvanlar öngörülemez olduğundan fren yapın ve durmaya hazırlanın. Motosiklet Sürücü Kılavuzu, hayvanın ne tarafa hareket edeceği üzerine kumar oynamak yerine yavaşlamayı ve durmaya hazır olmayı tavsiye eder.","hi":"हिरण जैसे बड़े जानवर अप्रत्याशित होते हैं, इसलिए ब्रेक लगाएँ और रुकने के लिए तैयार रहें। Motorcycle Operator Manual जानवर किस दिशा में जाएगा इस पर दाँव लगाने के बजाय धीमा करने और रुकने के लिए तैयार रहने की सलाह देता है।","ar":"الحيوانات الكبيرة مثل الغزلان غير متوقعة، لذا اكبح واستعد للتوقف. ينصح دليل مشغل الدراجة النارية بالإبطاء والاستعداد للتوقف بدلاً من المراهنة على الاتجاه الذي سيتحرك إليه الحيوان."}},{"cat":"hazards","a":3,"q":{"en":"Why should you avoid riding directly on painted lane lines, tar snakes, or steel plates, particularly in the rain?","es":"¿Por qué debes evitar conducir directamente sobre líneas pintadas del carril, sellos de alquitrán (tar snakes) o placas de acero, en especial bajo la lluvia?","ru":"Почему следует избегать езды прямо по нанесённой разметке, битумным заплаткам или стальным плитам, особенно в дождь?","tr":"Özellikle yağmurda, doğrudan boyalı şerit çizgilerinin, zift dolgularının veya çelik plakaların üzerinde sürmekten neden kaçınmalısınız?","hi":"आपको पेंट की गई लेन रेखाओं, टार स्नेक या स्टील प्लेटों पर सीधे चलने से क्यों बचना चाहिए, खासकर बारिश में?","ar":"لماذا ينبغي أن تتجنّب القيادة مباشرةً على خطوط المسار المطلية أو خطوط القار أو الألواح الفولاذية، خاصة في المطر؟"},"o":[{"en":"They always carry a small electric charge that can shock the tires","es":"Siempre llevan una pequeña carga eléctrica que puede dar toques a las llantas","ru":"Они всегда несут небольшой электрический заряд, который может ударить шины током","tr":"Her zaman lastikleri çarpabilecek küçük bir elektrik yükü taşırlar","hi":"वे हमेशा एक छोटा बिजली का चार्ज रखते हैं जो टायरों को झटका दे सकता है","ar":"تحمل دائماً شحنة كهربائية صغيرة يمكن أن تصعق الإطارات"},{"en":"They reflect headlights and blind oncoming drivers","es":"Reflejan los faros y deslumbran a los conductores que vienen de frente","ru":"Они отражают свет фар и ослепляют встречных водителей","tr":"Farları yansıtır ve karşıdan gelen sürücülerin gözünü kör eder","hi":"वे हेडलाइट परावर्तित करते हैं और सामने से आ रहे चालकों को अंधा कर देते हैं","ar":"تعكس المصابيح الأمامية وتُعمي السائقين القادمين"},{"en":"They are softer than the road and can trap a motorcycle tire","es":"Son más blandos que la vía y pueden atrapar una llanta de motocicleta","ru":"Они мягче дороги и могут защемить шину мотоцикла","tr":"Yoldan daha yumuşaktırlar ve bir motosiklet lastiğini hapsedebilirler","hi":"वे सड़क से नरम होते हैं और मोटरसाइकिल के टायर को फँसा सकते हैं","ar":"إنها أنعم من الطريق ويمكن أن تحتجز إطار دراجة نارية"},{"en":"They are smooth surfaces that offer much less traction than pavement","es":"Son superficies lisas que ofrecen mucha menos tracción que el pavimento","ru":"Это гладкие поверхности, обеспечивающие гораздо меньшее сцепление, чем покрытие","tr":"Zeminden çok daha az tutuş sunan pürüzsüz yüzeylerdir","hi":"वे चिकनी सतहें हैं जो सड़क की तुलना में बहुत कम कर्षण देती हैं","ar":"إنها أسطح ناعمة توفر قوة احتكاك أقل بكثير من الرصيف"}],"e":{"en":"Smooth surfaces like lane markings, tar patches, and steel plates provide far less grip than ordinary pavement and become especially slick when wet. The Motorcycle Operator Manual urges riders to avoid them or cross with caution.","es":"Las superficies lisas como las marcas del carril, los parches de alquitrán y las placas de acero ofrecen mucho menos agarre que el pavimento común y se vuelven especialmente resbalosas cuando están mojadas. El Manual del Operador de Motocicletas insta a los conductores a evitarlas o cruzarlas con precaución.","ru":"Гладкие поверхности, такие как разметка полос, битумные заплатки и стальные плиты, обеспечивают гораздо меньшее сцепление, чем обычное покрытие, и становятся особенно скользкими при намокании. Руководство для водителей мотоциклов настоятельно советует избегать их или пересекать с осторожностью.","tr":"Şerit işaretleri, zift yamaları ve çelik plakalar gibi pürüzsüz yüzeyler, sıradan zeminden çok daha az tutuş sağlar ve ıslakken özellikle kayganlaşır. Motosiklet Sürücü Kılavuzu, sürücüleri bunlardan kaçınmaya veya dikkatle geçmeye teşvik eder.","hi":"लेन चिह्न, टार पैच और स्टील प्लेट जैसी चिकनी सतहें साधारण सड़क की तुलना में बहुत कम पकड़ देती हैं और गीली होने पर विशेष रूप से फिसलन भरी हो जाती हैं। Motorcycle Operator Manual सवारों से इनसे बचने या सावधानी से पार करने का आग्रह करता है।","ar":"توفر الأسطح الناعمة مثل علامات المسار ورقع القار والألواح الفولاذية قوة قبضة أقل بكثير من الرصيف العادي وتصبح زلقة بشكل خاص عند البلل. يحث دليل مشغل الدراجة النارية السائقين على تجنّبها أو عبورها بحذر."}},{"cat":"passenger","a":0,"q":{"en":"Before carrying a passenger, your motorcycle must be properly equipped. Which of the following is required?","es":"Antes de llevar a un pasajero, tu motocicleta debe estar debidamente equipada. ¿Cuál de los siguientes es requerido?","ru":"Перед перевозкой пассажира мотоцикл должен быть надлежащим образом оборудован. Что из перечисленного является обязательным?","tr":"Bir yolcu taşımadan önce, motosikletiniz uygun şekilde donatılmış olmalıdır. Aşağıdakilerden hangisi gereklidir?","hi":"यात्री ले जाने से पहले, आपकी मोटरसाइकिल ठीक से सुसज्जित होनी चाहिए। निम्नलिखित में से कौन सी आवश्यक है?","ar":"قبل حمل راكب، يجب أن تكون دراجتك النارية مجهّزة بشكل صحيح. أي مما يلي مطلوب؟"},"o":[{"en":"A proper seat large enough for both of you plus footrests for the passenger","es":"Un asiento adecuado lo bastante grande para los dos, además de estribos para el pasajero","ru":"Подходящее сиденье, достаточно большое для вас обоих, плюс подножки для пассажира","tr":"İkinizi de alacak kadar büyük uygun bir sele ve yolcu için ayaklıklar","hi":"आप दोनों के लिए पर्याप्त बड़ी उचित सीट और यात्री के लिए फुटरेस्ट","ar":"مقعد مناسب كبير بما يكفي لكليكما إضافةً إلى مساند قدمين للراكب"},{"en":"A windshield to shield the passenger from wind","es":"Un parabrisas para proteger al pasajero del viento","ru":"Ветровое стекло для защиты пассажира от ветра","tr":"Yolcuyu rüzgardan korumak için bir ön cam","hi":"यात्री को हवा से बचाने के लिए विंडशील्ड","ar":"حاجب رياح لحماية الراكب من الرياح"},{"en":"A backrest bolted to the rear fender","es":"Un respaldo atornillado al guardabarros trasero","ru":"Спинка, привинченная к заднему крылу","tr":"Arka çamurluğa cıvatalanmış bir sırt desteği","hi":"पीछे के फेंडर पर बोल्ट किया गया बैकरेस्ट","ar":"مسند ظهر مثبّت بالرفرف الخلفي"},{"en":"An extra mirror mounted for the passenger","es":"Un espejo adicional montado para el pasajero","ru":"Дополнительное зеркало, установленное для пассажира","tr":"Yolcu için monte edilmiş ekstra bir ayna","hi":"यात्री के लिए लगाया गया एक अतिरिक्त मिरर","ar":"مرآة إضافية مركّبة للراكب"}],"e":{"en":"The motorcycle should have a proper seat large enough to hold both you and the passenger without crowding, along with passenger footrests. Source: Motorcycle Operator Manual.","es":"La motocicleta debe tener un asiento adecuado lo bastante grande para sostenerte a ti y al pasajero sin apretujarse, junto con estribos para el pasajero. Fuente: Manual del Operador de Motocicletas.","ru":"Мотоцикл должен иметь подходящее сиденье, достаточно большое, чтобы вместить вас и пассажира без тесноты, а также подножки для пассажира. Источник: Руководство для водителей мотоциклов.","tr":"Motosiklet, sizi ve yolcuyu sıkışmadan alacak kadar büyük uygun bir seleye ve yolcu ayaklıklarına sahip olmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"मोटरसाइकिल में आप और यात्री दोनों को बिना भीड़ के समाने के लिए पर्याप्त बड़ी उचित सीट होनी चाहिए, साथ ही यात्री के फुटरेस्ट भी। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يكون للدراجة النارية مقعد مناسب كبير بما يكفي لاستيعابك أنت والراكب دون ازدحام، إضافةً إلى مساند قدمين للراكب. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should a passenger hold on while you are riding?","es":"¿De dónde debe sujetarse un pasajero mientras conduces?","ru":"За что должен держаться пассажир, пока вы едете?","tr":"Siz sürerken bir yolcu nereye tutunmalıdır?","hi":"सवारी करते समय यात्री को कहाँ पकड़ना चाहिए?","ar":"أين ينبغي أن يتمسك الراكب أثناء قيادتك؟"},"o":[{"en":"Onto the rear of the seat with both hands","es":"De la parte trasera del asiento con ambas manos","ru":"За заднюю часть сиденья обеими руками","tr":"İki eliyle selenin arkasına","hi":"सीट के पीछे दोनों हाथों से","ar":"بمؤخرة المقعد بكلتا يديه"},{"en":"To your waist, hips, or belt, or to the passenger handholds","es":"De tu cintura, caderas o cinturón, o de los agarres para pasajero","ru":"За вашу талию, бёдра или ремень, либо за поручни для пассажира","tr":"Belinize, kalçanıza veya kemerinize ya da yolcu tutamaklarına","hi":"आपकी कमर, कूल्हों या बेल्ट को, या यात्री हैंडहोल्ड को","ar":"بخصرك أو وركيك أو حزامك، أو بمقابض اليد الخاصة بالراكب"},{"en":"Onto your shoulders to steer with you","es":"De tus hombros para dirigir contigo","ru":"За ваши плечи, чтобы рулить вместе с вами","tr":"Sizinle birlikte yönlendirmek için omuzlarınıza","hi":"आपके साथ स्टीयर करने के लिए आपके कंधों को","ar":"بكتفيك ليوجّه معك"},{"en":"To the sissy bar behind them","es":"De la barra trasera (sissy bar) que está detrás de él","ru":"За спинку-дугу позади себя","tr":"Arkalarındaki sissy bara","hi":"उनके पीछे की सिसी बार को","ar":"بقضيب المسند الخلفي خلفه"}],"e":{"en":"A passenger should hold firmly to your waist, hips, or belt, or use the motorcycle's passenger handholds. Source: Motorcycle Operator Manual.","es":"El pasajero debe sujetarse firmemente de tu cintura, caderas o cinturón, o usar los agarres para pasajero de la motocicleta. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен крепко держаться за вашу талию, бёдра или ремень, либо использовать пассажирские поручни мотоцикла. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, belinize, kalçanıza veya kemerinize sıkıca tutunmalı ya da motosikletin yolcu tutamaklarını kullanmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपकी कमर, कूल्हों या बेल्ट को मज़बूती से पकड़ना चाहिए, या मोटरसाइकिल के यात्री हैंडहोल्ड का उपयोग करना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يتمسك الراكب بإحكام بخصرك أو وركيك أو حزامك، أو يستخدم مقابض اليد الخاصة بالراكب في الدراجة النارية. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":2,"q":{"en":"What should a passenger do with their feet when the motorcycle comes to a stop at a red light?","es":"¿Qué debe hacer un pasajero con los pies cuando la motocicleta se detiene en una luz roja?","ru":"Что должен делать пассажир со своими ногами, когда мотоцикл останавливается на красный сигнал?","tr":"Motosiklet kırmızı ışıkta durduğunda bir yolcu ayaklarıyla ne yapmalıdır?","hi":"जब मोटरसाइकिल लाल बत्ती पर रुके तो यात्री को अपने पैरों के साथ क्या करना चाहिए?","ar":"ماذا ينبغي أن يفعل الراكب بقدميه عندما تتوقف الدراجة النارية عند إشارة حمراء؟"},"o":[{"en":"Put both feet down on the ground for balance","es":"Poner ambos pies en el suelo para mantener el equilibrio","ru":"Поставить обе ноги на землю для равновесия","tr":"Denge için iki ayağını da yere koymalı","hi":"संतुलन के लिए दोनों पैर ज़मीन पर रखें","ar":"يضع كلتا قدميه على الأرض للتوازن"},{"en":"Lift their feet up onto the seat","es":"Levantar los pies sobre el asiento","ru":"Поднять ноги на сиденье","tr":"Ayaklarını selenin üzerine kaldırmalı","hi":"अपने पैर सीट पर ऊपर उठाएँ","ar":"يرفع قدميه إلى المقعد"},{"en":"Keep both feet firmly on the footrests","es":"Mantener ambos pies firmes sobre los estribos","ru":"Держать обе ноги крепко на подножках","tr":"Her iki ayağını da ayaklıklarda sıkıca tutmalı","hi":"दोनों पैर फुटरेस्ट पर मज़बूती से रखें","ar":"يبقي كلتا قدميه بثبات على مساند القدمين"},{"en":"Place one foot down to steady the bike","es":"Poner un pie en el suelo para estabilizar la moto","ru":"Поставить одну ногу на землю, чтобы стабилизировать мотоцикл","tr":"Motosikleti dengelemek için bir ayağını yere koymalı","hi":"बाइक को स्थिर करने के लिए एक पैर नीचे रखें","ar":"يضع قدماً واحدة على الأرض لتثبيت الدراجة"}],"e":{"en":"A passenger should keep both feet firmly on the footrests even when the motorcycle is stopped; firm footing keeps them from falling off and pulling you off. Source: Motorcycle Operator Manual.","es":"Un pasajero debe mantener ambos pies firmes sobre los estribos incluso cuando la motocicleta está detenida; un apoyo firme evita que se caiga y te tire a ti también. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен держать обе ноги крепко на подножках, даже когда мотоцикл стоит; крепкая опора не даёт ему упасть и стянуть вас за собой. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, motosiklet dururken bile her iki ayağını da ayaklıklarda sıkıca tutmalıdır; sağlam basış, düşüp sizi de düşürmesini önler. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को मोटरसाइकिल रुकी होने पर भी दोनों पैर फुटरेस्ट पर मज़बूती से रखने चाहिए; मज़बूत पकड़ उन्हें गिरने और आपको खींचकर गिराने से रोकती है। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يبقي الراكب كلتا قدميه بثبات على مساند القدمين حتى عند توقف الدراجة النارية؛ فالموطئ الثابت يمنعه من السقوط وجذبك معه. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should the passenger sit on the motorcycle?","es":"¿Dónde debe sentarse el pasajero en la motocicleta?","ru":"Где должен сидеть пассажир на мотоцикле?","tr":"Yolcu motosiklette nerede oturmalıdır?","hi":"यात्री को मोटरसाइकिल पर कहाँ बैठना चाहिए?","ar":"أين ينبغي أن يجلس الراكب على الدراجة النارية؟"},"o":[{"en":"As far back as possible to reduce crowding","es":"Lo más atrás posible para reducir el apretujamiento","ru":"Как можно дальше назад, чтобы уменьшить тесноту","tr":"Sıkışmayı azaltmak için olabildiğince geride","hi":"भीड़ कम करने के लिए जितना संभव हो उतना पीछे","ar":"في أقصى الخلف قدر الإمكان لتقليل الازدحام"},{"en":"As far forward as possible without crowding you, directly behind you","es":"Lo más adelante posible sin apretujarte, directamente detrás de ti","ru":"Как можно дальше вперёд, не создавая для вас тесноты, прямо позади вас","tr":"Sizi sıkıştırmadan olabildiğince önde, tam arkanızda","hi":"आपको भीड़ दिए बिना जितना संभव हो उतना आगे, सीधे आपके पीछे","ar":"في أقصى الأمام قدر الإمكان دون ازدحامك، مباشرةً خلفك"},{"en":"In front of you so you can watch over them","es":"Frente a ti para que puedas vigilarlo","ru":"Перед вами, чтобы вы могли присматривать за ним","tr":"Onları gözetebilmeniz için önünüzde","hi":"आपके सामने ताकि आप उन पर नज़र रख सकें","ar":"أمامك حتى تتمكن من مراقبته"},{"en":"Off to one side to balance the load","es":"A un lado para equilibrar la carga","ru":"Сбоку, чтобы уравновесить нагрузку","tr":"Yükü dengelemek için bir tarafa","hi":"भार संतुलित करने के लिए एक तरफ़","ar":"إلى أحد الجانبين لموازنة الحمل"}],"e":{"en":"A passenger should sit as far forward as possible without crowding you and stay directly behind you. Source: Motorcycle Operator Manual.","es":"Un pasajero debe sentarse lo más adelante posible sin apretujarte y permanecer directamente detrás de ti. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен сидеть как можно дальше вперёд, не создавая для вас тесноты, и оставаться прямо позади вас. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, sizi sıkıştırmadan olabildiğince önde oturmalı ve tam arkanızda kalmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपको भीड़ दिए बिना जितना संभव हो उतना आगे बैठना चाहिए और सीधे आपके पीछे रहना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يجلس الراكب في أقصى الأمام قدر الإمكان دون ازدحامك ويبقى مباشرةً خلفك. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":2,"q":{"en":"How should a passenger handle their body when you ride through a turn or curve?","es":"¿Cómo debe manejar su cuerpo un pasajero cuando conduces por un giro o una curva?","ru":"Как должен вести себя пассажир, когда вы проезжаете поворот или вираж?","tr":"Bir dönüş veya virajdan geçerken yolcu vücuduyla nasıl baş etmelidir?","hi":"जब आप किसी मोड़ या कर्व से गुज़रें तो यात्री को अपने शरीर को कैसे संभालना चाहिए?","ar":"كيف ينبغي أن يتعامل الراكب مع جسمه عندما تقود عبر انعطاف أو منعطف؟"},"o":[{"en":"Sit upright and resist leaning to stay stable","es":"Sentarse erguido y resistir inclinarse para mantenerse estable","ru":"Сидеть прямо и сопротивляться наклону, чтобы сохранять устойчивость","tr":"Sabit kalmak için dik oturup yatmaya direnmeli","hi":"स्थिर रहने के लिए सीधे बैठें और झुकने से बचें","ar":"يجلس منتصباً ويقاوم الميل ليبقى ثابتاً"},{"en":"Lean away from the turn to counterbalance the bike","es":"Inclinarse en sentido contrario a la curva para contrabalancear la moto","ru":"Наклоняться в сторону от поворота, чтобы уравновесить мотоцикл","tr":"Motosikleti dengelemek için dönüşten uzağa yatmalı","hi":"बाइक को संतुलित करने के लिए मोड़ से दूर झुकें","ar":"يميل بعيداً عن الانعطاف لموازنة الدراجة"},{"en":"Lean with you, looking over your shoulder in the direction of the turn","es":"Inclinarse contigo, mirando por encima de tu hombro en la dirección del giro","ru":"Наклоняться вместе с вами, глядя через ваше плечо в направлении поворота","tr":"Sizinle birlikte yatmalı, dönüş yönünde omzunuzun üzerinden bakmalı","hi":"आपके साथ झुकें, मोड़ की दिशा में आपके कंधे के ऊपर से देखते हुए","ar":"يميل معك، ناظراً فوق كتفك في اتجاه الانعطاف"},{"en":"Shift their weight to the outside of the curve","es":"Desplazar su peso hacia el exterior de la curva","ru":"Переносить вес на внешнюю сторону виража","tr":"Ağırlığını virajın dışına kaydırmalı","hi":"अपना वज़न कर्व के बाहर की ओर शिफ्ट करें","ar":"ينقل وزنه إلى خارج المنعطف"}],"e":{"en":"A passenger should lean as you lean and look over your shoulder in the direction of turns and curves. Source: Motorcycle Operator Manual.","es":"Un pasajero debe inclinarse cuando tú te inclines y mirar por encima de tu hombro en la dirección de los giros y curvas. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен наклоняться, когда наклоняетесь вы, и смотреть через ваше плечо в направлении поворотов и виражей. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, siz yattıkça yatmalı ve dönüşler ile virajların yönünde omzunuzun üzerinden bakmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपके झुकने पर झुकना चाहिए और मोड़ों व कर्व की दिशा में आपके कंधे के ऊपर से देखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يميل الراكب كما تميل وينظر فوق كتفك في اتجاه الانعطافات والمنعطفات. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When should the passenger get on the motorcycle?","es":"¿Cuándo debe subirse el pasajero a la motocicleta?","ru":"Когда пассажир должен садиться на мотоцикл?","tr":"Yolcu motosiklete ne zaman binmelidir?","hi":"यात्री को मोटरसाइकिल पर कब चढ़ना चाहिए?","ar":"متى ينبغي أن يصعد الراكب على الدراجة النارية؟"},"o":[{"en":"Before you start the engine, while the bike is on its stand","es":"Antes de que arranques el motor, mientras la moto está en su soporte","ru":"До того как вы заведёте двигатель, пока мотоцикл стоит на подставке","tr":"Siz motoru çalıştırmadan önce, motosiklet sehpasındayken","hi":"आपके इंजन शुरू करने से पहले, जब बाइक अपने स्टैंड पर हो","ar":"قبل تشغيل المحرك، بينما الدراجة على حاملها"},{"en":"After you have started the engine","es":"Después de que hayas arrancado el motor","ru":"После того как вы завели двигатель","tr":"Siz motoru çalıştırdıktan sonra","hi":"आपके इंजन शुरू करने के बाद","ar":"بعد أن تكون قد شغّلت المحرك"},{"en":"While the motorcycle is rolling slowly","es":"Mientras la motocicleta avanza despacio","ru":"Пока мотоцикл медленно катится","tr":"Motosiklet yavaşça hareket halindeyken","hi":"जब मोटरसाइकिल धीरे-धीरे चल रही हो","ar":"بينما الدراجة النارية تتدحرج ببطء"},{"en":"Only after you have already begun to ride","es":"Solo después de que ya hayas empezado a conducir","ru":"Только после того как вы уже начали движение","tr":"Yalnızca siz sürmeye başladıktan sonra","hi":"केवल आपके सवारी शुरू करने के बाद","ar":"فقط بعد أن تكون قد بدأت القيادة بالفعل"}],"e":{"en":"The passenger should get on the motorcycle only after the engine has been started. Source: Motorcycle Operator Manual.","es":"El pasajero debe subirse a la motocicleta solo después de que el motor haya sido arrancado. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен садиться на мотоцикл только после того, как двигатель запущен. Источник: Руководство для водителей мотоциклов.","tr":"Yolcu, motosiklete yalnızca motor çalıştırıldıktan sonra binmelidir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को इंजन शुरू हो जाने के बाद ही मोटरसाइकिल पर चढ़ना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يصعد الراكب على الدراجة النارية فقط بعد تشغيل المحرك. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"While your passenger is mounting the motorcycle, what should you do?","es":"Mientras tu pasajero se sube a la motocicleta, ¿qué debes hacer?","ru":"Пока ваш пассажир садится на мотоцикл, что следует делать вам?","tr":"Yolcunuz motosiklete binerken ne yapmalısınız?","hi":"जब आपका यात्री मोटरसाइकिल पर चढ़ रहा हो, तब आपको क्या करना चाहिए?","ar":"أثناء صعود راكبك على الدراجة النارية، ماذا ينبغي أن تفعل؟"},"o":[{"en":"Keep both feet on the ground with the brakes applied","es":"Mantener ambos pies en el suelo con los frenos aplicados","ru":"Держать обе ноги на земле с зажатыми тормозами","tr":"Frenler basılı halde her iki ayağınızı yerde tutun","hi":"दोनों पैर ज़मीन पर रखें और ब्रेक लगाए रखें","ar":"أبقِ كلتا قدميك على الأرض مع تطبيق المكابح"},{"en":"Rev the throttle slightly to keep the engine from stalling","es":"Acelerar ligeramente para evitar que el motor se apague","ru":"Слегка газовать дросселем, чтобы двигатель не заглох","tr":"Motorun stop etmemesi için gazı hafifçe artırın","hi":"इंजन को बंद होने से बचाने के लिए थ्रॉटल को थोड़ा रेव करें","ar":"ارفع سرعة دواسة الوقود قليلاً لمنع المحرك من التوقف"},{"en":"Put the bike in first gear and hold the clutch","es":"Poner la moto en primera y sostener el embrague","ru":"Включить первую передачу и держать сцепление","tr":"Motosikleti birinci vitese takın ve debriyajı tutun","hi":"बाइक को पहले गियर में रखें और क्लच पकड़ें","ar":"ضع الدراجة في الترس الأول وامسك القابض"},{"en":"Lift the side stand and balance with one foot","es":"Levantar el soporte lateral y equilibrarte con un pie","ru":"Поднять боковую подставку и балансировать на одной ноге","tr":"Yan sehpayı kaldırın ve tek ayakla dengeleyin","hi":"साइड स्टैंड उठाएँ और एक पैर से संतुलन बनाएँ","ar":"ارفع الحامل الجانبي وحافظ على التوازن بقدم واحدة"}],"e":{"en":"As the passenger mounts, keep both of your feet on the ground and the brakes applied to hold the motorcycle steady. Source: Motorcycle Operator Manual.","es":"Mientras el pasajero se sube, mantén ambos pies en el suelo y los frenos aplicados para sostener la motocicleta firme. Fuente: Manual del Operador de Motocicletas.","ru":"Пока пассажир садится, держите обе свои ноги на земле и зажатые тормоза, чтобы удерживать мотоцикл устойчиво. Источник: Руководство для водителей мотоциклов.","tr":"Yolcu binerken, motosikleti sabit tutmak için her iki ayağınızı yerde ve frenleri basılı tutun. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"जब यात्री चढ़ता है, तो मोटरसाइकिल को स्थिर रखने के लिए अपने दोनों पैर ज़मीन पर रखें और ब्रेक लगाए रखें। स्रोत: Motorcycle Operator Manual।","ar":"أثناء صعود الراكب، أبقِ كلتا قدميك على الأرض والمكابح مطبّقة لتثبيت الدراجة النارية. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Why should you instruct your passenger on cycling basics before every trip?","es":"¿Por qué debes instruir a tu pasajero sobre lo básico del manejo en moto antes de cada viaje?","ru":"Почему следует инструктировать пассажира об основах езды на мотоцикле перед каждой поездкой?","tr":"Her yolculuktan önce yolcunuza motosiklet sürmenin temelleri konusunda neden talimat vermelisiniz?","hi":"आपको हर यात्रा से पहले अपने यात्री को साइकिलिंग की बुनियादी बातें क्यों समझानी चाहिए?","ar":"لماذا ينبغي أن تُرشد راكبك إلى أساسيات ركوب الدراجة قبل كل رحلة؟"},"o":[{"en":"Because the law requires a verbal safety briefing","es":"Porque la ley exige una charla verbal de seguridad","ru":"Потому что закон требует устного инструктажа по безопасности","tr":"Yasa sözlü bir güvenlik bilgilendirmesi gerektirdiği için","hi":"क्योंकि कानून मौखिक सुरक्षा ब्रीफिंग की आवश्यकता रखता है","ar":"لأن القانون يتطلب إحاطة أمان شفهية"},{"en":"Because you should not assume passengers know how to handle a motorcycle, even experienced riders","es":"Porque no debes suponer que los pasajeros saben cómo manejar una motocicleta, incluso los conductores experimentados","ru":"Потому что не следует предполагать, что пассажиры знают, как вести себя на мотоцикле, даже опытные мотоциклисты","tr":"Deneyimli sürücüler bile olsalar yolcuların bir motosikleti nasıl ele alacaklarını bildiklerini varsaymamanız gerektiği için","hi":"क्योंकि आपको यह नहीं मान लेना चाहिए कि यात्री मोटरसाइकिल संभालना जानते हैं, भले ही वे अनुभवी सवार हों","ar":"لأنه لا ينبغي أن تفترض أن الركاب يعرفون كيفية التعامل مع دراجة نارية، حتى السائقين ذوي الخبرة"},{"en":"Because the passenger must repeat the instructions back to you","es":"Porque el pasajero debe repetirte las instrucciones","ru":"Потому что пассажир должен повторить инструкции вам в ответ","tr":"Yolcunun talimatları size geri tekrar etmesi gerektiği için","hi":"क्योंकि यात्री को निर्देश आपको दोहराकर बताने पड़ते हैं","ar":"لأن على الراكب أن يكرر التعليمات لك"},{"en":"Because it warms up the engine while you talk","es":"Porque calienta el motor mientras hablas","ru":"Потому что это прогревает двигатель, пока вы говорите","tr":"Siz konuşurken motoru ısıttığı için","hi":"क्योंकि बात करते समय यह इंजन को गर्म कर देता है","ar":"لأن ذلك يُسخّن المحرك أثناء حديثك"}],"e":{"en":"Riders should not assume passengers are familiar with motorcycle handling and balance, so always instruct your passenger before starting, even if the passenger is a rider. Source: Motorcycle Operator Manual.","es":"Los conductores no deben suponer que los pasajeros están familiarizados con el manejo y el equilibrio de una motocicleta, así que siempre instruye a tu pasajero antes de arrancar, aunque el pasajero también sea conductor. Fuente: Manual del Operador de Motocicletas.","ru":"Водителям не следует предполагать, что пассажиры знакомы с управлением и балансировкой мотоцикла, поэтому всегда инструктируйте своего пассажира перед началом движения, даже если пассажир сам водитель. Источник: Руководство для водителей мотоциклов.","tr":"Sürücüler, yolcuların motosiklet kullanımı ve dengesine aşina olduklarını varsaymamalıdır, bu yüzden yolcu bir sürücü olsa bile başlamadan önce her zaman yolcunuza talimat verin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"सवारों को यह नहीं मान लेना चाहिए कि यात्री मोटरसाइकिल को संभालने और संतुलन से परिचित हैं, इसलिए शुरू करने से पहले हमेशा अपने यात्री को निर्देश दें, भले ही यात्री स्वयं सवार हो। स्रोत: Motorcycle Operator Manual।","ar":"لا ينبغي للسائقين أن يفترضوا أن الركاب على دراية بالتعامل مع الدراجة النارية وتوازنها، لذا أرشد راكبك دائماً قبل البدء، حتى لو كان الراكب سائقاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"Why should a passenger keep their legs positioned carefully during the ride?","es":"¿Por qué debe un pasajero mantener las piernas cuidadosamente colocadas durante el viaje?","ru":"Почему пассажир должен внимательно следить за положением своих ног во время поездки?","tr":"Bir yolcu, yolculuk boyunca bacaklarını neden dikkatlice konumlandırmalıdır?","hi":"यात्री को सवारी के दौरान अपने पैरों को सावधानी से क्यों रखना चाहिए?","ar":"لماذا ينبغي أن يبقي الراكب ساقيه في وضع دقيق أثناء الرحلة؟"},"o":[{"en":"To keep their legs away from the hot muffler and moving parts","es":"Para mantener las piernas lejos del mofle caliente y de las partes móviles","ru":"Чтобы держать ноги подальше от горячего глушителя и движущихся частей","tr":"Bacaklarını sıcak egzozdan ve hareketli parçalardan uzak tutmak için","hi":"अपने पैरों को गर्म मफलर और चलते पुर्ज़ों से दूर रखने के लिए","ar":"لإبعاد ساقيه عن كاتم الصوت الساخن والأجزاء المتحركة"},{"en":"To help push the motorcycle through turns","es":"Para ayudar a empujar la motocicleta en las curvas","ru":"Чтобы помогать толкать мотоцикл в поворотах","tr":"Motosikleti dönüşlerden geçirmeye yardımcı olmak için","hi":"मोटरसाइकिल को मोड़ों से धकेलने में मदद के लिए","ar":"للمساعدة في دفع الدراجة النارية عبر الانعطافات"},{"en":"To act as an extra kickstand at stops","es":"Para servir de pata de apoyo adicional en las paradas","ru":"Чтобы служить дополнительной подставкой на остановках","tr":"Duruşlarda ekstra bir yan sehpa görevi görmek için","hi":"रुकने पर एक अतिरिक्त किकस्टैंड के रूप में काम करने के लिए","ar":"ليعمل كحامل إضافي عند التوقف"},{"en":"To grip the rear tire for traction","es":"Para agarrar la llanta trasera y dar tracción","ru":"Чтобы держаться за заднюю шину для сцепления","tr":"Tutuş için arka lastiği kavramak için","hi":"कर्षण के लिए पीछे के टायर को पकड़ने के लिए","ar":"ليُمسك بالإطار الخلفي لزيادة قوة الاحتكاك"}],"e":{"en":"A passenger should keep their legs away from the muffler(s), chains, and other moving parts to avoid burns and injury. Source: Motorcycle Operator Manual.","es":"Un pasajero debe mantener las piernas lejos del o de los mofles, las cadenas y otras partes móviles para evitar quemaduras y lesiones. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен держать ноги подальше от глушителя(ей), цепей и других движущихся частей, чтобы избежать ожогов и травм. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, yanıkları ve yaralanmaları önlemek için bacaklarını egzoz(lar)dan, zincirlerden ve diğer hareketli parçalardan uzak tutmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को जलने और चोट से बचने के लिए अपने पैरों को मफलर, चेन और अन्य चलते पुर्ज़ों से दूर रखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يبقي الراكب ساقيه بعيداً عن كاتم (كواتم) الصوت والسلاسل والأجزاء المتحركة الأخرى لتجنّب الحروق والإصابة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How does carrying a passenger affect the way your motorcycle responds?","es":"¿Cómo afecta llevar a un pasajero la forma en que responde tu motocicleta?","ru":"Как перевозка пассажира влияет на то, как реагирует ваш мотоцикл?","tr":"Bir yolcu taşımak motosikletinizin tepki verme şeklini nasıl etkiler?","hi":"यात्री ले जाना आपकी मोटरसाइकिल की प्रतिक्रिया करने के तरीके को कैसे प्रभावित करता है?","ar":"كيف يؤثر حمل راكب على طريقة استجابة دراجتك النارية؟"},"o":[{"en":"It speeds up and stops faster because of added traction","es":"Acelera y se detiene más rápido por la tracción adicional","ru":"Он разгоняется и останавливается быстрее из-за дополнительного сцепления","tr":"Ek tutuş nedeniyle daha hızlı hızlanır ve daha hızlı durur","hi":"जोड़े गए कर्षण के कारण यह तेज़ी से गति पकड़ती और रुकती है","ar":"تتسارع وتتوقف أسرع بسبب زيادة قوة الاحتكاك"},{"en":"It responds more slowly, taking longer to speed up, slow down, or turn","es":"Responde más lento, tardando más en acelerar, frenar o girar","ru":"Он реагирует медленнее, дольше разгоняется, замедляется или поворачивает","tr":"Daha yavaş tepki verir; hızlanması, yavaşlaması veya dönmesi daha uzun sürer","hi":"यह अधिक धीरे प्रतिक्रिया करती है, गति पकड़ने, धीमा होने या मुड़ने में अधिक समय लेती है","ar":"تستجيب ببطء أكبر، وتستغرق وقتاً أطول للتسارع أو الإبطاء أو الانعطاف"},{"en":"It has no noticeable effect once you are moving","es":"No tiene un efecto notable una vez que estás en movimiento","ru":"Это не оказывает заметного влияния, когда вы уже движетесь","tr":"Hareket halindeyken fark edilir bir etkisi yoktur","hi":"एक बार चलने के बाद इसका कोई ध्यान देने योग्य प्रभाव नहीं होता","ar":"ليس له تأثير ملحوظ بمجرد أن تتحرك"},{"en":"It only affects cornering, not acceleration or braking","es":"Solo afecta el manejo en curvas, no la aceleración ni el frenado","ru":"Это влияет только на прохождение поворотов, а не на разгон или торможение","tr":"Yalnızca virajları etkiler, hızlanmayı veya frenlemeyi değil","hi":"यह केवल कॉर्नरिंग को प्रभावित करती है, एक्सीलरेशन या ब्रेकिंग को नहीं","ar":"يؤثر فقط على المنعطفات، وليس على التسارع أو الكبح"}],"e":{"en":"The motorcycle responds more slowly with a passenger; the heavier the passenger, the longer it takes to speed up, slow down, or turn. Source: Motorcycle Operator Manual.","es":"La motocicleta responde más lento con un pasajero; mientras más pesado sea el pasajero, más tarda en acelerar, frenar o girar. Fuente: Manual del Operador de Motocicletas.","ru":"С пассажиром мотоцикл реагирует медленнее; чем тяжелее пассажир, тем дольше уходит на разгон, замедление или поворот. Источник: Руководство для водителей мотоциклов.","tr":"Motosiklet bir yolcuyla daha yavaş tepki verir; yolcu ne kadar ağırsa hızlanması, yavaşlaması veya dönmesi o kadar uzun sürer. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री के साथ मोटरसाइकिल अधिक धीरे प्रतिक्रिया करती है; यात्री जितना भारी होगा, गति पकड़ने, धीमा होने या मुड़ने में उतना ही अधिक समय लगता है। स्रोत: Motorcycle Operator Manual।","ar":"تستجيب الدراجة النارية ببطء أكبر مع راكب؛ كلما كان الراكب أثقل، استغرق الأمر وقتاً أطول للتسارع أو الإبطاء أو الانعطاف. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When riding with a passenger, how should you approach a stop?","es":"Cuando conduces con un pasajero, ¿cómo debes acercarte a una parada?","ru":"При езде с пассажиром как следует подъезжать к остановке?","tr":"Bir yolcuyla sürerken bir duruşa nasıl yaklaşmalısınız?","hi":"यात्री के साथ सवारी करते समय, आपको रुकने के लिए कैसे पहुँचना चाहिए?","ar":"عند القيادة مع راكب، كيف ينبغي أن تقترب من التوقف؟"},"o":[{"en":"Brake harder at the last moment to save distance","es":"Frenar más fuerte en el último momento para ahorrar distancia","ru":"Тормозить сильнее в последний момент, чтобы сэкономить дистанцию","tr":"Mesafeden tasarruf etmek için son anda daha sert fren yapın","hi":"दूरी बचाने के लिए आखिरी क्षण में ज़ोर से ब्रेक लगाएँ","ar":"اكبح بقوة أكبر في اللحظة الأخيرة لتوفير المسافة"},{"en":"Start slowing earlier and keep a larger space cushion","es":"Empezar a reducir la velocidad antes y mantener un colchón de espacio más grande","ru":"Начинать замедление раньше и сохранять больший запас пространства","tr":"Daha erken yavaşlamaya başlayın ve daha büyük bir tampon boşluğu koruyun","hi":"पहले धीमा करना शुरू करें और बड़ा स्पेस कुशन बनाए रखें","ar":"ابدأ الإبطاء مبكراً وحافظ على مسافة أمان أكبر"},{"en":"Coast in neutral to reduce braking effort","es":"Avanzar en neutro para reducir el esfuerzo de frenado","ru":"Катиться на нейтрали, чтобы уменьшить усилие торможения","tr":"Frenleme çabasını azaltmak için boşta süzülün","hi":"ब्रेकिंग प्रयास कम करने के लिए न्यूट्रल में कोस्ट करें","ar":"انزلق في وضع الحياد لتقليل جهد الكبح"},{"en":"Stop in the same distance as you would riding alone","es":"Detenerte en la misma distancia que lo harías conduciendo solo","ru":"Останавливаться на той же дистанции, что и при езде в одиночку","tr":"Tek başına sürerken yapacağınız aynı mesafede durun","hi":"अकेले सवारी करने जितनी ही दूरी में रुकें","ar":"توقف في نفس المسافة كما لو كنت تقود بمفردك"}],"e":{"en":"With a passenger you should start slowing earlier and maintain a larger space cushion whenever slowing or stopping. Source: Motorcycle Operator Manual.","es":"Con un pasajero debes empezar a reducir la velocidad antes y mantener un colchón de espacio más grande siempre que reduzcas la velocidad o te detengas. Fuente: Manual del Operador de Motocicletas.","ru":"С пассажиром следует начинать замедление раньше и сохранять больший запас пространства всякий раз при замедлении или остановке. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcuyla, yavaşlarken veya dururken daha erken yavaşlamaya başlamalı ve daha büyük bir tampon boşluğu korumalısınız. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री के साथ आपको पहले धीमा करना शुरू करना चाहिए और जब भी धीमा हों या रुकें तो बड़ा स्पेस कुशन बनाए रखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"مع راكب، ينبغي أن تبدأ الإبطاء مبكراً وتحافظ على مسافة أمان أكبر كلما أبطأت أو توقفت. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When carrying a passenger, how should you handle gaps in traffic when crossing or merging?","es":"Al llevar a un pasajero, ¿cómo debes manejar los espacios en el tráfico al cruzar o incorporarte?","ru":"При перевозке пассажира как следует обращаться с промежутками в потоке при пересечении или перестроении?","tr":"Bir yolcu taşırken, geçerken veya katılırken trafikteki boşlukları nasıl ele almalısınız?","hi":"यात्री ले जाते समय, सड़क पार करते या मर्ज करते समय आपको ट्रैफ़िक के अंतरालों को कैसे संभालना चाहिए?","ar":"عند حمل راكب، كيف ينبغي أن تتعامل مع الفجوات في حركة المرور عند العبور أو الاندماج؟"},"o":[{"en":"Use the same gaps you would use riding alone","es":"Usar los mismos espacios que usarías conduciendo solo","ru":"Использовать те же промежутки, что и при езде в одиночку","tr":"Tek başına sürerken kullanacağınız aynı boşlukları kullanın","hi":"वही अंतराल उपयोग करें जो आप अकेले सवारी करते समय करते हैं","ar":"استخدم نفس الفجوات التي تستخدمها عند القيادة بمفردك"},{"en":"Wait for larger gaps to cross, enter, or merge","es":"Esperar espacios más grandes para cruzar, entrar o incorporarte","ru":"Ждать более крупных промежутков для пересечения, въезда или перестроения","tr":"Geçmek, girmek veya katılmak için daha büyük boşlukları bekleyin","hi":"पार करने, प्रवेश करने या मर्ज करने के लिए बड़े अंतरालों का इंतज़ार करें","ar":"انتظر فجوات أكبر للعبور أو الدخول أو الاندماج"},{"en":"Take smaller gaps quickly before the extra weight slows you","es":"Tomar espacios más pequeños rápidamente antes de que el peso extra te frene","ru":"Быстро использовать меньшие промежутки, пока дополнительный вес не замедлил вас","tr":"Ekstra ağırlık sizi yavaşlatmadan önce küçük boşlukları hızla alın","hi":"अतिरिक्त वज़न आपको धीमा करने से पहले छोटे अंतरालों को जल्दी लें","ar":"استغل الفجوات الأصغر بسرعة قبل أن يبطئك الوزن الإضافي"},{"en":"Avoid merging entirely until the passenger gets off","es":"Evitar incorporarte por completo hasta que el pasajero se baje","ru":"Полностью избегать перестроений, пока пассажир не сойдёт","tr":"Yolcu inene kadar katılmaktan tamamen kaçının","hi":"यात्री के उतरने तक मर्ज करने से पूरी तरह बचें","ar":"تجنّب الاندماج تماماً حتى ينزل الراكب"}],"e":{"en":"Because the loaded motorcycle accelerates more slowly, wait for larger gaps to cross, enter, or merge in traffic when carrying a passenger. Source: Motorcycle Operator Manual.","es":"Como la motocicleta cargada acelera más lento, espera espacios más grandes para cruzar, entrar o incorporarte al tráfico cuando lleves a un pasajero. Fuente: Manual del Operador de Motocicletas.","ru":"Поскольку нагруженный мотоцикл разгоняется медленнее, ждите более крупных промежутков для пересечения, въезда или перестроения в потоке при перевозке пассажира. Источник: Руководство для водителей мотоциклов.","tr":"Yüklü motosiklet daha yavaş hızlandığı için bir yolcu taşırken trafiğe geçmek, girmek veya katılmak için daha büyük boşlukları bekleyin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"क्योंकि लदी हुई मोटरसाइकिल अधिक धीरे गति पकड़ती है, इसलिए यात्री ले जाते समय ट्रैफ़िक में पार करने, प्रवेश करने या मर्ज करने के लिए बड़े अंतरालों का इंतज़ार करें। स्रोत: Motorcycle Operator Manual।","ar":"لأن الدراجة النارية المحمّلة تتسارع ببطء أكبر، انتظر فجوات أكبر للعبور أو الدخول أو الاندماج في حركة المرور عند حمل راكب. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What is the recommended way to position cargo relative to the rear axle?","es":"¿Cuál es la forma recomendada de colocar la carga respecto al eje trasero?","ru":"Каков рекомендуемый способ размещения груза относительно задней оси?","tr":"Yükü arka aksa göre konumlandırmanın önerilen yolu nedir?","hi":"पीछे के एक्सल के सापेक्ष कार्गो को रखने का अनुशंसित तरीका क्या है?","ar":"ما هي الطريقة الموصى بها لوضع البضائع بالنسبة للمحور الخلفي؟"},"o":[{"en":"Behind the rear axle to keep weight off the front tire","es":"Detrás del eje trasero para quitar peso de la llanta delantera","ru":"Позади задней оси, чтобы убрать вес с передней шины","tr":"Ağırlığı ön lastikten uzak tutmak için arka aksın arkasında","hi":"सामने के टायर से वज़न हटाने के लिए पीछे के एक्सल के पीछे","ar":"خلف المحور الخلفي لإبعاد الوزن عن الإطار الأمامي"},{"en":"Over, or in front of, the rear axle","es":"Sobre el eje trasero, o delante de él","ru":"Над задней осью или перед ней","tr":"Arka aksın üzerinde veya önünde","hi":"पीछे के एक्सल के ऊपर, या उसके सामने","ar":"فوق المحور الخلفي أو أمامه"},{"en":"Directly above the rear axle only","es":"Directamente encima del eje trasero únicamente","ru":"Только прямо над задней осью","tr":"Yalnızca tam olarak arka aksın üzerinde","hi":"केवल पीछे के एक्सल के ठीक ऊपर","ar":"فوق المحور الخلفي مباشرةً فقط"},{"en":"As far to the rear as the luggage rack allows","es":"Lo más atrás que permita el portaequipajes","ru":"Как можно дальше назад, насколько позволяет багажник","tr":"Bagaj rafının izin verdiği kadar arkada","hi":"लगेज रैक जितना पीछे अनुमति दे उतना पीछे","ar":"في أقصى الخلف قدر ما يسمح حامل الأمتعة"}],"e":{"en":"Keep the load forward by placing it over, or in front of, the rear axle; loads mounted behind the rear axle can affect turning and braking and cause a wobble. Source: Motorcycle Operator Manual.","es":"Mantén la carga hacia adelante colocándola sobre el eje trasero o delante de él; las cargas montadas detrás del eje trasero pueden afectar el giro y el frenado y causar un bamboleo. Fuente: Manual del Operador de Motocicletas.","ru":"Держите груз спереди, размещая его над задней осью или перед ней; груз, установленный позади задней оси, может влиять на поворот и торможение и вызывать вихляние. Источник: Руководство для водителей мотоциклов.","tr":"Yükü aksın üzerine veya önüne yerleştirerek öne doğru tutun; arka aksın arkasına monte edilen yükler dönüşü ve frenlemeyi etkileyebilir ve sallanmaya neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को पीछे के एक्सल के ऊपर, या उसके सामने रखकर आगे रखें; पीछे के एक्सल के पीछे लगाए गए भार मुड़ने और ब्रेकिंग को प्रभावित कर सकते हैं और लड़खड़ाहट पैदा कर सकते हैं। स्रोत: Motorcycle Operator Manual।","ar":"أبقِ الحمل إلى الأمام بوضعه فوق المحور الخلفي أو أمامه؛ فالأحمال المركّبة خلف المحور الخلفي يمكن أن تؤثر على الانعطاف والكبح وتسبب تمايلاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"Why should you avoid mounting a heavy load behind the rear axle?","es":"¿Por qué debes evitar montar una carga pesada detrás del eje trasero?","ru":"Почему следует избегать размещения тяжёлого груза позади задней оси?","tr":"Arka aksın arkasına ağır bir yük monte etmekten neden kaçınmalısınız?","hi":"आपको पीछे के एक्सल के पीछे भारी भार लगाने से क्यों बचना चाहिए?","ar":"لماذا ينبغي أن تتجنّب تركيب حمل ثقيل خلف المحور الخلفي؟"},"o":[{"en":"It can affect how the motorcycle turns and brakes and may cause a wobble","es":"Puede afectar cómo gira y frena la motocicleta y puede causar un bamboleo","ru":"Это может повлиять на то, как мотоцикл поворачивает и тормозит, и может вызвать вихляние","tr":"Motosikletin nasıl döndüğünü ve frenlediğini etkileyebilir ve sallanmaya neden olabilir","hi":"यह मोटरसाइकिल के मुड़ने और ब्रेकिंग को प्रभावित कर सकता है और लड़खड़ाहट पैदा कर सकता है","ar":"يمكن أن يؤثر على كيفية انعطاف الدراجة النارية وكبحها وقد يسبب تمايلاً"},{"en":"It improves cornering but ruins fuel economy","es":"Mejora el manejo en curvas pero arruina el rendimiento de combustible","ru":"Это улучшает прохождение поворотов, но ухудшает экономичность расхода топлива","tr":"Virajı iyileştirir ama yakıt ekonomisini bozar","hi":"यह कॉर्नरिंग सुधारता है लेकिन ईंधन क्षमता बर्बाद करता है","ar":"يحسّن المنعطفات لكنه يدمّر اقتصاد الوقود"},{"en":"It overloads the front tire and causes a skid","es":"Sobrecarga la llanta delantera y causa un derrape","ru":"Это перегружает переднюю шину и вызывает занос","tr":"Ön lastiği aşırı yükler ve kaymaya neden olur","hi":"यह सामने के टायर पर अधिक भार डालता है और स्किड पैदा करता है","ar":"يثقل الإطار الأمامي ويسبب انزلاقاً"},{"en":"It is illegal in most states","es":"Es ilegal en la mayoría de los estados","ru":"Это незаконно в большинстве штатов","tr":"Çoğu eyalette yasa dışıdır","hi":"यह अधिकांश राज्यों में अवैध है","ar":"إنه غير قانوني في معظم الولايات"}],"e":{"en":"Mounting loads behind the rear axle can affect how the motorcycle turns and brakes and can also cause a wobble. Source: Motorcycle Operator Manual.","es":"Montar cargas detrás del eje trasero puede afectar cómo gira y frena la motocicleta y también puede causar un bamboleo. Fuente: Manual del Operador de Motocicletas.","ru":"Размещение груза позади задней оси может повлиять на то, как мотоцикл поворачивает и тормозит, а также может вызвать вихляние. Источник: Руководство для водителей мотоциклов.","tr":"Yükleri arka aksın arkasına monte etmek, motosikletin nasıl döndüğünü ve frenlediğini etkileyebilir ve ayrıca sallanmaya neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"पीछे के एक्सल के पीछे भार लगाने से मोटरसाइकिल के मुड़ने और ब्रेकिंग का तरीका प्रभावित हो सकता है और लड़खड़ाहट भी पैदा हो सकती है। स्रोत: Motorcycle Operator Manual।","ar":"يمكن أن يؤثر تركيب الأحمال خلف المحور الخلفي على كيفية انعطاف الدراجة النارية وكبحها ويمكن أيضاً أن يسبب تمايلاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How high on the motorcycle should you secure cargo?","es":"¿A qué altura de la motocicleta debes asegurar la carga?","ru":"На какой высоте на мотоцикле следует закреплять груз?","tr":"Yükü motosiklette ne kadar yükseğe sabitlemelisiniz?","hi":"आपको मोटरसाइकिल पर कार्गो को कितनी ऊँचाई पर सुरक्षित करना चाहिए?","ar":"إلى أي ارتفاع على الدراجة النارية ينبغي أن تثبّت البضائع؟"},"o":[{"en":"As high as possible to keep it out of the wheels","es":"Lo más alto posible para mantenerla fuera de las ruedas","ru":"Как можно выше, чтобы держать его подальше от колёс","tr":"Tekerleklerden uzak tutmak için olabildiğince yükseğe","hi":"जितना संभव हो उतना ऊँचा ताकि यह पहियों से बाहर रहे","ar":"إلى أعلى ارتفاع ممكن لإبقائها بعيداً عن العجلات"},{"en":"As low as possible, or in the saddlebags","es":"Lo más bajo posible, o en las alforjas","ru":"Как можно ниже или в боковых кофрах","tr":"Olabildiğince alçağa veya yan çantalara","hi":"जितना संभव हो उतना नीचा, या सैडलबैग में","ar":"إلى أدنى ارتفاع ممكن، أو في الحقائب الجانبية"},{"en":"On top of a sissy bar for easy access","es":"Encima de una barra trasera (sissy bar) para acceder con facilidad","ru":"На верху спинки-дуги для удобного доступа","tr":"Kolay erişim için bir sissy barın üzerine","hi":"आसान पहुँच के लिए सिसी बार के ऊपर","ar":"فوق قضيب المسند الخلفي لسهولة الوصول"},{"en":"At seat height, strapped to the backrest","es":"A la altura del asiento, amarrada al respaldo","ru":"На высоте сиденья, пристёгнутым к спинке","tr":"Sele yüksekliğinde, sırt desteğine bağlı","hi":"सीट की ऊँचाई पर, बैकरेस्ट से बँधा हुआ","ar":"عند ارتفاع المقعد، مربوطة بمسند الظهر"}],"e":{"en":"Secure loads low, or put them in saddlebags; attaching a load high (such as to a sissy bar) raises the center of gravity and can upset the bike's balance. Source: Motorcycle Operator Manual.","es":"Asegura las cargas en una posición baja, o ponlas en las alforjas; sujetar una carga en alto (como a una barra trasera o sissy bar) eleva el centro de gravedad y puede alterar el equilibrio de la moto. Fuente: Manual del Operador de Motocicletas.","ru":"Закрепляйте груз низко или кладите его в боковые кофры; крепление груза высоко (например, к спинке-дуге) поднимает центр тяжести и может нарушить баланс мотоцикла. Источник: Руководство для водителей мотоциклов.","tr":"Yükleri alçağa sabitleyin veya yan çantalara koyun; bir yükü yükseğe (sissy bar gibi) bağlamak ağırlık merkezini yükseltir ve motosikletin dengesini bozabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को नीचे सुरक्षित करें, या उन्हें सैडलबैग में रखें; भार को ऊँचा (जैसे सिसी बार से) लगाना गुरुत्वाकर्षण केंद्र को ऊपर उठाता है और बाइक का संतुलन बिगाड़ सकता है। स्रोत: Motorcycle Operator Manual।","ar":"ثبّت الأحمال منخفضة، أو ضعها في الحقائب الجانبية؛ فربط الحمل عالياً (مثل قضيب المسند الخلفي) يرفع مركز الثقل ويمكن أن يخلّ بتوازن الدراجة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How should you distribute weight when loading saddlebags on both sides?","es":"¿Cómo debes distribuir el peso al cargar alforjas en ambos lados?","ru":"Как следует распределять вес при загрузке боковых кофров с обеих сторон?","tr":"Her iki tarafa yan çanta yüklerken ağırlığı nasıl dağıtmalısınız?","hi":"दोनों ओर सैडलबैग लोड करते समय आपको वज़न कैसे वितरित करना चाहिए?","ar":"كيف ينبغي أن توزّع الوزن عند تحميل الحقائب الجانبية على كلا الجانبين؟"},"o":[{"en":"Put more weight on the side away from traffic","es":"Poner más peso en el lado alejado del tráfico","ru":"Класть больше веса на сторону, удалённую от потока","tr":"Trafikten uzak tarafa daha fazla ağırlık koyun","hi":"ट्रैफ़िक से दूर वाली ओर अधिक वज़न रखें","ar":"ضع وزناً أكبر على الجانب البعيد عن حركة المرور"},{"en":"Load each saddlebag with about the same weight","es":"Cargar cada alforja con aproximadamente el mismo peso","ru":"Загружать каждый кофр примерно одинаковым весом","tr":"Her yan çantaya yaklaşık aynı ağırlığı yükleyin","hi":"प्रत्येक सैडलबैग को लगभग समान वज़न से लोड करें","ar":"حمّل كل حقيبة جانبية بوزن متساوٍ تقريباً"},{"en":"Put all the heavy items in one bag for easy access","es":"Poner todos los objetos pesados en una alforja para acceder con facilidad","ru":"Класть все тяжёлые предметы в один кофр для удобного доступа","tr":"Kolay erişim için tüm ağır eşyaları tek çantaya koyun","hi":"आसान पहुँच के लिए सभी भारी सामान एक बैग में रखें","ar":"ضع كل الأشياء الثقيلة في حقيبة واحدة لسهولة الوصول"},{"en":"Keep the right bag heavier to offset the kickstand","es":"Mantener la alforja derecha más pesada para compensar el soporte","ru":"Держать правый кофр тяжелее, чтобы компенсировать подставку","tr":"Yan sehpayı dengelemek için sağ çantayı daha ağır tutun","hi":"किकस्टैंड की भरपाई के लिए दायाँ बैग भारी रखें","ar":"أبقِ الحقيبة اليمنى أثقل لموازنة الحامل الجانبي"}],"e":{"en":"Load each saddlebag with about the same weight; an uneven load can cause the motorcycle to pull to one side. Source: Motorcycle Operator Manual.","es":"Carga cada alforja con aproximadamente el mismo peso; una carga despareja puede hacer que la motocicleta jale hacia un lado. Fuente: Manual del Operador de Motocicletas.","ru":"Загружайте каждый боковой кофр примерно одинаковым весом; неравномерная нагрузка может заставить мотоцикл тянуть в одну сторону. Источник: Руководство для водителей мотоциклов.","tr":"Her yan çantaya yaklaşık aynı ağırlığı yükleyin; dengesiz bir yük motosikletin bir tarafa çekmesine neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"प्रत्येक सैडलबैग को लगभग समान वज़न से लोड करें; असमान भार मोटरसाइकिल को एक तरफ़ खींच सकता है। स्रोत: Motorcycle Operator Manual।","ar":"حمّل كل حقيبة جانبية بوزن متساوٍ تقريباً؛ فالحمل غير المتساوي يمكن أن يجعل الدراجة النارية تنحرف إلى جانب واحد. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What is the recommended way to fasten cargo to your motorcycle?","es":"¿Cuál es la forma recomendada de sujetar la carga a tu motocicleta?","ru":"Каков рекомендуемый способ крепления груза к мотоциклу?","tr":"Yükü motosikletinize sabitlemenin önerilen yolu nedir?","hi":"अपनी मोटरसाइकिल पर कार्गो बाँधने का अनुशंसित तरीका क्या है?","ar":"ما هي الطريقة الموصى بها لربط البضائع بدراجتك النارية؟"},"o":[{"en":"Tie it down with rope and knots","es":"Amarrarla con cuerda y nudos","ru":"Привязать его верёвкой с узлами","tr":"İp ve düğümlerle bağlayın","hi":"इसे रस्सी और गाँठों से बाँधें","ar":"اربطها بحبل وعُقد"},{"en":"Fasten it securely with elastic cords such as bungee cords or nets","es":"Sujetarla firmemente con cuerdas elásticas, como cuerdas elásticas (bungee) o redes","ru":"Надёжно закрепить его эластичными шнурами, например резиновыми стяжками или сетками","tr":"Bungee kordonlar veya filer gibi elastik kordonlarla sıkıca sabitleyin","hi":"इसे लचीली डोरियों जैसे बंजी कॉर्ड या जालों से मज़बूती से बाँधें","ar":"ثبّتها بإحكام بحبال مطاطية مثل حبال البنجي أو الشِّباك"},{"en":"Set it loosely so it can shift to absorb bumps","es":"Colocarla suelta para que pueda moverse y absorber los baches","ru":"Уложить его свободно, чтобы он мог смещаться, поглощая неровности","tr":"Tümsekleri emmesi için gevşekçe yerleştirin","hi":"इसे ढीला रखें ताकि यह उभारों को सोखने के लिए हिल सके","ar":"ضعها بشكل مرتخٍ حتى تتمكن من التحرك لامتصاص المطبات"},{"en":"Hold it in place with one hand while riding","es":"Sostenerla en su lugar con una mano mientras conduces","ru":"Удерживать его на месте одной рукой во время езды","tr":"Sürerken tek elinizle yerinde tutun","hi":"सवारी करते समय इसे एक हाथ से पकड़ें","ar":"أمسكها في مكانها بيد واحدة أثناء القيادة"}],"e":{"en":"Fasten the load securely with elastic cords (bungee cords or nets); rope can stretch and knots can come loose, letting the load shift or fall. Source: Motorcycle Operator Manual.","es":"Sujeta la carga firmemente con cuerdas elásticas (cuerdas bungee o redes); la cuerda puede estirarse y los nudos pueden aflojarse, dejando que la carga se mueva o se caiga. Fuente: Manual del Operador de Motocicletas.","ru":"Надёжно закрепляйте груз эластичными шнурами (резиновыми стяжками или сетками); верёвка может растягиваться, а узлы развязываться, позволяя грузу сместиться или упасть. Источник: Руководство для водителей мотоциклов.","tr":"Yükü elastik kordonlarla (bungee kordonlar veya filer) sıkıca sabitleyin; ip esneyebilir ve düğümler gevşeyebilir, bu da yükün kaymasına veya düşmesine izin verir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को लचीली डोरियों (बंजी कॉर्ड या जालों) से मज़बूती से बाँधें; रस्सी खिंच सकती है और गाँठें ढीली हो सकती हैं, जिससे भार हिल सकता है या गिर सकता है। स्रोत: Motorcycle Operator Manual।","ar":"ثبّت الحمل بإحكام بحبال مطاطية (حبال البنجي أو الشِّباك)؛ فالحبل يمكن أن يتمدد والعُقد يمكن أن تنفك، مما يجعل الحمل يتحرك أو يسقط. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What can happen if cargo or a saddlebag works loose and catches in the wheel or chain?","es":"¿Qué puede pasar si la carga o una alforja se afloja y se atora en la rueda o la cadena?","ru":"Что может произойти, если груз или боковой кофр ослабнет и попадёт в колесо или цепь?","tr":"Yük veya bir yan çanta gevşeyip tekerleğe ya da zincire takılırsa ne olabilir?","hi":"अगर कार्गो या सैडलबैग ढीला होकर पहिए या चेन में फँस जाए तो क्या हो सकता है?","ar":"ماذا يمكن أن يحدث إذا انفكّت البضائع أو حقيبة جانبية وعلقت في العجلة أو السلسلة؟"},"o":[{"en":"Nothing serious, the load simply drags behind","es":"Nada grave, la carga simplemente se arrastra detrás","ru":"Ничего серьёзного, груз просто потащится сзади","tr":"Ciddi bir şey olmaz, yük sadece arkadan sürüklenir","hi":"कुछ गंभीर नहीं, भार बस पीछे घिसटता है","ar":"لا شيء خطير، فالحمل ببساطة يُجرّ خلفها"},{"en":"The rear wheel can lock up, causing the motorcycle to skid","es":"La rueda trasera puede bloquearse, causando que la motocicleta derrape","ru":"Заднее колесо может заблокироваться, вызвав занос мотоцикла","tr":"Arka tekerlek kilitlenebilir ve motosikletin kaymasına neden olabilir","hi":"पीछे का पहिया लॉक हो सकता है, जिससे मोटरसाइकिल स्किड कर सकती है","ar":"يمكن أن تنغلق العجلة الخلفية، مما يسبب انزلاق الدراجة النارية"},{"en":"The engine will stall safely","es":"El motor se apagará de forma segura","ru":"Двигатель безопасно заглохнет","tr":"Motor güvenli bir şekilde stop eder","hi":"इंजन सुरक्षित रूप से बंद हो जाएगा","ar":"سيتوقف المحرك بأمان"},{"en":"The front brake will automatically release","es":"El freno delantero se soltará automáticamente","ru":"Передний тормоз автоматически отпустится","tr":"Ön fren otomatik olarak serbest kalır","hi":"फ्रंट ब्रेक अपने आप रिलीज़ हो जाएगा","ar":"سيُحرّر المكبح الأمامي تلقائياً"}],"e":{"en":"A loose load or overloaded saddlebag can catch in the wheel or chain, locking the rear wheel and causing the motorcycle to skid, so check the load often. Source: Motorcycle Operator Manual.","es":"Una carga suelta o una alforja sobrecargada puede atorarse en la rueda o la cadena, bloqueando la rueda trasera y causando que la motocicleta derrape, así que revisa la carga con frecuencia. Fuente: Manual del Operador de Motocicletas.","ru":"Ослабленный груз или перегруженный боковой кофр может попасть в колесо или цепь, заблокировав заднее колесо и вызвав занос мотоцикла, поэтому проверяйте груз почаще. Источник: Руководство для водителей мотоциклов.","tr":"Gevşek bir yük veya aşırı yüklenmiş bir yan çanta tekerleğe veya zincire takılabilir, arka tekerleği kilitleyip motosikletin kaymasına neden olabilir, bu yüzden yükü sık sık kontrol edin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"ढीला भार या ज़्यादा लदा सैडलबैग पहिए या चेन में फँस सकता है, जिससे पीछे का पहिया लॉक हो जाता है और मोटरसाइकिल स्किड कर जाती है, इसलिए भार को बार-बार जाँचें। स्रोत: Motorcycle Operator Manual।","ar":"يمكن لحمل منفك أو حقيبة جانبية محمّلة بإفراط أن يعلق في العجلة أو السلسلة، مما يقفل العجلة الخلفية ويسبب انزلاق الدراجة النارية، لذا افحص الحمل كثيراً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Who should be chosen as the lead rider and the sweep (last) rider in a group ride?","es":"¿A quién se debe elegir como conductor líder y como conductor de cierre (último) en un recorrido en grupo?","ru":"Кого следует выбирать ведущим и замыкающим (последним) при групповой поездке?","tr":"Bir grup sürüşünde lider sürücü ve sweep (en son) sürücü olarak kim seçilmelidir?","hi":"समूह सवारी में लीड सवार और स्वीप (अंतिम) सवार के रूप में किसे चुना जाना चाहिए?","ar":"من ينبغي أن يُختار سائقاً قائداً وسائقاً مرافقاً (الأخير) في ركوب جماعي؟"},"o":[{"en":"The two riders with the fastest motorcycles","es":"A los dos conductores con las motocicletas más rápidas","ru":"Двух мотоциклистов с самыми быстрыми мотоциклами","tr":"En hızlı motosikletlere sahip iki sürücü","hi":"सबसे तेज़ मोटरसाइकिलों वाले दो सवार","ar":"السائقان اللذان يملكان أسرع دراجتين ناريتين"},{"en":"The most experienced riders in the group","es":"A los conductores más experimentados del grupo","ru":"Самых опытных мотоциклистов в группе","tr":"Gruptaki en deneyimli sürücüler","hi":"समूह के सबसे अनुभवी सवार","ar":"أكثر السائقين خبرة في المجموعة"},{"en":"The newest riders, so they can learn","es":"A los conductores más nuevos, para que aprendan","ru":"Самых новых мотоциклистов, чтобы они учились","tr":"En yeni sürücüler, öğrenebilmeleri için","hi":"सबसे नए सवार, ताकि वे सीख सकें","ar":"أحدث السائقين، حتى يتعلموا"},{"en":"Whoever knows the route, regardless of experience","es":"A quien conozca la ruta, sin importar su experiencia","ru":"Того, кто знает маршрут, независимо от опыта","tr":"Deneyimden bağımsız olarak güzergahı bilen kişi","hi":"जो भी रास्ता जानता हो, अनुभव की परवाह किए बिना","ar":"من يعرف الطريق، بغض النظر عن الخبرة"}],"e":{"en":"The lead rider and the sweep rider should be the most experienced riders of the group. Source: Motorcycle Operator Manual.","es":"El conductor líder y el conductor de cierre deben ser los conductores más experimentados del grupo. Fuente: Manual del Operador de Motocicletas.","ru":"Ведущим и замыкающим должны быть самые опытные мотоциклисты группы. Источник: Руководство для водителей мотоциклов.","tr":"Lider sürücü ve sweep sürücü, grubun en deneyimli sürücüleri olmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"लीड सवार और स्वीप सवार समूह के सबसे अनुभवी सवार होने चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يكون السائق القائد والسائق المرافق أكثر السائقين خبرة في المجموعة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should inexperienced riders be placed in a group formation?","es":"¿Dónde se debe ubicar a los conductores sin experiencia en una formación de grupo?","ru":"Где в групповом построении следует размещать неопытных мотоциклистов?","tr":"Bir grup formasyonunda deneyimsiz sürücüler nereye yerleştirilmelidir?","hi":"समूह संरचना में अनुभवहीन सवारों को कहाँ रखा जाना चाहिए?","ar":"أين ينبغي أن يُوضع السائقون عديمو الخبرة في تشكيل جماعي؟"},"o":[{"en":"At the very back, behind the sweep rider","es":"En la parte de atrás, detrás del conductor de cierre","ru":"В самом конце, позади замыкающего","tr":"En arkaya, sweep sürücünün arkasına","hi":"सबसे पीछे, स्वीप सवार के पीछे","ar":"في أقصى الخلف، خلف السائق المرافق"},{"en":"Just behind the leader","es":"Justo detrás del líder","ru":"Сразу за ведущим","tr":"Hemen liderin arkasına","hi":"लीडर के ठीक पीछे","ar":"خلف القائد مباشرةً"},{"en":"In the middle, surrounded by experienced riders","es":"En el medio, rodeados de conductores experimentados","ru":"В середине, в окружении опытных мотоциклистов","tr":"Ortaya, deneyimli sürücülerle çevrili","hi":"बीच में, अनुभवी सवारों से घिरे हुए","ar":"في المنتصف، محاطين بسائقين ذوي خبرة"},{"en":"Wherever they feel most comfortable","es":"Donde se sientan más cómodos","ru":"Там, где им наиболее комфортно","tr":"En rahat hissettikleri yere","hi":"जहाँ भी वे सबसे सहज महसूस करें","ar":"حيثما يشعرون بالراحة أكثر"}],"e":{"en":"Place inexperienced riders just behind the leader so they do not have to chase the group and the experienced riders behind can watch them. Source: Motorcycle Operator Manual.","es":"Ubica a los conductores sin experiencia justo detrás del líder, para que no tengan que perseguir al grupo y los conductores experimentados de atrás puedan vigilarlos. Fuente: Manual del Operador de Motocicletas.","ru":"Размещайте неопытных мотоциклистов сразу за ведущим, чтобы им не приходилось догонять группу, а опытные мотоциклисты позади могли за ними присматривать. Источник: Руководство для водителей мотоциклов.","tr":"Deneyimsiz sürücüleri hemen liderin arkasına yerleştirin, böylece grubu kovalamak zorunda kalmazlar ve arkadaki deneyimli sürücüler onları gözetebilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"अनुभवहीन सवारों को लीडर के ठीक पीछे रखें ताकि उन्हें समूह का पीछा न करना पड़े और पीछे के अनुभवी सवार उन पर नज़र रख सकें। स्रोत: Motorcycle Operator Manual।","ar":"ضع السائقين عديمي الخبرة خلف القائد مباشرةً حتى لا يضطروا إلى ملاحقة المجموعة ويتمكن السائقون ذوو الخبرة في الخلف من مراقبتهم. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"In a staggered formation on a straight road, where does the leader ride and where does the second rider ride?","es":"En una formación escalonada en una vía recta, ¿dónde conduce el líder y dónde conduce el segundo conductor?","ru":"В шахматном построении на прямой дороге где едет ведущий и где едет второй мотоциклист?","tr":"Düz bir yolda kaydırmalı (staggered) formasyonda lider nerede sürer ve ikinci sürücü nerede sürer?","hi":"सीधी सड़क पर स्टैगर्ड संरचना में, लीडर कहाँ चलता है और दूसरा सवार कहाँ चलता है?","ar":"في تشكيل متعرّج على طريق مستقيم، أين يركب القائد وأين يركب السائق الثاني؟"},"o":[{"en":"The leader rides in the center; the second rider rides directly behind","es":"El líder conduce en el centro; el segundo conductor va directamente detrás","ru":"Ведущий едет по центру; второй мотоциклист едет прямо позади","tr":"Lider ortada sürer; ikinci sürücü tam arkasında sürer","hi":"लीडर केंद्र में चलता है; दूसरा सवार सीधे पीछे चलता है","ar":"يركب القائد في المنتصف؛ ويركب السائق الثاني خلفه مباشرةً"},{"en":"The leader rides in the left of the lane; the second rider rides at least one second back in the right of the lane","es":"El líder conduce en la parte izquierda del carril; el segundo conductor va al menos un segundo atrás en la parte derecha del carril","ru":"Ведущий едет в левой части полосы; второй мотоциклист едет не менее чем в одной секунде позади в правой части полосы","tr":"Lider şeritin solunda sürer; ikinci sürücü şeritin sağında en az bir saniye geride sürer","hi":"लीडर लेन के बाएँ में चलता है; दूसरा सवार लेन के दाएँ में कम से कम 1 सेकंड पीछे रहता है","ar":"يركب القائد في يسار المسار؛ ويركب السائق الثاني على بُعد ثانية واحدة على الأقل في يمين المسار"},{"en":"The leader and second rider ride side by side across the lane","es":"El líder y el segundo conductor van lado a lado a lo ancho del carril","ru":"Ведущий и второй мотоциклист едут бок о бок поперёк полосы","tr":"Lider ve ikinci sürücü şerit boyunca yan yana sürer","hi":"लीडर और दूसरा सवार लेन के आर-पार अगल-बगल चलते हैं","ar":"يركب القائد والسائق الثاني جنباً إلى جنب عبر المسار"},{"en":"The leader rides in the right of the lane; the second rider rides on the shoulder","es":"El líder conduce en la parte derecha del carril; el segundo conductor va en el acotamiento","ru":"Ведущий едет в правой части полосы; второй мотоциклист едет по обочине","tr":"Lider şeritin sağında sürer; ikinci sürücü bankette sürer","hi":"लीडर लेन के दाएँ में चलता है; दूसरा सवार कंधे पर चलता है","ar":"يركب القائد في يمين المسار؛ ويركب السائق الثاني على الكتف"}],"e":{"en":"In staggered formation the leader rides in the left of the lane and the second rider stays at least one second back in the right of the lane, keeping the group close with a space cushion. Source: Motorcycle Operator Manual.","es":"En la formación escalonada el líder conduce en la parte izquierda del carril y el segundo conductor se mantiene al menos un segundo atrás en la parte derecha del carril, manteniendo al grupo unido con un colchón de espacio. Fuente: Manual del Operador de Motocicletas.","ru":"В шахматном построении ведущий едет в левой части полосы, а второй мотоциклист держится не менее чем в одной секунде позади в правой части полосы, сохраняя группу плотной с запасом пространства. Источник: Руководство для водителей мотоциклов.","tr":"Kaydırmalı formasyonda lider şeritin solunda sürer ve ikinci sürücü şeritin sağında en az bir saniye geride kalır, grubu bir tampon boşluğuyla yakın tutar. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"स्टैगर्ड संरचना में लीडर लेन के बाएँ में चलता है और दूसरा सवार लेन के दाएँ में कम से कम 1 सेकंड पीछे रहता है, समूह को स्पेस कुशन के साथ पास रखते हुए। स्रोत: Motorcycle Operator Manual।","ar":"في التشكيل المتعرّج يركب القائد في يسار المسار ويبقى السائق الثاني على بُعد ثانية واحدة على الأقل في يمين المسار، مع إبقاء المجموعة متقاربة مع مسافة أمان. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When is it best for a group to switch from staggered formation to single file?","es":"¿Cuándo es mejor que un grupo cambie de la formación escalonada a fila india (uno detrás de otro)?","ru":"Когда группе лучше всего переходить из шахматного построения в одну колонну?","tr":"Bir grubun kaydırmalı formasyondan tek sıraya geçmesi en iyi ne zamandır?","hi":"समूह के लिए स्टैगर्ड संरचना से सिंगल फ़ाइल में बदलना कब सबसे अच्छा होता है?","ar":"متى يكون من الأفضل للمجموعة أن تتحول من التشكيل المتعرّج إلى الصف الواحد؟"},"o":[{"en":"Only at night or in the rain","es":"Solo de noche o bajo la lluvia","ru":"Только ночью или в дождь","tr":"Yalnızca gece veya yağmurda","hi":"केवल रात में या बारिश में","ar":"فقط ليلاً أو في المطر"},{"en":"When riding in curves, turning, or entering or leaving freeways and highways","es":"Al conducir en curvas, al girar o al entrar o salir de autopistas y carreteras","ru":"При прохождении поворотов, виражей или въезде на автомагистрали и шоссе и съезде с них","tr":"Virajlarda sürerken, dönerken veya otoyollara ve karayollarına girip çıkarken","hi":"कर्व में चलते समय, मुड़ते समय, या फ़्रीवे और राजमार्गों में प्रवेश करते या निकलते समय","ar":"عند القيادة في المنعطفات أو الانعطاف أو الدخول إلى الطرق السريعة أو الخروج منها"},{"en":"Whenever the speed limit increases","es":"Cada vez que aumenta el límite de velocidad","ru":"Всякий раз, когда повышается ограничение скорости","tr":"Hız sınırı her arttığında","hi":"जब भी गति सीमा बढ़े","ar":"كلما زادت سرعة الحد المسموح"},{"en":"Never; staggered formation is used everywhere","es":"Nunca; la formación escalonada se usa en todas partes","ru":"Никогда; шахматное построение используется везде","tr":"Asla; kaydırmalı formasyon her yerde kullanılır","hi":"कभी नहीं; स्टैगर्ड संरचना हर जगह उपयोग होती है","ar":"أبداً؛ يُستخدم التشكيل المتعرّج في كل مكان"}],"e":{"en":"It is best to move to single-file formation when riding in curves, turning, and entering or leaving freeways or highways. Source: Motorcycle Operator Manual.","es":"Lo mejor es pasar a la formación en fila india al conducir en curvas, al girar y al entrar o salir de autopistas o carreteras. Fuente: Manual del Operador de Motocicletas.","ru":"Лучше всего переходить в построение в одну колонну при прохождении поворотов, виражей и въезде на автомагистрали или шоссе и съезде с них. Источник: Руководство для водителей мотоциклов.","tr":"Virajlarda sürerken, dönerken ve otoyollara veya karayollarına girip çıkarken tek sıra formasyona geçmek en iyisidir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"कर्व में चलते समय, मुड़ते समय, और फ़्रीवे या राजमार्गों में प्रवेश करते या निकलते समय सिंगल-फ़ाइल संरचना में जाना सबसे अच्छा होता है। स्रोत: Motorcycle Operator Manual।","ar":"من الأفضل الانتقال إلى تشكيل الصف الواحد عند القيادة في المنعطفات والانعطاف والدخول إلى الطرق السريعة أو الخروج منها. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"According to studies cited in the Motorcycle Operator Manual, roughly what share of riders killed in motorcycle crashes had been drinking?","es":"Según los estudios citados en el Manual del Operador de Motocicletas, ¿aproximadamente qué proporción de los conductores muertos en choques de motocicleta habían estado bebiendo?","ru":"Согласно исследованиям, приведённым в Руководстве для водителей мотоциклов, какая примерно доля мотоциклистов, погибших в авариях, употребляла алкоголь?","tr":"Motosiklet Sürücü Kılavuzu'nda atıfta bulunulan çalışmalara göre, motosiklet kazalarında ölen sürücülerin kabaca ne kadarı içki içmişti?","hi":"Motorcycle Operator Manual में उद्धृत अध्ययनों के अनुसार, मोटरसाइकिल दुर्घटनाओं में मारे गए सवारों में से लगभग कितने हिस्से ने शराब पी रखी थी?","ar":"وفقاً للدراسات المذكورة في دليل مشغل الدراجة النارية، ما هي تقريباً نسبة السائقين الذين قُتلوا في حوادث الدراجات النارية وكانوا قد تناولوا الكحول؟"},"o":[{"en":"Nearly 90 percent","es":"Casi 90 por ciento","ru":"Почти 90 процентов","tr":"Neredeyse yüzde 90","hi":"लगभग 90 प्रतिशत","ar":"نحو 90 بالمئة"},{"en":"About 40 to 45 percent","es":"Cerca de 40 a 45 por ciento","ru":"Около 40–45 процентов","tr":"Yaklaşık yüzde 40 ila 45","hi":"लगभग 40 से 45 प्रतिशत","ar":"نحو 40 إلى 45 بالمئة"},{"en":"About 10 percent","es":"Cerca de 10 por ciento","ru":"Около 10 процентов","tr":"Yaklaşık yüzde 10","hi":"लगभग 10 प्रतिशत","ar":"نحو 10 بالمئة"},{"en":"Fewer than 5 percent","es":"Menos de 5 por ciento","ru":"Менее 5 процентов","tr":"Yüzde 5'ten az","hi":"5 प्रतिशत से कम","ar":"أقل من 5 بالمئة"}],"e":{"en":"Studies show that 40 to 45 percent of all riders killed in motorcycle crashes had been drinking, making alcohol a leading factor in fatal motorcycle crashes per the Motorcycle Operator Manual.","es":"Los estudios muestran que del 40 al 45 por ciento de todos los conductores muertos en choques de motocicleta habían estado bebiendo, lo que hace del alcohol un factor principal en los choques mortales de motocicleta, según el Manual del Operador de Motocicletas.","ru":"Исследования показывают, что от 40 до 45 процентов всех мотоциклистов, погибших в авариях, употребляли алкоголь, что делает алкоголь ведущим фактором смертельных аварий мотоциклов, согласно Руководству для водителей мотоциклов.","tr":"Çalışmalar, motosiklet kazalarında ölen tüm sürücülerin yüzde 40 ila 45'inin içki içmiş olduğunu göstermektedir; bu da Motosiklet Sürücü Kılavuzu'na göre alkolü ölümcül motosiklet kazalarında önde gelen bir etken yapar.","hi":"अध्ययन दिखाते हैं कि मोटरसाइकिल दुर्घटनाओं में मारे गए सभी सवारों में से 40 से 45 प्रतिशत ने शराब पी रखी थी, जिससे Motorcycle Operator Manual के अनुसार शराब घातक मोटरसाइकिल दुर्घटनाओं में एक प्रमुख कारक बन जाती है।","ar":"تُظهر الدراسات أن 40 إلى 45 بالمئة من جميع السائقين الذين قُتلوا في حوادث الدراجات النارية كانوا قد تناولوا الكحول، مما يجعل الكحول عاملاً رئيسياً في حوادث الدراجات النارية المميتة وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"Which ability does alcohol begin to impair first, even at low levels well below the legal limit?","es":"¿Qué capacidad empieza a afectar primero el alcohol, incluso en niveles bajos muy por debajo del límite legal?","ru":"Какую способность алкоголь начинает ослаблять в первую очередь, даже при низких уровнях, значительно ниже допустимого предела?","tr":"Yasal sınırın çok altındaki düşük seviyelerde bile alkol önce hangi yeteneği bozmaya başlar?","hi":"शराब किस क्षमता को सबसे पहले बिगाड़ना शुरू करती है, यहाँ तक कि कानूनी सीमा से काफी कम निम्न स्तर पर भी?","ar":"أي قدرة يبدأ الكحول بإضعافها أولاً، حتى عند مستويات منخفضة أقل بكثير من الحد القانوني؟"},"o":[{"en":"Judgment and good sense","es":"El juicio y el buen sentido","ru":"Рассудительность и здравый смысл","tr":"Muhakeme ve sağduyu","hi":"निर्णय और समझदारी","ar":"الحكم والإدراك السليم"},{"en":"Hearing","es":"La audición","ru":"Слух","tr":"İşitme","hi":"सुनना","ar":"السمع"},{"en":"Grip strength","es":"La fuerza de agarre","ru":"Силу хвата","tr":"Kavrama gücü","hi":"पकड़ की ताकत","ar":"قوة القبضة"},{"en":"Sense of smell","es":"El sentido del olfato","ru":"Обоняние","tr":"Koku alma duyusu","hi":"सूँघने की भावना","ar":"حاسة الشم"}],"e":{"en":"Alcohol affects judgment and good sense first, often before any obvious signs appear and before a rider reaches the legal limit, according to the Motorcycle Operator Manual.","es":"El alcohol afecta primero el juicio y el buen sentido, a menudo antes de que aparezca cualquier señal evidente y antes de que un conductor alcance el límite legal, según el Manual del Operador de Motocicletas.","ru":"Алкоголь в первую очередь влияет на рассудительность и здравый смысл, часто до появления каких-либо явных признаков и до того, как мотоциклист достигнет допустимого предела, согласно Руководству для водителей мотоциклов.","tr":"Alkol, Motosiklet Sürücü Kılavuzu'na göre, çoğu zaman herhangi bir belirgin işaret ortaya çıkmadan ve sürücü yasal sınıra ulaşmadan önce, ilk olarak muhakemeyi ve sağduyuyu etkiler.","hi":"शराब सबसे पहले निर्णय और समझदारी को प्रभावित करती है, अक्सर किसी भी स्पष्ट संकेत के प्रकट होने से पहले और सवार के कानूनी सीमा तक पहुँचने से पहले, Motorcycle Operator Manual के अनुसार।","ar":"يؤثر الكحول على الحكم والإدراك السليم أولاً، غالباً قبل ظهور أي علامات واضحة وقبل أن يصل السائق إلى الحد القانوني، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"What is the only thing that will actually sober up a person who has been drinking?","es":"¿Qué es lo único que realmente despeja a una persona que ha estado bebiendo?","ru":"Что единственное действительно отрезвит человека, который употреблял алкоголь?","tr":"İçki içmiş bir kişiyi gerçekten ayıltacak tek şey nedir?","hi":"शराब पीने वाले व्यक्ति को वास्तव में होश में लाने वाली एकमात्र चीज़ क्या है?","ar":"ما هو الشيء الوحيد الذي يُفيق فعلاً شخصاً تناول الكحول؟"},"o":[{"en":"Taking a cold shower","es":"Darse una ducha fría","ru":"Холодный душ","tr":"Soğuk duş almak","hi":"ठंडा शॉवर लेना","ar":"أخذ دش بارد"},{"en":"Drinking strong coffee","es":"Tomar café cargado","ru":"Крепкий кофе","tr":"Sert kahve içmek","hi":"कड़क कॉफ़ी पीना","ar":"شرب قهوة قوية"},{"en":"Doing physical exercise","es":"Hacer ejercicio físico","ru":"Физические упражнения","tr":"Fiziksel egzersiz yapmak","hi":"शारीरिक व्यायाम करना","ar":"ممارسة التمارين البدنية"},{"en":"The passage of time","es":"El paso del tiempo","ru":"Прошедшее время","tr":"Zamanın geçmesi","hi":"समय का बीतना","ar":"مرور الوقت"}],"e":{"en":"Only time eliminates alcohol from the body. Coffee, cold showers, and exercise do not speed up the process, says the Motorcycle Operator Manual.","es":"Solo el tiempo elimina el alcohol del cuerpo. El café, las duchas frías y el ejercicio no aceleran el proceso, dice el Manual del Operador de Motocicletas.","ru":"Только время выводит алкоголь из организма. Кофе, холодный душ и упражнения не ускоряют этот процесс, говорит Руководство для водителей мотоциклов.","tr":"Alkolü vücuttan yalnızca zaman temizler. Motosiklet Sürücü Kılavuzu'na göre kahve, soğuk duş ve egzersiz bu süreci hızlandırmaz.","hi":"केवल समय ही शरीर से शराब को खत्म करता है। कॉफ़ी, ठंडे शॉवर और व्यायाम इस प्रक्रिया को तेज़ नहीं करते, Motorcycle Operator Manual कहता है।","ar":"الوقت وحده هو ما يزيل الكحول من الجسم. القهوة والدش البارد والتمارين لا تسرّع العملية، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"About how quickly does the body eliminate alcohol?","es":"¿Aproximadamente qué tan rápido elimina el cuerpo el alcohol?","ru":"Примерно с какой скоростью организм выводит алкоголь?","tr":"Vücut alkolü yaklaşık ne kadar hızlı atar?","hi":"शरीर लगभग कितनी जल्दी शराब को खत्म करता है?","ar":"ما هي تقريباً السرعة التي يتخلص بها الجسم من الكحول؟"},"o":[{"en":"About one drink every ten minutes","es":"Cerca de un trago cada diez minutos","ru":"Примерно одна порция каждые десять минут","tr":"Her on dakikada yaklaşık bir içki","hi":"लगभग हर 10 मिनट में एक ड्रिंक","ar":"نحو مشروب واحد كل عشر دقائق"},{"en":"Almost instantly","es":"Casi de inmediato","ru":"Почти мгновенно","tr":"Neredeyse anında","hi":"लगभग तुरंत","ar":"تقريباً فوراً"},{"en":"About one drink per hour","es":"Cerca de un trago por hora","ru":"Примерно одна порция в час","tr":"Saatte yaklaşık bir içki","hi":"लगभग एक ड्रिंक प्रति घंटा","ar":"نحو مشروب واحد في الساعة"},{"en":"About four drinks per hour","es":"Cerca de cuatro tragos por hora","ru":"Примерно четыре порции в час","tr":"Saatte yaklaşık dört içki","hi":"लगभग चार ड्रिंक प्रति घंटा","ar":"نحو أربعة مشروبات في الساعة"}],"e":{"en":"The body eliminates alcohol at a rate of about one drink per hour, so drinking faster than that causes alcohol to accumulate, per the Motorcycle Operator Manual.","es":"El cuerpo elimina el alcohol a una tasa de cerca de un trago por hora, así que beber más rápido que eso hace que el alcohol se acumule, según el Manual del Operador de Motocicletas.","ru":"Организм выводит алкоголь со скоростью примерно одна порция в час, поэтому употребление быстрее этого приводит к накоплению алкоголя, согласно Руководству для водителей мотоциклов.","tr":"Vücut, alkolü saatte yaklaşık bir içki hızında atar, bu yüzden bundan daha hızlı içmek, Motosiklet Sürücü Kılavuzu'na göre alkolün birikmesine neden olur.","hi":"शरीर लगभग एक ड्रिंक प्रति घंटे की दर से शराब को खत्म करता है, इसलिए इससे तेज़ी से पीने पर शराब जमा हो जाती है, Motorcycle Operator Manual के अनुसार।","ar":"يتخلص الجسم من الكحول بمعدل نحو مشروب واحد في الساعة، لذا فإن الشرب بمعدل أسرع من ذلك يجعل الكحول يتراكم، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Besides judgment, which combination of riding skills is most directly impaired by alcohol?","es":"Además del juicio, ¿qué combinación de habilidades de conducción se ve afectada más directamente por el alcohol?","ru":"Помимо рассудительности, какое сочетание навыков езды наиболее напрямую ослабляется алкоголем?","tr":"Muhakemenin yanı sıra, hangi sürüş becerileri kombinasyonu alkolden en doğrudan etkilenir?","hi":"निर्णय के अलावा, सवारी कौशल का कौन सा संयोजन शराब से सबसे सीधे प्रभावित होता है?","ar":"إلى جانب الحكم، أي مجموعة من مهارات القيادة هي الأكثر تأثراً مباشرةً بالكحول؟"},"o":[{"en":"Color vision only","es":"Solo la visión de color","ru":"Только цветовое зрение","tr":"Yalnızca renkli görüş","hi":"केवल रंग दृष्टि","ar":"رؤية الألوان فقط"},{"en":"Memory and appetite","es":"La memoria y el apetito","ru":"Память и аппетит","tr":"Hafıza ve iştah","hi":"स्मृति और भूख","ar":"الذاكرة والشهية"},{"en":"Balance and coordination","es":"El equilibrio y la coordinación","ru":"Равновесие и координация","tr":"Denge ve koordinasyon","hi":"संतुलन और समन्वय","ar":"التوازن والتناسق"},{"en":"Height perception only","es":"Solo la percepción de altura","ru":"Только восприятие высоты","tr":"Yalnızca yükseklik algısı","hi":"केवल ऊँचाई की धारणा","ar":"إدراك الارتفاع فقط"}],"e":{"en":"Alcohol impairs the balance and coordination that motorcycle control depends on, in addition to judgment and vision, according to the Motorcycle Operator Manual.","es":"El alcohol afecta el equilibrio y la coordinación de los que depende el control de la motocicleta, además del juicio y la visión, según el Manual del Operador de Motocicletas.","ru":"Алкоголь ослабляет равновесие и координацию, от которых зависит управление мотоциклом, в дополнение к рассудительности и зрению, согласно Руководству для водителей мотоциклов.","tr":"Alkol, Motosiklet Sürücü Kılavuzu'na göre, muhakeme ve görüşün yanı sıra motosiklet kontrolünün dayandığı denge ve koordinasyonu da bozar.","hi":"शराब उस संतुलन और समन्वय को बिगाड़ती है जिस पर मोटरसाइकिल का नियंत्रण निर्भर करता है, निर्णय और दृष्टि के अलावा, Motorcycle Operator Manual के अनुसार।","ar":"يُضعف الكحول التوازن والتناسق اللذين يعتمد عليهما التحكم في الدراجة النارية، إضافةً إلى الحكم والرؤية، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Which of the following counts as one standard drink for purposes of estimating impairment?","es":"¿Cuál de los siguientes cuenta como un trago estándar para efectos de estimar el deterioro?","ru":"Что из перечисленного считается одной стандартной порцией для целей оценки опьянения?","tr":"Aşağıdakilerden hangisi, bozulmayı tahmin etmek açısından bir standart içki sayılır?","hi":"निम्नलिखित में से कौन सा क्षीणता आँकने के उद्देश्य से एक मानक ड्रिंक के रूप में गिना जाता है?","ar":"أي مما يلي يُحتسب مشروباً قياسياً واحداً لأغراض تقدير الضعف؟"},"o":[{"en":"A pint of liquor","es":"Una pinta de licor","ru":"Пинта крепкого алкоголя","tr":"Bir pint sert içki","hi":"एक पिंट शराब","ar":"نصف لتر من المشروبات الروحية"},{"en":"Three shots of liquor","es":"Tres caballitos de licor","ru":"Три рюмки крепкого алкоголя","tr":"Üç shot sert içki","hi":"तीन शॉट शराब","ar":"ثلاث جرعات من المشروبات الروحية"},{"en":"A 12-ounce can of regular beer","es":"Una lata de 12 onzas de cerveza regular","ru":"Банка обычного пива объёмом 12 унций","tr":"12 onsluk bir kutu normal bira","hi":"12-ounce साधारण बीयर का एक कैन","ar":"علبة بيرة عادية سعة 12 أونصة"},{"en":"A full bottle of wine","es":"Una botella completa de vino","ru":"Полная бутылка вина","tr":"Bir şişe dolusu şarap","hi":"शराब की एक पूरी बोतल","ar":"زجاجة نبيذ كاملة"}],"e":{"en":"A standard drink is a 12-ounce can of beer, a 5-ounce glass of wine, or a mixed drink with one shot of liquor, notes the Motorcycle Operator Manual.","es":"Un trago estándar es una lata de 12 onzas de cerveza, una copa de 5 onzas de vino o un trago mezclado con un caballito de licor, señala el Manual del Operador de Motocicletas.","ru":"Стандартная порция — это банка пива объёмом 12 унций, бокал вина объёмом 5 унций или смешанный напиток с одной рюмкой крепкого алкоголя, отмечает Руководство для водителей мотоциклов.","tr":"Motosiklet Sürücü Kılavuzu'na göre bir standart içki, 12 onsluk bir kutu bira, 5 onsluk bir kadeh şarap veya bir shot sert içki içeren bir kokteyldir.","hi":"एक मानक ड्रिंक 12-ounce बीयर का कैन, 5-ounce वाइन का गिलास, या एक शॉट शराब वाला मिश्रित पेय होता है, Motorcycle Operator Manual बताता है।","ar":"المشروب القياسي هو علبة بيرة سعة 12 أونصة، أو كأس نبيذ سعة 5 أونصات، أو مشروب ممزوج بجرعة واحدة من المشروبات الروحية، يشير دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"A friend has had several drinks and wants to ride home. What is the best way to help, according to the manual?","es":"Un amigo ha tomado varios tragos y quiere irse conduciendo a casa. ¿Cuál es la mejor manera de ayudar, según el manual?","ru":"Ваш друг выпил несколько порций и хочет ехать домой. Как, согласно Руководству, лучше всего помочь?","tr":"Bir arkadaşınız birkaç içki içti ve eve gitmek üzere sürmek istiyor. Kılavuza göre yardım etmenin en iyi yolu nedir?","hi":"एक दोस्त ने कई ड्रिंक पी ली हैं और घर तक बाइक चलाना चाहता है। मैनुअल के अनुसार मदद करने का सबसे अच्छा तरीका क्या है?","ar":"تناول صديق عدة مشروبات ويريد القيادة إلى المنزل. ما هي أفضل طريقة للمساعدة، وفقاً للدليل؟"},"o":[{"en":"Arrange a safe ride home for them","es":"Conseguirle un viaje seguro a casa","ru":"Организовать ему безопасную доставку домой","tr":"Onlar için eve güvenli bir ulaşım ayarlamak","hi":"उनके लिए घर तक सुरक्षित सवारी की व्यवस्था करें","ar":"رتّب له وسيلة آمنة للعودة إلى المنزل"},{"en":"Have them ride slowly behind the group","es":"Hacer que conduzca despacio detrás del grupo","ru":"Пусть едет медленно позади группы","tr":"Grubun arkasında yavaşça sürmelerini sağlamak","hi":"उन्हें समूह के पीछे धीरे-धीरे चलने दें","ar":"اجعله يقود ببطء خلف المجموعة"},{"en":"Give them coffee and let them go","es":"Darle café y dejarlo ir","ru":"Дать ему кофе и отпустить","tr":"Onlara kahve verip gitmelerine izin vermek","hi":"उन्हें कॉफ़ी दें और जाने दें","ar":"أعطه قهوة ودعه يذهب"},{"en":"Let them ride if they feel fine","es":"Dejarlo conducir si se siente bien","ru":"Позволить ему ехать, если он чувствует себя нормально","tr":"İyi hissediyorlarsa sürmelerine izin vermek","hi":"अगर वे ठीक महसूस करें तो उन्हें बाइक चलाने दें","ar":"دعه يقود إذا شعر أنه بخير"}],"e":{"en":"Arranging a safe ride home, such as a sober driver or a place to stay, keeps an impaired rider off the bike. The Motorcycle Operator Manual lists this as a key intervention.","es":"Conseguir un viaje seguro a casa, como un conductor sobrio o un lugar para quedarse, mantiene a un conductor afectado fuera de la moto. El Manual del Operador de Motocicletas menciona esto como una intervención clave.","ru":"Организация безопасной доставки домой, например с трезвым водителем или с местом для ночлега, не даёт нетрезвому мотоциклисту сесть за руль. Руководство для водителей мотоциклов перечисляет это как ключевое вмешательство.","tr":"Ayık bir sürücü veya kalacak bir yer gibi eve güvenli bir ulaşım ayarlamak, bozulmuş bir sürücüyü motosikletten uzak tutar. Motosiklet Sürücü Kılavuzu bunu önemli bir müdahale olarak sıralar.","hi":"घर तक सुरक्षित सवारी की व्यवस्था करना, जैसे कोई शांत चालक या रुकने की जगह, क्षीण सवार को बाइक से दूर रखता है। Motorcycle Operator Manual इसे एक प्रमुख हस्तक्षेप के रूप में सूचीबद्ध करता है।","ar":"ترتيب وسيلة آمنة للعودة إلى المنزل، مثل سائق غير ثمل أو مكان للمبيت، يُبقي السائق المتأثر بعيداً عن الدراجة. يدرج دليل مشغل الدراجة النارية هذا كتدخّل رئيسي."}},{"cat":"impairment","a":1,"q":{"en":"Which group strategy can help keep a friend from drinking too much to ride at a gathering?","es":"¿Qué estrategia de grupo puede ayudar a evitar que un amigo beba demasiado para conducir en una reunión?","ru":"Какая групповая стратегия может помочь не дать другу выпить слишком много, чтобы ехать, на мероприятии?","tr":"Bir buluşmada bir arkadaşın sürmek için çok fazla içmesini önlemeye hangi grup stratejisi yardımcı olabilir?","hi":"कौन सी समूह रणनीति किसी समारोह में किसी दोस्त को बाइक चलाने के लिए बहुत अधिक पीने से रोकने में मदद कर सकती है?","ar":"أي استراتيجية جماعية يمكن أن تساعد في منع صديق من الإفراط في الشرب بحيث لا يستطيع القيادة في تجمّع؟"},"o":[{"en":"Ignore how much they drink","es":"Ignorar cuánto bebe","ru":"Игнорировать, сколько он пьёт","tr":"Ne kadar içtiklerini görmezden gelin","hi":"वे कितना पीते हैं इसे अनदेखा करें","ar":"تجاهل كمية ما يشربه"},{"en":"Slow the pace of drinking","es":"Hacer más lento el ritmo de la bebida","ru":"Замедлить темп употребления","tr":"İçki temposunu yavaşlatın","hi":"पीने की गति धीमी करें","ar":"إبطاء وتيرة الشرب"},{"en":"Switch them to stronger drinks","es":"Cambiarlo a tragos más fuertes","ru":"Перевести его на более крепкие напитки","tr":"Onları daha sert içkilere geçirin","hi":"उन्हें तेज़ ड्रिंक पर शिफ्ट करें","ar":"تحويله إلى مشروبات أقوى"},{"en":"Buy rounds faster","es":"Comprar rondas más rápido","ru":"Покупать раунды быстрее","tr":"Daha hızlı sıra ısmarlayın","hi":"तेज़ी से राउंड खरीदें","ar":"شراء جولات بوتيرة أسرع"}],"e":{"en":"Slowing the pace of drinking, by involving the person in other activities and encouraging food and non-alcoholic drinks, reduces impairment, per the Motorcycle Operator Manual.","es":"Hacer más lento el ritmo de la bebida, involucrando a la persona en otras actividades y animándola a comer y a tomar bebidas sin alcohol, reduce el deterioro, según el Manual del Operador de Motocicletas.","ru":"Замедление темпа употребления путём вовлечения человека в другие занятия и поощрения еды и безалкогольных напитков снижает опьянение, согласно Руководству для водителей мотоциклов.","tr":"Kişiyi başka etkinliklere dahil ederek ve yemek ile alkolsüz içecekleri teşvik ederek içki temposunu yavaşlatmak, Motosiklet Sürücü Kılavuzu'na göre bozulmayı azaltır.","hi":"पीने की गति धीमी करना, व्यक्ति को अन्य गतिविधियों में शामिल करके और भोजन व ग़ैर-शराबी पेय को प्रोत्साहित करके, क्षीणता को कम करता है, Motorcycle Operator Manual के अनुसार।","ar":"إبطاء وتيرة الشرب، بإشراك الشخص في أنشطة أخرى وتشجيع تناول الطعام والمشروبات غير الكحولية، يقلل الضعف، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"A riding buddy is clearly impaired but insists on leaving. What does the manual suggest the group do?","es":"Un compañero de viaje está claramente afectado pero insiste en irse. ¿Qué sugiere el manual que haga el grupo?","ru":"Товарищ по поездке явно нетрезв, но настаивает на отъезде. Что Руководство предлагает сделать группе?","tr":"Bir sürüş arkadaşı açıkça bozulmuş ama ayrılmakta ısrar ediyor. Kılavuz grubun ne yapmasını önerir?","hi":"एक सवारी साथी स्पष्ट रूप से क्षीण है लेकिन जाने पर अड़ा है। मैनुअल समूह को क्या करने का सुझाव देता है?","ar":"رفيق ركوب متأثر بوضوح لكنه يصرّ على المغادرة. بماذا يقترح الدليل أن تفعل المجموعة؟"},"o":[{"en":"Let one person argue alone","es":"Dejar que una sola persona discuta a solas","ru":"Пусть один человек спорит в одиночку","tr":"Bir kişinin tek başına tartışmasına izin verin","hi":"एक व्यक्ति को अकेले बहस करने दें","ar":"دع شخصاً واحداً يجادل بمفرده"},{"en":"Race ahead so they keep up","es":"Adelantarse para que él siga el ritmo","ru":"Мчаться вперёд, чтобы он не отставал","tr":"Onlar yetişsin diye öne fırlayın","hi":"आगे दौड़ें ताकि वे साथ चलते रहें","ar":"تسابق إلى الأمام حتى يواكب"},{"en":"Get other friends involved to intervene","es":"Involucrar a otros amigos para intervenir","ru":"Привлечь других друзей для вмешательства","tr":"Müdahale etmek için diğer arkadaşları da işin içine katın","hi":"हस्तक्षेप के लिए अन्य दोस्तों को शामिल करें","ar":"أشرك أصدقاء آخرين للتدخل"},{"en":"Take away only their helmet","es":"Quitarle solo el casco","ru":"Забрать только его шлем","tr":"Yalnızca kasklarını alın","hi":"केवल उनका हेलमेट ले लें","ar":"خذ خوذته فقط"}],"e":{"en":"Getting friends involved increases the social pressure to make the safe choice; a group is harder to ignore than one person. The Motorcycle Operator Manual recommends this.","es":"Involucrar a los amigos aumenta la presión social para tomar la decisión segura; es más difícil ignorar a un grupo que a una sola persona. El Manual del Operador de Motocicletas recomienda esto.","ru":"Привлечение друзей усиливает социальное давление в пользу безопасного выбора; группу труднее проигнорировать, чем одного человека. Руководство для водителей мотоциклов рекомендует это.","tr":"Arkadaşları işin içine katmak, güvenli seçimi yapma yönündeki sosyal baskıyı artırır; bir grubu görmezden gelmek tek bir kişiyi görmezden gelmekten daha zordur. Motosiklet Sürücü Kılavuzu bunu önerir.","hi":"दोस्तों को शामिल करना सुरक्षित विकल्प चुनने के लिए सामाजिक दबाव बढ़ाता है; एक समूह को नज़रअंदाज़ करना एक व्यक्ति की तुलना में कठिन होता है। Motorcycle Operator Manual इसकी सिफ़ारिश करता है।","ar":"إشراك الأصدقاء يزيد الضغط الاجتماعي لاتخاذ الخيار الآمن؛ فمن الأصعب تجاهل مجموعة من تجاهل شخص واحد. يوصي دليل مشغل الدراجة النارية بهذا."}},{"cat":"impairment","a":3,"q":{"en":"If you cannot stop an impaired friend from leaving immediately, what is another reasonable step?","es":"Si no puedes evitar que un amigo afectado se vaya de inmediato, ¿cuál es otro paso razonable?","ru":"Если вы не можете сразу остановить нетрезвого друга от отъезда, какой ещё разумный шаг можно предпринять?","tr":"Bozulmuş bir arkadaşınızın hemen ayrılmasını engelleyemezseniz, makul bir başka adım nedir?","hi":"अगर आप किसी क्षीण दोस्त को तुरंत जाने से नहीं रोक सकते, तो एक और उचित कदम क्या है?","ar":"إذا لم تستطع منع صديق متأثر من المغادرة فوراً، ما هي خطوة معقولة أخرى؟"},"o":[{"en":"Pour them one more drink","es":"Servirle un trago más","ru":"Налить ему ещё одну порцию","tr":"Onlara bir içki daha doldurun","hi":"उन्हें एक और ड्रिंक डालकर दें","ar":"اسكب له مشروباً آخر"},{"en":"Remove their mirrors","es":"Quitarle los espejos","ru":"Снять его зеркала","tr":"Aynalarını çıkarın","hi":"उनके मिरर हटा दें","ar":"أزل مراياه"},{"en":"Tell them to ride faster to get home sooner","es":"Decirle que conduzca más rápido para llegar antes a casa","ru":"Сказать ему ехать быстрее, чтобы скорее добраться домой","tr":"Eve daha çabuk varmaları için daha hızlı sürmelerini söyleyin","hi":"उन्हें जल्दी घर पहुँचने के लिए तेज़ चलने को कहें","ar":"اطلب منه القيادة أسرع للوصول إلى المنزل في وقت أقرب"},{"en":"Find a way to keep them there until they sober up","es":"Encontrar la manera de retenerlo ahí hasta que se le pase el efecto","ru":"Найти способ удержать его на месте, пока он не протрезвеет","tr":"Ayılana kadar onları orada tutmanın bir yolunu bulun","hi":"उन्हें होश में आने तक वहाँ रोके रखने का कोई तरीका खोजें","ar":"جِد طريقة لإبقائه هناك حتى يفيق"}],"e":{"en":"Keeping the person there, by slowing things down or offering food and a place to rest, buys time for the alcohol to wear off, says the Motorcycle Operator Manual.","es":"Retener a la persona ahí, haciendo más lentas las cosas u ofreciéndole comida y un lugar para descansar, da tiempo para que el efecto del alcohol disminuya, dice el Manual del Operador de Motocicletas.","ru":"Удержание человека на месте путём замедления событий или предложения еды и места для отдыха выигрывает время для выведения алкоголя, говорит Руководство для водителей мотоциклов.","tr":"İşleri yavaşlatarak veya yemek ve dinlenecek bir yer sunarak kişiyi orada tutmak, Motosiklet Sürücü Kılavuzu'na göre alkolün etkisinin geçmesi için zaman kazandırır.","hi":"व्यक्ति को वहीं रोके रखना, चीज़ों को धीमा करके या भोजन व आराम की जगह देकर, शराब का असर कम होने के लिए समय देता है, Motorcycle Operator Manual कहता है।","ar":"إبقاء الشخص هناك، بإبطاء الأمور أو تقديم الطعام ومكان للراحة، يكسب وقتاً حتى يزول مفعول الكحول، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"How does fatigue affect a motorcycle rider?","es":"¿Cómo afecta la fatiga a un motociclista?","ru":"Как усталость влияет на водителя мотоцикла?","tr":"Yorgunluk bir motosiklet sürücüsünü nasıl etkiler?","hi":"थकान मोटरसाइकिल सवार को कैसे प्रभावित करती है?","ar":"كيف يؤثر التعب على سائق الدراجة النارية؟"},"o":[{"en":"It has no real effect on a short trip","es":"No tiene un efecto real en un viaje corto","ru":"Она не оказывает реального влияния в короткой поездке","tr":"Kısa bir yolculukta gerçek bir etkisi yoktur","hi":"छोटी यात्रा पर इसका कोई वास्तविक प्रभाव नहीं होता","ar":"ليس له تأثير حقيقي في رحلة قصيرة"},{"en":"It sharpens reaction time","es":"Agudiza el tiempo de reacción","ru":"Она обостряет время реакции","tr":"Tepki süresini keskinleştirir","hi":"यह प्रतिक्रिया समय को तेज़ करती है","ar":"يُحدّ من زمن رد الفعل"},{"en":"It slows reactions and impairs judgment like alcohol","es":"Hace más lentas las reacciones y afecta el juicio, como el alcohol","ru":"Она замедляет реакции и ослабляет рассудительность подобно алкоголю","tr":"Tepkileri yavaşlatır ve muhakemeyi tıpkı alkol gibi bozar","hi":"यह शराब की तरह प्रतिक्रियाओं को धीमा करती है और निर्णय बिगाड़ती है","ar":"يُبطئ ردود الفعل ويُضعف الحكم مثل الكحول"},{"en":"It only affects vision at night","es":"Solo afecta la visión de noche","ru":"Она влияет только на зрение ночью","tr":"Yalnızca gece görüşü etkiler","hi":"यह केवल रात में दृष्टि को प्रभावित करती है","ar":"يؤثر فقط على الرؤية ليلاً"}],"e":{"en":"Fatigue, like alcohol, slows reactions and impairs judgment and concentration. The Motorcycle Operator Manual stresses protecting yourself against it on long rides.","es":"La fatiga, al igual que el alcohol, hace más lentas las reacciones y afecta el juicio y la concentración. El Manual del Operador de Motocicletas resalta protegerte contra ella en los recorridos largos.","ru":"Усталость, как и алкоголь, замедляет реакции и ослабляет рассудительность и концентрацию. Руководство для водителей мотоциклов подчёркивает важность защиты от неё в длительных поездках.","tr":"Yorgunluk, tıpkı alkol gibi tepkileri yavaşlatır ve muhakeme ile konsantrasyonu bozar. Motosiklet Sürücü Kılavuzu, uzun sürüşlerde kendinizi buna karşı korumanın önemini vurgular.","hi":"थकान, शराब की तरह, प्रतिक्रियाओं को धीमा करती है और निर्णय व एकाग्रता को बिगाड़ती है। Motorcycle Operator Manual लंबी सवारियों पर इससे खुद को बचाने पर ज़ोर देता है।","ar":"التعب، مثل الكحول، يُبطئ ردود الفعل ويُضعف الحكم والتركيز. يشدد دليل مشغل الدراجة النارية على حماية نفسك منه في الرحلات الطويلة."}},{"cat":"impairment","a":3,"q":{"en":"Which is a good way to protect yourself against fatigue on a long ride?","es":"¿Cuál es una buena manera de protegerte contra la fatiga en un recorrido largo?","ru":"Что является хорошим способом защититься от усталости в длительной поездке?","tr":"Uzun bir sürüşte kendinizi yorgunluğa karşı korumanın iyi bir yolu nedir?","hi":"लंबी सवारी पर थकान से खुद को बचाने का एक अच्छा तरीका कौन सा है?","ar":"ما هي الطريقة الجيدة لحماية نفسك من التعب في رحلة طويلة؟"},"o":[{"en":"Skip meals to stay alert","es":"Saltarte las comidas para mantenerte alerta","ru":"Пропускать приёмы пищи, чтобы оставаться бодрым","tr":"Uyanık kalmak için öğünleri atlayın","hi":"सतर्क रहने के लिए भोजन छोड़ दें","ar":"تخطّ الوجبات للبقاء يقظاً"},{"en":"Ride straight through without stopping","es":"Conducir de corrido sin detenerte","ru":"Ехать без остановок до конца","tr":"Hiç durmadan baştan sona sürün","hi":"बिना रुके सीधे चलते रहें","ar":"قُد دون توقف حتى النهاية"},{"en":"Wear heavier dark clothing","es":"Usar ropa oscura más pesada","ru":"Носить более тяжёлую тёмную одежду","tr":"Daha ağır koyu kıyafetler giyin","hi":"भारी गहरे रंग के कपड़े पहनें","ar":"ارتدِ ملابس داكنة أثقل"},{"en":"Limit your distance and take frequent rest breaks","es":"Limitar tu distancia y tomar descansos frecuentes","ru":"Ограничивать дистанцию и делать частые перерывы на отдых","tr":"Mesafenizi sınırlayın ve sık sık dinlenme molaları verin","hi":"अपनी दूरी सीमित करें और बार-बार आराम के ब्रेक लें","ar":"حُدّ من مسافتك وخذ فترات راحة متكررة"}],"e":{"en":"Limiting distance, taking frequent breaks, dressing to stay protected from the elements, and avoiding alcohol all help fight fatigue, per the Motorcycle Operator Manual.","es":"Limitar la distancia, tomar descansos frecuentes, vestirte para protegerte de los elementos y evitar el alcohol ayudan a combatir la fatiga, según el Manual del Operador de Motocicletas.","ru":"Ограничение дистанции, частые перерывы, одежда, защищающая от стихии, и отказ от алкоголя — всё это помогает бороться с усталостью, согласно Руководству для водителей мотоциклов.","tr":"Mesafeyi sınırlamak, sık molalar vermek, hava koşullarından korunmak için giyinmek ve alkolden kaçınmak, Motosiklet Sürücü Kılavuzu'na göre yorgunlukla mücadeleye yardımcı olur.","hi":"दूरी सीमित करना, बार-बार ब्रेक लेना, मौसम से बचाव के लिए कपड़े पहनना और शराब से बचना सभी थकान से लड़ने में मदद करते हैं, Motorcycle Operator Manual के अनुसार।","ar":"الحد من المسافة، وأخذ فترات راحة متكررة، والملبس الذي يحميك من العوامل الجوية، وتجنّب الكحول، كلها تساعد على مكافحة التعب، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"How much of the lane is a motorcycle entitled to use?","es":"¿Cuánto del carril tiene derecho a usar una motocicleta?","ru":"Какую часть полосы мотоцикл имеет право использовать?","tr":"Bir motosiklet şeritin ne kadarını kullanma hakkına sahiptir?","hi":"एक मोटरसाइकिल लेन का कितना हिस्सा उपयोग करने की हकदार है?","ar":"ما مقدار المسار الذي يحق للدراجة النارية استخدامه؟"},"o":[{"en":"Half the lane so a car can share it","es":"La mitad del carril para que un auto pueda compartirlo","ru":"Половину полосы, чтобы автомобиль мог делить её с ним","tr":"Bir arabanın paylaşabilmesi için şeritin yarısı","hi":"आधी लेन ताकि एक कार साझा कर सके","ar":"نصف المسار حتى تتمكن سيارة من مشاركته"},{"en":"The full width of the lane","es":"El ancho completo del carril","ru":"Полную ширину полосы","tr":"Şeritin tüm genişliği","hi":"लेन की पूरी चौड़ाई","ar":"العرض الكامل للمسار"},{"en":"Only the right third","es":"Solo el tercio derecho","ru":"Только правую треть","tr":"Yalnızca sağ üçte biri","hi":"केवल दायाँ तिहाई","ar":"الثلث الأيمن فقط"},{"en":"Only the center stripe area","es":"Solo el área de la raya central","ru":"Только зону центральной полосы","tr":"Yalnızca orta şerit bölgesi","hi":"केवल केंद्र पट्टी का क्षेत्र","ar":"منطقة الخط الأوسط فقط"}],"e":{"en":"A motorcycle is entitled to the full width of a lane. It needs the whole lane to maneuver and respond to hazards, according to the Motorcycle Operator Manual.","es":"Una motocicleta tiene derecho al ancho completo de un carril. Necesita todo el carril para maniobrar y responder ante los peligros, según el Manual del Operador de Motocicletas.","ru":"Мотоцикл имеет право на полную ширину полосы. Ему нужна вся полоса для манёвра и реагирования на опасности, согласно Руководству для водителей мотоциклов.","tr":"Bir motosiklet, şeritin tüm genişliğini kullanma hakkına sahiptir. Motosiklet Sürücü Kılavuzu'na göre manevra yapmak ve tehlikelere tepki vermek için tüm şerite ihtiyaç duyar.","hi":"एक मोटरसाइकिल लेन की पूरी चौड़ाई की हकदार है। इसे चलने-फिरने और खतरों पर प्रतिक्रिया करने के लिए पूरी लेन चाहिए, Motorcycle Operator Manual के अनुसार।","ar":"يحق للدراجة النارية استخدام العرض الكامل للمسار. فهي تحتاج إلى المسار بأكمله للمناورة والاستجابة للمخاطر، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"Why should you not ride side-by-side in the same lane next to a car?","es":"¿Por qué no debes conducir lado a lado en el mismo carril junto a un auto?","ru":"Почему не следует ехать бок о бок в одной полосе рядом с автомобилем?","tr":"Bir arabanın yanında aynı şeritte yan yana neden sürmemelisiniz?","hi":"आपको किसी कार के बगल में एक ही लेन में अगल-बगल क्यों नहीं चलना चाहिए?","ar":"لماذا ينبغي ألا تركب جنباً إلى جنب في نفس المسار بجوار سيارة؟"},"o":[{"en":"A car and a motorcycle each need a full lane to operate safely","es":"Un auto y una motocicleta necesitan cada uno un carril completo para operar de forma segura","ru":"Автомобилю и мотоциклу каждому нужна полная полоса для безопасного движения","tr":"Bir araba ve bir motosikletin her biri güvenli çalışmak için tam bir şerite ihtiyaç duyar","hi":"सुरक्षित रूप से चलने के लिए कार और मोटरसाइकिल को एक-एक पूरी लेन चाहिए","ar":"تحتاج كل من السيارة والدراجة النارية إلى مسار كامل للعمل بأمان"},{"en":"It is required only on highways","es":"Solo es obligatorio en las autopistas","ru":"Это требуется только на шоссе","tr":"Yalnızca otoyollarda gereklidir","hi":"यह केवल राजमार्गों पर आवश्यक है","ar":"إنه مطلوب فقط على الطرق السريعة"},{"en":"It is faster for both vehicles","es":"Es más rápido para ambos vehículos","ru":"Это быстрее для обоих транспортных средств","tr":"Her iki araç için de daha hızlıdır","hi":"यह दोनों वाहनों के लिए तेज़ है","ar":"إنه أسرع لكلتا المركبتين"},{"en":"Cars cannot see motorcycles behind them","es":"Los autos no pueden ver a las motocicletas detrás de ellos","ru":"Автомобили не видят мотоциклы позади себя","tr":"Arabalar arkalarındaki motosikletleri göremez","hi":"कारें अपने पीछे की मोटरसाइकिलों को नहीं देख सकतीं","ar":"لا تستطيع السيارات رؤية الدراجات النارية خلفها"}],"e":{"en":"Cars and motorcycles each need a full lane; sharing one side-by-side leaves no room to maneuver and the driver may move over. The Motorcycle Operator Manual warns against it.","es":"Los autos y las motocicletas necesitan cada uno un carril completo; compartir uno lado a lado no deja espacio para maniobrar y el conductor podría moverse hacia ti. El Manual del Operador de Motocicletas advierte contra esto.","ru":"Автомобилям и мотоциклам каждому нужна полная полоса; совместное использование одной полосы бок о бок не оставляет места для манёвра, и водитель может перестроиться. Руководство для водителей мотоциклов предостерегает от этого.","tr":"Arabalar ve motosikletlerin her biri tam bir şerite ihtiyaç duyar; bir şeriti yan yana paylaşmak manevra için yer bırakmaz ve sürücü size doğru kayabilir. Motosiklet Sürücü Kılavuzu buna karşı uyarır.","hi":"कारों और मोटरसाइकिलों को एक-एक पूरी लेन चाहिए; एक को अगल-बगल साझा करने पर चलने-फिरने की कोई जगह नहीं बचती और चालक इधर आ सकता है। Motorcycle Operator Manual इसके खिलाफ़ चेतावनी देता है।","ar":"تحتاج السيارات والدراجات النارية كل منها إلى مسار كامل؛ فمشاركة مسار واحد جنباً إلى جنب لا تترك مجالاً للمناورة وقد ينتقل السائق نحوك. يحذر دليل مشغل الدراجة النارية من ذلك."}},{"cat":"impairment","a":0,"q":{"en":"What does the manual say about lane splitting, riding between rows of stopped or moving cars?","es":"¿Qué dice el manual sobre la circulación entre carriles (lane splitting), conducir entre filas de autos detenidos o en movimiento?","ru":"Что Руководство говорит о езде между рядами, то есть движении между рядами стоящих или движущихся автомобилей?","tr":"Kılavuz, şerit ayırma (lane splitting), yani durmuş veya hareket halindeki araba sıraları arasında sürme hakkında ne der?","hi":"लेन स्प्लिटिंग, यानी रुकी हुई या चलती कारों की कतारों के बीच चलने, के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن شق المسار، أي القيادة بين صفوف السيارات المتوقفة أو المتحركة؟"},"o":[{"en":"Its legality varies by state and it can be dangerous","es":"Su legalidad varía según el estado y puede ser peligrosa","ru":"Её законность зависит от штата, и она может быть опасной","tr":"Yasallığı eyalete göre değişir ve tehlikeli olabilir","hi":"इसकी वैधता राज्य के अनुसार बदलती है और यह खतरनाक हो सकता है","ar":"تتفاوت قانونيته حسب الولاية ويمكن أن يكون خطراً"},{"en":"It is required in heavy traffic","es":"Es obligatoria en tráfico pesado","ru":"Она обязательна в плотном потоке","tr":"Yoğun trafikte zorunludur","hi":"भारी ट्रैफ़िक में यह आवश्यक है","ar":"إنه مطلوب في حركة المرور الكثيفة"},{"en":"It is the safest place to ride","es":"Es el lugar más seguro para conducir","ru":"Это самое безопасное место для езды","tr":"Sürmek için en güvenli yerdir","hi":"यह चलने के लिए सबसे सुरक्षित जगह है","ar":"إنه أكثر مكان آمن للقيادة"},{"en":"It is always legal nationwide","es":"Siempre es legal en todo el país","ru":"Она всегда законна по всей стране","tr":"Ülke genelinde her zaman yasaldır","hi":"यह देशभर में हमेशा वैध है","ar":"إنه قانوني دائماً على مستوى البلاد"}],"e":{"en":"Lane splitting is illegal in most states and its legality varies; it leaves no space cushion and is hazardous, says the Motorcycle Operator Manual.","es":"La circulación entre carriles es ilegal en la mayoría de los estados y su legalidad varía; no deja colchón de espacio y es peligrosa, dice el Manual del Operador de Motocicletas.","ru":"Езда между рядами незаконна в большинстве штатов, и её законность различается; она не оставляет запаса пространства и опасна, говорит Руководство для водителей мотоциклов.","tr":"Şerit ayırma çoğu eyalette yasa dışıdır ve yasallığı değişir; tampon boşluğu bırakmaz ve tehlikelidir, der Motosiklet Sürücü Kılavuzu.","hi":"लेन स्प्लिटिंग अधिकांश राज्यों में अवैध है और इसकी वैधता बदलती रहती है; यह कोई स्पेस कुशन नहीं छोड़ता और खतरनाक है, Motorcycle Operator Manual कहता है।","ar":"شق المسار غير قانوني في معظم الولايات وتتفاوت قانونيته؛ وهو لا يترك مسافة أمان وخطر، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"When riding near a large truck or bus, what should you keep in mind about its blind spots?","es":"Al conducir cerca de un camión o autobús grande, ¿qué debes tener en cuenta sobre sus puntos ciegos?","ru":"При езде рядом с большим грузовиком или автобусом что следует помнить о его слепых зонах?","tr":"Büyük bir kamyon veya otobüsün yakınında sürerken, kör noktaları hakkında neyi akılda tutmalısınız?","hi":"किसी बड़े ट्रक या बस के पास चलते समय, आपको इसके ब्लाइंड स्पॉट के बारे में क्या ध्यान रखना चाहिए?","ar":"عند القيادة بالقرب من شاحنة أو حافلة كبيرة، ماذا ينبغي أن تضع في اعتبارك بشأن نقاطها العمياء؟"},"o":[{"en":"Large vehicles have no blind spots","es":"Los vehículos grandes no tienen puntos ciegos","ru":"У больших транспортных средств нет слепых зон","tr":"Büyük araçların kör noktası yoktur","hi":"बड़े वाहनों के कोई ब्लाइंड स्पॉट नहीं होते","ar":"ليس للمركبات الكبيرة نقاط عمياء"},{"en":"They have big blind spots, so avoid lingering alongside","es":"Tienen puntos ciegos grandes, así que evita quedarte a su costado","ru":"У них большие слепые зоны, поэтому не задерживайтесь рядом с ними","tr":"Büyük kör noktaları vardır, bu yüzden yanlarında oyalanmaktan kaçının","hi":"उनके बड़े ब्लाइंड स्पॉट होते हैं, इसलिए बगल में रुके रहने से बचें","ar":"لها نقاط عمياء كبيرة، لذا تجنّب البقاء بجانبها"},{"en":"Their mirrors show everything behind them","es":"Sus espejos muestran todo lo que hay detrás de ellos","ru":"Их зеркала показывают всё, что находится позади них","tr":"Aynaları arkalarındaki her şeyi gösterir","hi":"उनके मिरर पीछे का सब कुछ दिखाते हैं","ar":"مراياها تُظهر كل شيء خلفها"},{"en":"Only the front has a blind spot","es":"Solo el frente tiene un punto ciego","ru":"Слепая зона есть только спереди","tr":"Yalnızca ön tarafın bir kör noktası vardır","hi":"केवल सामने एक ब्लाइंड स्पॉट होता है","ar":"الجزء الأمامي فقط له نقطة عمياء"}],"e":{"en":"Large vehicles have big blind spots; if you cannot see the driver in the mirror, the driver cannot see you, so do not linger alongside, per the Motorcycle Operator Manual.","es":"Los vehículos grandes tienen puntos ciegos grandes; si no puedes ver al conductor en el espejo, el conductor no puede verte a ti, así que no te quedes a su costado, según el Manual del Operador de Motocicletas.","ru":"У больших транспортных средств большие слепые зоны; если вы не видите водителя в зеркале, водитель не видит вас, поэтому не задерживайтесь рядом, согласно Руководству для водителей мотоциклов.","tr":"Büyük araçların büyük kör noktaları vardır; sürücüyü aynada göremiyorsanız, sürücü de sizi göremez, bu yüzden yanlarında oyalanmayın, Motosiklet Sürücü Kılavuzu'na göre.","hi":"बड़े वाहनों के बड़े ब्लाइंड स्पॉट होते हैं; अगर आप मिरर में चालक को नहीं देख सकते, तो चालक आपको नहीं देख सकता, इसलिए बगल में रुके न रहें, Motorcycle Operator Manual के अनुसार।","ar":"للمركبات الكبيرة نقاط عمياء كبيرة؛ إذا لم تستطع رؤية السائق في المرآة، فلا يستطيع السائق رؤيتك، لذا لا تبقَ بجانبها، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"You find yourself riding alongside another vehicle in the next lane. What is the safer choice?","es":"Te encuentras conduciendo junto a otro vehículo en el carril contiguo. ¿Cuál es la opción más segura?","ru":"Вы обнаруживаете, что едете рядом с другим транспортным средством в соседней полосе. Какой выбор безопаснее?","tr":"Kendinizi bir sonraki şeritte başka bir aracın yanında sürerken buluyorsunuz. Daha güvenli seçim hangisidir?","hi":"आप खुद को अगली लेन में किसी अन्य वाहन के बगल में चलते हुए पाते हैं। अधिक सुरक्षित विकल्प क्या है?","ar":"تجد نفسك تقود بجانب مركبة أخرى في المسار المجاور. ما هو الخيار الأكثر أماناً؟"},"o":[{"en":"Stay even with it so it can see you","es":"Quedarte a la par de él para que pueda verte","ru":"Держаться вровень с ним, чтобы оно могло вас видеть","tr":"Sizi görebilmesi için onunla aynı hizada kalın","hi":"इसके बराबर बने रहें ताकि यह आपको देख सके","ar":"ابقَ محاذياً لها حتى تتمكن من رؤيتك"},{"en":"Match its exact speed indefinitely","es":"Igualar su velocidad exacta de forma indefinida","ru":"Постоянно подстраиваться под его точную скорость","tr":"Tam hızına süresiz olarak uyun","hi":"अनिश्चित काल तक इसकी ठीक गति से मिलाएँ","ar":"اضبط سرعتك تماماً على سرعتها إلى ما لا نهاية"},{"en":"Speed up or drop back out of the blind spot","es":"Acelerar o quedarte atrás para salir del punto ciego","ru":"Ускориться или отстать, выйдя из слепой зоны","tr":"Hızlanın veya kör noktadan geriye düşün","hi":"गति बढ़ाएँ या ब्लाइंड स्पॉट से पीछे हट जाएँ","ar":"تسارع أو تراجع للخروج من النقطة العمياء"},{"en":"Move onto the lane line","es":"Colocarte sobre la línea del carril","ru":"Перестроиться на разделительную линию полос","tr":"Şerit çizgisinin üzerine geçin","hi":"लेन रेखा पर आ जाएँ","ar":"انتقل إلى خط المسار"}],"e":{"en":"Riding alongside puts you in a blind spot and limits your escape routes; speeding up or dropping back keeps you visible and safe, advises the Motorcycle Operator Manual.","es":"Conducir a la par te coloca en un punto ciego y limita tus rutas de escape; acelerar o quedarte atrás te mantiene visible y seguro, aconseja el Manual del Operador de Motocicletas.","ru":"Езда рядом помещает вас в слепую зону и ограничивает пути отхода; ускорение или отставание сохраняет вашу видимость и безопасность, советует Руководство для водителей мотоциклов.","tr":"Yan yana sürmek sizi bir kör noktaya sokar ve kaçış yollarınızı sınırlar; hızlanmak veya geriye düşmek sizi görünür ve güvende tutar, der Motosiklet Sürücü Kılavuzu.","hi":"बगल में चलना आपको ब्लाइंड स्पॉट में डालता है और आपके बचने के रास्ते सीमित करता है; गति बढ़ाना या पीछे हटना आपको दृश्यमान और सुरक्षित रखता है, Motorcycle Operator Manual सलाह देता है।","ar":"القيادة بجانبها تضعك في نقطة عمياء وتحد من مسارات هروبك؛ التسارع أو التراجع يُبقيك مرئياً وآمناً، ينصح دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"When another vehicle is passing you, what is the best lane position to hold?","es":"Cuando otro vehículo te está rebasando, ¿cuál es la mejor posición en el carril que debes mantener?","ru":"Когда другое транспортное средство обгоняет вас, какое положение на полосе лучше всего держать?","tr":"Başka bir araç sizi geçerken, en iyi şerit konumu hangisidir?","hi":"जब कोई अन्य वाहन आपको पास कर रहा हो, तो रखने के लिए सबसे अच्छी लेन स्थिति क्या है?","ar":"عندما تتجاوزك مركبة أخرى، ما هو أفضل موضع في المسار للحفاظ عليه؟"},"o":[{"en":"Ride the lane line nearest the passer","es":"Conducir sobre la línea del carril más cercana a quien te rebasa","ru":"Ехать по линии полосы, ближайшей к обгоняющему","tr":"Geçen aracın en yakınındaki şerit çizgisinde sürün","hi":"पास करने वाले के सबसे पास वाली लेन रेखा पर चलें","ar":"اركب على خط المسار الأقرب إلى المتجاوِز"},{"en":"Move to the far side away from the vehicle","es":"Moverte al extremo opuesto, lejos del vehículo","ru":"Сместиться на дальнюю сторону, подальше от транспортного средства","tr":"Araçtan uzak tarafa geçin","hi":"वाहन से दूर वाली ओर हट जाएँ","ar":"انتقل إلى الجانب البعيد بعيداً عن المركبة"},{"en":"Stay in the center portion of your lane","es":"Permanecer en la porción central de tu carril","ru":"Оставаться в центральной части своей полосы","tr":"Şeritinizin orta bölümünde kalın","hi":"अपनी लेन के केंद्रीय हिस्से में रहें","ar":"ابقَ في الجزء الأوسط من مسارك"},{"en":"Move onto the shoulder","es":"Moverte al acotamiento","ru":"Сместиться на обочину","tr":"Bankete geçin","hi":"कंधे पर हट जाएँ","ar":"انتقل إلى الكتف"}],"e":{"en":"Stay in the center portion of your lane while being passed; moving away can invite the driver to cut back in too soon, says the Motorcycle Operator Manual.","es":"Permanece en la porción central de tu carril mientras te rebasan; moverte hacia un lado puede invitar al conductor a regresar a tu carril demasiado pronto, dice el Manual del Operador de Motocicletas.","ru":"Оставайтесь в центральной части своей полосы во время обгона; смещение в сторону может побудить водителя перестроиться обратно слишком рано, говорит Руководство для водителей мотоциклов.","tr":"Geçilirken şeritinizin orta bölümünde kalın; uzaklaşmak sürücünün çok erken geri kesmesine davetiye çıkarabilir, der Motosiklet Sürücü Kılavuzu.","hi":"पास किए जाने के दौरान अपनी लेन के केंद्रीय हिस्से में रहें; दूर हटना चालक को बहुत जल्दी वापस कट करने का न्योता दे सकता है, Motorcycle Operator Manual कहता है।","ar":"ابقَ في الجزء الأوسط من مسارك أثناء تجاوزك؛ فالابتعاد قد يدعو السائق إلى العودة إلى مسارك مبكراً جداً، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"What is the correct sequence when you pass another vehicle on a motorcycle?","es":"¿Cuál es la secuencia correcta cuando rebasas a otro vehículo en motocicleta?","ru":"Какова правильная последовательность действий при обгоне другого транспортного средства на мотоцикле?","tr":"Bir motosiklette başka bir aracı geçtiğinizde doğru sıralama nedir?","hi":"जब आप मोटरसाइकिल पर किसी अन्य वाहन को पास करें तो सही क्रम क्या है?","ar":"ما هو التسلسل الصحيح عندما تتجاوز مركبة أخرى على دراجة نارية؟"},"o":[{"en":"Honk, then drift across slowly","es":"Tocar la bocina y luego desplazarte lentamente","ru":"Подать сигнал, затем медленно сместиться поперёк","tr":"Korna çalın, ardından yavaşça karşıya geçin","hi":"हॉर्न बजाएँ, फिर धीरे-धीरे आर-पार बहें","ar":"انفخ البوق، ثم انتقل عبره ببطء"},{"en":"Pass first, then signal once clear","es":"Rebasar primero y luego señalizar una vez libre","ru":"Сначала обогнать, затем просигналить, когда освободитесь","tr":"Önce geçin, ardından temiz olunca bir kez sinyal verin","hi":"पहले पास करें, फिर साफ़ होने पर सिग्नल दें","ar":"تجاوز أولاً، ثم أشِر بمجرد أن تخلو الطريق"},{"en":"Pass on the shoulder without signaling","es":"Rebasar por el acotamiento sin señalizar","ru":"Обгонять по обочине без сигнала","tr":"Sinyal vermeden bankette geçin","hi":"बिना सिग्नल दिए कंधे पर पास करें","ar":"تجاوز على الكتف دون إشارة"},{"en":"Signal, check mirrors and turn your head, then pass and signal back","es":"Señalizar, revisar los espejos y girar la cabeza, luego rebasar y volver a señalizar","ru":"Просигналить, проверить зеркала и повернуть голову, затем обогнать и снова просигналить","tr":"Sinyal verin, aynaları kontrol edip başınızı çevirin, ardından geçip geri sinyal verin","hi":"सिग्नल दें, मिरर जाँचें और सिर घुमाएँ, फिर पास करें और वापस सिग्नल दें","ar":"أشِر، تحقق من المرايا وأدِر رأسك، ثم تجاوز وأشِر للعودة"}],"e":{"en":"Signal and check for traffic with your mirrors and a head turn before moving out, complete the pass, then signal and return to your lane, per the Motorcycle Operator Manual.","es":"Señaliza y revisa el tráfico con tus espejos y un giro de cabeza antes de salirte, completa el rebase, luego señaliza y regresa a tu carril, según el Manual del Operador de Motocicletas.","ru":"Просигнальте и проверьте обстановку зеркалами и поворотом головы перед выездом, завершите обгон, затем просигнальте и вернитесь на свою полосу, согласно Руководству для водителей мотоциклов.","tr":"Dışarı çıkmadan önce sinyal verin ve aynalarınız ile bir baş çevirmeyle trafiği kontrol edin, geçişi tamamlayın, ardından sinyal verip şeritinize dönün, Motosiklet Sürücü Kılavuzu'na göre.","hi":"बाहर निकलने से पहले सिग्नल दें और मिरर व सिर घुमाकर ट्रैफ़िक जाँचें, पास पूरा करें, फिर सिग्नल देकर अपनी लेन में लौटें, Motorcycle Operator Manual के अनुसार।","ar":"أشِر وتحقق من حركة المرور بمراياك وإدارة الرأس قبل الانتقال، أكمل التجاوز، ثم أشِر وعُد إلى مسارك، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"When should you use your turn signals on a motorcycle?","es":"¿Cuándo debes usar tus direccionales en una motocicleta?","ru":"Когда следует использовать указатели поворота на мотоцикле?","tr":"Bir motosiklette sinyallerinizi ne zaman kullanmalısınız?","hi":"आपको मोटरसाइकिल पर अपने टर्न सिग्नल कब उपयोग करने चाहिए?","ar":"متى ينبغي أن تستخدم إشارات الانعطاف على دراجة نارية؟"},"o":[{"en":"Only at intersections with signals","es":"Solo en intersecciones con semáforos","ru":"Только на перекрёстках со светофорами","tr":"Yalnızca sinyalizasyonlu kavşaklarda","hi":"केवल सिग्नल वाले चौराहों पर","ar":"فقط عند التقاطعات ذات الإشارات"},{"en":"Anytime you plan to turn or change lanes, even if no one seems around","es":"Cada vez que planees girar o cambiar de carril, aunque parezca que no hay nadie cerca","ru":"Каждый раз, когда планируете повернуть или перестроиться, даже если рядом, кажется, никого нет","tr":"Etrafta kimse yokmuş gibi görünse bile, dönmeyi veya şerit değiştirmeyi planladığınız her an","hi":"जब भी आप मुड़ने या लेन बदलने की योजना बनाएँ, भले ही कोई आसपास न दिखे","ar":"في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى لو بدا أنه لا أحد حولك"},{"en":"Only when turning left","es":"Solo al girar a la izquierda","ru":"Только при повороте налево","tr":"Yalnızca sola dönerken","hi":"केवल बाएँ मुड़ते समय","ar":"فقط عند الانعطاف يساراً"},{"en":"Only when other vehicles are nearby","es":"Solo cuando haya otros vehículos cerca","ru":"Только когда поблизости есть другие транспортные средства","tr":"Yalnızca başka araçlar yakındayken","hi":"केवल जब अन्य वाहन पास हों","ar":"فقط عندما تكون مركبات أخرى قريبة"}],"e":{"en":"Use your signals anytime you plan to turn or change lanes, even when you think no one is around, because they make your intentions clear, says the Motorcycle Operator Manual.","es":"Usa tus direccionales cada vez que planees girar o cambiar de carril, incluso cuando creas que no hay nadie alrededor, porque dejan claras tus intenciones, dice el Manual del Operador de Motocicletas.","ru":"Используйте сигналы каждый раз, когда планируете повернуть или перестроиться, даже когда кажется, что рядом никого нет, потому что они ясно показывают ваши намерения, говорит Руководство для водителей мотоциклов.","tr":"Sinyallerinizi, dönmeyi veya şerit değiştirmeyi planladığınız her an, etrafta kimse olmadığını düşündüğünüzde bile kullanın, çünkü niyetlerinizi netleştirirler, der Motosiklet Sürücü Kılavuzu.","hi":"अपने सिग्नल जब भी मुड़ने या लेन बदलने की योजना बनाएँ तब उपयोग करें, भले ही आपको लगे कि कोई आसपास नहीं है, क्योंकि वे आपके इरादे स्पष्ट करते हैं, Motorcycle Operator Manual कहता है।","ar":"استخدم إشاراتك في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى عندما تظن أنه لا أحد حولك، لأنها توضّح نواياك، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Because most motorcycle turn signals do not self-cancel, what must the rider remember to do?","es":"Como la mayoría de las direccionales de motocicleta no se cancelan solas, ¿qué debe recordar hacer el conductor?","ru":"Поскольку большинство указателей поворота на мотоциклах не отключаются автоматически, что должен помнить водитель?","tr":"Çoğu motosiklet sinyali kendiliğinden iptal olmadığı için, sürücünün ne yapmayı hatırlaması gerekir?","hi":"क्योंकि अधिकांश मोटरसाइकिल टर्न सिग्नल स्वतः रद्द नहीं होते, सवार को क्या याद रखना चाहिए?","ar":"لأن معظم إشارات الانعطاف في الدراجات النارية لا تُلغى ذاتياً، ماذا يجب أن يتذكر السائق فعله؟"},"o":[{"en":"Replace the signal bulb weekly","es":"Reemplazar el foco de la direccional cada semana","ru":"Менять лампу указателя поворота еженедельно","tr":"Sinyal ampulünü haftalık değiştirmek","hi":"हर हफ़्ते सिग्नल बल्ब बदलें","ar":"استبدال مصباح الإشارة أسبوعياً"},{"en":"Signal only with hand gestures","es":"Señalizar solo con gestos de la mano","ru":"Сигналить только жестами рук","tr":"Yalnızca el işaretleriyle sinyal vermek","hi":"केवल हाथ के इशारों से सिग्नल दें","ar":"الإشارة فقط بإيماءات اليد"},{"en":"Manually cancel the signal after completing the turn","es":"Cancelar manualmente la direccional después de completar el giro","ru":"Вручную отключать указатель поворота после завершения поворота","tr":"Dönüşü tamamladıktan sonra sinyali manuel olarak iptal etmek","hi":"मोड़ पूरा करने के बाद सिग्नल को मैन्युअल रूप से रद्द करें","ar":"إلغاء الإشارة يدوياً بعد إتمام الانعطاف"},{"en":"Leave the signal on until the next turn","es":"Dejar la direccional encendida hasta el siguiente giro","ru":"Оставлять указатель включённым до следующего поворота","tr":"Sinyali bir sonraki dönüşe kadar açık bırakmak","hi":"अगले मोड़ तक सिग्नल चालू छोड़ दें","ar":"ترك الإشارة مضاءة حتى الانعطاف التالي"}],"e":{"en":"Most motorcycle signals are not self-canceling, so cancel them manually after the maneuver; a forgotten signal can mislead other drivers, notes the Motorcycle Operator Manual.","es":"La mayoría de las direccionales de motocicleta no se cancelan solas, así que cancélalas manualmente después de la maniobra; una direccional olvidada puede confundir a otros conductores, señala el Manual del Operador de Motocicletas.","ru":"Большинство указателей поворота на мотоциклах не отключаются автоматически, поэтому отменяйте их вручную после манёвра; забытый сигнал может ввести в заблуждение других водителей, отмечает Руководство для водителей мотоциклов.","tr":"Çoğu motosiklet sinyali kendiliğinden iptal olmaz, bu yüzden manevradan sonra bunları manuel olarak iptal edin; unutulmuş bir sinyal diğer sürücüleri yanıltabilir, belirtir Motosiklet Sürücü Kılavuzu.","hi":"अधिकांश मोटरसाइकिल सिग्नल स्वतः रद्द नहीं होते, इसलिए युद्धाभ्यास के बाद उन्हें मैन्युअल रूप से रद्द करें; एक भूला हुआ सिग्नल अन्य चालकों को गुमराह कर सकता है, Motorcycle Operator Manual बताता है।","ar":"معظم إشارات الدراجات النارية لا تُلغى ذاتياً، لذا ألغِها يدوياً بعد المناورة؛ فالإشارة المنسية يمكن أن تضلل السائقين الآخرين، يشير دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"A driver is tailgating you closely. What does the manual recommend?","es":"Un conductor te va siguiendo muy de cerca (te va pegado). ¿Qué recomienda el manual?","ru":"Водитель близко едет у вас на хвосте. Что рекомендует Руководство?","tr":"Bir sürücü sizi yakından takip ediyor (yakın takip). Kılavuz ne önerir?","hi":"एक चालक आपके बहुत पास से पीछे लगकर चल रहा है। मैनुअल क्या सिफ़ारिश करता है?","ar":"سائق يلتصق بك من الخلف عن قرب. بماذا يوصي الدليل؟"},"o":[{"en":"Brake hard to warn them","es":"Frenar fuerte para advertirle","ru":"Резко затормозить, чтобы предупредить его","tr":"Onları uyarmak için sert fren yapın","hi":"उन्हें चेताने के लिए ज़ोर से ब्रेक लगाएँ","ar":"اكبح بقوة لتحذيره"},{"en":"Speed up to outrun the tailgater","es":"Acelerar para dejar atrás al que te va pegado","ru":"Ускориться, чтобы оторваться от того, кто едет на хвосте","tr":"Yakın takipçiyi geride bırakmak için hızlanın","hi":"टेलगेटर से आगे निकलने के लिए गति बढ़ाएँ","ar":"تسارع للهروب من الملتصق"},{"en":"Ignore them and keep your speed","es":"Ignorarlo y mantener tu velocidad","ru":"Игнорировать его и держать свою скорость","tr":"Onları görmezden gelin ve hızınızı koruyun","hi":"उन्हें अनदेखा करें और अपनी गति बनाए रखें","ar":"تجاهله وحافظ على سرعتك"},{"en":"Change lanes or slow down to let them pass","es":"Cambiar de carril o reducir la velocidad para dejarlo pasar","ru":"Перестроиться или замедлиться, чтобы дать ему обогнать","tr":"Şerit değiştirin veya yavaşlayıp geçmelerine izin verin","hi":"लेन बदलें या धीमा करें ताकि वे पास कर सकें","ar":"غيّر المسار أو أبطئ للسماح له بالتجاوز"}],"e":{"en":"Encourage a tailgater to pass by changing lanes or slowing and opening extra space ahead so both of you have room to stop, advises the Motorcycle Operator Manual.","es":"Anima a quien te va pegado a rebasar cambiando de carril o reduciendo la velocidad y abriendo espacio adicional adelante, para que ambos tengan lugar para detenerse, aconseja el Manual del Operador de Motocicletas.","ru":"Побудите едущего на хвосте обогнать, перестроившись или замедлившись и открыв дополнительное пространство впереди, чтобы у вас обоих было место для остановки, советует Руководство для водителей мотоциклов.","tr":"Yakın takipçiyi geçmeye teşvik etmek için şerit değiştirin ya da yavaşlayıp önünüzde ekstra alan açın, böylece ikinizin de durmak için yeri olur, tavsiye eder Motosiklet Sürücü Kılavuzu.","hi":"लेन बदलकर या धीमा करके और आगे अतिरिक्त जगह खोलकर टेलगेटर को पास करने के लिए प्रोत्साहित करें ताकि आप दोनों के पास रुकने की जगह हो, Motorcycle Operator Manual सलाह देता है।","ar":"شجّع الملتصق من الخلف على التجاوز بتغيير المسار أو الإبطاء وفتح مساحة إضافية أمامك حتى يكون لكليكما مجال للتوقف، ينصح دليل مشغل الدراجة النارية."}}]};
